-- Poems batch 453
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-86','寄漢陽故人','張籍','唐','御定全唐诗','yuding','','[]','知君漢陽住，煙樹遠重重。歸使雨中發，寄書燈下封。',48,'御定全唐詩/json/384.json','["知君漢陽住，煙樹遠重重。歸使雨中發，寄書燈下封。", "同時買江塢，今日別雲松。欲問新移處，青蘿最北峰。"]'),
('yuding-87','送安西將','張籍','唐','御定全唐诗','yuding','','[]','萬里海西路，茫茫邊草秋。計程沙塞口，望伴驛峰頭。',48,'御定全唐詩/json/384.json','["萬里海西路，茫茫邊草秋。計程沙塞口，望伴驛峰頭。", "雪暗非時宿，沙深獨去愁。塞鄉人易老，莫住近蕃州。"]'),
('yuding-88','題李山人幽居','張籍','唐','御定全唐诗','yuding','','[]','襄陽南郭外，茅屋一書生。無事焚香坐，有時尋竹行。',48,'御定全唐詩/json/384.json','["襄陽南郭外，茅屋一書生。無事焚香坐，有時尋竹行。", "畫苔藤杖細，踏石筍鞋輕。應笑風塵客，區區逐世名。"]'),
('yuding-89','早春閒遊','張籍','唐','御定全唐诗','yuding','','[]','年長身多病，獨宜作冷官。從來閑坐慣，漸覺出門難。',48,'御定全唐詩/json/384.json','["年長身多病，獨宜作冷官。從來閑坐慣，漸覺出門難。", "樹影新猶薄，池光晚尚寒。遙聞有花發，騎馬暫行看。"]'),
('yuding-90','贈太常王建藤杖筍鞋','張籍','唐','御定全唐诗','yuding','','[]','蠻藤剪為杖，楚筍結成鞋。稱與詩人用，堪隨禮寺齋。',48,'御定全唐詩/json/384.json','["蠻藤剪為杖，楚筍結成鞋。稱與詩人用，堪隨禮寺齋。", "尋花入幽徑，步日下寒階。以此持相贈，君應愜素懷。"]'),
('yuding-91','和周贊善聞子規','張籍','唐','御定全唐诗','yuding','','[]','秦城啼楚鳥，遠思更紛紛。況是街西夜，偏當雨裏聞。',48,'御定全唐詩/json/384.json','["秦城啼楚鳥，遠思更紛紛。況是街西夜，偏當雨裏聞。", "應投最高樹，似隔數重雲。此處誰能聽，遙知獨有君。"]'),
('yuding-92','送李騎曹靈州歸覲','張籍','唐','御定全唐诗','yuding','','[]','翩翩出上京，幾日到邊城。漸覺風沙起，還將弓箭行。',48,'御定全唐詩/json/384.json','["翩翩出上京，幾日到邊城。漸覺風沙起，還將弓箭行。", "席箕侵路暗，野馬見人驚。軍府知歸慶，應教數騎迎。"]'),
('yuding-93','寒食夜寄姚侍郎','張籍','唐','御定全唐诗','yuding','','[]','貧官多寂寞，不異野人居。作酒和山藥，教兒寫道書。',48,'御定全唐詩/json/384.json','["貧官多寂寞，不異野人居。作酒和山藥，教兒寫道書。", "五湖歸去遠，百事病來疏。況憶同懷者，寒庭月上初。"]'),
('yuding-94','題清澈上人院','張籍','唐','御定全唐诗','yuding','','[]','古寺臨壇久，松間別起堂。看添浴佛水，自合讀經香。',48,'御定全唐詩/json/384.json','["古寺臨壇久，松間別起堂。看添浴佛水，自合讀經香。", "愛養無家客，多傳得效方。過齋長不出，坐臥一繩床。"]'),
('yuding-95','寄靈一上人初歸雲門寺','張籍','唐','御定全唐诗','yuding','','[]','寒山白雲裏，法侶自招攜。竹徑通城下，松門隔水西。',48,'御定全唐詩/json/384.json','["寒山白雲裏，法侶自招攜。竹徑通城下，松門隔水西。", "方同沃洲去，不作武陵迷。仿佛遙看處，秋風是會稽。"]'),
('yuding-96','和裴司空即事通簡舊僚','張籍','唐','御定全唐诗','yuding','','[]','肅肅上臺坐，四方皆仰風。當朝奉明政，早日立元功。',48,'御定全唐詩/json/384.json','["肅肅上臺坐，四方皆仰風。當朝奉明政，早日立元功。", "獨對赤墀下，密宣黃閣中。猶聞動高韻，思與舊僚同。"]'),
('yuding-97','使回留別襄陽李司空','張籍','唐','御定全唐诗','yuding','','[]','江亭寒日晚，弦管有離聲。從此一筵別，獨為千里行。',48,'御定全唐詩/json/384.json','["江亭寒日晚，弦管有離聲。從此一筵別，獨為千里行。", "遲遲戀恩德，役役限公程。回首吟新句，霜雲滿楚城。"]'),
('yuding-98','和戶部令狐尚書喜裴司空見招看雪','張籍','唐','御定全唐诗','yuding','','[]','南園新覆雪，上宰曉來看。誰共登春榭，唯聞有地官。',48,'御定全唐詩/json/384.json','["南園新覆雪，上宰曉來看。誰共登春榭，唯聞有地官。", "色連山遠靜，氣與竹偏寒。高韻更相應，寧同歌吹歡。"]'),
('yuding-99','和裴司空以詩請刑部白侍郎雙鶴','張籍','唐','御定全唐诗','yuding','','[]','皎皎仙家鶴，遠留閑宅中。徘徊幽樹月，嘹唳小亭風。',48,'御定全唐詩/json/384.json','["皎皎仙家鶴，遠留閑宅中。徘徊幽樹月，嘹唳小亭風。", "丞相西園好，池塘野水通。欲將來放此，賞望與賓同。"]'),
('yuding-100','同錦州胡郎中清明日對雨西亭宴','張籍','唐','御定全唐诗','yuding','','[]','郡內開新火，高齋雨氣清。惜花邀客賞，勸酒促歌聲。',48,'御定全唐詩/json/384.json','["郡內開新火，高齋雨氣清。惜花邀客賞，勸酒促歌聲。", "共醉移芳席，留歡閉暮城。政閑方宴語，琴築任遙情。"]'),
('yuding-101','莊陵挽歌詞三首','張籍','唐','御定全唐诗','yuding','','[]','白日已昭昭，干戈亦漸消。迎師親出道，從諫早臨朝。',144,'御定全唐詩/json/384.json','["白日已昭昭，干戈亦漸消。迎師親出道，從諫早臨朝。", "佞幸威權薄，忠良寵錫饒。丘陵今一變，無複白雲謠。", "觀風欲巡洛，習戰亦開池。始改三年政，旋聞七月期。", "陵分內外使，官具吉凶儀。渭北新園路，簫笳遠更悲。", "曉日龍車動，秋風閶闔開。行帷六宮出，執紼萬方來。", "慘慘郊原暮，遲遲挽唱哀。空山煙雨夕，新陌繞陵台。"]'),
('yuding-102','和左司元郎中秋居十首','張籍','唐','御定全唐诗','yuding','','[]','選得閒坊住，秋來草樹肥。風前捲筒簟，雨裏脫荷衣。',480,'御定全唐詩/json/384.json','["選得閒坊住，秋來草樹肥。風前捲筒簟，雨裏脫荷衣。", "野客留方去，山童取藥歸。非因入朝省，過此出門稀。", "有地唯栽竹，無池亦養鵝。學書求墨蹟，釀酒愛朝和。", "古鏡銘文淺，神方謎語多。居貧閑自樂，豪客莫相過。", "閑來松菊地，未省有埃塵。直去多將藥，朝回不訪人。", "見僧收酒器，迎客換紗巾。更恐登清要，難成自在身。", "自知清靜好，不要問時豪。就石安琴枕，穿松壓酒槽。", "山晴因月甚，詩語入秋高。身外無餘事，唯應筆硯勞。", "閑堂新掃灑，稱是早秋天。書客多呈帖，琴僧與合弦。", "莎台乘晚上，竹院就涼眠。終日無忙事，還應似得仙。", "醉倚斑藤杖，閑眠癭木床。案頭行氣訣，爐裏降真香。", "尚儉經營少，居閑意思長。秋茶莫夜飲，新自作松漿。", "每憶舊山居，新教上墨圖。晚花回地種，好酒問人沽。", "夜後開朝簿，申前發省符。為郎凡幾歲，已見白髭須。", "菊地才通履，茶房不壘階。憑醫看蜀藥，寄信覓吳鞋。", "盡得仙家法，多隨道客齋。本無榮辱意，不是學安排。", "林下無拘束，閑行放性靈。好時開藥灶，高處置琴亭。", "更撰居山記，唯尋相鶴經。初當授衣假，無吏挽門鈴。", "客散高齋晚，東園景象偏。晴明猶有蝶，涼冷漸無蟬。", "藤折霜來子，蝸行雨後涎。新詩才上卷，已得滿城傳。"]'),
('yuding-103','經王處士原居','張籍','唐','御定全唐诗','yuding','','[]','舊宅誰相近，唯僧近竹關。庭閑雲滿井，窗曉雪通山。',48,'御定全唐詩/json/384.json','["舊宅誰相近，唯僧近竹關。庭閑雲滿井，窗曉雪通山。", "來客半留宿，借書多寄還。明時未中歲，莫便一生閑。"]'),
('yuding-104','不食仙姑山房','張籍','唐','御定全唐诗','yuding','','[]','寂寂花枝裏，草堂唯素琴。因山曾改眼，見客不言心。',48,'御定全唐詩/json/384.json','["寂寂花枝裏，草堂唯素琴。因山曾改眼，見客不言心。", "月出溪路靜，鶴鳴雲樹深。丹砂如可學，便欲住幽林。"]'),
('yuding-105','江頭','張籍','唐','御定全唐诗','yuding','','[]','晚步隨江遠，來帆過眼頻。試尋新住客，少見故鄉人。',48,'御定全唐詩/json/384.json','["晚步隨江遠，來帆過眼頻。試尋新住客，少見故鄉人。", "回首憐歸翼，長吟任此身。應同南浦雁，更見嶺頭春。"]'),
('yuding-106','寄孫沖主簿','張籍','唐','御定全唐诗','yuding','','[]','低折滄洲簿，無書整兩春。馬從同事借，妻怕罷官貧。',48,'御定全唐詩/json/384.json','["低折滄洲簿，無書整兩春。馬從同事借，妻怕罷官貧。", "道僻收閑藥，詩高笑故人。仍聞長吏奏，表乞鎖廳頻。"]'),
('yuding-107','贈任懶','張籍','唐','御定全唐诗','yuding','','[]','未肯求科第，深坊且隱居。勝游尋野客，高臥看兵書。',48,'御定全唐詩/json/384.json','["未肯求科第，深坊且隱居。勝游尋野客，高臥看兵書。", "點藥醫閑馬，分泉灌遠蔬。漢庭無得意，誰擬薦相如。"]'),
('yuding-108','舊宮人','張籍','唐','御定全唐诗','yuding','','[]','歌舞梁州女，歸時白髮生。全家沒蕃地，無處問鄉程。',48,'御定全唐詩/json/384.json','["歌舞梁州女，歸時白髮生。全家沒蕃地，無處問鄉程。", "宮錦不傳樣，禦香空記名。一身難自說，愁逐路人行。"]'),
('yuding-109','春日留別','張籍','唐','御定全唐诗','yuding','','[]','遊人欲別離，半醉對花枝。看著春又晚，莫輕少年時。',48,'御定全唐詩/json/384.json','["遊人欲別離，半醉對花枝。看著春又晚，莫輕少年時。", "臨行記分處，回首是相思。各向天涯去，重來未可期。"]'),
('yuding-110','沒蕃故人','張籍','唐','御定全唐诗','yuding','','[]','前年伐月支，城上沒全師。蕃漢斷消息，死生長別離。',48,'御定全唐詩/json/384.json','["前年伐月支，城上沒全師。蕃漢斷消息，死生長別離。", "無人收廢帳，歸馬識殘旗。欲祭疑君在，天涯哭此時。"]'),
('yuding-111','贈箕山僧','張籍','唐','御定全唐诗','yuding','','[]','久住空林下，長齋耳目清。蒲團借客坐，石磹甃人行。',48,'御定全唐詩/json/384.json','["久住空林下，長齋耳目清。蒲團借客坐，石磹甃人行。", "似鶴難知性，因山強號名。時聞衣袖裏，暗掐念珠聲。"]'),
('yuding-112','冬夕','張籍','唐','御定全唐诗','yuding','','[]','寒蛩獨罷織，湘雁猶能鳴。月色當窗入，鄉心半夜生。',48,'御定全唐詩/json/384.json','["寒蛩獨罷織，湘雁猶能鳴。月色當窗入，鄉心半夜生。", "不成高枕夢，複作繞階行。回首嗟淹泊，城頭北斗橫。"]'),
('yuding-113','奉和陝州十四翁中丞寄雷州二十二翁司戶之作','張籍','唐','御定全唐诗','yuding','','[]','聯飛獨不前，迥落海南天。賈傅竟行矣，邵公惟泫然。',48,'御定全唐詩/json/384.json','["聯飛獨不前，迥落海南天。賈傅竟行矣，邵公惟泫然。", "瘴開山更遠，路極水無邊。沉劣本多感，況聞原上篇。"]'),
('yuding-114','老將','張籍','唐','御定全唐诗','yuding','','[]','鬢衰頭似雪，行步急如風。不怕騎生馬，猶能挽硬弓。',48,'御定全唐詩/json/384.json','["鬢衰頭似雪，行步急如風。不怕騎生馬，猶能挽硬弓。", "兵書封錦字，手詔滿香筒。今日身憔悴，猶誇定遠功。"]'),
('yuding-115','送友生游峽中','張籍','唐','御定全唐诗','yuding','','[]','風靜楊柳垂，看花又別離。幾年同在此，今日各驅馳。',48,'御定全唐詩/json/384.json','["風靜楊柳垂，看花又別離。幾年同在此，今日各驅馳。", "峽裏聞猿叫，山頭見月時。殷勤一杯酒，珍重歲寒姿。"]'),
('yuding-116','送安法師','張籍','唐','御定全唐诗','yuding','','[]','出郭見落日，別君臨古津。遠程無野寺，宿處問何人。',48,'御定全唐詩/json/384.json','["出郭見落日，別君臨古津。遠程無野寺，宿處問何人。", "原色不分路，錫聲遙隔塵。山陰到家節，猶及蕙蘭春。"]'),
('yuding-117','水','張籍','唐','御定全唐诗','yuding','','[]','蕩漾空沙際，虛明入遠天。秋光照不極，鳥色去無邊。',48,'御定全唐詩/json/384.json','["蕩漾空沙際，虛明入遠天。秋光照不極，鳥色去無邊。", "勢引長雲闊，波輕片雪連。汀洲杳難測，萬古覆蒼煙。"]'),
('yuding-118','嶽州晚景','張籍','唐','御定全唐诗','yuding','','[]','晚景寒鴉集，秋聲旅雁歸。水光浮日去，霞彩映江飛。',48,'御定全唐詩/json/384.json','["晚景寒鴉集，秋聲旅雁歸。水光浮日去，霞彩映江飛。", "洲白蘆花吐，園紅柿葉稀。長沙卑濕地，九月未成衣。"]'),
('yuding-119','寒食後','張籍','唐','御定全唐诗','yuding','','[]','田舍清明日，家家出火遲。白衫眠古巷，紅索搭高枝。',48,'御定全唐詩/json/384.json','["田舍清明日，家家出火遲。白衫眠古巷，紅索搭高枝。", "紗帶生難結，銅釵重易垂。斬新衣著盡，還似去年時。"]'),
('yuding-120','寒食書事二首','張籍','唐','御定全唐诗','yuding','','[]','今朝一百五，出戶雨初晴。舞愛雙飛蝶，歌聞數裏鶯。',96,'御定全唐詩/json/384.json','["今朝一百五，出戶雨初晴。舞愛雙飛蝶，歌聞數裏鶯。", "江深青草岸，花滿白雲城。為政多孱懦，應無酷吏名。", "出城煙火少，況複是今朝。閑坐將誰語，臨觴只自謠。", "階前春蘚遍，衣上落花飄。妓樂州人戲，使君心寂寥。"]'),
('yuding-121','和李僕射雨中寄盧、嚴二給事','張籍','唐','御定全唐诗','yuding','','[]','郊原飛雨至，城闕濕雲埋。迸點時穿牖，浮漚欲上階。',72,'御定全唐詩/json/384.json','["郊原飛雨至，城闕濕雲埋。迸點時穿牖，浮漚欲上階。", "偏滋解籜竹，並灑落花槐。晚潤生琴匣，新涼滿藥齋。", "從容朝務退，放曠掖曹乖。盡日無來客，閑吟感此懷。"]'),
('yuding-122','酬李僕射晚春見寄','張籍','唐','御定全唐诗','yuding','','[]','戟戶洞初晨，鶯聲雨後頻。虛庭清氣在，眾藥濕光新。',72,'御定全唐詩/json/384.json','["戟戶洞初晨，鶯聲雨後頻。虛庭清氣在，眾藥濕光新。", "魚動芳池面，苔侵老竹身。教鋪嘗酒處，自問探花人。", "獨此長多病，幽居欲過春。今朝聽高韻，忽覺離埃塵。"]'),
('yuding-123','和盧常侍寄華山鄭隱者','張籍','唐','御定全唐诗','yuding','','[]','獨住三峰下，年深學煉丹。一間松葉屋，數片石花冠。',72,'御定全唐詩/json/384.json','["獨住三峰下，年深學煉丹。一間松葉屋，數片石花冠。", "酒待山中飲，琴將洞口彈。開門移遠竹，剪草出幽蘭。", "荒壁通泉架，晴崖曬藥壇。寄知騎省客，長向白雲閑。"]'),
('yuding-124','和令狐尚書平泉東莊近居李僕射有寄十韻','張籍','唐','御定全唐诗','yuding','','[]','平地有清泉，伊南古寺邊。漲池閑繞屋，出野遍澆田。',120,'御定全唐詩/json/384.json','["平地有清泉，伊南古寺邊。漲池閑繞屋，出野遍澆田。", "舊隱離多日，新鄰得幾年。探幽皆一絕，選勝又雙全。", "門靜山光別，園深竹影連。斜分采藥徑，直過釣魚船。", "雞犬還應識，雲霞頓覺鮮。追思應不遠，賞愛諒難偏。", "此處堪長往，遊人早共傳。各當恩寄重，歸臥恐無緣。"]'),
('yuding-125','送鄭尚書出鎮南海','張籍','唐','御定全唐诗','yuding','','[]','遠鎮承新命，王程不假催。班行爭路送，恩賜並時來。',72,'御定全唐詩/json/384.json','["遠鎮承新命，王程不假催。班行爭路送，恩賜並時來。", "牙旆從城展，兵符到府開。蠻聲喧夜市，海色浸潮台。", "畫角天邊月，寒關嶺上梅。共知公望重，多是來年回。"]'),
('yuding-126','徐州試反舌無聲','張籍','唐','御定全唐诗','yuding','','[]','夏木多好鳥，偏知反舌名。林幽仍共宿，時過即無聲。',72,'御定全唐詩/json/384.json','["夏木多好鳥，偏知反舌名。林幽仍共宿，時過即無聲。", "竹外天空曉，溪頭雨自晴。居人宜寂寞，深院益淒清。", "入霧暗相失，當風閑易驚。來年上林苑，知爾最先鳴。"]'),
('yuding-127','省試行不由徑','張籍','唐','御定全唐诗','yuding','','[]','田裏有微徑，賢人不復行。孰知求捷步，又恐異端成。',72,'御定全唐詩/json/384.json','["田裏有微徑，賢人不復行。孰知求捷步，又恐異端成。", "從易眾所欲，安邪患亦生。誰能達天道，共此競前程。", "子羽有遺跡，孔門傳舊聲。今逢大君子，士節自光明。"]'),
('yuding-128','新城甲仗樓','張籍','唐','御定全唐诗','yuding','','[]','謝氏起新樓，西臨城角頭。圖功百尺麗，藏器五兵修。',120,'御定全唐詩/json/384.json','["謝氏起新樓，西臨城角頭。圖功百尺麗，藏器五兵修。", "結締榱甍固，虛明戶檻幽。魚龍卷旗幟，霜雪積戈矛。", "暑雨熇烝隔，涼風宴位留。地高形出沒，山靜氣清優。", "睥睨斜光徹，闌幹宿靄浮。芊芊粳稻色，脈脈苑溪流。", "郡化黃丞相，詩成沉隱侯。居茲良得景，殊勝峴山遊。"]'),
('yuding-129','贈殷山人','張籍','唐','御定全唐诗','yuding','','[]','鬱鬱山中客，知名四十年。恓惶身獨隱，寂寞性應便。',360,'御定全唐詩/json/384.json','["鬱鬱山中客，知名四十年。恓惶身獨隱，寂寞性應便。", "世業公侯籍，生涯黍稷田。藤懸讀書帳，竹系網魚船。", "已種千頭橘，新開數脈泉。閒遊攜酒遠，幽語向僧偏。", "入洞題松過，看花選石眠。避喧長汩沒，逢勝即留連。", "自古多高跡，如君少比肩。耕耘此辛苦，章句已流傳。", "昔日交遊盛，當時省閣賢。同袍還共弊，連轡每推先。", "講序居重席，群儒願執鞭。滿堂虛左待，眾目望喬遷。", "才異時難用，情高道自全。畏人顏慘澹，疏物勢迍邅。", "賢者聞知命，吾生複禮玄。深藏報恩劍，久緝養生篇。", "憔悴眾夫笑，經過郡守憐。夕陽悲病鶴，霜氣動饑鸇。", "處士誰能薦，窮途世所捐。伯鸞甘寄食，元淑苦無錢。", "策蹇秋塵裏，吟詩黃葉前。故裘餘白領，廢瑟斷朱弦。", "志氣終猶在，逍遙任自然。家貧念婚嫁，身老戀雲煙。", "放逸棲岩鹿，清虛飲露蟬。鄭逃秦谷口，嚴愛越溪邊。", "霄漢予猶阻，榮枯子不牽。山城一相遇，感激意難宣。"]'),
('yuding-130','夏日可畏','張籍','唐','御定全唐诗','yuding','','[]','赫赫溫風扇，炎炎夏日徂。火威馳迥野，畏景鑠遙途。',72,'御定全唐詩/json/384.json','["赫赫溫風扇，炎炎夏日徂。火威馳迥野，畏景鑠遙途。", "勢矯翔陽翰，功分造化爐。禁城千品燭，黃道一輪孤。", "落照頻空簟，餘暉卷夕梧。如何倦遊子，中路獨踟躕。"]'),
('yuding-131','罔象得玄珠','張籍','唐','御定全唐诗','yuding','','[]','赤水今何處，遺珠已渺然。離婁徒肆目，罔象乃通玄。',72,'御定全唐詩/json/384.json','["赤水今何處，遺珠已渺然。離婁徒肆目，罔象乃通玄。", "皎潔因成性，圓明不在泉。暗中看夜色，塵外照晴田。", "無脛真難掬，懷疑實易遷。今朝搜擇得，應免媚晴川。"]'),
('yuding-132','和李僕射西園','張籍','唐','御定全唐诗','yuding','','[]','遇午歸閑處，西庭敞四簷。高眠著琴枕，散帖檢書簽。',96,'御定全唐詩/json/384.json','["遇午歸閑處，西庭敞四簷。高眠著琴枕，散帖檢書簽。", "印在休通客，山晴好捲簾。竹涼蠅少到，藤暗蝶爭潛。", "曉鵲頻驚喜，疏蟬不許拈。石苔生紫點，欄藥吐紅尖。", "虛坐詩情遠，幽探道侶兼。所營尚勝地，雖儉複誰嫌。"]'),
('yuding-0','送裴相公赴鎮太原','張籍','唐','御定全唐诗','yuding','','[]','盛德雄名遠近知，功高先乞守藩維。銜恩暫遣分龍節，',40,'御定全唐詩/json/385.json','["盛德雄名遠近知，功高先乞守藩維。銜恩暫遣分龍節，", "明年塞北清蕃落，應建生祠請立碑。"]'),
('yuding-1','寄元員外','張籍','唐','御定全唐诗','yuding','','[]','外郎直罷無餘事，掃灑書堂試藥爐。門巷不教當要鬧，',40,'御定全唐詩/json/385.json','["外郎直罷無餘事，掃灑書堂試藥爐。門巷不教當要鬧，", "朝省入頻閑日少，可能同作舊遊無。"]'),
('yuding-2','贈梅處士','張籍','唐','御定全唐诗','yuding','','[]','早聞聲價滿京城，頭白江湖放曠情。講易自傳新注義，',40,'御定全唐詩/json/385.json','["早聞聲價滿京城，頭白江湖放曠情。講易自傳新注義，", "天子如今議封禪，應將束帛請先生。"]'),
('yuding-3','贈王秘書','張籍','唐','御定全唐诗','yuding','','[]','不曾浪出謁公侯，唯向花間水畔遊。每著新衣看藥灶，',40,'御定全唐詩/json/385.json','["不曾浪出謁公侯，唯向花間水畔遊。每著新衣看藥灶，", "自領閑司了無事，得來君處喜相留。"]'),
('yuding-4','謝裴司空寄馬','張籍','唐','御定全唐诗','yuding','','[]','騄耳新駒駿得名，司空遠自寄書生。乍離華廄移蹄澀，',40,'御定全唐詩/json/385.json','["騄耳新駒駿得名，司空遠自寄書生。乍離華廄移蹄澀，", "長思歲旦沙堤上，得從鳴珂傍火城。"]'),
('yuding-5','酬秘書王丞見寄','張籍','唐','御定全唐诗','yuding','','[]','相看頭白來城闕，卻憶漳溪舊往還。今體詩中偏出格，',40,'御定全唐詩/json/385.json','["相看頭白來城闕，卻憶漳溪舊往還。今體詩中偏出格，", "芸閣水曹雖最冷，與君長喜得身閑。"]'),
('yuding-6','送李餘及第後歸蜀','張籍','唐','御定全唐诗','yuding','','[]','十年人詠好詩章，今日成名出舉場。歸去唯將新誥牒，',40,'御定全唐詩/json/385.json','["十年人詠好詩章，今日成名出舉場。歸去唯將新誥牒，", "鄉里親情相見日，一時攜酒賀高堂。"]'),
('yuding-7','早朝寄白舍人、嚴郎中','張籍','唐','御定全唐诗','yuding','','[]','鼓聲初動未聞雞，羸馬街中踏凍泥。燭暗有時沖石柱，',40,'御定全唐詩/json/385.json','["鼓聲初動未聞雞，羸馬街中踏凍泥。燭暗有時沖石柱，", "鳳闕星郎離去遠，合門開日入還齊。"]'),
('yuding-8','書懷寄元郎中','張籍','唐','御定全唐诗','yuding','','[]','轉覺人間無氣味，常因身外省因緣。經過獨愛遊山客，',40,'御定全唐詩/json/385.json','["轉覺人間無氣味，常因身外省因緣。經過獨愛遊山客，", "吟君釣客詞中說，便欲南歸榜小船。"]'),
('yuding-9','贈道士宜師','張籍','唐','御定全唐诗','yuding','','[]','自到王城得幾年，巴童蜀馬共隨緣。兩朝侍從當時貴，',40,'御定全唐詩/json/385.json','["自到王城得幾年，巴童蜀馬共隨緣。兩朝侍從當時貴，", "閒房暫喜居相近，還得陪師坐竹邊。"]'),
('yuding-10','書懷寄王秘書','張籍','唐','御定全唐诗','yuding','','[]','白髮如今欲滿頭，從來百事盡應休。只於觸目須防病，',40,'御定全唐詩/json/385.json','["白髮如今欲滿頭，從來百事盡應休。只於觸目須防病，", "賴君同在京城住，每到花前免獨遊。"]'),
('yuding-11','題韋郎中新亭','張籍','唐','御定全唐诗','yuding','','[]','起得幽亭景複新，碧莎地上更無塵。琴書著盡猶嫌少，',40,'御定全唐詩/json/385.json','["起得幽亭景複新，碧莎地上更無塵。琴書著盡猶嫌少，", "成名同日官連署，此處經過有幾人。"]'),
('yuding-12','送楊州判官','張籍','唐','御定全唐诗','yuding','','[]','應得煙霞出俗心，茅山道士共追尋。閑憐鶴貌偏能畫，',40,'御定全唐詩/json/385.json','["應得煙霞出俗心，茅山道士共追尋。閑憐鶴貌偏能畫，", "征南幕裏多賓客，君獨相知最校深。"]'),
('yuding-13','喜王起侍郎放牒','張籍','唐','御定全唐诗','yuding','','[]','東風節氣近清明，車馬爭來滿禁城。二十八人初上牒，',40,'御定全唐詩/json/385.json','["東風節氣近清明，車馬爭來滿禁城。二十八人初上牒，", "共賀春司能鑒識，今年定合有公卿。"]'),
('yuding-14','贈王司馬','張籍','唐','御定全唐诗','yuding','','[]','白笏朱衫年少時，久登班列會朝儀。貯財不省關身用，',40,'御定全唐詩/json/385.json','["白笏朱衫年少時，久登班列會朝儀。貯財不省關身用，", "未曾相識多聞說，遙望長如白玉枝。"]'),
('yuding-15','書懷','張籍','唐','御定全唐诗','yuding','','[]','自小信成疏懶性，人間事事總無功。別從仙客求方法，',40,'御定全唐詩/json/385.json','["自小信成疏懶性，人間事事總無功。別從仙客求方法，", "未能即便休官去，慚愧南山采藥翁。"]'),
('yuding-16','贈令狐博士','張籍','唐','御定全唐诗','yuding','','[]','頭白新年六十餘，近聞生計轉空虛。久為博士誰能識，',40,'御定全唐詩/json/385.json','["頭白新年六十餘，近聞生計轉空虛。久為博士誰能識，", "古來賢哲皆如此，應是才高與眾疏。"]'),
('yuding-17','送從弟刪東歸','張籍','唐','御定全唐诗','yuding','','[]','雲水東南兩月程，貪歸慶節馬蹄輕。春橋欲醉攀花別，',40,'御定全唐詩/json/385.json','["雲水東南兩月程，貪歸慶節馬蹄輕。春橋欲醉攀花別，", "舊山風月知應好，莫向秋時不到京。"]'),
('yuding-18','贈王秘書','張籍','唐','御定全唐诗','yuding','','[]','早在山東聲價遠，曾將順策佐嫖姚。賦來詩句無閑語，',40,'御定全唐詩/json/385.json','["早在山東聲價遠，曾將順策佐嫖姚。賦來詩句無閑語，", "獨從書閣歸時晚，春水渠邊看柳條。"]'),
('yuding-19','哭丘長史','張籍','唐','御定全唐诗','yuding','','[]','曾是先皇殿上臣，丹砂久服不成真。常騎馬在嘶空櫪，',40,'御定全唐詩/json/385.json','["曾是先皇殿上臣，丹砂久服不成真。常騎馬在嘶空櫪，", "最悲昨日同遊處，看卻春風樹樹新。"]'),
('yuding-20','送枝江劉明府','張籍','唐','御定全唐诗','yuding','','[]','老著青衫為楚宰，平生志業有誰知。家僮從去愁行遠，',40,'御定全唐詩/json/385.json','["老著青衫為楚宰，平生志業有誰知。家僮從去愁行遠，", "向南漸漸雲山好，一路唯聞唱竹枝。"]'),
('yuding-21','送從弟徹東歸','張籍','唐','御定全唐诗','yuding','','[]','緱山領印知公奏，才稱同時盡不如。奉使賀成登冊禮，',40,'御定全唐詩/json/385.json','["緱山領印知公奏，才稱同時盡不如。奉使賀成登冊禮，", "早晚得為朝署拜，閑坊買宅作鄰居。"]'),
('yuding-22','哭胡十八遇','張籍','唐','御定全唐诗','yuding','','[]','早得聲名年尚少，尋常志氣出風塵。文場繼續成三代，',40,'御定全唐詩/json/385.json','["早得聲名年尚少，尋常志氣出風塵。文場繼續成三代，", "送君帳下衣裳白，數尺墳頭柏樹新。"]'),
('yuding-23','贈賈島','張籍','唐','御定全唐诗','yuding','','[]','籬落荒涼僮僕饑，樂游原上住多時。蹇驢放飽騎將出，',40,'御定全唐詩/json/385.json','["籬落荒涼僮僕饑，樂游原上住多時。蹇驢放飽騎將出，", "姓名未上登科記，身屈惟應內史知。"]'),
('yuding-24','逢王建有贈','張籍','唐','御定全唐诗','yuding','','[]','年狀皆齊初有髭，鵲山漳水每追隨。使君座下朝聽易，',40,'御定全唐詩/json/385.json','["年狀皆齊初有髭，鵲山漳水每追隨。使君座下朝聽易，", "經今三十餘年事，卻說還同昨日時。"]'),
('yuding-25','移居靜安坊，答元八郎中','張籍','唐','御定全唐诗','yuding','','[]','長安寺裏多時住，雖守卑官不苦貧。作活每常嫌費力，',40,'御定全唐詩/json/385.json','["長安寺裏多時住，雖守卑官不苦貧。作活每常嫌費力，", "更喜往還相去近，門前減卻送書人。"]'),
('yuding-26','送楊少尹赴鳳翔','張籍','唐','御定全唐诗','yuding','','[]','詩名往日動長安，首首人家卷裏看。西學已行秦博士，',40,'御定全唐詩/json/385.json','["詩名往日動長安，首首人家卷裏看。西學已行秦博士，", "今去岐州生計薄，移居偏近隴頭寒。"]'),
('yuding-27','送韓侍禦歸山','張籍','唐','御定全唐诗','yuding','','[]','聞君久臥在雲間，為佐嫖姚未得還。新結茅廬招隱逸，',40,'御定全唐詩/json/385.json','["聞君久臥在雲間，為佐嫖姚未得還。新結茅廬招隱逸，", "明日珂聲出城去，家僮不復掃柴關。"]'),
('yuding-28','新除水曹郎，答白舍人見賀','張籍','唐','御定全唐诗','yuding','','[]','年過五十到南宮，章句無名荷至公。黃紙開呈相府後，',40,'御定全唐詩/json/385.json','["年過五十到南宮，章句無名荷至公。黃紙開呈相府後，", "最幸紫薇郎見愛，獨稱官與古人同。"]'),
('yuding-29','送楊少尹赴滿城','張籍','唐','御定全唐诗','yuding','','[]','官為本府當身榮，因得還鄉任野情。自廢田園今作主，',40,'御定全唐詩/json/385.json','["官為本府當身榮，因得還鄉任野情。自廢田園今作主，", "公事況閑詩更好，將隨相逐上山行。"]'),
('yuding-30','哭元九少府','張籍','唐','御定全唐诗','yuding','','[]','平生志業獨相知，早結雲山老去期。初作學官常共宿，',40,'御定全唐詩/json/385.json','["平生志業獨相知，早結雲山老去期。初作學官常共宿，", "今日春風花滿宅，入門行哭見靈帷。"]'),
('yuding-31','送侯判官赴廣州從軍','張籍','唐','御定全唐诗','yuding','','[]','年少才高求自展，將身萬里赴軍門。辟書遠到開呈客，',40,'御定全唐詩/json/385.json','["年少才高求自展，將身萬里赴軍門。辟書遠到開呈客，", "海花蠻草連冬有，行處無家不滿園。"]'),
('yuding-32','答白杭州郡樓登望畫圖見寄','張籍','唐','御定全唐诗','yuding','','[]','畫得江城登望處，寄來今日到長安。乍驚物色從詩出，',40,'御定全唐詩/json/385.json','["畫得江城登望處，寄來今日到長安。乍驚物色從詩出，", "見君向此閑吟意，肯恨當時作外官。"]'),
('yuding-33','贈趙將軍','張籍','唐','御定全唐诗','yuding','','[]','當年膽略已縱橫，每見妖星氣不平。身貴早登龍尾道，',40,'御定全唐詩/json/385.json','["當年膽略已縱橫，每見妖星氣不平。身貴早登龍尾道，", "會取安西將報國，淩煙閣上大書名。"]'),
('yuding-34','送和蕃公主','張籍','唐','御定全唐诗','yuding','','[]','塞上如今無戰塵，漢家公主出和親。邑司猶屬宗卿寺，',40,'御定全唐詩/json/385.json','["塞上如今無戰塵，漢家公主出和親。邑司猶屬宗卿寺，", "氈城南望無回日，空見沙蓬水柳春。"]'),
('yuding-35','寒食內宴二首','張籍','唐','御定全唐诗','yuding','','[]','朝光瑞氣滿宮樓，彩纛魚龍四周稠。廊下禦廚分冷食，',80,'御定全唐詩/json/385.json','["朝光瑞氣滿宮樓，彩纛魚龍四周稠。廊下禦廚分冷食，", "共喜拜恩侵夜出，金吾不敢問行由。", "城闕沉沉向曉寒，恩當令節賜餘歡，瑞煙深處開三殿，", "宮筵戲樂年年別，已得三回對禦看。"]'),
('yuding-36','朝日敕賜百官櫻桃','張籍','唐','御定全唐诗','yuding','','[]','仙果人間都未有，今朝忽見下天門。捧盤小吏初宣敕，',40,'御定全唐詩/json/385.json','["仙果人間都未有，今朝忽見下天門。捧盤小吏初宣敕，", "每年重此先偏待，願得千春奉至尊。"]'),
('yuding-37','太白老人','張籍','唐','御定全唐诗','yuding','','[]','日觀東峰幽客住，竹巾藤帶亦逢迎。暗修黃籙無人見，',40,'御定全唐詩/json/385.json','["日觀東峰幽客住，竹巾藤帶亦逢迎。暗修黃籙無人見，", "春泉四面繞茅屋，日日唯聞杵臼聲。"]'),
('yuding-38','和裴司空酬滿城楊少尹','張籍','唐','御定全唐诗','yuding','','[]','聖朝偏重大司空，人詠元和第一功。擁節高臨漢水上，',40,'御定全唐詩/json/385.json','["聖朝偏重大司空，人詠元和第一功。擁節高臨漢水上，", "誰不望歸丞相府，江邊楊柳又秋風。"]'),
('yuding-39','寄和州劉使君','張籍','唐','御定全唐诗','yuding','','[]','別離已久猶為郡，閑向春風倒酒瓶。送客特過沙口堰，',40,'御定全唐詩/json/385.json','["別離已久猶為郡，閑向春風倒酒瓶。送客特過沙口堰，", "到此詩情應更遠，醉中高詠有誰聽。"]'),
('yuding-40','贈商州王使君','張籍','唐','御定全唐诗','yuding','','[]','銜命南來會郡堂，卻思朝裏接班行。才雄猶是山城守，',40,'御定全唐詩/json/385.json','["銜命南來會郡堂，卻思朝裏接班行。才雄猶是山城守，", "明朝從此辭君去，獨出商關路漸長。"]'),
('yuding-41','寄令狐賓客','張籍','唐','御定全唐诗','yuding','','[]','勳名盡得國家傳，退狎琴僧與酒仙。還帶郡符經幾處，',40,'御定全唐詩/json/385.json','["勳名盡得國家傳，退狎琴僧與酒仙。還帶郡符經幾處，", "秋日出城伊水好，領誰相逐上閑船。"]'),
('yuding-42','寄梅處士','張籍','唐','御定全唐诗','yuding','','[]','擾擾人間是與非，官閑自覺省心機。六行班裏身常下，',40,'御定全唐詩/json/385.json','["擾擾人間是與非，官閑自覺省心機。六行班裏身常下，", "君今獨得居山樂，應喜多時未辦歸。"]'),
('yuding-43','送施肩吾東歸','張籍','唐','御定全唐诗','yuding','','[]','知君本是煙霞客，被薦因來城闕間。世業偏臨七裏瀨，',40,'御定全唐詩/json/385.json','["知君本是煙霞客，被薦因來城闕間。世業偏臨七裏瀨，", "惆悵灞亭相送去，雲中琪樹不同攀。"]'),
('yuding-44','昆侖兒','張籍','唐','御定全唐诗','yuding','','[]','昆侖家住海中州，蠻客將來漢地遊。言語解教秦吉了，',40,'御定全唐詩/json/385.json','["昆侖家住海中州，蠻客將來漢地遊。言語解教秦吉了，", "自愛肌膚黑如漆，行時半脫木綿裘。"]'),
('yuding-45','贈李杭州','張籍','唐','御定全唐诗','yuding','','[]','仙郎白首未歸朝，應為蒼生領六條。惠化州人盡清淨，',40,'御定全唐詩/json/385.json','["仙郎白首未歸朝，應為蒼生領六條。惠化州人盡清淨，", "終日政聲長獨坐，開門長望浙江潮。"]'),
('yuding-46','送鄭尚書赴廣州','張籍','唐','御定全唐诗','yuding','','[]','聖朝選將持符節，內使宣時百辟聽。海北蠻夷來舞蹈，',40,'御定全唐詩/json/385.json','["聖朝選將持符節，內使宣時百辟聽。海北蠻夷來舞蹈，", "此處莫言多瘴癘，天邊看取老人星。"]'),
('yuding-47','賀秘書王丞南郊攝將軍','張籍','唐','御定全唐诗','yuding','','[]','正初天子親郊禮，詔攝將軍領衛兵。斜帶銀刀入黃道，',40,'御定全唐詩/json/385.json','["正初天子親郊禮，詔攝將軍領衛兵。斜帶銀刀入黃道，", "共喜與君逢此日，病中無計得隨行。"]'),
('yuding-48','送令狐尚書赴東都留守','張籍','唐','御定全唐诗','yuding','','[]','朝廷重寄在關東，共說從前選上公。勳業新城大樑鎮，',40,'御定全唐詩/json/385.json','["朝廷重寄在關東，共說從前選上公。勳業新城大樑鎮，", "每領群臣拜章慶，半開門仗日曈曈。"]'),
('yuding-49','拜豐陵','張籍','唐','御定全唐诗','yuding','','[]','歲朝園寢遣公卿，學省班中亦攝行。身逐陵官齊再拜，',40,'御定全唐詩/json/385.json','["歲朝園寢遣公卿，學省班中亦攝行。身逐陵官齊再拜，", "卻下龍門看漸遠，金峰高處日微明。"]'),
('yuding-50','贈孔尚書','張籍','唐','御定全唐诗','yuding','','[]','能將直道曆榮班，事著元和實錄間。三表自陳辭北闕，',40,'御定全唐詩/json/385.json','["能將直道曆榮班，事著元和實錄間。三表自陳辭北闕，", "宅近青山高靜處，時歸林下暫開關。"]'),
('yuding-51','酬杭州白使君，兼寄浙東元大夫','張籍','唐','御定全唐诗','yuding','','[]','相印暫離臨遠鎮，掖垣出守複同時。一行已作三年別，',40,'御定全唐詩/json/385.json','["相印暫離臨遠鎮，掖垣出守複同時。一行已作三年別，", "人間聚散真難料，莫歎平生信所之。"]'),
('yuding-52','寄蘇州白二十二使君','張籍','唐','御定全唐诗','yuding','','[]','三朝出入紫微臣，頭白金章未在身。登第早年同座主，',40,'御定全唐詩/json/385.json','["三朝出入紫微臣，頭白金章未在身。登第早年同座主，", "此處吟詩向山寺，知君忘卻曲江春。"]'),
('yuding-53','送白賓客分司東都','張籍','唐','御定全唐诗','yuding','','[]','赫赫聲名三十春，高情人獨出埃塵。病辭省闥歸閑地，',40,'御定全唐詩/json/385.json','["赫赫聲名三十春，高情人獨出埃塵。病辭省闥歸閑地，", "老人也擬休官去，便是君家池上人。"]'),
('yuding-54','贈閻少保','張籍','唐','御定全唐诗','yuding','','[]','辭榮戀闕未還鄉，修養年多氣力強。半俸歸燒伏火藥，',40,'御定全唐詩/json/385.json','["辭榮戀闕未還鄉，修養年多氣力強。半俸歸燒伏火藥，", "竹樹晴深寒院靜，長懸石磬在虛廊。"]'),
('yuding-55','贈別王侍禦赴任陝州司馬','張籍','唐','御定全唐诗','yuding','','[]','京城在處閒人少，唯共君行並馬蹄。更和詩篇名最出，',40,'御定全唐詩/json/385.json','["京城在處閒人少，唯共君行並馬蹄。更和詩篇名最出，", "今日春明門外別，更無因得到街西。"]'),
('yuding-56','田司空入朝','張籍','唐','御定全唐诗','yuding','','[]','西來將相位兼雄，不與諸君覲禮同。早變山東知順命，',40,'御定全唐詩/json/385.json','["西來將相位兼雄，不與諸君覲禮同。早變山東知順命，", "閶闔曉開銅漏靜，身當受冊大明宮。"]'),
('yuding-57','送浙西周判官','張籍','唐','御定全唐诗','yuding','','[]','由來自是煙霞客，早已聞名詩酒間。天闕因將賀表到，',40,'御定全唐詩/json/385.json','["由來自是煙霞客，早已聞名詩酒間。天闕因將賀表到，", "吳越主人偏愛重，多應不肯放君閑。"]'),
('yuding-58','送吳煉師歸王屋','張籍','唐','御定全唐诗','yuding','','[]','玉陽峰下學長生，玉洞仙中已有名。獨戴熊須冠暫出，',40,'御定全唐詩/json/385.json','["玉陽峰下學長生，玉洞仙中已有名。獨戴熊須冠暫出，", "卻到瑤壇上頭宿，應聞空裏步虛聲。"]'),
('yuding-59','送邵州林使君','張籍','唐','御定全唐诗','yuding','','[]','詞客南行寵命新，瀟湘郡入曲江津。山幽自足探微處，',40,'御定全唐詩/json/385.json','["詞客南行寵命新，瀟湘郡入曲江津。山幽自足探微處，", "知君不作家私計，遷日還同到日貧。"]'),
('yuding-60','寄王六侍禦','張籍','唐','御定全唐诗','yuding','','[]','漸覺近來筋力少，難堪今日在風塵。誰能借問功名事，',40,'御定全唐詩/json/385.json','["漸覺近來筋力少，難堪今日在風塵。誰能借問功名事，", "洞庭已置新居處，歸去安期與作鄰。"]'),
('yuding-61','送稽亭山寺僧','張籍','唐','御定全唐诗','yuding','','[]','師住稽亭高處寺，斜廊曲閣倚雲開。山門十裏松間入，',40,'御定全唐詩/json/385.json','["師住稽亭高處寺，斜廊曲閣倚雲開。山門十裏松間入，", "舊房到日閑吟後，林下還登說法台。"]'),
('yuding-62','送汀州源使君','張籍','唐','御定全唐诗','yuding','','[]','曾成趙北歸朝計，因拜王門最好官。為郡暫辭雙鳳闕，',40,'御定全唐詩/json/385.json','["曾成趙北歸朝計，因拜王門最好官。為郡暫辭雙鳳闕，", "地僻尋常來客少，刺桐花發共誰看。"]'),
('yuding-63','寄孫洛陽格','張籍','唐','御定全唐诗','yuding','','[]','久持刑憲聲名遠，好是中朝正直臣。赤縣上來應足事，',40,'御定全唐詩/json/385.json','["久持刑憲聲名遠，好是中朝正直臣。赤縣上來應足事，", "遙愛南橋秋日晚，雨邊楊柳映天津。"]'),
('yuding-64','胡山人歸王屋，因有贈','張籍','唐','御定全唐诗','yuding','','[]','轉轉無成到白頭，人間舉眼盡堪愁。此生已是蹉跎去，',40,'御定全唐詩/json/385.json','["轉轉無成到白頭，人間舉眼盡堪愁。此生已是蹉跎去，", "君歸與訪移家處，若個峰頭最較幽。"]'),
('yuding-65','寄虔州韓使君','張籍','唐','御定全唐诗','yuding','','[]','南康太守負才豪，五十如今未擁旄。早得一人知姓字，',40,'御定全唐詩/json/385.json','["南康太守負才豪，五十如今未擁旄。早得一人知姓字，", "郡政已成秋思遠，閑吟應不問官曹。"]'),
('yuding-66','送從弟蒙赴饒州','張籍','唐','御定全唐诗','yuding','','[]','京城南去鄱陽遠，風月悠悠別思勞。三領郡符新寄重，',40,'御定全唐詩/json/385.json','["京城南去鄱陽遠，風月悠悠別思勞。三領郡符新寄重，", "到日更行清靜化，春田應不見蓬蒿。"]'),
('yuding-67','羅道士','張籍','唐','御定全唐诗','yuding','','[]','城裏無人得實年，衣襟常帶臭黃煙。樓中賒酒唯留藥，',40,'御定全唐詩/json/385.json','["城裏無人得實年，衣襟常帶臭黃煙。樓中賒酒唯留藥，", "尋常行處皆逢見，世上多疑是謫仙。"]'),
('yuding-68','寄陸渾趙明府','張籍','唐','御定全唐诗','yuding','','[]','與君學省同官處，常日相隨說道情。新作陸渾山縣長，',40,'御定全唐詩/json/385.json','["與君學省同官處，常日相隨說道情。新作陸渾山縣長，", "公事稀疏來客少，無妨著屐獨閑行。"]'),
('yuding-69','同將作韋二少監贈水部李郎中','張籍','唐','御定全唐诗','yuding','','[]','舊年同是水曹郎，各罷魚符自楚鄉。重著青衫承詔命，',40,'御定全唐詩/json/385.json','["舊年同是水曹郎，各罷魚符自楚鄉。重著青衫承詔命，", "憶得當時亦連步，如今獨在讀書堂。"]'),
('yuding-70','贈王侍禦','張籍','唐','御定全唐诗','yuding','','[]','心同野鶴與塵遠，詩似冰壺見底清。府縣同趨昨日事，',40,'御定全唐詩/json/385.json','["心同野鶴與塵遠，詩似冰壺見底清。府縣同趨昨日事，", "自歎獨為折腰吏，可憐驄馬路傍行。"]'),
('yuding-71','送金少卿副使歸新羅','張籍','唐','御定全唐诗','yuding','','[]','雲島茫茫天畔微，向東萬里一帆飛。久為侍子承恩重，',40,'御定全唐詩/json/385.json','["雲島茫茫天畔微，向東萬里一帆飛。久為侍子承恩重，", "從前此去人無數，光彩如君定是稀。"]'),
('yuding-72','送李司空赴鎮襄陽','張籍','唐','御定全唐诗','yuding','','[]','中外兼權社稷臣，千官齊出拜行塵。再調公鼎勳庸盛，',40,'御定全唐詩/json/385.json','["中外兼權社稷臣，千官齊出拜行塵。再調公鼎勳庸盛，", "襄陽風景由來好，重與江山作主人。"]'),
('yuding-73','送李僕射愬赴鎮鳳翔','張籍','唐','御定全唐诗','yuding','','[]','由來勳業屬英雄，兄弟連營列位同。先入賊城擒首惡，',40,'御定全唐詩/json/385.json','["由來勳業屬英雄，兄弟連營列位同。先入賊城擒首惡，", "天子新收秦隴地，故教移鎮古扶風。"]'),
('yuding-74','寄白二十二舍人','張籍','唐','御定全唐诗','yuding','','[]','早知內詔過先輩，蹭蹬江南百事疏。湓浦城中為上佐，',40,'御定全唐詩/json/385.json','["早知內詔過先輩，蹭蹬江南百事疏。湓浦城中為上佐，", "三省比來名望重，肯容君去樂樵漁。"]'),
('yuding-75','送友人盧處士游吳越','張籍','唐','御定全唐诗','yuding','','[]','羨君東去見殘梅，惟有王孫獨未回。吳苑夕陽明古堞，',40,'御定全唐詩/json/385.json','["羨君東去見殘梅，惟有王孫獨未回。吳苑夕陽明古堞，", "試問漁舟看雪浪，幾多江燕荇花開。"]'),
('yuding-76','蘇州江岸留別樂天','張籍','唐','御定全唐诗','yuding','','[]','銀泥裙映錦障泥，畫舸停橈馬簇蹄。清管曲終鸚鵡語，',40,'御定全唐詩/json/385.json','["銀泥裙映錦障泥，畫舸停橈馬簇蹄。清管曲終鸚鵡語，", "莫忘使君吟詠處，女墳湖北武丘西。"]'),
('yuding-77','寒食看花','張籍','唐','御定全唐诗','yuding','','[]','早入公門到夜歸，不因寒食少閒時。顛狂繞樹猿離鎖，',40,'御定全唐詩/json/385.json','["早入公門到夜歸，不因寒食少閒時。顛狂繞樹猿離鎖，", "老來自喜常無事，仰面西園得詠詩。"]'),
('yuding-78','酬浙東元尚書見寄綾素','張籍','唐','御定全唐诗','yuding','','[]','越地繒紗紋樣新，遠封來寄學曹人。便令裁制為時服，',40,'御定全唐詩/json/385.json','["越地繒紗紋樣新，遠封來寄學曹人。便令裁制為時服，", "三千裏外無由見，海上東風又一春。"]'),
('yuding-79','贈項斯','張籍','唐','御定全唐诗','yuding','','[]','端坐吟詩忘忍饑，萬人中覓似君稀。門連野水風長到，',40,'御定全唐詩/json/385.json','["端坐吟詩忘忍饑，萬人中覓似君稀。門連野水風長到，", "曲江亭上頻頻見，為愛鸕鷀雨裏飛。"]'),
('yuding-0','和韋開州盛山十二首：宿雲亭','張籍','唐','御定全唐诗','yuding','','[]','清淨當深處，虛明向遠開。捲簾無俗客，應只見雲來。',24,'御定全唐詩/json/386.json','["清淨當深處，虛明向遠開。捲簾無俗客，應只見雲來。"]'),
('yuding-1','和韋開州盛山十二首：梅溪','張籍','唐','御定全唐诗','yuding','','[]','自愛新梅好，行尋一徑斜。不教人掃石，恐損落來花。',24,'御定全唐詩/json/386.json','["自愛新梅好，行尋一徑斜。不教人掃石，恐損落來花。"]'),
('yuding-2','和韋開州盛山十二首：茶嶺','張籍','唐','御定全唐诗','yuding','','[]','紫芽連白蕊，初向嶺頭生。自看家人摘，尋常觸露行。',24,'御定全唐詩/json/386.json','["紫芽連白蕊，初向嶺頭生。自看家人摘，尋常觸露行。"]'),
('yuding-3','和韋開州盛山十二首：流杯渠','張籍','唐','御定全唐诗','yuding','','[]','淥酒白螺杯，隨流去複回。似知人把處，各向面前來。',24,'御定全唐詩/json/386.json','["淥酒白螺杯，隨流去複回。似知人把處，各向面前來。"]'),
('yuding-4','和韋開州盛山十二首：磐石磴','張籍','唐','御定全唐诗','yuding','','[]','壘石盤空遠，層層勢不危。不知行幾匝，得到上頭時。',24,'御定全唐詩/json/386.json','["壘石盤空遠，層層勢不危。不知行幾匝，得到上頭時。"]'),
('yuding-5','和韋開州盛山十二首：桃塢','張籍','唐','御定全唐诗','yuding','','[]','春塢桃花發，多將野客遊。日西殊未散，看望酒缸頭。',24,'御定全唐詩/json/386.json','["春塢桃花發，多將野客遊。日西殊未散，看望酒缸頭。"]'),
('yuding-6','和韋開州盛山十二首：竹岩','張籍','唐','御定全唐诗','yuding','','[]','獨入千竿裏，緣岩踏石層。筍頭齊欲出，更不許人登。',24,'御定全唐詩/json/386.json','["獨入千竿裏，緣岩踏石層。筍頭齊欲出，更不許人登。"]'),
('yuding-7','和韋開州盛山十二首：琵琶台','張籍','唐','御定全唐诗','yuding','','[]','臺上綠蘿春，閑登不待人。每當休暇日，著履戴紗巾。',24,'御定全唐詩/json/386.json','["臺上綠蘿春，閑登不待人。每當休暇日，著履戴紗巾。"]'),
('yuding-8','和韋開州盛山十二首：胡蘆沼','張籍','唐','御定全唐诗','yuding','','[]','曲沼春流滿，新蒲映野鵝。閑齋朝飯後，拄杖繞行多。',24,'御定全唐詩/json/386.json','["曲沼春流滿，新蒲映野鵝。閑齋朝飯後，拄杖繞行多。"]'),
('yuding-9','和韋開州盛山十二首：隱月岫','張籍','唐','御定全唐诗','yuding','','[]','月出深峰裏，清涼夜亦寒。每嫌西落疾，不得到明看。',24,'御定全唐詩/json/386.json','["月出深峰裏，清涼夜亦寒。每嫌西落疾，不得到明看。"]'),
('yuding-10','和韋開州盛山十二首：繡衣石榻','張籍','唐','御定全唐诗','yuding','','[]','山城無別味，藥草兼魚果。時到繡衣人，同來石上坐。',24,'御定全唐詩/json/386.json','["山城無別味，藥草兼魚果。時到繡衣人，同來石上坐。"]'),
('yuding-11','和韋開州盛山十二首：上士泉瓶','張籍','唐','御定全唐诗','yuding','','[]','階上一眼泉，四邊青石甃。唯有護淨僧，添瓶將盥漱。',24,'御定全唐詩/json/386.json','["階上一眼泉，四邊青石甃。唯有護淨僧，添瓶將盥漱。"]'),
('yuding-12','送遠客','張籍','唐','御定全唐诗','yuding','','[]','憔悴遠歸客，殷勤欲別杯。九星壇下路，幾日見重來。',24,'御定全唐詩/json/386.json','["憔悴遠歸客，殷勤欲別杯。九星壇下路，幾日見重來。"]'),
('yuding-13','寄西峰僧','張籍','唐','御定全唐诗','yuding','','[]','松暗水涓涓，夜涼人未眠。西峰月猶在，遙憶草堂前。',24,'御定全唐詩/json/386.json','["松暗水涓涓，夜涼人未眠。西峰月猶在，遙憶草堂前。"]'),
('yuding-14','禪師','張籍','唐','御定全唐诗','yuding','','[]','獨在西峰頂，年年閉石房。定中無弟子，人到為焚香。',24,'御定全唐詩/json/386.json','["獨在西峰頂，年年閉石房。定中無弟子，人到為焚香。"]'),
('yuding-15','惜花','張籍','唐','御定全唐诗','yuding','','[]','山中春已晚，處處見花稀。明日來應盡，林間宿不歸。',24,'御定全唐詩/json/386.json','["山中春已晚，處處見花稀。明日來應盡，林間宿不歸。"]'),
('yuding-16','題暉師影堂','張籍','唐','御定全唐诗','yuding','','[]','日早欲參禪，竟無相識緣。道場今獨到，惆悵影堂前。',24,'御定全唐詩/json/386.json','["日早欲參禪，竟無相識緣。道場今獨到，惆悵影堂前。"]'),
('yuding-17','涇州塞','張籍','唐','御定全唐诗','yuding','','[]','行到涇州塞，唯聞羌戍鼙。道邊古雙堠，猶記向安西。',24,'御定全唐詩/json/386.json','["行到涇州塞，唯聞羌戍鼙。道邊古雙堠，猶記向安西。"]'),
('yuding-18','野田','張籍','唐','御定全唐诗','yuding','','[]','漠漠野田草，草中牛羊道。古墓無子孫，白楊不得老。',24,'御定全唐詩/json/386.json','["漠漠野田草，草中牛羊道。古墓無子孫，白楊不得老。"]'),
('yuding-19','岸花','張籍','唐','御定全唐诗','yuding','','[]','可憐岸邊樹，紅蕊發青條。東風吹渡水，沖著木蘭橈。',24,'御定全唐詩/json/386.json','["可憐岸邊樹，紅蕊發青條。東風吹渡水，沖著木蘭橈。"]'),
('yuding-20','別于鵠','張籍','唐','御定全唐诗','yuding','','[]','離燈及晨輝，行人起複思。出門兩相顧，青山路逶迤。',24,'御定全唐詩/json/386.json','["離燈及晨輝，行人起複思。出門兩相顧，青山路逶迤。"]'),
('yuding-21','送蜀客','張籍','唐','御定全唐诗','yuding','','[]','蜀客南行祭碧雞，木綿花發錦江西。',32,'御定全唐詩/json/386.json','["蜀客南行祭碧雞，木綿花發錦江西。", "山橋日晚行人少，時見猩猩樹上啼。"]'),
('yuding-22','送元結','張籍','唐','御定全唐诗','yuding','','[]','昔日同遊漳水邊，如今重說恨綿綿。',32,'御定全唐詩/json/386.json','["昔日同遊漳水邊，如今重說恨綿綿。", "天涯相見還離別，客路秋風又幾年。"]'),
('yuding-23','宿山祠','張籍','唐','御定全唐诗','yuding','','[]','秋草宮人斜裏墓，宮人誰送葬來時。',32,'御定全唐詩/json/386.json','["秋草宮人斜裏墓，宮人誰送葬來時。", "千千萬萬皆如此，家在邊城亦不知。"]'),
('yuding-24','美人宮棋','張籍','唐','御定全唐诗','yuding','','[]','紅燭臺前出翠娥，海沙鋪局巧相和。',32,'御定全唐詩/json/386.json','["紅燭臺前出翠娥，海沙鋪局巧相和。", "趁行移手巡收盡，數數看誰得最多。"]'),
('yuding-25','蠻州','張籍','唐','御定全唐诗','yuding','','[]','瘴水蠻中入洞流，人家多住竹棚頭。',32,'御定全唐詩/json/386.json','["瘴水蠻中入洞流，人家多住竹棚頭。", "一山海上無城郭，唯見松牌記象州。"]'),
('yuding-26','送元宗簡','張籍','唐','御定全唐诗','yuding','','[]','貂帽垂肩窄皂裘，雪深騎馬向西州。',32,'御定全唐詩/json/386.json','["貂帽垂肩窄皂裘，雪深騎馬向西州。", "暫時相見還相送，卻閉閑門依舊愁。"]'),
('yuding-27','寄徐晦','張籍','唐','御定全唐诗','yuding','','[]','鄠陂魚美酒偏濃，不出琴齋見雪峰。',32,'御定全唐詩/json/386.json','["鄠陂魚美酒偏濃，不出琴齋見雪峰。", "應勝昨來趨府日，簿書床上亂重重。"]'),
('yuding-28','寄白學士','張籍','唐','御定全唐诗','yuding','','[]','自掌天書見客稀，縱因休沐鎖雙扉。',32,'御定全唐詩/json/386.json','["自掌天書見客稀，縱因休沐鎖雙扉。", "幾回扶病欲相訪，知向禁中歸未歸。"]'),
('yuding-29','喜王六同宿','張籍','唐','御定全唐诗','yuding','','[]','十八年來恨別離，唯同一宿詠新詩。',32,'御定全唐詩/json/386.json','["十八年來恨別離，唯同一宿詠新詩。", "更相借問詩中語，共說如今勝舊時。"]'),
('yuding-30','題玉像堂','張籍','唐','御定全唐诗','yuding','','[]','玉毫不著世間塵，輝相分明十八身。',32,'御定全唐詩/json/386.json','["玉毫不著世間塵，輝相分明十八身。", "入夜無煙燈更好，堂中唯有轉經人。"]'),
('yuding-31','與賈島閒遊','張籍','唐','御定全唐诗','yuding','','[]','水北原南草色新，雪消風暖不生塵。',32,'御定全唐詩/json/386.json','["水北原南草色新，雪消風暖不生塵。", "城中車馬應無數，能解閑行有幾人。"]'),
('yuding-32','哭丘長史','張籍','唐','御定全唐诗','yuding','','[]','丘公已歿故人稀，欲過街西更訪誰。',32,'御定全唐詩/json/386.json','["丘公已歿故人稀，欲過街西更訪誰。", "每到子城東路上，憶君相逐入朝時。"]'),
('yuding-33','哭孟寂','張籍','唐','御定全唐诗','yuding','','[]','曲江院裏題名處，十九人中最少年。',32,'御定全唐詩/json/386.json','["曲江院裏題名處，十九人中最少年。", "今日春光君不見，杏花零落寺門前。"]'),
('yuding-34','患眼','張籍','唐','御定全唐诗','yuding','','[]','三年患眼今年校，免與風光便隔生。',32,'御定全唐詩/json/386.json','["三年患眼今年校，免與風光便隔生。", "昨日韓家後園裏，看花猶似未分明。"]'),
('yuding-35','答劉競','張籍','唐','御定全唐诗','yuding','','[]','劉君久被時拋擲，老向城中作選人。',32,'御定全唐詩/json/386.json','["劉君久被時拋擲，老向城中作選人。", "昨日街西相近住，每來存問老夫身。"]'),
('yuding-36','贈華嚴院僧','張籍','唐','御定全唐诗','yuding','','[]','一身依止荒閑院，燭耀窗中有宿煙。',32,'御定全唐詩/json/386.json','["一身依止荒閑院，燭耀窗中有宿煙。", "遍禮華嚴經裏字，不曾行到寺門前。"]'),
('yuding-37','逢故人','張籍','唐','御定全唐诗','yuding','','[]','山東一十餘年別，今日相逢在上都。',32,'御定全唐詩/json/386.json','["山東一十餘年別，今日相逢在上都。", "說盡向來無限事，相看摩捋白髭須。"]'),
('yuding-38','送蕭遠弟','張籍','唐','御定全唐诗','yuding','','[]','街北槐花傍馬垂，病身相送出門遲。',32,'御定全唐詩/json/386.json','["街北槐花傍馬垂，病身相送出門遲。", "與君別後秋風夜，作得新詩說向誰。"]'),
('yuding-39','送辛少府任樂安','張籍','唐','御定全唐诗','yuding','','[]','才多不肯浪容身，老大詩章轉更新。',32,'御定全唐詩/json/386.json','["才多不肯浪容身，老大詩章轉更新。", "選得天臺山下住，一家全作學仙人。"]'),
('yuding-40','贈任道人','張籍','唐','御定全唐诗','yuding','','[]','長安多病無生計，藥鋪醫人亂索錢。',32,'御定全唐詩/json/386.json','["長安多病無生計，藥鋪醫人亂索錢。", "欲得定知身上事，憑君為算小行年。"]'),
('yuding-41','招周居士','張籍','唐','御定全唐诗','yuding','','[]','閉門秋雨濕牆莎，俗客來稀野思多。',32,'御定全唐詩/json/386.json','["閉門秋雨濕牆莎，俗客來稀野思多。", "已掃書齋安藥灶，山人作意早經過。"]'),
('yuding-42','送許處士','張籍','唐','御定全唐诗','yuding','','[]','高情自與俗人疏，獨向藍溪選僻居。',32,'御定全唐詩/json/386.json','["高情自與俗人疏，獨向藍溪選僻居。", "會到白雲長取醉，不能窗下讀閒書。"]'),
('yuding-43','送律師歸婺州','張籍','唐','御定全唐诗','yuding','','[]','京中開講已多時，曾作壇頭證戒師。',32,'御定全唐詩/json/386.json','["京中開講已多時，曾作壇頭證戒師。", "歸到雙溪橋北寺，鄉僧爭就學威儀。"]'),
('yuding-44','題楊秘書新居','張籍','唐','御定全唐诗','yuding','','[]','愛閑不向爭名地，宅在街西最靜坊。',32,'御定全唐詩/json/386.json','["愛閑不向爭名地，宅在街西最靜坊。", "卷裏詩過一千首，白頭新受秘書郎。"]'),
('yuding-45','送晊師','張籍','唐','御定全唐诗','yuding','','[]','九星台下煎茶別，五老峰頭覓寺居。',32,'御定全唐詩/json/386.json','["九星台下煎茶別，五老峰頭覓寺居。", "作得新詩旋相寄，人來請莫達空書。"]'),
('yuding-46','送僧往金州','張籍','唐','御定全唐诗','yuding','','[]','聞道溪陰山水好，師行一一遍經過。',32,'御定全唐詩/json/386.json','["聞道溪陰山水好，師行一一遍經過。", "事須覓取堪居處，若個溪頭藥最多。"]'),
('yuding-47','尋徐道士','張籍','唐','御定全唐诗','yuding','','[]','尋師遠到暉天觀，竹院森森閉藥房。',32,'御定全唐詩/json/386.json','["尋師遠到暉天觀，竹院森森閉藥房。", "聞入靜來經七日，仙童簷下獨焚香。"]'),
('yuding-48','答開州韋使君寄車前子','張籍','唐','御定全唐诗','yuding','','[]','開州午日車前子，作藥人皆道有神。',32,'御定全唐詩/json/386.json','["開州午日車前子，作藥人皆道有神。", "慚愧使君憐病眼，三千餘裏寄閒人。"]'),
('yuding-49','憶故州','張籍','唐','御定全唐诗','yuding','','[]','壘石為山伴野夫，自收靈藥讀仙書。',32,'御定全唐詩/json/386.json','["壘石為山伴野夫，自收靈藥讀仙書。", "如今身是他州客，每見青山憶舊居。"]'),
('yuding-50','送客游蜀','張籍','唐','御定全唐诗','yuding','','[]','行盡青山到益州，錦城樓下二江流。',32,'御定全唐詩/json/386.json','["行盡青山到益州，錦城樓下二江流。", "杜家曾向此中住，為到浣花溪水頭。"]'),
('yuding-51','送陸暢','張籍','唐','御定全唐诗','yuding','','[]','共踏長安街裏塵，吳州獨作未歸身。',32,'御定全唐詩/json/386.json','["共踏長安街裏塵，吳州獨作未歸身。", "昔年舊宅今誰住，君過西塘與問人。"]'),
('yuding-52','感春','張籍','唐','御定全唐诗','yuding','','[]','遠客悠悠任病身，謝家池上又逢春。',32,'御定全唐詩/json/386.json','["遠客悠悠任病身，謝家池上又逢春。", "明年各自東西去，此地看花是別人。"]'),
('yuding-53','贈李司議','張籍','唐','御定全唐诗','yuding','','[]','漢庭誰問投荒客，十載天南著白衣。',32,'御定全唐詩/json/386.json','["漢庭誰問投荒客，十載天南著白衣。", "秋草茫茫惡溪路，嶺頭遙送北人稀。"]'),
('yuding-54','別客','張籍','唐','御定全唐诗','yuding','','[]','青山歷歷水悠悠，今日相逢明日秋。',32,'御定全唐詩/json/386.json','["青山歷歷水悠悠，今日相逢明日秋。", "系馬城邊楊柳樹，為君沽酒暫淹留。"]'),
('yuding-55','登樓寄胡家兄弟','張籍','唐','御定全唐诗','yuding','','[]','獨上西樓盡日閑，林煙演漾鳥蠻蠻。',32,'御定全唐詩/json/386.json','["獨上西樓盡日閑，林煙演漾鳥蠻蠻。", "謝家兄弟重城裏，不得同看雨後山。"]'),
('yuding-56','答劉明府','張籍','唐','御定全唐诗','yuding','','[]','身病多時又客居，滿城親舊盡相疏。',32,'御定全唐詩/json/386.json','["身病多時又客居，滿城親舊盡相疏。", "可憐絳縣劉明府，猶解頻頻寄遠書。"]'),
('yuding-57','酬藤杖','張籍','唐','御定全唐诗','yuding','','[]','病裏出門行步遲，喜君相贈古藤枝。',32,'御定全唐詩/json/386.json','["病裏出門行步遲，喜君相贈古藤枝。", "倚來自覺身生力，每向傍人說得時。"]'),
('yuding-58','法雄寺東樓','張籍','唐','御定全唐诗','yuding','','[]','汾陽舊宅今為寺，猶有當時歌舞樓。',32,'御定全唐詩/json/386.json','["汾陽舊宅今為寺，猶有當時歌舞樓。", "四十年來車馬絕，古槐深巷暮蟬愁。"]'),
('yuding-59','寄故人','張籍','唐','御定全唐诗','yuding','','[]','靜曲閒房病客居，蟬聲滿樹槿花疏。',32,'御定全唐詩/json/386.json','["靜曲閒房病客居，蟬聲滿樹槿花疏。", "故人只在藍田縣，強半年來未得書。"]'),
('yuding-60','鄰婦哭征夫','張籍','唐','御定全唐诗','yuding','','[]','雙鬟初合便分離，萬里征夫不得隨。',32,'御定全唐詩/json/386.json','["雙鬟初合便分離，萬里征夫不得隨。", "今日軍回身獨歿，去時鞍馬別人騎。"]'),
('yuding-61','和崔駙馬聞蟬','張籍','唐','御定全唐诗','yuding','','[]','鳳凰樓下多歡樂，不覺秋風暮雨天。',32,'御定全唐詩/json/386.json','["鳳凰樓下多歡樂，不覺秋風暮雨天。", "應為昨來身暫病，蟬聲得到耳傍邊。"]'),
('yuding-62','和裴僕射看櫻桃花','張籍','唐','御定全唐诗','yuding','','[]','昨日南園新雨後，櫻桃花發舊枝柯。',32,'御定全唐詩/json/386.json','["昨日南園新雨後，櫻桃花發舊枝柯。", "天明不待人同看，繞樹重重履跡多。"]'),
('yuding-63','和長安郭明府與友人縣中會飲','張籍','唐','御定全唐诗','yuding','','[]','一尊清酒兩人同，好在街西水縣中。',32,'御定全唐詩/json/386.json','["一尊清酒兩人同，好在街西水縣中。", "自恨病身相去遠，此時閑坐對秋風。"]'),
('yuding-64','唐昌觀看花','張籍','唐','御定全唐诗','yuding','','[]','新紅舊紫不相宜，看覺從前兩月遲。',32,'御定全唐詩/json/386.json','["新紅舊紫不相宜，看覺從前兩月遲。", "更向同來詩客道，明年到此莫過時。"]'),
('yuding-65','九華觀看花','張籍','唐','御定全唐诗','yuding','','[]','街西無數閒遊處，不似九華仙觀中。',32,'御定全唐詩/json/386.json','["街西無數閒遊處，不似九華仙觀中。", "花裏可憐池上景，幾重牆壁貯春風。"]'),
('yuding-66','贈姚合','張籍','唐','御定全唐诗','yuding','','[]','丹鳳城門向曉開，千官相次入朝來。',32,'御定全唐詩/json/386.json','["丹鳳城門向曉開，千官相次入朝來。", "唯君獨走沖塵土，下馬橋邊報直回。"]'),
('yuding-67','同韋員外開元觀尋時道士','張籍','唐','御定全唐诗','yuding','','[]','觀裏初晴竹樹涼，閑行共到最高房。',32,'御定全唐詩/json/386.json','["觀裏初晴竹樹涼，閑行共到最高房。", "昨來官罷無生計，欲就師求斷谷方。"]'),
('yuding-68','同韓侍禦南溪夜賞','張籍','唐','御定全唐诗','yuding','','[]','喜作閒人得出城，南溪兩月逐君行。',32,'御定全唐詩/json/386.json','["喜作閒人得出城，南溪兩月逐君行。", "忽聞新命須歸去，一夜船中語到明。"]'),
('yuding-69','使行望悟真寺','張籍','唐','御定全唐诗','yuding','','[]','采玉峰連佛寺幽，高高斜對驛門樓。',32,'御定全唐詩/json/386.json','["采玉峰連佛寺幽，高高斜對驛門樓。", "無端來去騎官馬，寸步教身不得遊。"]'),
('yuding-70','重陽日至峽道','張籍','唐','御定全唐诗','yuding','','[]','無限青山行已盡，回看忽覺遠離家。',32,'御定全唐詩/json/386.json','["無限青山行已盡，回看忽覺遠離家。", "逢高欲飲重陽酒，山菊今朝未有花。"]'),
('yuding-71','贈主客劉郎中','張籍','唐','御定全唐诗','yuding','','[]','憶昔君登南省日，老夫猶是褐衣身。',32,'御定全唐詩/json/386.json','["憶昔君登南省日，老夫猶是褐衣身。", "誰知二十餘年後，來作客曹相替人。"]'),
('yuding-72','同嚴給事聞唐昌觀玉蕊近有仙過，因成絕句二首','張籍','唐','御定全唐诗','yuding','','[]','千枝花裏玉塵飛，阿母宮中見亦稀。',64,'御定全唐詩/json/386.json','["千枝花裏玉塵飛，阿母宮中見亦稀。", "應共諸仙鬥百草，獨來偷得一枝歸。", "九色雲中紫鳳車，尋仙來到洞仙家。", "飛輪回處無蹤跡，唯有斑斑滿地花。"]'),
('yuding-73','秋思','張籍','唐','御定全唐诗','yuding','','[]','洛陽城裏見秋風，欲作歸書意萬重。',32,'御定全唐詩/json/386.json','["洛陽城裏見秋風，欲作歸書意萬重。", "忽恐匆匆說不盡，行人臨發又開封。"]'),
('yuding-74','憶遠','張籍','唐','御定全唐诗','yuding','','[]','行人猶未有歸期，萬里初程日暮時。',32,'御定全唐詩/json/386.json','["行人猶未有歸期，萬里初程日暮時。", "唯愛門前雙柳樹，枝枝葉葉不相離。"]'),
('yuding-75','玉仙館','張籍','唐','御定全唐诗','yuding','','[]','長溪新雨色如泥，野水陰雲盡向西。',32,'御定全唐詩/json/386.json','["長溪新雨色如泥，野水陰雲盡向西。", "楚客天南行漸遠，山山樹裏鷓鴣啼。"]'),
('yuding-76','寄府吏','張籍','唐','御定全唐诗','yuding','','[]','野外尋花共作期，今朝出郭不相隨。',32,'御定全唐詩/json/386.json','["野外尋花共作期，今朝出郭不相隨。", "待君公事有閑日，此地春風應過時。"]'),
('yuding-77','弟蕭遠雪夜同宿','張籍','唐','御定全唐诗','yuding','','[]','數卷新遊蜀客詩，長安僻巷得相隨。',32,'御定全唐詩/json/386.json','["數卷新遊蜀客詩，長安僻巷得相隨。", "草堂雪夜攜琴宿，說是青城館裏時。"]'),
('yuding-78','涼州詞三首','張籍','唐','御定全唐诗','yuding','','[]','邊城暮雨雁飛低，蘆筍初生漸欲齊。',96,'御定全唐詩/json/386.json','["邊城暮雨雁飛低，蘆筍初生漸欲齊。", "無數鈴聲遙過磧，應馱白練到安西。", "古鎮城門白磧開，胡兵往往傍沙堆。", "巡邊使客行應早，欲問平安無使來。", "鳳林關裏水東流，白草黃榆六十秋。", "邊將皆承主恩澤，無人解道取涼州。"]'),
('yuding-79','宮詞','張籍','唐','御定全唐诗','yuding','','[]','新鷹初放兔猶肥，白日君王在內稀。',64,'御定全唐詩/json/386.json','["新鷹初放兔猶肥，白日君王在內稀。", "薄暮千門臨欲鎖，紅妝飛騎向前歸。", "黃金捍撥紫檀槽，弦索初張調更高。", "盡理昨來新上曲，內官簾外送櫻桃。"]'),
('yuding-80','華清宮','張籍','唐','御定全唐诗','yuding','','[]','溫泉流入漢離宮，宮樹行行浴殿空。',32,'御定全唐詩/json/386.json','["溫泉流入漢離宮，宮樹行行浴殿空。", "武帝時人今欲盡，青山空閉禦牆中。"]'),
('yuding-81','崔駙馬養鶴','張籍','唐','御定全唐诗','yuding','','[]','身閑無事稱高情，已有人間章句名。',32,'御定全唐詩/json/386.json','["身閑無事稱高情，已有人間章句名。", "求得鶴來教翦翅，望仙台下亦將行。"]'),
('yuding-82','閒遊','張籍','唐','御定全唐诗','yuding','','[]','老身不計人間事，野寺秋晴每獨過。',32,'御定全唐詩/json/386.json','["老身不計人間事，野寺秋晴每獨過。", "病眼校來猶斷酒，卻嫌行處菊花多。"]'),
('yuding-83','劉兵曹贈酒','張籍','唐','御定全唐诗','yuding','','[]','一瓶顏色似甘泉，閑向新栽小竹前。',32,'御定全唐詩/json/386.json','["一瓶顏色似甘泉，閑向新栽小竹前。", "飲罷身中更無事，移床獨就夕陽眠。"]'),
('yuding-84','送梧州王使君','張籍','唐','御定全唐诗','yuding','','[]','楚江亭上秋風起，看發蒼梧太守船。',32,'御定全唐詩/json/386.json','["楚江亭上秋風起，看發蒼梧太守船。", "千里同行從此別，相逢又隔幾多年。"]'),
('yuding-85','春日早朝','張籍','唐','御定全唐诗','yuding','','[]','曉陌春寒朝騎來，瑞雲深處見樓臺。',32,'御定全唐詩/json/386.json','["曉陌春寒朝騎來，瑞雲深處見樓臺。", "夜來新雨沙堤濕，東上合門應未開。"]'),
('yuding-86','寄朱、闞二山人','張籍','唐','御定全唐诗','yuding','','[]','為個朝章束此身，眼看東路去無因。',32,'御定全唐詩/json/386.json','["為個朝章束此身，眼看東路去無因。", "曆陽舊客今應少，轉憶鄰家二老人。"]'),
('yuding-87','寄李渤','張籍','唐','御定全唐诗','yuding','','[]','五度溪頭躑躅紅，嵩陽寺裏講時鐘。',32,'御定全唐詩/json/386.json','["五度溪頭躑躅紅，嵩陽寺裏講時鐘。", "春山處處行應好，一月看花到幾峰。"]'),
('yuding-88','尋仙','張籍','唐','御定全唐诗','yuding','','[]','溪頭一徑入青崖，處處仙居隔杏花。',32,'御定全唐詩/json/386.json','["溪頭一徑入青崖，處處仙居隔杏花。", "更見峰西幽客說，雲中猶有兩三家。"]'),
('yuding-89','同白侍郎杏園贈劉郎中','張籍','唐','御定全唐诗','yuding','','[]','一去瀟湘頭欲白，今朝始見杏花春。',32,'御定全唐詩/json/386.json','["一去瀟湘頭欲白，今朝始見杏花春。", "從來遷客應無數，重到花前有幾人。"]'),
('yuding-90','答鄱陽客藥名詩','張籍','唐','御定全唐诗','yuding','','[]','江皋歲暮相逢地，黃葉霜前半夏枝。',32,'御定全唐詩/json/386.json','["江皋歲暮相逢地，黃葉霜前半夏枝。", "子夜吟詩向松桂，心中萬事喜君知。"]'),
('yuding-91','寄宋景','張籍','唐','御定全唐诗','yuding','','[]','詔發官兵取亂臣，將軍弓箭不離身。',32,'御定全唐詩/json/386.json','["詔發官兵取亂臣，將軍弓箭不離身。", "今君獨在征東府，莫遣功名屬別人。"]'),
('yuding-92','寄王侍禦','張籍','唐','御定全唐诗','yuding','','[]','愛君紫閣峰前好，新作書堂藥灶成。',32,'御定全唐詩/json/386.json','["愛君紫閣峰前好，新作書堂藥灶成。", "見欲移居相近住，有田多與種黃精。"]'),
('yuding-93','題渭北寺上方','張籍','唐','御定全唐诗','yuding','','[]','昔祭郊壇今謁陵，寺中高處最來登。',32,'御定全唐詩/json/386.json','["昔祭郊壇今謁陵，寺中高處最來登。", "十餘年後人多別，喜見當時轉讀僧。"]'),
('yuding-94','閒遊','張籍','唐','御定全唐诗','yuding','','[]','終日不離塵土間，若為能見此身閑。',32,'御定全唐詩/json/386.json','["終日不離塵土間，若為能見此身閑。", "今朝暫共遊僧語，更恨趨時別舊山。"]'),
('yuding-95','倡女詞','張籍','唐','御定全唐诗','yuding','','[]','輕鬢叢梳闊掃眉，為嫌風日下樓稀。',32,'御定全唐詩/json/386.json','["輕鬢叢梳闊掃眉，為嫌風日下樓稀。", "畫羅金縷難相稱，故著尋常淡薄衣。"]'),
('yuding-96','答元八遺紗帽','張籍','唐','御定全唐诗','yuding','','[]','黑紗方帽君邊得，稱對山前坐竹床。',32,'御定全唐詩/json/386.json','["黑紗方帽君邊得，稱對山前坐竹床。", "唯恐被人偷剪樣，不曾閑戴出書堂。"]'),
('yuding-97','題僧院','張籍','唐','御定全唐诗','yuding','','[]','聞師行講青龍疏，本寺住來多少年。',32,'御定全唐詩/json/386.json','["聞師行講青龍疏，本寺住來多少年。", "靜掃空房唯獨坐，千莖秋竹在簷前。"]'),
('yuding-98','送元八','張籍','唐','御定全唐诗','yuding','','[]','百神齋祭相隨遍，尋竹看山亦共行。',32,'御定全唐詩/json/386.json','["百神齋祭相隨遍，尋竹看山亦共行。", "明日城西送君去，舊遊重到獨題名。"]'),
('yuding-99','吳楚歌詞','張籍','唐','御定全唐诗','yuding','','[]','庭前春鳥啄林聲，紅夾羅襦縫未成。',32,'御定全唐詩/json/386.json','["庭前春鳥啄林聲，紅夾羅襦縫未成。", "今朝社日停針線，起向朱櫻樹下行。"]'),
('yuding-100','題方睦上人月臺觀','張籍','唐','御定全唐诗','yuding','','[]','一身清淨無童子，獨坐空堂得幾年。',32,'御定全唐詩/json/386.json','["一身清淨無童子，獨坐空堂得幾年。", "每夜焚香通月觀，可憐光影最團圓。"]'),
('yuding-101','華山廟','張籍','唐','御定全唐诗','yuding','','[]','金天廟下西京道，巫女紛紛走似煙。',32,'御定全唐詩/json/386.json','["金天廟下西京道，巫女紛紛走似煙。", "手把紙錢迎過客，遣求恩福到神前。"]'),
('yuding-102','病中酬元宗簡','張籍','唐','御定全唐诗','yuding','','[]','東風漸暖滿城春，獨佔幽居養病身。',32,'御定全唐詩/json/386.json','["東風漸暖滿城春，獨佔幽居養病身。", "莫說櫻桃花已發，今年不作看花人。"]'),
('yuding-103','寺宿齋','張籍','唐','御定全唐诗','yuding','','[]','晚到金光門外寺，寺中新竹隔簾多。',32,'御定全唐詩/json/386.json','["晚到金光門外寺，寺中新竹隔簾多。", "齋官禁與僧相見，院院開門不得過。"]'),
('yuding-104','贈施肩吾','張籍','唐','御定全唐诗','yuding','','[]','世間漸覺無多事，雖有空名未著身。',32,'御定全唐詩/json/386.json','["世間漸覺無多事，雖有空名未著身。", "合取藥成相待吃，不須先作上天人。"]'),
('yuding-105','贈王建','張籍','唐','御定全唐诗','yuding','','[]','白君去後交遊少，東野亡來篋笥貧。',32,'御定全唐詩/json/386.json','["白君去後交遊少，東野亡來篋笥貧。", "賴有白頭王建在，眼前猶見詠詩人。"]'),
('yuding-106','逢賈島','張籍','唐','御定全唐诗','yuding','','[]','僧房逢著款冬花，出寺行吟日已斜。',32,'御定全唐詩/json/386.json','["僧房逢著款冬花，出寺行吟日已斜。", "十二街中春雪遍，馬蹄今去入誰家。"]'),
('yuding-107','山中酬人','張籍','唐','御定全唐诗','yuding','','[]','山中日暖春鳩鳴，逐水看花任意行。',32,'御定全唐詩/json/386.json','["山中日暖春鳩鳴，逐水看花任意行。", "向晚歸來石窗下，菖蒲葉上見題名。"]'),
('yuding-108','弱柏院僧影堂','張籍','唐','御定全唐诗','yuding','','[]','弱柏倒垂如線蔓，簷頭不見有枝柯。',32,'御定全唐詩/json/386.json','["弱柏倒垂如線蔓，簷頭不見有枝柯。", "影堂香火長相續，應得人來禮拜多。"]'),
('yuding-109','題故僧影堂','張籍','唐','御定全唐诗','yuding','','[]','香消雲鎖舊僧家，僧刹殘形半壁斜。',32,'御定全唐詩/json/386.json','["香消雲鎖舊僧家，僧刹殘形半壁斜。", "日暮松煙寒漠漠，秋風吹破紙蓮花。"]'),
('yuding-110','無題','張籍','唐','御定全唐诗','yuding','','[]','桃溪柳陌好經過，燈下妝成月下歌。',32,'御定全唐詩/json/386.json','["桃溪柳陌好經過，燈下妝成月下歌。", "為是襄王故宮地，至今猶有細腰多。"]'),
('yuding-111','山禽','張籍','唐','御定全唐诗','yuding','','[]','山禽毛如白練帶，棲我庭前栗樹枝。',32,'御定全唐詩/json/386.json','["山禽毛如白練帶，棲我庭前栗樹枝。", "獼猴半夜來取栗，一雙中林向月飛。"]'),
('yuding-112','秋山','張籍','唐','御定全唐诗','yuding','','[]','秋山無雲複無風，溪頭看月出深松。',32,'御定全唐詩/json/386.json','["秋山無雲複無風，溪頭看月出深松。", "草堂不閉石床靜，葉間墜露聲重重。"]'),
('yuding-113','玉真觀','張籍','唐','御定全唐诗','yuding','','[]','台殿曾為貴主家，春風吹盡竹窗紗。',32,'御定全唐詩/json/386.json','["台殿曾為貴主家，春風吹盡竹窗紗。", "院中仙女修香火，不許閒人入看花。"]'),
('yuding-114','蠻中','張籍','唐','御定全唐诗','yuding','','[]','銅柱南邊毒草春，行人幾日到金麟。',32,'御定全唐詩/json/386.json','["銅柱南邊毒草春，行人幾日到金麟。", "玉鐶穿耳誰家女，自抱琵琶迎海神。"]'),
('yuding-115','贈道士','張籍','唐','御定全唐诗','yuding','','[]','茅山近別剡溪逢，玉節青旄十二重。',32,'御定全唐詩/json/386.json','["茅山近別剡溪逢，玉節青旄十二重。", "自說年年上天去，羅浮最近海邊峰。"]'),
('yuding-116','重平驛作','張籍','唐','御定全唐诗','yuding','','[]','茫茫菰草平如地，渺渺長堤曲似城。',32,'御定全唐詩/json/386.json','["茫茫菰草平如地，渺渺長堤曲似城。", "日暮未知投宿處，逢人更問向前程。"]'),
('yuding-117','宿天竺寺，寄靈隱寺僧','張籍','唐','御定全唐诗','yuding','','[]','夜向靈溪息此身，風泉竹露淨衣塵。',32,'御定全唐詩/json/386.json','["夜向靈溪息此身，風泉竹露淨衣塵。", "月明石上堪同宿，那作山南山北人。"]'),
('yuding-118','酬朱慶餘','張籍','唐','御定全唐诗','yuding','','[]','越女新妝出鏡心，自知明豔更沉吟。',32,'御定全唐詩/json/386.json','["越女新妝出鏡心，自知明豔更沉吟。", "齊紈未是人間貴，一曲菱歌敵萬金。"]'),
('yuding-119','寒食憶歸','張籍','唐','御定全唐诗','yuding','','[]','京中曹局無多事，寒食貧兒要在家。',32,'御定全唐詩/json/386.json','["京中曹局無多事，寒食貧兒要在家。", "遮莫杏園勝別處，亦須歸看傍村花。"]'),
('yuding-120','寒食','張籍','唐','御定全唐诗','yuding','','[]','綠楊枝上五絲繩，枝弱春多欲不勝。',33,'御定全唐詩/json/386.json','["綠楊枝上五絲繩，枝弱春多欲不勝。", "唯有一年寒食日，女郎相喚擺階o3。"]'),
('yuding-121','賦花','張籍','唐','御定全唐诗','yuding','','[]','花，花。落早，開賒。對酒客，興詩家。能回游騎，',23,'御定全唐詩/json/386.json','["花，花。落早，開賒。對酒客，興詩家。能回游騎，"]'),
('yuding-122','句','張籍','唐','御定全唐诗','yuding','','[]','韓公國大賢，道德赫已聞。時出為陽山，爾區來趨奔。',49,'御定全唐詩/json/386.json','["韓公國大賢，道德赫已聞。時出為陽山，爾區來趨奔。", "韓官遷掾曹，子隨至荊門。韓入為博士，崎嶇送歸輪。", "。"]'),
('yuding-0','月蝕詩','盧仝','唐','御定全唐诗','yuding','','[]','新天子即位五年，歲次庚寅，斗柄插子，律調黃鐘。',543,'御定全唐詩/json/387.json','["新天子即位五年，歲次庚寅，斗柄插子，律調黃鐘。", "森森萬木夜僵立，寒氣贔屭頑無風。爛銀盤從海底出，", "初疑白蓮花，浮出龍王宮。八月十五夜，比並不可雙。", "此時怪事發，有物吞食來。輪如壯士斧斫壞，", "火龍珠，飛出腦，卻入蚌蛤胎。摧環破璧眼看盡，", "不料至神物，有此大狼狽。星如撒沙出，爭頭事光大。", "奴婢炷暗燈，掩菼如玳瑁。今夜吐焰長如虹，", "念此日月者，太陰太陽精。皇天要識物，日月乃化生。", "走天汲汲勞四體，與天作眼行光明。此眼不自保，", "又孔子師老子雲，五色令人目盲。吾恐天似人，", "恐是眶睫間，掩塞所化成。黃帝有二目，帝舜重瞳明。", "二帝懸四目，四海生光輝。吾不遇二帝，滉漭不可知。", "何故瞳子上，坐受蟲豸欺。長嗟白兔搗靈藥，", "憶昔堯為天，十日燒九州。金爍水銀流，玉煼丹砂焦。", "六合烘為窯，堯心增百憂。帝見堯心憂，", "撐腸拄肚礧傀如山丘，自可飽死更不偷。不獨填饑坑，", "嗚呼，人養虎，被虎齧。天媚蟆，被蟆瞎。乃知恩非類，", "上天不為臣立梯磴，臣血肉身，無由飛上天，揚天光。", "封詞付與小心風，颰排閶闔入紫宮。密邇玉幾前擘坼，", "西方攫虎立踦踦，斧為牙，鑿為齒。偷犧牲，食封豕。", "大蟆一臠，固當軟美。見似不見，是何道理。", "爪牙根天不念天，天若准擬錯准擬。北方寒龜被蛇縛，", "且當以其肉充臛，死殼沒信處，唯堪支床腳，", "支盧謫罰何災凶。土星與土性相背，反養福德生禍害。"]'),
('yuding-1','哭玉碑子','盧仝','唐','御定全唐诗','yuding','','[]','山有洞左頰，拾得玉碑子。其長一周尺，其闊一藥匕。',288,'御定全唐詩/json/387.json','["山有洞左頰，拾得玉碑子。其長一周尺，其闊一藥匕。", "顏色九秋天，棱角四面起。輕敲吐寒流，清悲動神鬼。", "稽首置手中，只似一片水。至文反無文，上帝應有以。", "予疑仙石靈，願以仙人比。心期香湯洗，歸送籙堂裏。", "頗奈窮相驢，行動如跛鱉。十裏五裏行，百蹶複千蹶。", "顏子不少夭，玉碑中路折。橫文尋龜兆，直理任瓦裂。", "劈竹不可合，破環永離別。向人如有情，似痛滴無血。", "勘鬥平地上，罅坼多齧缺。百見百傷心，不堪再提挈。", "怪哉堅貞姿，忽脆不堅固。矧曰人間人，安能保常度。", "敢問生物成，敗為有真素。為稟靈異氣，不得受穢汙。", "驢罪真不厚，驢生亦錯誤。更將前前行，複恐山神怒。", "白雲蓊閉嶺，高松吟古墓。置此忍其傷，驅驢下山路。"]'),
('yuding-2','觀放魚歌','盧仝','唐','御定全唐诗','yuding','','[]','常州賢刺史，從諫議大夫除。天地好生物，',256,'御定全唐詩/json/387.json','["常州賢刺史，從諫議大夫除。天地好生物，", "命舟人，駕舫子，漾漾菰蒲。酒興引行處，正見漁人魚。", "刺史密會山客意，複念網羅嬰無辜。忽脫身上殷緋袍，", "老鯉變化頗神異，三十六鱗如抹朱。水苞弘窟有蛟鼉，", "亦憶清江使，橫遭乎餘且。聖神七十鑽，不及泥中鰍。", "哀哉托非賢，五臟生冤仇。若當刺史時，聖物保不囚。", "不疑且不蔔，二子安能諛。二子倘故諛，吾知心受誅。", "禮重一草木，易封稱中孚。又曰釣不綱，又曰遠庖廚。", "故仁人用心，刺史盡合符。昔魯公觀棠距箴，", "因說十千天子事，福力當與刺史俱。天雨曼陀羅花深沒膝，", "念魚承奉刺史仁，深僻處，遠遠遊。刺史官職小，"]'),
('yuding-3','示添丁','盧仝','唐','御定全唐诗','yuding','','[]','春風苦不仁，呼逐馬蹄行人家。慚愧瘴氣卻憐我，',46,'御定全唐詩/json/387.json','["春風苦不仁，呼逐馬蹄行人家。慚愧瘴氣卻憐我，", "父憐母惜摑不得，卻生癡笑令人嗟。宿舂連曉不成米，"]'),
('yuding-4','寄男抱孫','盧仝','唐','御定全唐诗','yuding','','[]','別來三得書，書道違離久。書處甚粗殺，且喜見汝手。',408,'御定全唐詩/json/387.json','["別來三得書，書道違離久。書處甚粗殺，且喜見汝手。", "殷十七又報，汝文頗新有。別來才經年，囊盎未合鬥。", "當是汝母賢，日夕加訓誘。尚書當畢功，禮記速須剖。", "嘍羅兒讀書，何異摧枯朽。尋義低作聲，便可養年壽。", "莫學村學生，粗氣強叫吼。下學偷功夫，新宅鋤蔾莠。", "乘涼勸奴婢，園裏耨蔥韭。遠籬編榆棘，近眼栽桃柳。", "引水灌竹中，蒲池種蓮藕。撈漉蛙蟆腳，莫遣生科鬥。", "竹林吾最惜，新筍好看守。萬籜苞龍兒，攢迸溢林藪。", "吾眼恨不見，心腸痛如搊。宅錢都未還，債利日日厚。", "籜龍正稱冤，莫殺入汝口。丁寧囑託汝，汝活籜龍不。", "殷十七老儒，是汝父師友。傳讀有疑誤，輒告諮問取。", "兩手莫破拳，一吻莫飲酒。莫學捕鳩鴿，莫學打雞狗。", "小時無大傷，習性防已後。頑發苦惱人，汝母必不受。", "任汝惱弟妹，任汝惱姨舅。姨舅非吾親，弟妹多老醜。", "莫惱添丁郎，淚子作面垢。莫引添丁郎，赫赤日裏走。", "添丁郎小小，別吾來久久。脯脯不得吃，兄兄莫撚搜。", "他日吾歸來，家人若彈糾。一百放一下，打汝九十九。"]'),
('yuding-5','自詠三首','盧仝','唐','御定全唐诗','yuding','','[]','為報玉川子，知君未是賢。低頭雖有地，仰面輒無天。',144,'御定全唐詩/json/387.json','["為報玉川子，知君未是賢。低頭雖有地，仰面輒無天。", "骨肉清成瘦，萵蔓老覺膻。家書與心事，相伴過流年。", "盧子躘踵也，賢愚總莫驚。蚊虻當家口，草石是親情。", "萬卷堆胸朽，三光撮眼明。翻悲廣成子，閒氣說長生。", "物外無知己，人間一癖王。生涯身是夢，耽樂酒為鄉。", "日月黏髭須，雲山鎖肺腸。愚公只公是，不用謾驚張。"]'),
('yuding-6','送王儲詹事西遊獻兵書','盧仝','唐','御定全唐诗','yuding','','[]','美酒撥醅酌，楊花飛盡時。落日長安道，方寸無人知。',72,'御定全唐詩/json/387.json','["美酒撥醅酌，楊花飛盡時。落日長安道，方寸無人知。", "篋中制勝術，氣雄屈指算。半醉千殷勤，仰天一長歎。", "玉匣百煉劍，龜文又龍吼。抽贈王將軍，勿使虛白首。"]'),
('yuding-7','送邵兵曹歸江南','盧仝','唐','御定全唐诗','yuding','','[]','春風楊柳陌，連騎醉離觴。千里遠山碧，一條歸路長。',48,'御定全唐詩/json/387.json','["春風楊柳陌，連騎醉離觴。千里遠山碧，一條歸路長。", "花開愁北渚，雲去渡南湘。東望濛濛處，煙波是故鄉。"]'),
('yuding-8','寄外兄魏澈','盧仝','唐','御定全唐诗','yuding','','[]','何處堪惆悵，情親不得親。興寧樓上月，辜負酒家春。',24,'御定全唐詩/json/387.json','["何處堪惆悵，情親不得親。興寧樓上月，辜負酒家春。"]'),
('yuding-9','喜逢鄭三游山','盧仝','唐','御定全唐诗','yuding','','[]','相逢之處花茸茸，石壁攢峰千萬重。',32,'御定全唐詩/json/387.json','["相逢之處花茸茸，石壁攢峰千萬重。", "他日期君何處好，寒流石上一株松。"]'),
('yuding-10','卓女怨','盧仝','唐','御定全唐诗','yuding','','[]','妾本懷春女，春愁不自任。迷魂隨鳳客，嬌思入琴心。',48,'御定全唐詩/json/387.json','["妾本懷春女，春愁不自任。迷魂隨鳳客，嬌思入琴心。", "托援交情重，當壚酌意深。誰家有夫婿，作賦得黃金。"]'),
('yuding-11','守歲二首','盧仝','唐','御定全唐诗','yuding','','[]','去年留不住，年來也任他。當壚一榼酒，爭奈兩年何。',48,'御定全唐詩/json/387.json','["去年留不住，年來也任他。當壚一榼酒，爭奈兩年何。", "老來經節臘，樂事甚悠悠。不及兒童日，都盧不解愁。"]'),
('yuding-12','新月','盧仝','唐','御定全唐诗','yuding','','[]','仙宮雲箔卷，露出玉簾鉤。清光無所贈，相憶鳳凰樓。',24,'御定全唐詩/json/387.json','["仙宮雲箔卷，露出玉簾鉤。清光無所贈，相憶鳳凰樓。"]'),
('yuding-13','解悶','盧仝','唐','御定全唐诗','yuding','','[]','人生都幾日，一半是離憂。但有尊中物，從他萬事休。',24,'御定全唐詩/json/387.json','["人生都幾日，一半是離憂。但有尊中物，從他萬事休。"]'),
('yuding-14','揚子津','盧仝','唐','御定全唐诗','yuding','','[]','風卷魚龍暗楚關，白波沉卻海門山。',32,'御定全唐詩/json/387.json','["風卷魚龍暗楚關，白波沉卻海門山。", "鵬騰鼇倒且快性，地坼天開總是閑。"]'),
('yuding-15','人日立春','盧仝','唐','御定全唐诗','yuding','','[]','春度春歸無限春，今朝方始覺成人。',32,'御定全唐詩/json/387.json','["春度春歸無限春，今朝方始覺成人。", "從今克己應猶及，顏與梅花俱自新。"]'),
('yuding-16','送尉遲羽之歸宣州','盧仝','唐','御定全唐诗','yuding','','[]','君歸乎，君歸興不孤。謝脁澄江今夜月，也應憶著此山夫。',26,'御定全唐詩/json/387.json','["君歸乎，君歸興不孤。謝脁澄江今夜月，也應憶著此山夫。"]'),
('yuding-17','悲新年','盧仝','唐','御定全唐诗','yuding','','[]','新年何事最堪悲，病客遙聽百舌兒。',32,'御定全唐詩/json/387.json','["新年何事最堪悲，病客遙聽百舌兒。", "太歲只游桃李徑，春風肯管歲寒枝。"]'),
('yuding-18','憶酒寄劉侍郎','盧仝','唐','御定全唐诗','yuding','','[]','愛酒如偷蜜，憎醒似見刀。君為麹糵主，酒醴莫辭勞。',24,'御定全唐詩/json/387.json','["愛酒如偷蜜，憎醒似見刀。君為麹糵主，酒醴莫辭勞。"]'),
('yuding-19','白鷺鷥','盧仝','唐','御定全唐诗','yuding','','[]','刻成片玉白鷺鷥，欲捉纖鱗心自急。',32,'御定全唐詩/json/387.json','["刻成片玉白鷺鷥，欲捉纖鱗心自急。", "翹足沙頭不得時，傍人不知謂閑立。"]'),
('yuding-20','風中琴','盧仝','唐','御定全唐诗','yuding','','[]','五音六律十三徽，龍吟鶴響思庖羲。',32,'御定全唐詩/json/387.json','["五音六律十三徽，龍吟鶴響思庖羲。", "一彈流水一彈月，水月風生松樹枝。"]'),
('yuding-21','感秋別怨','盧仝','唐','御定全唐诗','yuding','','[]','霜秋自斷魂，楚調怨離分。魄散瑤台月，心隨巫峽雲。',48,'御定全唐詩/json/387.json','["霜秋自斷魂，楚調怨離分。魄散瑤台月，心隨巫峽雲。", "蛾眉誰共畫，鳳曲不同聞。莫似湘妃淚，斑斑點翠裙。"]'),
('yuding-22','新蟬','盧仝','唐','御定全唐诗','yuding','','[]','泉溜潛幽咽，琴鳴乍往還。長風翦不斷，還在樹枝間。',24,'御定全唐詩/json/387.json','["泉溜潛幽咽，琴鳴乍往還。長風翦不斷，還在樹枝間。"]'),
('yuding-23','題褚遂良孫庭竹','盧仝','唐','御定全唐诗','yuding','','[]','負霜停雪舊根枝，龍笙鳳管君莫截。',32,'御定全唐詩/json/387.json','["負霜停雪舊根枝，龍笙鳳管君莫截。", "春風一番琴上來，搖碎金尊碧天月。"]'),
('yuding-24','訪含曦上人','盧仝','唐','御定全唐诗','yuding','','[]','三入寺，曦未來。轆轤無人井百尺，渴心歸去生塵埃。',24,'御定全唐詩/json/387.json','["三入寺，曦未來。轆轤無人井百尺，渴心歸去生塵埃。"]'),
('yuding-25','客淮南病','盧仝','唐','御定全唐诗','yuding','','[]','揚州蒸毒似燂湯，客病清枯鬢欲霜。',32,'御定全唐詩/json/387.json','["揚州蒸毒似燂湯，客病清枯鬢欲霜。", "且喜閉門無俗物，四肢安穩一張床。"]'),
('yuding-26','村醉','盧仝','唐','御定全唐诗','yuding','','[]','昨夜村飲歸，健倒三四五。摩挲青莓苔，莫嗔驚著汝。',24,'御定全唐詩/json/387.json','["昨夜村飲歸，健倒三四五。摩挲青莓苔，莫嗔驚著汝。"]'),
('yuding-27','蕭宅二三子贈答詩二十首：客贈石','盧仝','唐','御定全唐诗','yuding','','[]','竹下青莎中，細長三四片。主人雖不歸，長見主人面。',24,'御定全唐詩/json/387.json','["竹下青莎中，細長三四片。主人雖不歸，長見主人面。"]'),
('yuding-28','蕭宅二三子贈答詩二十首：石讓竹','盧仝','唐','御定全唐诗','yuding','','[]','自顧撥不轉，何敢當主人。竹弟有清風，可以娛嘉賓。',24,'御定全唐詩/json/387.json','["自顧撥不轉，何敢當主人。竹弟有清風，可以娛嘉賓。"]'),
('yuding-29','蕭宅二三子贈答詩二十首：竹答客','盧仝','唐','御定全唐诗','yuding','','[]','竹弟謝石兄，清風非所任。隨分有蕭瑟，實無堅重心。',24,'御定全唐詩/json/387.json','["竹弟謝石兄，清風非所任。隨分有蕭瑟，實無堅重心。"]'),
('yuding-30','蕭宅二三子贈答詩二十首：石請客','盧仝','唐','御定全唐诗','yuding','','[]','竹弟雖讓客，不敢當客恩。自慚埋沒久，滿面蒼苔痕。',24,'御定全唐詩/json/387.json','["竹弟雖讓客，不敢當客恩。自慚埋沒久，滿面蒼苔痕。"]'),
('yuding-31','蕭宅二三子贈答詩二十首：客答石','盧仝','唐','御定全唐诗','yuding','','[]','遍索天地間，彼此最癡癖。主人幸未來，與君為莫逆。',24,'御定全唐詩/json/387.json','["遍索天地間，彼此最癡癖。主人幸未來，與君為莫逆。"]'),
('yuding-32','蕭宅二三子贈答詩二十首：石答竹','盧仝','唐','御定全唐诗','yuding','','[]','石報孤竹君，此客甚高調。共我相共癡，不怕主人天下笑。',114,'御定全唐詩/json/387.json','["石報孤竹君，此客甚高調。共我相共癡，不怕主人天下笑。", "我非蛺蝶兒，我非桃李枝。不要兒女撲，不要春風吹。", "苔蘚印我面，雨露皴我皮。此故不嫌我，突兀蒙相知。", "此客即西歸，我心徒依依。我欲隨客去，累重不解飛。", "知弟虛心亦待客，此客何以共報之。"]'),
('yuding-33','蕭宅二三子贈答詩二十首：竹請客','盧仝','唐','御定全唐诗','yuding','','[]','我本泰山阿，避地到南國。主人欲移家，我亦要歸北。',48,'御定全唐詩/json/387.json','["我本泰山阿，避地到南國。主人欲移家，我亦要歸北。", "上客幸先歸，願托歸飛翼。唯將翛翛風，累路報恩德。"]'),
('yuding-34','蕭宅二三子贈答詩二十首：客謝竹','盧仝','唐','御定全唐诗','yuding','','[]','揚州駁雜地，不辨龍蜥蜴。客身正乾枯，行處無膏澤。',48,'御定全唐詩/json/387.json','["揚州駁雜地，不辨龍蜥蜴。客身正乾枯，行處無膏澤。", "太山道不遠，相庇實無力。君若隨我行，必有煎茶厄。"]'),
('yuding-35','蕭宅二三子贈答詩二十首：石請客','盧仝','唐','御定全唐诗','yuding','','[]','啟母是諸母，三十六峰是諸父。知君家近父母家，',38,'御定全唐詩/json/387.json','["啟母是諸母，三十六峰是諸父。知君家近父母家，", "小人無以報君恩，使君池亭風月古。"]'),
('yuding-36','蕭宅二三子贈答詩二十首：客謝石','盧仝','唐','御定全唐诗','yuding','','[]','我有水竹莊，甚近嵩之巔。是君歸休處，可以終天年。',48,'御定全唐詩/json/387.json','["我有水竹莊，甚近嵩之巔。是君歸休處，可以終天年。", "雖有提攜勞，不憂糧食錢。但恐主人心，疑我相釣竿。"]'),
('yuding-37','蕭宅二三子贈答詩二十首：石再請客','盧仝','唐','御定全唐诗','yuding','','[]','主人若知我，應喜我結得君。主人不知我，',31,'御定全唐詩/json/387.json','["主人若知我，應喜我結得君。主人不知我，", "可得杠壓我，使我頭不出。"]'),
('yuding-38','蕭宅二三子贈答詩二十首：客許石','盧仝','唐','御定全唐诗','yuding','','[]','石公說道理，句句出凡格。相知貴知心，豈恨主為客。',48,'御定全唐詩/json/387.json','["石公說道理，句句出凡格。相知貴知心，豈恨主為客。", "過須歸去來，旦晚上無厄。主人誠賢人，多應不相責。"]'),
('yuding-39','蕭宅二三子贈答詩二十首：井請客','盧仝','唐','御定全唐诗','yuding','','[]','我生天地間，頗是往還數。已效炊爨勞，我亦不願住。',48,'御定全唐詩/json/387.json','["我生天地間，頗是往還數。已效炊爨勞，我亦不願住。", "君有造化力，在君一降顧。我願拔黃泉，輕舉隨君去。"]'),
('yuding-40','蕭宅二三子贈答詩二十首：客謝井','盧仝','唐','御定全唐诗','yuding','','[]','改邑不改井，此是井卦辭。井公莫怪驚，說我成憨癡。',48,'御定全唐詩/json/387.json','["改邑不改井，此是井卦辭。井公莫怪驚，說我成憨癡。", "我縱有神力，爭敢將公歸。揚州惡百姓，疑我卷地皮。"]'),
('yuding-41','蕭宅二三子贈答詩二十首：馬蘭請客','盧仝','唐','御定全唐诗','yuding','','[]','蘭蘭是小草，不怕郎君罵。願得隨君行，暫到嵩山下。',24,'御定全唐詩/json/387.json','["蘭蘭是小草，不怕郎君罵。願得隨君行，暫到嵩山下。"]'),
('yuding-42','蕭宅二三子贈答詩二十首：客請馬蘭','盧仝','唐','御定全唐诗','yuding','','[]','嵩山未必憐蘭蘭，蘭蘭已受郎君恩。',32,'御定全唐詩/json/387.json','["嵩山未必憐蘭蘭，蘭蘭已受郎君恩。", "不須刷帚跳蹤走，只擬蘭浪出其門。"]'),
('yuding-43','蕭宅二三子贈答詩二十首：蛺蝶請客','盧仝','唐','御定全唐诗','yuding','','[]','粉末為四體，春風為生涯。願得紛飛去，與君為眼花。',24,'御定全唐詩/json/387.json','["粉末為四體，春風為生涯。願得紛飛去，與君為眼花。"]'),
('yuding-44','蕭宅二三子贈答詩二十首：客答蛺蝶','盧仝','唐','御定全唐诗','yuding','','[]','君是輕薄子，莫窺君子腸。且須看雀兒，雀兒銜爾將。',24,'御定全唐詩/json/387.json','["君是輕薄子，莫窺君子腸。且須看雀兒，雀兒銜爾將。"]'),
('yuding-45','蕭宅二三子贈答詩二十首：蝦蟆請客','盧仝','唐','御定全唐诗','yuding','','[]','凡有水竹處，我曹長先行。願君借我一勺水，',20,'御定全唐詩/json/387.json','["凡有水竹處，我曹長先行。願君借我一勺水，"]'),
('yuding-46','蕭宅二三子贈答詩二十首：客請蝦蟆','盧仝','唐','御定全唐诗','yuding','','[]','蝦蟆蟆，叩頭莫語人聞聲。揚州蝦蜆忽得便，',20,'御定全唐詩/json/387.json','["蝦蟆蟆，叩頭莫語人聞聲。揚州蝦蜆忽得便，"]'),
('yuding-0','龜銘','盧仝','唐','御定全唐诗','yuding','','[]','龜，汝靈於人，不靈於身，致網於津。吾靈於身，',22,'御定全唐詩/json/388.json','["龜，汝靈於人，不靈於身，致網於津。吾靈於身，"]'),
('yuding-1','梳銘','盧仝','唐','御定全唐诗','yuding','','[]','有發兮朝朝思理，有身兮胡不如是。',16,'御定全唐詩/json/388.json','["有發兮朝朝思理，有身兮胡不如是。"]'),
('yuding-2','小婦吟','盧仝','唐','御定全唐诗','yuding','','[]','小婦欲入門，隈門勻紅妝。大婦出門迎，正頓羅衣裳。',90,'御定全唐詩/json/388.json','["小婦欲入門，隈門勻紅妝。大婦出門迎，正頓羅衣裳。", "門邊兩相見，笑樂不可當。夫子于傍聊斷腸，", "願言兩相樂，永與同心事我郎。夫子于傍剩欲狂。", "珠簾風度百花香，翠帳雲屏白玉床。啼鳥休啼花莫笑，"]'),
('yuding-3','月下寄徐希仁','盧仝','唐','御定全唐诗','yuding','','[]','夜半沙上行，月瑩天心明。沙月浩無際，此中離思生。',48,'御定全唐詩/json/388.json','["夜半沙上行，月瑩天心明。沙月浩無際，此中離思生。", "上天何寥廓，下地何崢嶸。吾道豈已矣，為君傾兕觥。"]'),
('yuding-4','贈徐希仁石硯別','盧仝','唐','御定全唐诗','yuding','','[]','靈山一片不靈石，手斫成器心所惜。鳳鳥不至池不成，',48,'御定全唐詩/json/388.json','["靈山一片不靈石，手斫成器心所惜。鳳鳥不至池不成，", "今日贈君離別心，此中至淺造化深。用之可以過珪璧，"]'),
('yuding-5','有所思','盧仝','唐','御定全唐诗','yuding','','[]','當時我醉美人家，美人顏色嬌如花。今日美人棄我去，',96,'御定全唐詩/json/388.json','["當時我醉美人家，美人顏色嬌如花。今日美人棄我去，", "翠眉蟬鬢生別離，一望不見心斷絕。心斷絕，幾千里。", "夢中醉臥巫山雲，覺來淚滴湘江水。湘江兩岸花木深，", "美人兮美人，不知為暮雨兮為朝雲。相思一夜梅花發，"]'),
('yuding-6','樓上女兒曲','盧仝','唐','御定全唐诗','yuding','','[]','誰家女兒樓上頭，指揮婢子掛簾鉤。林花撩亂心之愁，',94,'御定全唐詩/json/388.json','["誰家女兒樓上頭，指揮婢子掛簾鉤。林花撩亂心之愁，", "相思弦斷情不斷，落花紛紛心欲穿。心欲穿，憑欄幹。", "相憶柳條綠，相思錦帳寒。直緣感君恩愛一回顧，", "鶯花爛熳君不來，及至君來花已老。心腸寸斷誰得知，"]'),
('yuding-7','秋夢行','盧仝','唐','御定全唐诗','yuding','','[]','客行一夜秋風起，客夢南游渡湘水。湘水泠泠徹底清，',112,'御定全唐詩/json/388.json','["客行一夜秋風起，客夢南游渡湘水。湘水泠泠徹底清，", "長眉入鬢何連娟，肌膚白玉秀且鮮。裴回共詠東方日，", "殷勤纖手驚破夢，中宵寂寞心淒然。心淒然，腸亦絕。", "寐不寐兮玉枕寒，夜深夜兮霜似雪。鏡中不見雙翠眉，", "願此眉兮如此月，千里萬里光不滅。"]'),
('yuding-8','自君之出矣','盧仝','唐','御定全唐诗','yuding','','[]','自君之出矣，壁上蜘蛛織。近取見妾心，夜夜無休息。',96,'御定全唐詩/json/388.json','["自君之出矣，壁上蜘蛛織。近取見妾心，夜夜無休息。", "妾有雙玉環，寄君表相憶。環是妾之心，玉是君之德。", "馳情增悴容，蓄思損精力。玉簟寒淒淒，延想心惻惻。", "風含霜月明，水泛碧天色。此水有盡時，此情無終極。"]'),
('yuding-9','走筆謝孟諫議寄新茶','盧仝','唐','御定全唐诗','yuding','','[]','日高丈五睡正濃，軍將打門驚周公。口雲諫議送書信，',139,'御定全唐詩/json/388.json','["日高丈五睡正濃，軍將打門驚周公。口雲諫議送書信，", "聞道新年入山裏，蟄蟲驚動春風起。天子須嘗陽羨茶，", "摘鮮焙芳旋封裹，至精至好且不奢。至尊之餘合王公，", "碧雲引風吹不斷，白花浮光凝碗面。一碗喉吻潤，", "七碗吃不得也，唯覺兩腋習習清風生。蓬萊山，在何處。", "玉川子，乘此清風欲歸去。山上群仙司下土，"]'),
('yuding-10','冬行三首','盧仝','唐','御定全唐诗','yuding','','[]','蟲豸臘月皆在蟄，吾獨何乃勞其形。小大無由知天命，',466,'御定全唐詩/json/388.json','["蟲豸臘月皆在蟄，吾獨何乃勞其形。小大無由知天命，", "自顧不及遭霜葉，旦夕保得同飄零。達生何足雲，", "長年愛伊洛，決計卜長久。賒買裏仁宅，水竹且小有。", "賣宅將還資，舊業苦不厚。債家征利心，餓虎血染口。", "臘風刀刻肌，遂向東南走。賢哉韓員外，勸我莫強取。", "憑風謝長者，敢不愧心苟。賃載得估舟，估雜非吾偶。", "壯色排榻席，別座誇羊酒。落日無精光，啞暝被掣肘。", "漕石生齒牙，洗灘亂相掫。奔澌嚼篙杖，夾岸雪龍吼。", "可憐聖明朝，還為喪家狗。通運隔南溟，債利拄北斗。", "揚州屋舍賤，還債堪了不。此宅貯書籍，地濕憂蠹朽。", "賈僎舊相識，十年與營守。貧交多變態，僎得君子不。", "利命子罕言，我誠孔門醜。且貴終焉圖，死免慚狐首。", "何當歸帝鄉，白雲永相友。", "不敢唾汴水，汴水入東海。污泥龍王宮，恐獲不敬罪。", "不敢蹋汴堤，汴堤連秦宮。蹋盡天子土，饋餫無由通。", "此言雖太闊，且是臣心腸。野風結陰兵，千里鳴刀槍。", "海月護羈魄，到曉點孤光。上不事天子，下不識侯王。", "夜半睡獨覺，爽氣盈心堂。顏子甚年少，孔聖同行藏。", "我年過顏子，敢道不自強。船人雖奴兵，亦有意智長。", "問我何所得，樂色填清揚。我報果有為，孔經在衣裳。"]'),
('yuding-11','常州孟諫議座上聞韓員外職方貶國子博士有感五首','盧仝','唐','御定全唐诗','yuding','','[]','忽見除書到，韓君又學官。死生縱有命，人事始知難。',240,'御定全唐詩/json/388.json','["忽見除書到，韓君又學官。死生縱有命，人事始知難。", "烈火先燒玉，庭蕪不養蘭。山夫與刺史，相對兩巑岏。", "幹祿無便佞，宜知黜此身。員郎猶小小，國學大頻頻。", "孤宦心肝直，天王苦死嗔。朝廷無諫議，誰是雪韓人。", "何事遭朝貶，知何被不容。不如思所自，只欲涕無從。", "爵服何曾好，荷衣已慣縫。朝官莫相識，歸去老岩松。", "力小垂垂上，天高又不登。致身唯一己，獲罪則顏朋。", "祿位埋坑阱，康莊壘劍棱。公卿共惜取，莫遣玉山崩。", "誰憐野田子，海內一韓侯。左道官雖樂，剛腸得健無。", "功名生地獄，禮教死天囚。莫言耕種好，須避蒺藜秋。"]'),
('yuding-12','夏夜聞蚯蚓吟','盧仝','唐','御定全唐诗','yuding','','[]','夏夜雨欲作，傍砌蚯蚓吟。念爾無筋骨，也應天地心。',72,'御定全唐詩/json/388.json','["夏夜雨欲作，傍砌蚯蚓吟。念爾無筋骨，也應天地心。", "汝無親朋累，汝無名利侵。孤韻似有說，哀怨何其深。", "泛泛輕薄子，旦夕還謳吟。肝膽異汝輩，熱血徒相侵。"]'),
('yuding-13','揚州送伯齡過江','盧仝','唐','御定全唐诗','yuding','','[]','伯齡不厭山，山不養伯齡。松顛有樵墮，石上無禾生。',96,'御定全唐詩/json/388.json','["伯齡不厭山，山不養伯齡。松顛有樵墮，石上無禾生。", "不忍六尺軀，遂作東南行。諸侯盡食肉，壯氣吞八紘。", "不唧溜鈍漢，何由通姓名。夷齊餓死日，武王稱聖明。", "節義士枉死，何異鴻毛輕。努力事幹謁，我心終不平。"]'),
('yuding-14','憶金鵝山沈山人二首','盧仝','唐','御定全唐诗','yuding','','[]','君家山頭松樹風，適來入我竹林裏。一片新茶破鼻香，',144,'御定全唐詩/json/388.json','["君家山頭松樹風，適來入我竹林裏。一片新茶破鼻香，", "閑來共我說真意，齒下領取真長生。不須服藥求神仙，", "白日上升應不惡，藥成且輒一丸藥。暫時上天少問天，", "君愛煉藥藥欲成，我愛煉骨骨已清。試自比校得仙者，", "夜叉守門晝不啟，夜半醮祭夜半開。夜叉喜歡動關鎖，", "太上道君蓮花台，九門隔闊安在哉。嗚呼沈君大藥成，"]'),
('yuding-15','寄蕭二十三慶中','盧仝','唐','御定全唐诗','yuding','','[]','蕭乎蕭乎，憶蕭者嵩山之盧。盧揚州，蕭歙州。',81,'御定全唐詩/json/388.json','["蕭乎蕭乎，憶蕭者嵩山之盧。盧揚州，蕭歙州。", "相思過春花，鬢毛生麥秋。千災萬怪天南道，", "就中南瘴欺北客，憑君數磨犀角吃，我憶君心千百間。", "千百間君何時還，使我夜夜勞魂魄。"]'),
('yuding-16','贈金鵝山人沈師魯','盧仝','唐','御定全唐诗','yuding','','[]','金鵝山中客，來到揚州市。買藥床頭一破顏，',92,'御定全唐詩/json/388.json','["金鵝山中客，來到揚州市。買藥床頭一破顏，", "人皆食穀與五味，獨食太和陰陽氣。浩浩流珠走百關，", "三日四日五六日，盤礴化元搜萬類。晝飲興酣陶天和，", "肉眼不識天上書，小儒安敢窺奧秘。昆侖路隔西北天，"]'),
('yuding-17','歎昨日三首','盧仝','唐','御定全唐诗','yuding','','[]','昨日之日不可追，今日之日須臾期。如此如此複如此，',120,'御定全唐詩/json/388.json','["昨日之日不可追，今日之日須臾期。如此如此複如此，", "賢名聖行甚辛苦，周公孔子徒自欺。", "天下薄夫苦耽酒，玉川先生也耽酒。薄夫有錢恣張樂，", "平生心事消散盡，天上白日悠悠懸。", "上帝板板主何物，日車劫劫西向沒。自古賢聖無奈何，", "何時出得禁酒國，滿甕釀酒曝背眠。"]'),
('yuding-18','月蝕詩','盧仝','唐','御定全唐诗','yuding','','[]','東海出明月，清明照毫髮。朱弦初罷彈，金兔正奇絕。',120,'御定全唐詩/json/388.json','["東海出明月，清明照毫髮。朱弦初罷彈，金兔正奇絕。", "三五與二八，此時光滿時。頗奈蝦蟆兒，吞我芳桂枝。", "我愛明鏡潔，爾乃痕翳之。爾且無六翮，焉得升天涯。", "方寸有白刃，無由揚清輝。如何萬里光，遭爾小物欺。", "卻吐天漢中，良久素魄微。日月尚如此，人情良可知。"]'),
('yuding-19','直鉤吟','盧仝','唐','御定全唐诗','yuding','','[]','初歲學釣魚，自謂魚易得。三十持釣竿，一魚釣不得。',48,'御定全唐詩/json/388.json','["初歲學釣魚，自謂魚易得。三十持釣竿，一魚釣不得。", "人鉤曲，我鉤直，哀哉我鉤又無食。文王已沒不復生，"]'),
('yuding-20','與馬異結交詩','盧仝','唐','御定全唐诗','yuding','','[]','天地日月如等閒，盧仝四十無往還。唯有一片心脾骨，',220,'御定全唐詩/json/388.json','["天地日月如等閒，盧仝四十無往還。唯有一片心脾骨，", "天不容，地不受，日月不敢偷照耀。神農畫八卦，", "此龍此蛇得死病，神農合藥救死命。天怪神農党龍蛇，", "不知元氣元不死，忽聞空中喚馬異。馬異若不是祥瑞，", "今日仝自仝，異不異，是謂仝不往兮異不至，", "平生結交若少人，憶君眼前如見君。青雲欲開白日沒，", "半折半殘壓山谷，盤根蹙節成蛟螭。", "忽雷霹靂卒風暴雨撼不動，欲動不動千變萬化總是鱗皴皮。", "此奇怪物不可欺。盧仝見馬異文章，酌得馬異胸中事。", "風姿骨本恰如此，是不是，寄一字。"]'),
('yuding-21','感古四首','盧仝','唐','御定全唐诗','yuding','','[]','天生聖明君，必資忠賢臣。舜禹竭股肱，共佐堯為君。',564,'御定全唐詩/json/388.json','["天生聖明君，必資忠賢臣。舜禹竭股肱，共佐堯為君。", "四載成地理，七政齊天文。階下蓂莢生，琴上南風熏。", "輪轉夏殷周，時複猶一人。秦漢事讒巧，魏晉忘機鈞。", "猜忌相翦滅，爾來迷恩親。以愚保其身，不覺身沉淪。", "以智理其國，遂為國之賊。苟圖容一身，萬事良可惻。", "可憐萬乘君，聰明受沉惑。忠良伏草莽，無因施羽翼。", "日月異又蝕，天地晦如墨。既亢而後求，異哉龍之德。", "人生何所貴，所貴有終始。昨日盈尺璧，今朝盡瑕棄。", "蒼蠅點垂棘，巧舌成錦綺。箕子為之奴，比干諫而死。", "仲尼魯司寇，出走為群婢。假如屈原醒，其奈一國醉。", "一國醉號呶，一人行清高。便欲激頹波，此事真徒勞。", "上山逢猛虎，入海逢巨鼇。王者苟不死，腰下魚鱗刀。", "東海波連天，三度成桑田。高岸高於屋，斯須變溪穀。", "天地猶尚然，人情難久全。夜半白刃仇，旦來金石堅。", "蕭綬既解坼，陳印亦棄捐。竭節遇刀割，輸忠遭禍纏。", "不予衾之眠，信予衾之穿。鏡明不自照，膏潤徒自煎。", "抱劍長太息，淚墮秋風前。", "古來不患寡，所患患不均。單醪投長河，三軍盡沉淪。", "今人異古人，結托唯親賓。毀坼維鵲巢，不行鳲鳩仁。", "鄙吝不識分，有心占陽春。鸞鶴日已疏，燕雀日已親。", "小物無大志，安測棲松筠。恩眷多棄故，物情尚逐新。", "瓦礫暫拂拭，光掩連城珍。唇吻恣談鑠，黃金同灰塵。", "蘇秦北游趙，張祿西入秦。既變嫂叔節，仍擯華陽君。", "萬世金石交，一餉如浮雲。骨肉且不顧，何況長羈貧。"]'),
('yuding-22','雜興','盧仝','唐','御定全唐诗','yuding','','[]','意智未成百不解，見人富貴亦心愛。等閒對酒呼三達，',88,'御定全唐詩/json/388.json','["意智未成百不解，見人富貴亦心愛。等閒對酒呼三達，", "廚中玉饌盈金盤，方丈厭見嫌不餐。飛鷹躍馬實快性，", "昨朝惆悵不如君，今日悲君不如我。否泰交加無定主，", "三五圖書舊揣摩，五千道德新規矩。"]'),
('yuding-23','酬徐公以新文見招','盧仝','唐','御定全唐诗','yuding','','[]','昨夜霜月明，果有清音生。便欲走相和，愁聞寒玉聲。',24,'御定全唐詩/json/388.json','["昨夜霜月明，果有清音生。便欲走相和，愁聞寒玉聲。"]'),
('yuding-24','門箴','盧仝','唐','御定全唐诗','yuding','','[]','貪殘奸酗，狡佞訐愎，身之八殺。背惠，恃己，狎不肖，',25,'御定全唐詩/json/388.json','["貪殘奸酗，狡佞訐愎，身之八殺。背惠，恃己，狎不肖，"]'),
('yuding-25','孟夫子生生亭賦','盧仝','唐','御定全唐诗','yuding','','[]','玉川子沿孟冬之寒流兮，輟棹上登生生亭。夫子何之兮，',138,'御定全唐詩/json/388.json','["玉川子沿孟冬之寒流兮，輟棹上登生生亭。夫子何之兮，", "予日衰期人生之世斯已矣，爰為今日猶猶岐路之心生。", "悲夫，南國風濤，魚龍畜伏。予小子戇樸，必不能濟夫子欲。", "嗟自慚承夫子而不失予兮，傳古道甚分明。", "予且廣孤目遐齎於天壤兮，庶得外盡萬物變化之幽情。", "然後慚愧而來歸兮，大息吾躬于夫子之亭。"]'),
('yuding-0','走筆追王內丘','盧仝','唐','御定全唐诗','yuding','','[]','自識夫子面，便獲夫子心。夫子一啟顏，義重千黃金。',83,'御定全唐詩/json/389.json','["自識夫子面，便獲夫子心。夫子一啟顏，義重千黃金。", "平原孟嘗骨已土，始有夫子堪知音。忽然夫子不語，", "不如對此景，含笑傾金罍。莫問四肢暢，暫取眉頭開。", "弦琴待夫子，夫子來不來。"]'),
('yuding-1','思君吟寄□□生','盧仝','唐','御定全唐诗','yuding','','[]','我思君兮河之壖。我為河中之泉，君為河中之青天。',67,'御定全唐詩/json/389.json','["我思君兮河之壖。我為河中之泉，君為河中之青天。", "天青青，泉泠泠。泉含青天天隔泉，我思君兮心亦然。", "心亦然，此心複在天之側。我心為風兮淅淅，"]'),
('yuding-2','將歸山招冰僧','盧仝','唐','御定全唐诗','yuding','','[]','買得一片田，濟源花洞前。千里石壁坼，一條流泌泉。',80,'御定全唐詩/json/389.json','["買得一片田，濟源花洞前。千里石壁坼，一條流泌泉。", "青松盤樛枝，森森上插青冥天。枝上有□猿，", "欲結塵外交，苦無塵外骨。泌泉有冰公，心靜見真佛。", "可結塵外交，占此松與月。"]'),
('yuding-3','酬願公雪中見寄','盧仝','唐','御定全唐诗','yuding','','[]','積雪三十日，車馬路不通。貧病交親絕，想憶唯願公。',72,'御定全唐詩/json/389.json','["積雪三十日，車馬路不通。貧病交親絕，想憶唯願公。", "春鳩報春歸，苦寒生暗風。簷乳墮懸玉，日腳浮輕紅。", "梅柳意卻活，園圃冰始融。更候四體好，方可到寺中。"]'),
('yuding-4','苦雪寄退之','盧仝','唐','御定全唐诗','yuding','','[]','天王二月行時令，白銀作雪漫天涯。山人門前遍受賜，',120,'御定全唐詩/json/389.json','["天王二月行時令，白銀作雪漫天涯。山人門前遍受賜，", "山人屋中凍欲死，千樹萬樹飛春花。菜頭出土膠入地，", "病妻煙眼淚滴滴，饑嬰哭乳聲呶呶。市頭博米不用物，", "天眼高開欺草芽，我死未肯興歎嗟。但恨口中無酒氣，", "聖明有道□命漢，可得再見朝日耶。柴門沒脛晝不掃，"]'),
('yuding-5','寄贈含曦上人','盧仝','唐','御定全唐诗','yuding','','[]','楞伽大師兄，誇曦識道理。破鎖推玄關，高辯果難揣。',408,'御定全唐詩/json/389.json','["楞伽大師兄，誇曦識道理。破鎖推玄關，高辯果難揣。", "論語老莊易，搜索通神鬼。起信中百門，敲骨得佛髓。", "此外雜經律，泛讀一萬紙。高殿排名僧，執卷坐累累。", "化物自一心，三教齊發起。隨鐘嚼宮商，滿口文字美。", "商賈女郎輩，不曾道生死。縱遇強禮拜，雅語不露齒。", "劈破天地來，節義可屈指。季展即此僧，孤立無依倚。", "近來愛作詩，新奇頗煩委。忽忽造古格，削盡俗綺靡。", "假如慵裹頭，但勤讀書史。切磋並工夫，休遠不可比。", "憐僧無遠□，信佛殘未已。貌古饒風情，清論興亹亹。", "訪餘十數度，相去三五裏。見時心亦喜，不見心亦喜。", "見時談謔樂，四座盡角嘴。不見養天和，無人聒人耳。", "昨朝披雪來，面色赤靴靴。封灶養黃金，許割方寸匕。", "泥丸佛□教，怛化莊亦恥。未達不敢嘗，孔子疑季子。", "藥成必分余，餘必投泥裏。不如向陽堂，撥醅泛浮蟻。", "麹米本無愆，酒成是法水。行道不見心，毀譽徒云爾。", "雪晴天氣和，日光弄梅李。春鳥嬌關關，春風醉旎旎。", "道上正無塵，人家有花卉。高僧有拄杖，願得數覯止。"]'),
('yuding-6','聽蕭君姬人彈琴','盧仝','唐','御定全唐诗','yuding','','[]','彈琴人似膝上琴，聽琴人似匣中弦。二物各一處，',130,'御定全唐詩/json/389.json','["彈琴人似膝上琴，聽琴人似匣中弦。二物各一處，", "初時天山之外飛白雪，漸漸萬丈澗底生流泉。", "風梅花落輕揚揚，十指乾淨聲涓涓。昭君可惜嫁單于，", "關山險隔一萬里，顏色錯漠生風煙。形魄散逐五音盡，", "金尊湛湛夜沉沉，餘音疊發清聯綿。主人醉盈有得色，", "拂衣屢命請中廢，月照書窗歸獨眠。"]'),
('yuding-7','蜻蜓歌','盧仝','唐','御定全唐诗','yuding','','[]','黃河中流日影斜，水天一色無津涯，處處驚波噴流飛雪花。',77,'御定全唐詩/json/389.json','["黃河中流日影斜，水天一色無津涯，處處驚波噴流飛雪花。", "篙工楫師力且武，進寸退尺莫能度。吾甚懼。念汝小蟲子，", "不學汝無端小蟲子，葉葉水上無一事，忽遭風雨水中死。"]'),
('yuding-8','出山作','盧仝','唐','御定全唐诗','yuding','','[]','出山忘掩山門路，釣竿插在枯桑樹。當時只有鳥窺窬，',24,'御定全唐詩/json/389.json','["出山忘掩山門路，釣竿插在枯桑樹。當時只有鳥窺窬，"]'),
('yuding-9','寄崔柳州','盧仝','唐','御定全唐诗','yuding','','[]','使者立取書，疊紙生百憂。使君若不信，他時看白頭。',72,'御定全唐詩/json/389.json','["使者立取書，疊紙生百憂。使君若不信，他時看白頭。", "三百六十州，克情惟柳州。柳州蠻天末，鄙夫嵩之幽。", "花落隴水頭，各自東西流。凜凜長相逐，為謝池上鷗。"]'),
('yuding-10','贈稚禪師','盧仝','唐','御定全唐诗','yuding','','[]','春風滿禪院，師獨坐南軒。萬化見中盡，始覺靜性尊。',48,'御定全唐詩/json/389.json','["春風滿禪院，師獨坐南軒。萬化見中盡，始覺靜性尊。", "我來契平生，目擊道自存。與師不動游，遊此無跡門。"]'),
('yuding-11','送好約法師歸江南','盧仝','唐','御定全唐诗','yuding','','[]','杯度度一身，法度度萬民。為報江南三二日，',20,'御定全唐詩/json/389.json','["杯度度一身，法度度萬民。為報江南三二日，"]'),
('yuding-12','蕭二十三赴歙州婚期二首','盧仝','唐','御定全唐诗','yuding','','[]','淮上客情殊冷落，蠻方春早客何如。',64,'御定全唐詩/json/389.json','["淮上客情殊冷落，蠻方春早客何如。", "相思莫道無來使，回雁峰前好寄書。", "南方山水生時興，教有新詩得寄餘。", "路帶長安迢遞急，多應不逐使君書。"]'),
('yuding-13','掩關銘','盧仝','唐','御定全唐诗','yuding','','[]','蛇毒毒有形，藥毒毒有名。人毒毒在心，對面如弟兄。',48,'御定全唐詩/json/389.json','["蛇毒毒有形，藥毒毒有名。人毒毒在心，對面如弟兄。", "美言不可聽，深於千丈坑。不如掩關坐，幽鳥時一聲。"]'),
('yuding-14','逢病軍人','盧仝','唐','御定全唐诗','yuding','','[]','行多有病住無糧，萬里還鄉未到鄉。',32,'御定全唐詩/json/389.json','["行多有病住無糧，萬里還鄉未到鄉。", "蓬鬢哀吟古城下，不堪秋氣入金瘡。"]'),
('yuding-15','山中','盧仝','唐','御定全唐诗','yuding','','[]','饑拾松花渴飲泉，偶從山后到山前。',32,'御定全唐詩/json/389.json','["饑拾松花渴飲泉，偶從山后到山前。", "陽坡軟草厚如織，困與鹿麛相伴眠。"]'),
('yuding-16','除夜','盧仝','唐','御定全唐诗','yuding','','[]','衰殘歸未遂，寂寞此宵情。舊國餘千里，新年隔數更。',96,'御定全唐詩/json/389.json','["衰殘歸未遂，寂寞此宵情。舊國餘千里，新年隔數更。", "寒猶近北峭，風漸向東生。惟見長安陌，晨鐘度火城。", "殷勤惜此夜，此夜在逡巡。燭盡年還別，雞鳴老更新。", "儺聲方去病，酒色已迎春。明日持杯處，誰為最後人。"]'),
('yuding-0','李憑箜篌引','李賀','唐','御定全唐诗','yuding','','[]','吳絲蜀桐張高秋，空白凝雲頹不流。江娥啼竹素女愁，',64,'御定全唐詩/json/390.json','["吳絲蜀桐張高秋，空白凝雲頹不流。江娥啼竹素女愁，", "十二門前融冷光，二十三絲動紫皇。女媧煉石補天處，", "吳質不眠倚桂樹，露腳斜飛濕寒兔。"]'),
('yuding-1','殘絲曲','李賀','唐','御定全唐诗','yuding','','[]','垂楊葉老鶯哺兒，殘絲欲斷黃蜂歸。綠鬢年少金釵客，',40,'御定全唐詩/json/390.json','["垂楊葉老鶯哺兒，殘絲欲斷黃蜂歸。綠鬢年少金釵客，", "榆莢相催不知數，沈郎青錢夾城路。"]'),
('yuding-2','還自會稽歌','李賀','唐','御定全唐诗','yuding','','[]','野粉椒壁黃，濕螢滿梁殿。台城應教人，秋衾夢銅輦。',48,'御定全唐詩/json/390.json','["野粉椒壁黃，濕螢滿梁殿。台城應教人，秋衾夢銅輦。", "吳霜點歸鬢，身與塘蒲晚。脈脈辭金魚，羈臣守迍賤。"]'),
('yuding-3','出城寄權璩、楊敬之','李賀','唐','御定全唐诗','yuding','','[]','草暖雲昏萬里春，宮花拂面送行人。',32,'御定全唐詩/json/390.json','["草暖雲昏萬里春，宮花拂面送行人。", "自言漢劍當飛去，何事還車載病身。"]'),
('yuding-4','示弟','李賀','唐','御定全唐诗','yuding','','[]','別弟三年後，還家一日餘。醁醽今夕酒，緗帙去時書。',48,'御定全唐詩/json/390.json','["別弟三年後，還家一日餘。醁醽今夕酒，緗帙去時書。", "病骨猶能在，人間底事無。何須問牛馬，拋擲任梟盧。"]'),
('yuding-5','竹','李賀','唐','御定全唐诗','yuding','','[]','入水文光動，抽空綠影春。露華生筍徑，苔色拂霜根。',48,'御定全唐詩/json/390.json','["入水文光動，抽空綠影春。露華生筍徑，苔色拂霜根。", "織可承香汗，裁堪釣錦鱗。三梁曾入用，一節奉王孫。"]'),
('yuding-6','同沈駙馬賦得禦溝水','李賀','唐','御定全唐诗','yuding','','[]','入苑白泱泱，宮人正靨黃。繞堤龍骨冷，拂岸鴨頭香。',48,'御定全唐詩/json/390.json','["入苑白泱泱，宮人正靨黃。繞堤龍骨冷，拂岸鴨頭香。", "別館驚殘夢，停杯泛小觴。幸因流浪處，暫得見何郎。"]'),
('yuding-7','始為奉禮憶昌谷山居','李賀','唐','御定全唐诗','yuding','','[]','掃斷馬蹄痕，衙回自閉門。長槍江米熟，小樹棗花春。',72,'御定全唐詩/json/390.json','["掃斷馬蹄痕，衙回自閉門。長槍江米熟，小樹棗花春。", "向壁懸如意，當簾閱角巾。犬書曾去洛，鶴病悔游秦。", "土甑封茶葉，山杯鎖竹根。不知船上月，誰棹滿溪雲。"]'),
('yuding-8','七夕','李賀','唐','御定全唐诗','yuding','','[]','別浦今朝暗，羅帷午夜愁。鵲辭穿線月，花入曝衣樓。',48,'御定全唐詩/json/390.json','["別浦今朝暗，羅帷午夜愁。鵲辭穿線月，花入曝衣樓。", "天上分金鏡，人間望玉鉤。錢塘蘇小小，更值一年秋。"]'),
('yuding-9','過華清宮','李賀','唐','御定全唐诗','yuding','','[]','春月夜啼鴉，宮簾隔禦花。雲生朱絡暗，石斷紫錢斜。',48,'御定全唐詩/json/390.json','["春月夜啼鴉，宮簾隔禦花。雲生朱絡暗，石斷紫錢斜。", "玉碗盛殘露，銀燈點舊紗。蜀王無近信，泉上有芹芽。"]'),
('yuding-10','送沈亞之歌','李賀','唐','御定全唐诗','yuding','','[]','吳興才人怨春風，桃花滿陌千里紅。紫絲竹斷驄馬小，',72,'御定全唐詩/json/390.json','["吳興才人怨春風，桃花滿陌千里紅。紫絲竹斷驄馬小，", "雄光寶礦獻春卿，煙底驀波乘一葉。春卿拾材白日下，", "吾聞壯夫重心骨，古人三走無摧捽。請君待旦事長鞭，"]'),
('yuding-11','詠懷二首','李賀','唐','御定全唐诗','yuding','','[]','長卿懷茂陵，綠草垂石井。彈琴看文君，春風吹鬢影。',96,'御定全唐詩/json/390.json','["長卿懷茂陵，綠草垂石井。彈琴看文君，春風吹鬢影。", "梁王與武帝，棄之如斷梗。惟留一簡書，金泥泰山頂。", "日夕著書罷，驚霜落素絲。鏡中聊自笑，詎是南山期。", "頭上無幅巾，苦檗已染衣。不見清溪魚，飲水得自宜。"]'),
('yuding-12','追和柳惲','李賀','唐','御定全唐诗','yuding','','[]','汀洲白蘋草，柳惲乘馬歸。江頭楂樹香，岸上蝴蝶飛。',48,'御定全唐詩/json/390.json','["汀洲白蘋草，柳惲乘馬歸。江頭楂樹香，岸上蝴蝶飛。", "酒杯箬葉露，玉軫蜀桐虛。朱樓通水陌，沙暖一雙魚。"]'),
('yuding-13','春坊正字劍子歌','李賀','唐','御定全唐诗','yuding','','[]','先輩匣中三尺水，曾入吳潭斬龍子。隙月斜明刮露寒，',50,'御定全唐詩/json/390.json','["先輩匣中三尺水，曾入吳潭斬龍子。隙月斜明刮露寒，", "直是荊軻一片心，莫教照見春坊字。挼絲團金懸bAzy，"]'),
('yuding-14','貴公子夜闌曲','李賀','唐','御定全唐诗','yuding','','[]','嫋嫋沉水煙，烏啼夜闌景。曲沼芙蓉波，腰圍白玉冷。',24,'御定全唐詩/json/390.json','["嫋嫋沉水煙，烏啼夜闌景。曲沼芙蓉波，腰圍白玉冷。"]'),
('yuding-15','雁門太守行','李賀','唐','御定全唐诗','yuding','','[]','黑雲壓城城欲摧，甲光向日金鱗開。角聲滿天秋色裏，',40,'御定全唐詩/json/390.json','["黑雲壓城城欲摧，甲光向日金鱗開。角聲滿天秋色裏，", "報君黃金臺上意，提攜玉龍為君死。"]'),
('yuding-16','大堤曲','李賀','唐','御定全唐诗','yuding','','[]','妾家住橫塘，紅紗滿桂香。青雲教綰頭上髻，',56,'御定全唐詩/json/390.json','["妾家住橫塘，紅紗滿桂香。青雲教綰頭上髻，", "郎食鯉魚尾，妾食猩猩唇。莫指襄陽道，綠浦歸帆少。", "今日菖蒲花，明朝楓樹老。"]'),
('yuding-17','蜀國弦','李賀','唐','御定全唐诗','yuding','','[]','楓香晚花靜，錦水南山影。驚石墜猿哀，竹雲愁半嶺。',48,'御定全唐詩/json/390.json','["楓香晚花靜，錦水南山影。驚石墜猿哀，竹雲愁半嶺。", "涼月生秋浦，玉沙粼粼光。誰家紅淚客，不忍過瞿塘。"]'),
('yuding-18','蘇小小墓','李賀','唐','御定全唐诗','yuding','','[]','幽蘭露，如啼眼。無物結同心，煙花不堪剪。草如茵，',24,'御定全唐詩/json/390.json','["幽蘭露，如啼眼。無物結同心，煙花不堪剪。草如茵，"]'),
('yuding-19','夢天','李賀','唐','御定全唐诗','yuding','','[]','老兔寒蟾泣天色，雲樓半開壁斜白。玉輪軋露濕團光，',40,'御定全唐詩/json/390.json','["老兔寒蟾泣天色，雲樓半開壁斜白。玉輪軋露濕團光，", "遙望齊州九點煙，一泓海水杯中瀉。"]'),
('yuding-20','唐兒歌','李賀','唐','御定全唐诗','yuding','','[]','頭玉磽磽眉刷翠，杜郎生得真男子。骨重神寒天廟器，',48,'御定全唐詩/json/390.json','["頭玉磽磽眉刷翠，杜郎生得真男子。骨重神寒天廟器，", "東家嬌娘求對值，濃笑畫空作唐字。眼大心雄知所以，"]'),
('yuding-21','綠章封事','李賀','唐','御定全唐诗','yuding','','[]','青霓扣額呼宮神，鴻龍玉狗開天門。石榴花發滿溪津，',48,'御定全唐詩/json/390.json','["青霓扣額呼宮神，鴻龍玉狗開天門。石榴花發滿溪津，", "虛空風氣不清泠，短衣小冠作塵土。金家香巷千輪鳴，"]'),
('yuding-22','河南府試十二月樂詞：正月','李賀','唐','御定全唐诗','yuding','','[]','上樓迎春新春歸，暗黃著柳宮漏遲。薄薄淡靄弄野姿，',40,'御定全唐詩/json/390.json','["上樓迎春新春歸，暗黃著柳宮漏遲。薄薄淡靄弄野姿，", "官街柳帶不堪折，早晚菖蒲勝綰結。"]'),
('yuding-23','河南府試十二月樂詞：二月','李賀','唐','御定全唐诗','yuding','','[]','二月飲酒采桑津，宜男草生蘭笑人。蒲如交劍風如熏，',24,'御定全唐詩/json/390.json','["二月飲酒采桑津，宜男草生蘭笑人。蒲如交劍風如熏，"]'),
('yuding-24','河南府試十二月樂詞：三月','李賀','唐','御定全唐诗','yuding','','[]','東方風來滿眼春，花城柳暗愁殺人。複宮深殿竹風起，',48,'御定全唐詩/json/390.json','["東方風來滿眼春，花城柳暗愁殺人。複宮深殿竹風起，", "軍裝宮妓掃蛾淺，搖搖錦旗夾城暖。曲水漂香去不歸，"]'),
('yuding-25','河南府試十二月樂詞：四月','李賀','唐','御定全唐诗','yuding','','[]','曉涼暮涼樹如盡，千山濃綠生雲外。依微香雨青氛氳，',24,'御定全唐詩/json/390.json','["曉涼暮涼樹如盡，千山濃綠生雲外。依微香雨青氛氳，"]'),
('yuding-26','河南府試十二月樂詞：五月','李賀','唐','御定全唐诗','yuding','','[]','雕玉押簾額，輕縠籠虛門。井汲鉛華水，扇織鴛鴦紋。',48,'御定全唐詩/json/390.json','["雕玉押簾額，輕縠籠虛門。井汲鉛華水，扇織鴛鴦紋。", "回雪舞涼殿，甘露洗空綠。羅袖從徊翔，香汗沾寶粟。"]'),
('yuding-27','河南府試十二月樂詞：六月','李賀','唐','御定全唐诗','yuding','','[]','裁生羅，伐湘竹，帔拂疏霜簟秋玉。炎炎紅鏡東方開，',24,'御定全唐詩/json/390.json','["裁生羅，伐湘竹，帔拂疏霜簟秋玉。炎炎紅鏡東方開，"]'),
('yuding-28','河南府試十二月樂詞：七月','李賀','唐','御定全唐诗','yuding','','[]','星依雲渚冷，露滴盤中圓。好花生木末，衰蕙愁空園。',60,'御定全唐詩/json/390.json','["星依雲渚冷，露滴盤中圓。好花生木末，衰蕙愁空園。", "夜天如玉砌，池葉極青錢。僅厭舞衫薄，稍知花簟寒。", "曉風何拂拂，北斗光闌幹。"]'),
('yuding-29','河南府試十二月樂詞：八月','李賀','唐','御定全唐诗','yuding','','[]','孀妾怨夜長，獨客夢歸家。傍簷蟲緝絲，向壁燈垂花。',48,'御定全唐詩/json/390.json','["孀妾怨夜長，獨客夢歸家。傍簷蟲緝絲，向壁燈垂花。", "簾外月光吐，簾內樹影斜。悠悠飛露姿，點綴池中荷。"]'),
('yuding-30','河南府試十二月樂詞：九月','李賀','唐','御定全唐诗','yuding','','[]','離宮散螢天似水，竹黃池冷芙蓉死。月綴金鋪光脈脈，',40,'御定全唐詩/json/390.json','["離宮散螢天似水，竹黃池冷芙蓉死。月綴金鋪光脈脈，", "雞人罷唱曉瓏璁，鴉啼金井下疏桐。"]'),
('yuding-31','河南府試十二月樂詞：十月','李賀','唐','御定全唐诗','yuding','','[]','玉壺銀箭稍難傾，釭花夜笑凝幽明。碎霜斜舞上羅幕，',24,'御定全唐詩/json/390.json','["玉壺銀箭稍難傾，釭花夜笑凝幽明。碎霜斜舞上羅幕，"]'),
('yuding-32','河南府試十二月樂詞：十一月','李賀','唐','御定全唐诗','yuding','','[]','宮城團回凜嚴光，白天碎碎墮瓊芳。撾鐘高飲千日酒，',24,'御定全唐詩/json/390.json','["宮城團回凜嚴光，白天碎碎墮瓊芳。撾鐘高飲千日酒，"]'),
('yuding-33','河南府試十二月樂詞：十二月','李賀','唐','御定全唐诗','yuding','','[]','日腳淡光紅灑灑，薄霜不銷桂枝下。',32,'御定全唐詩/json/390.json','["日腳淡光紅灑灑，薄霜不銷桂枝下。", "依稀和氣排冬嚴，已就長日辭長夜。"]'),
('yuding-34','河南府試十二月樂詞：閏月','李賀','唐','御定全唐诗','yuding','','[]','帝重光，年重時，七十二候回環推，天官玉管灰剩飛。',48,'御定全唐詩/json/390.json','["帝重光，年重時，七十二候回環推，天官玉管灰剩飛。", "今歲何長來歲遲，王母移桃獻天子，羲氏和氏迂龍轡。"]'),
('yuding-35','天上謠','李賀','唐','御定全唐诗','yuding','','[]','天河夜轉漂回星，銀浦流雲學水聲。玉宮桂樹花未落，',48,'御定全唐詩/json/390.json','["天河夜轉漂回星，銀浦流雲學水聲。玉宮桂樹花未落，", "王子吹笙鵝管長，呼龍耕煙種瑤草。粉霞紅綬藕絲裙，"]'),
('yuding-36','浩歌','李賀','唐','御定全唐诗','yuding','','[]','南風吹山作平地，帝遣天吳移海水。王母桃花千遍紅，',72,'御定全唐詩/json/390.json','["南風吹山作平地，帝遣天吳移海水。王母桃花千遍紅，", "箏人勸我金屈卮，神血未凝身問誰。不須浪飲丁都護，", "漏催水咽玉蟾蜍，衛娘發薄不勝梳。看見秋眉換新綠，"]'),
('yuding-37','秋來','李賀','唐','御定全唐诗','yuding','','[]','桐風驚心壯士苦，衰燈絡緯啼寒素。誰看青簡一編書，',40,'御定全唐詩/json/390.json','["桐風驚心壯士苦，衰燈絡緯啼寒素。誰看青簡一編書，", "秋墳鬼唱鮑家詩，恨血千年土中碧。"]'),
('yuding-38','帝子歌','李賀','唐','御定全唐诗','yuding','','[]','洞庭明月一千里，涼風雁啼天在水。九節菖蒲石上死，',40,'御定全唐詩/json/390.json','["洞庭明月一千里，涼風雁啼天在水。九節菖蒲石上死，", "沙浦走魚白石郎，閑取真珠擲龍堂。"]'),
('yuding-39','秦王飲酒','李賀','唐','御定全唐诗','yuding','','[]','秦王騎虎遊八極，劍光照空天自碧。羲和敲日玻璃聲，',48,'御定全唐詩/json/390.json','["秦王騎虎遊八極，劍光照空天自碧。羲和敲日玻璃聲，", "洞庭雨腳來吹笙，酒酣喝月使倒行。銀雲櫛櫛瑤殿明，"]'),
('yuding-40','洛姝真珠','李賀','唐','御定全唐诗','yuding','','[]','真珠小娘下清廓，洛苑香風飛綽綽。寒鬢斜釵玉燕光，',72,'御定全唐詩/json/390.json','["真珠小娘下清廓，洛苑香風飛綽綽。寒鬢斜釵玉燕光，", "花袍白馬不歸來，濃蛾疊柳香唇醉。金鵝屏風蜀山夢，", "市南曲陌無秋涼，楚腰衛鬢四時芳。玉喉窱窱排空光，"]'),
('yuding-41','李夫人歌','李賀','唐','御定全唐诗','yuding','','[]','紫皇宮殿重重開，夫人飛入瓊瑤台。綠香繡帳何時歇，',48,'御定全唐詩/json/390.json','["紫皇宮殿重重開，夫人飛入瓊瑤台。綠香繡帳何時歇，", "紅壁闌珊懸佩璫，歌台小妓遙相望。玉蟾滴水雞人唱，"]'),
('yuding-42','走馬引','李賀','唐','御定全唐诗','yuding','','[]','我有辭鄉劍，玉鋒堪截雲。襄陽走馬客，意氣自生春。',48,'御定全唐詩/json/390.json','["我有辭鄉劍，玉鋒堪截雲。襄陽走馬客，意氣自生春。", "朝嫌劍花淨，暮嫌劍光冷。能持劍向人，不解持照身。"]'),
('yuding-43','湘妃','李賀','唐','御定全唐诗','yuding','','[]','筠竹千年老不死，長伴秦娥蓋湘水。蠻娘吟弄滿寒空，',40,'御定全唐詩/json/390.json','["筠竹千年老不死，長伴秦娥蓋湘水。蠻娘吟弄滿寒空，", "幽愁秋氣上青楓，涼夜波間吟古龍。"]'),
('yuding-44','南園十三首','李賀','唐','御定全唐诗','yuding','','[]','花枝草蔓眼中開，小白長紅越女腮。',384,'御定全唐詩/json/390.json','["花枝草蔓眼中開，小白長紅越女腮。", "可憐日暮嫣香落，嫁與春風不用媒。", "宮北田塍曉氣酣，黃桑飲露窣宮簾。", "長腰健婦偷攀折，將喂吳王八繭蠶。", "竹裏繰絲挑網車，青蟬獨噪日光斜。", "桃膠迎夏香琥珀，自課越傭能種瓜。", "三十未有二十餘，白日長饑小甲蔬。", "橋頭長老相哀念，因遺戎韜一卷書。", "男兒何不帶吳鉤，收取關山五十州。", "請君暫上淩煙閣，若個書生萬戶侯。", "尋章摘句老雕蟲，曉月當簾掛玉弓。", "不見年年遼海上，文章何處哭秋風。", "長卿牢落悲空舍，曼倩詼諧取自容。", "見買若耶溪水劍，明朝歸去事猿公。", "春水初生乳燕飛，黃蜂小尾撲花歸。", "窗含遠色通書幌，魚擁香鉤近石磯。", "泉沙軟臥鴛鴦暖，曲岸回篙舴艋遲。", "瀉酒木欄椒葉蓋，病容扶起種菱絲。", "邊讓今朝憶蔡邕，無心裁曲臥春風。", "舍南有竹堪書字，老去溪頭作釣翁。", "長巒穀口倚嵇家，白晝千峰老翠華。", "自履藤鞋收石蜜，手牽苔絮長蓴花。", "松溪黑水新龍卵，桂洞生硝舊馬牙。", "誰遣虞卿裁道帔，輕綃一匹染朝霞。"]'),
('yuding-0','金銅仙人辭漢歌','李賀','唐','御定全唐诗','yuding','','[]','茂陵劉郎秋風客，夜聞馬嘶曉無跡。畫欄桂樹懸秋香，',48,'御定全唐詩/json/391.json','["茂陵劉郎秋風客，夜聞馬嘶曉無跡。畫欄桂樹懸秋香，", "空將漢月出宮門，憶君清淚如鉛水。衰蘭送客咸陽道，"]'),
('yuding-1','古悠悠行','李賀','唐','御定全唐诗','yuding','','[]','白景歸西山，碧華上迢迢。今古何處盡，千歲隨風飄。',48,'御定全唐詩/json/391.json','["白景歸西山，碧華上迢迢。今古何處盡，千歲隨風飄。", "海沙變成石，魚沫吹秦橋。空光遠流浪，銅柱從年消。"]'),
('yuding-2','黃頭郎','李賀','唐','御定全唐诗','yuding','','[]','黃頭郎，撈攏去不歸。南浦芙蓉影，愁紅獨自垂。',70,'御定全唐詩/json/391.json','["黃頭郎，撈攏去不歸。南浦芙蓉影，愁紅獨自垂。", "水弄湘娥佩，竹啼山露月。玉瑟調青門，石雲濕黃葛。", "沙上蘼蕪花，秋風已先發。好持掃羅薦，香出鴛鴦熱。"]'),
('yuding-3','馬詩二十三首','李賀','唐','御定全唐诗','yuding','','[]','龍脊貼連錢，銀蹄白踏煙。無人織錦韂，誰為鑄金鞭。',552,'御定全唐詩/json/391.json','["龍脊貼連錢，銀蹄白踏煙。無人織錦韂，誰為鑄金鞭。", "臘月草根甜，天街雪似鹽。未知口硬軟，先擬蒺藜銜。", "忽憶周天子，驅車上玉山。鳴騶辭鳳苑，赤驥最承恩。", "此馬非凡馬，房星本是星。向前敲瘦骨，猶自帶銅聲。", "大漠山如雪，燕山月似鉤。何當金絡腦，快走踏清秋。", "饑臥骨查牙，粗毛刺破花。鬣焦朱色落，發斷鋸長麻。", "西母酒將闌，東王飯已幹。君王若燕去，誰為拽車轅。", "赤兔無人用，當須呂布騎。吾聞果下馬，羈策任蠻兒。", "飂叔去匆匆，如今不豢龍。夜來霜壓棧，駿骨折西風。", "催榜渡烏江，神騅泣向風。君王今解劍，何處逐英雄。", "內馬賜宮人，銀韉刺騏驎。午時鹽阪上，蹭蹬溘風塵。", "批竹初攢耳，桃花未上身。他時須攪陣，牽去借將軍。", "寶玦誰家子，長聞俠骨香。堆金買駿骨，將送楚襄王。", "香襆赭羅新，盤龍蹙鐙鱗。回看南陌上，誰道不逢春。", "不從桓公獵，何能伏虎威。一朝溝隴出，看取拂雲飛。", "唐劍斬隋公，拳毛屬太宗。莫嫌金甲重，且去捉旋風。", "白鐵剉青禾，砧間落細莎。世人憐小頸，金埒畏長牙。", "伯樂向前看，旋毛在腹間。只今掊白草，何日驀青山。", "蕭寺馱經馬，元從竺國來。空知有善相，不解走章台。", "重圍如燕尾，寶劍似魚腸。欲求千里腳，先采眼中光。", "暫系騰黃馬，仙人上彩樓。須鞭玉勒吏，何事謫高州。", "汗血到王家，隨鸞撼玉珂。少君騎海上，人見是青騾。", "武帝愛神仙，燒金得紫煙。廄中皆肉馬，不解上青天。"]'),
('yuding-4','申鬍子觱篥歌','李賀','唐','御定全唐诗','yuding','','[]','顏熱感君酒，含嚼蘆中聲。花娘篸綏妥，休睡芙蓉屏。',96,'御定全唐詩/json/391.json','["顏熱感君酒，含嚼蘆中聲。花娘篸綏妥，休睡芙蓉屏。", "誰截太平管，列點排空星。直貫開花風，天上驅雲行。", "今夕歲華落，令人惜平生。心事如波濤，中坐時時驚。", "朔客騎白馬，劍弝懸蘭纓。俊健如生猱，肯拾蓬中螢。"]'),
('yuding-5','老夫采玉歌','李賀','唐','御定全唐诗','yuding','','[]','采玉采玉須水碧，琢作步搖徒好色。老夫饑寒龍為愁，',48,'御定全唐詩/json/391.json','["采玉采玉須水碧，琢作步搖徒好色。老夫饑寒龍為愁，", "藍溪之水厭生人，身死千年恨溪水。斜山柏風雨如嘯，"]'),
('yuding-6','傷心行','李賀','唐','御定全唐诗','yuding','','[]','咽咽學楚吟，病骨傷幽素。秋姿白髮生，木葉啼風雨。',48,'御定全唐詩/json/391.json','["咽咽學楚吟，病骨傷幽素。秋姿白髮生，木葉啼風雨。", "燈青蘭膏歇，落照飛蛾舞。古壁生凝塵，羈魂夢中語。"]'),
('yuding-7','湖中曲','李賀','唐','御定全唐诗','yuding','','[]','長眉越沙采蘭若，桂葉水葓春漠漠。橫船醉眠白晝閑，',40,'御定全唐詩/json/391.json','["長眉越沙采蘭若，桂葉水葓春漠漠。橫船醉眠白晝閑，", "蜀紙封巾報雲鬢，晚漏壺中水淋盡。"]'),
('yuding-8','黃家洞','李賀','唐','御定全唐诗','yuding','','[]','雀步蹙沙聲促促，四尺角弓青石鏃。黑幡三點銅鼓鳴，',48,'御定全唐詩/json/391.json','["雀步蹙沙聲促促，四尺角弓青石鏃。黑幡三點銅鼓鳴，", "山潭晚霧吟白鼉，竹蛇飛蠹射金沙。閑驅竹馬緩歸家，"]'),
('yuding-9','屏風曲','李賀','唐','御定全唐诗','yuding','','[]','蝶棲石竹銀交關，水凝綠鴨琉璃錢。團回六曲抱膏蘭，',40,'御定全唐詩/json/391.json','["蝶棲石竹銀交關，水凝綠鴨琉璃錢。團回六曲抱膏蘭，", "月風吹露屏外寒，城上烏啼楚女眠。"]'),
('yuding-10','南山田中行','李賀','唐','御定全唐诗','yuding','','[]','秋野明，秋風白，塘水漻漻蟲嘖嘖。雲根苔蘚山上石，',40,'御定全唐詩/json/391.json','["秋野明，秋風白，塘水漻漻蟲嘖嘖。雲根苔蘚山上石，", "石脈水流泉滴沙，鬼燈如漆點松花。"]'),
('yuding-11','貴主征行樂','李賀','唐','御定全唐诗','yuding','','[]','奚騎黃銅連鎖甲，羅旗香乾金畫葉。中軍留醉河陽城，',40,'御定全唐詩/json/391.json','["奚騎黃銅連鎖甲，羅旗香乾金畫葉。中軍留醉河陽城，", "女垣素月角咿咿，牙帳未開分錦衣。"]'),
('yuding-12','酒罷張大徹索贈詩','李賀','唐','御定全唐诗','yuding','','[]','長鬣張郎三十八，天遣裁詩花作骨。往還誰是龍頭人，',48,'御定全唐詩/json/391.json','["長鬣張郎三十八，天遣裁詩花作骨。往還誰是龍頭人，", "金門石閣知卿有，豸角雞香早晚含。隴西長吉摧頹客，"]'),
('yuding-13','羅浮山父與葛篇','李賀','唐','御定全唐诗','yuding','','[]','依依宜織江雨空，雨中六月蘭颱風。博羅老仙時出洞，',40,'御定全唐詩/json/391.json','["依依宜織江雨空，雨中六月蘭颱風。博羅老仙時出洞，", "欲剪箱中一尺天，吳娥莫道吳刀澀。"]'),
('yuding-14','仁和裏雜敘皇甫湜','李賀','唐','御定全唐诗','yuding','','[]','大人乞馬臒乃寒，宗人貸宅荒厥垣。橫庭鼠徑空土澀，',88,'御定全唐詩/json/391.json','["大人乞馬臒乃寒，宗人貸宅荒厥垣。橫庭鼠徑空土澀，", "還家白筆未上頭，使我清聲落人後。枉辱稱知犯君眼，", "那知堅都相草草，客枕幽單看春老。歸來骨薄面無膏，", "明朝下元複西道，崆峒敘別長如天。"]'),
('yuding-15','宮娃歌','李賀','唐','御定全唐诗','yuding','','[]','蠟光高懸照紗空，花房夜搗紅守宮。象口吹香毾bG暖，',49,'御定全唐詩/json/391.json','["蠟光高懸照紗空，花房夜搗紅守宮。象口吹香毾bG暖，", "啼蛄吊月鉤欄下，屈膝銅鋪鎖阿甄。夢入家門上沙渚，"]'),
('yuding-16','堂堂','李賀','唐','御定全唐诗','yuding','','[]','堂堂複堂堂，紅脫梅灰香。十年粉蠹生畫梁，',36,'御定全唐詩/json/391.json','["堂堂複堂堂，紅脫梅灰香。十年粉蠹生畫梁，", "華清源中礜石湯，裴回白鳳隨君王。"]'),
('yuding-17','勉愛行二首送小季之廬山','李賀','唐','御定全唐诗','yuding','','[]','洛郊無俎豆，弊廄慚老馬。小雁過爐峰，影落楚水下。',120,'御定全唐詩/json/391.json','["洛郊無俎豆，弊廄慚老馬。小雁過爐峰，影落楚水下。", "長船倚雲泊，石鏡秋涼夜。豈解有鄉情，弄月聊嗚啞。", "別柳當馬頭，官槐如兔目。欲將千里別，持我易鬥粟。", "南雲北雲空脈斷，靈台經絡懸春線。青軒樹轉月滿床，", "辭家三載今如此，索米王門一事無。荒溝古水光如刀，"]'),
('yuding-18','致酒行','李賀','唐','御定全唐诗','yuding','','[]','零落棲遲一杯酒，主人奉觴客長壽。主父西游困不歸，',48,'御定全唐詩/json/391.json','["零落棲遲一杯酒，主人奉觴客長壽。主父西游困不歸，", "空將箋上兩行書，直犯龍顏請恩澤。我有迷魂招不得，"]'),
('yuding-19','長歌續短歌','李賀','唐','御定全唐诗','yuding','','[]','長歌破衣襟，短歌斷白髮。秦王不可見，旦夕成內熱。',84,'御定全唐詩/json/391.json','["長歌破衣襟，短歌斷白髮。秦王不可見，旦夕成內熱。", "渴飲壺中酒，饑拔隴頭粟。淒淒四月闌，千里一時綠。", "夜峰何離離，明月落石底。裴回沿石尋，照出高峰外。", "不得與之游，歌成鬢先改。"]'),
('yuding-20','公莫舞歌','李賀','唐','御定全唐诗','yuding','','[]','方花古礎排九楹，刺豹淋血盛銀罌。華筵鼓吹無桐竹，',72,'御定全唐詩/json/391.json','["方花古礎排九楹，刺豹淋血盛銀罌。華筵鼓吹無桐竹，", "腰下三看寶玦光，項莊掉箾欄前起。材官小臣公莫舞，", "鐵樞鐵楗重束關，大旗五丈撞雙鐶。漢王今日頒秦印，"]'),
('yuding-21','昌穀北園新筍四首','李賀','唐','御定全唐诗','yuding','','[]','籜落長竿削玉開，君看母筍是龍材。',128,'御定全唐詩/json/391.json','["籜落長竿削玉開，君看母筍是龍材。", "更容一夜抽千尺，別卻池園數寸泥。", "斫取青光寫楚辭，膩香春粉黑離離。", "無情有恨何人見，露壓煙啼千萬枝。", "家泉石眼兩三莖，曉看陰根紫脈生。", "今年水曲春沙上，笛管新篁拔玉青。", "古竹老梢惹碧雲，茂陵歸臥歎清貧。", "風吹千畝迎雨嘯，鳥重一枝入酒尊。"]'),
('yuding-22','惱公','李賀','唐','御定全唐诗','yuding','','[]','宋玉愁空斷，嬌饒粉自紅。歌聲春草露，門掩杏花叢。',576,'御定全唐詩/json/391.json','["宋玉愁空斷，嬌饒粉自紅。歌聲春草露，門掩杏花叢。", "注口櫻桃小，添眉桂葉濃。曉奩妝秀靨，夜帳減香筒。", "鈿鏡飛孤鵲，江圖畫水葓。陂陀梳碧鳳，腰嫋帶金蟲。", "杜若含清露，河蒲聚紫茸。月分蛾黛破，花合靨朱融。", "發重疑盤霧，腰輕乍倚風。密書題豆蔻，隱語笑芙蓉。", "莫鎖茱萸匣，休開翡翠籠。弄珠驚漢燕，燒蜜引胡蜂。", "醉纈拋紅網，單羅掛綠蒙。數錢教姹女，買藥問巴賨。", "勻臉安斜雁，移燈想夢熊。腸攢非束竹，胘急是張弓。", "晚樹迷新蝶，殘霓憶斷虹。古時填渤澥，今日鑿崆峒。", "繡遝褰長幔，羅裙結短封。心搖如舞鶴，骨出似飛龍。", "井檻淋清漆，門鋪綴白銅。隈花開兔徑，向壁印狐蹤。", "玳瑁釘簾薄，琉璃疊扇烘。象床緣素柏，瑤席捲香蔥。", "細管吟朝幌，芳醪落夜楓。宜男生楚巷，梔子發金墉。", "龜甲開屏澀，鵝毛滲墨濃。黃庭留衛瓘，綠樹養韓馮。", "雞唱星懸柳，鴉啼露滴桐。黃娥初出座，寵妹始相從。", "蠟淚垂蘭燼，秋蕪掃綺櫳。吹笙翻舊引，沽酒待新豐。", "短佩愁填粟，長弦怨削菘。曲池眠乳鴨，小閣睡娃僮。", "褥縫篸雙線，鉤絛辮五總。蜀煙飛重錦，峽雨濺輕容。", "拂鏡羞溫嶠，熏衣避賈充。魚生玉藕下，人在石蓮中。", "含水彎蛾翠，登樓選馬鬃。使君居曲陌，園令住臨邛。", "桂火流蘇暖，金爐細炷通。春遲王子態，鶯囀謝娘慵。", "玉漏三星曙，銅街五馬逢。犀株防膽怯，銀液鎮心忪。", "跳脫看年命，琵琶道吉凶。王時應七夕，夫位在三宮。", "無力塗雲母，多方帶藥翁。符因青鳥送，囊用絳紗縫。"]'),
('yuding-23','感諷五首','李賀','唐','御定全唐诗','yuding','','[]','合浦無明珠，龍洲無木奴。足知造化力，不給使君須。',372,'御定全唐詩/json/391.json','["合浦無明珠，龍洲無木奴。足知造化力，不給使君須。", "越婦未織作，吳蠶始蠕蠕。縣官騎馬來，獰色虯紫須。", "懷中一方板，板上數行書。不因使君怒，焉得詣爾廬。", "越婦拜縣官，桑牙今尚小。會待春日晏，絲車方擲掉。", "越婦通言語，小姑具黃粱。縣官踏餐去，簿吏複登堂。", "奇俊無少年，日車何躃躃。我待紆雙綬，遺我星星發。", "都門賈生墓，青蠅久斷絕。寒食搖揚天，憤景長肅殺。", "皇漢十二帝，唯帝稱睿哲。一夕信豎兒，文明永淪歇。", "南山何其悲，鬼雨灑空草。長安夜半秋，風前幾人老。", "低迷黃昏徑，嫋嫋青櫟道。月午樹無影，一山唯白曉。", "漆炬迎新人，幽壙螢擾擾。", "星盡四方高，萬物知天曙。己生須己養，荷擔出門去。", "君平久不反，康伯循國路。曉思何譊譊，闤闠千人語。", "石根秋水明，石畔秋草瘦。侵衣野竹香，蟄蟄垂葉厚。", "岑中月歸來，蟾光掛空秀。桂露對仙娥，星星下雲逗。", "淒涼梔子落，山璺泣清漏。下有張仲蔚，披書案將朽。"]'),
('yuding-24','三月過行宮','李賀','唐','御定全唐诗','yuding','','[]','渠水紅繁擁禦牆，風嬌小葉學娥妝。',32,'御定全唐詩/json/391.json','["渠水紅繁擁禦牆，風嬌小葉學娥妝。", "垂簾幾度青春老，堪鎖千年白日長。"]'),
('yuding-0','追和何、謝銅雀妓','李賀','唐','御定全唐诗','yuding','','[]','佳人一壺酒，秋容滿千里。石馬臥新煙，憂來何所似。',48,'御定全唐詩/json/392.json','["佳人一壺酒，秋容滿千里。石馬臥新煙，憂來何所似。", "歌聲且潛弄，陵樹風自起。長裾壓高臺，淚眼看花機。"]'),
('yuding-1','送秦光祿北征','李賀','唐','御定全唐诗','yuding','','[]','北虜膠堪折，秋沙亂曉鼙。髯胡頻犯塞，驕氣似橫霓。',264,'御定全唐詩/json/392.json','["北虜膠堪折，秋沙亂曉鼙。髯胡頻犯塞，驕氣似橫霓。", "灞水樓船渡，營門細柳開。將軍馳白馬，豪彥騁雄材。", "箭射欃槍落，旗懸日月低。榆稀山易見，甲重馬頻嘶。", "天遠星光沒，沙平草葉齊。風吹雲路火，雪汙玉關泥。", "屢斷呼韓頸，曾然董卓臍。太常猶舊寵，光祿是新隮。", "寶玦麒麟起，銀壺狒狖啼。桃花連馬發，彩絮撲鞍來。", "呵臂懸金鬥，當唇注玉罍。清蘇和碎蟻，紫膩卷浮杯。", "虎鞟先蒙馬，魚腸且斷犀。䟃𧽼西旅狗，蹙額北方奚。", "守帳然香暮，看鷹永夜棲。黃龍就別鏡，青塚念陽臺。", "周處長橋役，侯調短弄哀。錢塘階鳳羽，正室擘鸞釵。", "內子攀琪樹，羌兒奏落梅。今朝擎劍去，何日刺蛟回。"]'),
('yuding-2','酬答二首','李賀','唐','御定全唐诗','yuding','','[]','金魚公子夾衫長，密裝腰鞓割玉方。',64,'御定全唐詩/json/392.json','["金魚公子夾衫長，密裝腰鞓割玉方。", "行處春風隨馬尾，柳花偏打內家香。", "雍州二月梅池春，禦水鵁鶄暖白蘋。試問酒旗歌板地，今朝誰是拗花人。"]'),
('yuding-3','畫角東城','李賀','唐','御定全唐诗','yuding','','[]','河轉曙蕭蕭，鴉飛睥睨高。帆長摽越甸，壁冷掛吳刀。',273,'御定全唐詩/json/392.json','["河轉曙蕭蕭，鴉飛睥睨高。帆長摽越甸，壁冷掛吳刀。", "淡菜生寒日，鮞魚潠白濤。水花沾抹額，旗鼓夜迎潮。", "謝秀才有妾縞練改從於人秀才引留之不得後生感憶座人製詩嘲謝賀復繼四首", "誰知泥憶雲，望斷梨花春。荷絲制機練，竹葉剪花裙。", "月明啼阿姊，燈暗會良人。也識君夫婿，金魚掛在身。", "銅鏡立青鸞，燕脂拂紫綿。腮花弄暗粉，眼尾淚侵寒。", "碧玉破不復，瑤琴重撥弦。今日非昔日，何人敢正看。", "洞房思不禁，蜂子作花心。灰暖殘香炷，發冷青蟲簪。", "夜遙燈焰短，睡熟小屏深。好作鴛鴦夢，南城罷搗砧。", "尋常輕宋玉，今日嫁文鴦。戟幹橫龍簴，刀環倚桂窗。", "邀人裁半袖，端坐據胡床。淚濕紅輪重，棲烏上井梁。"]'),
('yuding-4','昌谷讀書示巴童','李賀','唐','御定全唐诗','yuding','','[]','蟲響燈光薄，宵寒藥氣濃。君憐垂翅客，辛苦尚相從。',24,'御定全唐詩/json/392.json','["蟲響燈光薄，宵寒藥氣濃。君憐垂翅客，辛苦尚相從。"]'),
('yuding-5','巴童答','李賀','唐','御定全唐诗','yuding','','[]','巨鼻宜山褐，龐眉入苦吟。非君唱樂府，誰識怨秋深。',24,'御定全唐詩/json/392.json','["巨鼻宜山褐，龐眉入苦吟。非君唱樂府，誰識怨秋深。"]'),
('yuding-6','代崔家送客','李賀','唐','御定全唐诗','yuding','','[]','行盡柳煙下，馬蹄白翩翩。恐隨行處盡，何忍重揚鞭。',24,'御定全唐詩/json/392.json','["行盡柳煙下，馬蹄白翩翩。恐隨行處盡，何忍重揚鞭。"]'),
('yuding-7','出城','李賀','唐','御定全唐诗','yuding','','[]','雪下桂花稀，啼烏被彈歸。關水乘驢影，秦風帽帶垂。',48,'御定全唐詩/json/392.json','["雪下桂花稀，啼烏被彈歸。關水乘驢影，秦風帽帶垂。", "入鄉試萬里，無印自堪悲。卿卿忍相問，鏡中雙淚姿。"]'),
('yuding-8','莫種樹','李賀','唐','御定全唐诗','yuding','','[]','園中莫種樹，種樹四時愁。獨睡南床月，今秋似去秋。',24,'御定全唐詩/json/392.json','["園中莫種樹，種樹四時愁。獨睡南床月，今秋似去秋。"]'),
('yuding-9','將發','李賀','唐','御定全唐诗','yuding','','[]','東床卷席罷，濩落將行去。秋白遙遙空，日滿門前路。',24,'御定全唐詩/json/392.json','["東床卷席罷，濩落將行去。秋白遙遙空，日滿門前路。"]'),
('yuding-10','追賦畫江潭苑四首','李賀','唐','御定全唐诗','yuding','','[]','吳苑曉蒼蒼，宮衣水濺黃。小鬟紅粉薄，騎馬佩珠長。',192,'御定全唐詩/json/392.json','["吳苑曉蒼蒼，宮衣水濺黃。小鬟紅粉薄，騎馬佩珠長。", "路指台城迥，羅熏袴褶香。行雲沾翠輦，今日似襄王。", "寶襪菊衣單，蕉花密露寒。水光蘭澤葉，帶重剪刀錢。", "角暖盤弓易，靴長上馬難。淚痕沾寢帳，勻粉照金鞍。", "剪翅小鷹斜，絛根玉镟花。秋垂妝鈿粟，箭箙釘文牙。", "狒狒啼深竹，鵁鶄老濕沙。宮官燒蠟火，飛燼汙鉛華。", "十騎簇芙蓉，宮衣小隊紅。練香熏宋鵲，尋箭踏盧龍。", "旗濕金鈴重，霜幹玉鐙空。今朝畫眉早，不待景陽鐘。"]'),
('yuding-11','潞州張大宅病酒，遇江使，寄上十四兄','李賀','唐','御定全唐诗','yuding','','[]','秋至昭關後，當知趙國寒。系書隨短羽，寫恨破長箋。',144,'御定全唐詩/json/392.json','["秋至昭關後，當知趙國寒。系書隨短羽，寫恨破長箋。", "病客眠清曉，疏桐墜綠鮮。城鴉啼粉堞，軍吹壓蘆煙。", "岸幘褰沙幌，枯塘臥折蓮。木窗銀跡畫，石磴水痕錢。", "旅酒侵愁肺，離歌繞懦弦。詩封兩條淚，露折一枝蘭。", "莎老沙雞泣，松幹瓦獸殘。覺騎燕地馬，夢載楚溪船。", "椒桂傾長席，鱸魴斫玳筵。豈能忘舊路，江島滯佳年。"]'),
('yuding-12','難忘曲','李賀','唐','御定全唐诗','yuding','','[]','夾道開洞門，弱楊低畫戟。簾影竹華起，簫聲吹日色。',48,'御定全唐詩/json/392.json','["夾道開洞門，弱楊低畫戟。簾影竹華起，簫聲吹日色。", "蜂語繞妝鏡，拂蛾學春碧。亂系丁香梢，滿欄花向夕。"]'),
('yuding-13','賈公閭貴婿曲','李賀','唐','御定全唐诗','yuding','','[]','朝衣不須長，分花對袍縫。嚶嚶白馬來，滿腦黃金重。',72,'御定全唐詩/json/392.json','["朝衣不須長，分花對袍縫。嚶嚶白馬來，滿腦黃金重。", "今朝香氣苦，珊瑚澀難枕。且要弄風人，暖蒲沙上飲。", "燕語踏簾鉤，日虹屏中碧。潘令在河陽，無人死芳色。"]'),
('yuding-14','夜飲朝眠曲','李賀','唐','御定全唐诗','yuding','','[]','觴酣出座東方高，腰橫半解星勞勞。柳苑鴉啼公主醉，',40,'御定全唐詩/json/392.json','["觴酣出座東方高，腰橫半解星勞勞。柳苑鴉啼公主醉，", "夜飲朝眠斷無事，楚羅之幃臥皇子。"]'),
('yuding-15','王浚墓下作','李賀','唐','御定全唐诗','yuding','','[]','人間無阿童，猶唱水中龍。白草侵煙死，秋梨繞地紅。',72,'御定全唐詩/json/392.json','["人間無阿童，猶唱水中龍。白草侵煙死，秋梨繞地紅。", "古書平黑石，袖劍斷青銅。耕勢魚鱗起，墳科馬鬣封。", "菊花垂濕露，棘徑臥幹蓬。松柏愁香澀，南原幾夜風。"]'),
('yuding-16','客游','李賀','唐','御定全唐诗','yuding','','[]','悲滿千里心，日暖南山石。不謁承明廬，老作平原客。',48,'御定全唐詩/json/392.json','["悲滿千里心，日暖南山石。不謁承明廬，老作平原客。", "四時別家廟，三年去鄉國。旅歌屢彈鋏，歸問時裂帛。"]'),
('yuding-17','崇義裏滯雨','李賀','唐','御定全唐诗','yuding','','[]','落莫誰家子，來感長安秋。壯年抱羈恨，夢泣生白頭。',72,'御定全唐詩/json/392.json','["落莫誰家子，來感長安秋。壯年抱羈恨，夢泣生白頭。", "瘦馬秣敗草，雨沫飄寒溝。南宮古簾暗，濕景傳簽籌。", "家山遠千里，雲腳天東頭。憂眠枕劍匣，客帳夢封侯。"]'),
('yuding-18','馮小憐','李賀','唐','御定全唐诗','yuding','','[]','灣頭見小憐，請上琵琶弦。破得春風恨，今朝直幾錢。',48,'御定全唐詩/json/392.json','["灣頭見小憐，請上琵琶弦。破得春風恨，今朝直幾錢。", "裙垂竹葉帶，鬢濕杏花煙。玉冷紅絲重，齊宮妾駕鞭。"]'),
('yuding-19','贈陳商','李賀','唐','御定全唐诗','yuding','','[]','長安有男兒，二十心已朽。楞伽堆案前，楚辭系肘後。',204,'御定全唐詩/json/392.json','["長安有男兒，二十心已朽。楞伽堆案前，楚辭系肘後。", "人生有窮拙，日暮聊飲酒。只今道已塞，何必須白首。", "淒淒陳述聖，披褐鉏俎豆。學為堯舜文，時人責衰偶。", "柴門車轍凍，日下榆影瘦。黃昏訪我來，苦節青陽皺。", "太華五千仞，劈地抽森秀。旁古無寸尋，一上戛牛鬥。", "公卿縱不憐，寧能鎖吾口。李生師太華，大坐看白晝。", "逢霜作樸樕，得氣為春柳。禮節乃相去，憔悴如芻狗。", "風雪直齋壇，墨組貫銅綬。臣妾氣態間，唯欲承箕帚。", "天眼何時開，古劍庸一吼。"]'),
('yuding-20','釣魚詩','李賀','唐','御定全唐诗','yuding','','[]','秋水釣紅渠，仙人待素書。菱絲縈獨繭，蒲米蟄雙魚。',72,'御定全唐詩/json/392.json','["秋水釣紅渠，仙人待素書。菱絲縈獨繭，蒲米蟄雙魚。", "斜竹垂清沼，長綸貫碧虛。餌懸春蜥蜴，鉤墜小蟾蜍。", "詹子情無限，龍陽恨有餘。為看煙浦上，楚女淚沾裾。"]'),
('yuding-21','奉和二兄罷使遣馬歸延州','李賀','唐','御定全唐诗','yuding','','[]','空留三尺劍，不用一丸泥。馬向沙場去，人歸故國來。',72,'御定全唐詩/json/392.json','["空留三尺劍，不用一丸泥。馬向沙場去，人歸故國來。", "笛愁翻隴水，酒喜瀝春灰。錦帶休驚雁，羅衣尚鬥雞。", "還吳已渺渺，入郢莫淒淒。自是桃李樹，何畏不成蹊。"]'),
('yuding-22','答贈','李賀','唐','御定全唐诗','yuding','','[]','本是張公子，曾名萼綠華。沉香熏小像，楊柳伴啼鴉。',48,'御定全唐詩/json/392.json','["本是張公子，曾名萼綠華。沉香熏小像，楊柳伴啼鴉。", "露重金泥冷，杯闌玉樹斜。琴堂沽酒客，新買後園花。"]'),
('yuding-23','題趙生壁','李賀','唐','御定全唐诗','yuding','','[]','大婦然竹根，中婦舂玉屑。冬暖拾松枝，日煙坐蒙滅。',48,'御定全唐詩/json/392.json','["大婦然竹根，中婦舂玉屑。冬暖拾松枝，日煙坐蒙滅。", "木蘚青桐老，石井水聲發。曝背臥東亭，桃花滿肌骨。"]'),
('yuding-24','感春','李賀','唐','御定全唐诗','yuding','','[]','日暖自蕭條，花悲北郭騷。榆穿萊子眼，柳斷舞兒腰。',48,'御定全唐詩/json/392.json','["日暖自蕭條，花悲北郭騷。榆穿萊子眼，柳斷舞兒腰。", "上幕迎神燕，飛絲送百勞。胡琴今日恨，急語向檀槽。"]'),
('yuding-25','仙人','李賀','唐','御定全唐诗','yuding','','[]','彈琴石壁上，翻翻一仙人。手持白鸞尾，夜掃南山雲。',48,'御定全唐詩/json/392.json','["彈琴石壁上，翻翻一仙人。手持白鸞尾，夜掃南山雲。", "鹿飲寒澗下，魚歸清海濱。當時漢武帝，書報桃花春。"]'),
('yuding-26','河陽歌','李賀','唐','御定全唐诗','yuding','','[]','染羅衣，秋藍難著色。不是無心人，為作台邛客。',94,'御定全唐詩/json/392.json','["染羅衣，秋藍難著色。不是無心人，為作台邛客。", "花燒中潬城，顏郎身已老。惜許兩少年，抽心似春草。", "今日見銀牌，今夜鳴玉晏。牛頭高一尺，隔坐應相見。", "月從東方來，酒從東方轉。觥船飫口紅，蜜炬千枝爛。"]'),
('yuding-27','花游曲','李賀','唐','御定全唐诗','yuding','','[]','春柳南陌態，冷花寒露姿。今朝醉城外，拂鏡濃掃眉。',48,'御定全唐詩/json/392.json','["春柳南陌態，冷花寒露姿。今朝醉城外，拂鏡濃掃眉。", "煙濕愁車重，紅油覆畫衣。舞裙香不暖，酒色上來遲。"]'),
('yuding-28','春晝','李賀','唐','御定全唐诗','yuding','','[]','朱城報春更漏轉，光風催蘭吹小殿。草細堪梳，柳長如線。',61,'御定全唐詩/json/392.json','["朱城報春更漏轉，光風催蘭吹小殿。草細堪梳，柳長如線。", "卷衣秦帝，掃粉趙燕。日含畫幕，蜂上羅薦。平陽花塢，", "江南有情，塞北無恨。"]'),
('yuding-29','安樂宮','李賀','唐','御定全唐诗','yuding','','[]','深井桐烏起，尚複牽情水。未盥邵陵瓜，瓶中弄長翠。',60,'御定全唐詩/json/392.json','["深井桐烏起，尚複牽情水。未盥邵陵瓜，瓶中弄長翠。", "新成安樂宮，宮如鳳凰翅。歌回蠟板鳴，左悺提壺使。", "綠蘩悲水曲，茱萸別秋子。"]'),
('yuding-30','蝴蝶飛','李賀','唐','御定全唐诗','yuding','','[]','楊花撲帳春雲熱，龜甲屏風醉眼纈。',32,'御定全唐詩/json/392.json','["楊花撲帳春雲熱，龜甲屏風醉眼纈。", "東家蝴蝶西家飛，白騎少年今日歸。"]'),
('yuding-31','梁公子','李賀','唐','御定全唐诗','yuding','','[]','風彩出蕭家，本是菖蒲花。南塘蓮子熟，洗馬走江沙。',48,'御定全唐詩/json/392.json','["風彩出蕭家，本是菖蒲花。南塘蓮子熟，洗馬走江沙。", "禦箋銀沫冷，長簟鳳窠斜。種柳營中暗，題書賜館娃。"]'),
('yuding-32','牡丹種曲','李賀','唐','御定全唐诗','yuding','','[]','蓮枝未長秦蘅老，走馬馱金劚春草。水灌香泥卻月盆，',48,'御定全唐詩/json/392.json','["蓮枝未長秦蘅老，走馬馱金劚春草。水灌香泥卻月盆，", "梁王老去羅衣在，拂袖風吹蜀國弦。歸霞帔拖蜀帳昏，"]'),
('yuding-33','後園鑿井歌','李賀','唐','御定全唐诗','yuding','','[]','井上轆轤床上轉。水聲繁，弦聲淺。情若何，荀奉倩。',46,'御定全唐詩/json/392.json','["井上轆轤床上轉。水聲繁，弦聲淺。情若何，荀奉倩。", "城頭日，長向城頭住。一日作千年，不須流下去。"]'),
('yuding-34','開愁歌','李賀','唐','御定全唐诗','yuding','','[]','秋風吹地百草幹，華容碧影生晚寒。我當二十不得意，',48,'御定全唐詩/json/392.json','["秋風吹地百草幹，華容碧影生晚寒。我當二十不得意，", "旗亭下馬解秋衣，請貰宜陽一壺酒。壺中喚天雲不開，"]'),
('yuding-35','秦宮詩','李賀','唐','御定全唐诗','yuding','','[]','越羅衫袂迎春風，玉刻麒麟腰帶紅。樓頭曲宴仙人語，',88,'御定全唐詩/json/392.json','["越羅衫袂迎春風，玉刻麒麟腰帶紅。樓頭曲宴仙人語，", "飛窗複道傳籌飲，十夜銅盤膩燭黃。禿衿小袖調鸚鵡，", "桐英永巷騎新馬，內屋深屏生色畫。開門爛用水衡錢，", "鸞篦奪得不還人，醉睡氍毹滿堂月。"]'),
('yuding-36','古鄴城童子謠，效王粲刺曹操','李賀','唐','御定全唐诗','yuding','','[]','鄴城中，暮塵起。將黑丸，斫文吏。棘為鞭，虎為馬。',64,'御定全唐詩/json/392.json','["鄴城中，暮塵起。將黑丸，斫文吏。棘為鞭，虎為馬。", "團團走，鄴城下。切玉劍，射日弓。獻何人，奉相公。", "扶轂來，關右兒。香掃塗，相公歸。"]'),
('yuding-37','楊生青花紫石硯歌','李賀','唐','御定全唐诗','yuding','','[]','端州石工巧如神，踏天磨刀割紫雲。傭刓抱水含滿唇，',48,'御定全唐詩/json/392.json','["端州石工巧如神，踏天磨刀割紫雲。傭刓抱水含滿唇，", "幹膩薄重立腳勻，數寸光秋無日昏。圓毫促點聲靜新，"]'),
('yuding-38','房中思','李賀','唐','御定全唐诗','yuding','','[]','新桂如蛾眉，秋風吹小綠。行輪出門去，玉鑾聲斷續。',48,'御定全唐詩/json/392.json','["新桂如蛾眉，秋風吹小綠。行輪出門去，玉鑾聲斷續。", "月軒下風露，曉庭自幽澀。誰能事貞素，臥聽莎雞泣。"]'),
('yuding-39','石城曉','李賀','唐','御定全唐诗','yuding','','[]','月落大堤上，女垣棲烏起。細露濕團紅，寒香解夜醉。',72,'御定全唐詩/json/392.json','["月落大堤上，女垣棲烏起。細露濕團紅，寒香解夜醉。", "女牛渡天河，柳煙滿城曲。上客留斷纓，殘蛾鬥雙綠。", "春帳依微蟬翼羅，橫茵突金隱體花。帳前輕絮鶴毛起，"]'),
('yuding-40','苦晝短','李賀','唐','御定全唐诗','yuding','','[]','飛光飛光，勸爾一杯酒。吾不識青天高，黃地厚，',108,'御定全唐詩/json/392.json','["飛光飛光，勸爾一杯酒。吾不識青天高，黃地厚，", "神君何在，太一安有。天東有若木，下置銜燭龍。", "吾將斬龍足，嚼龍肉。使之朝不得回，夜不得伏。", "自然老者不死，少者不哭。何為服黃金，吞白玉。", "誰似任公子，雲中騎碧驢。劉徹茂陵多滯骨，"]'),
('yuding-41','章和二年中','李賀','唐','御定全唐诗','yuding','','[]','雲蕭索，田風拂拂，麥芒如篲黍如粟。關中父老百領襦，',49,'御定全唐詩/json/392.json','["雲蕭索，田風拂拂，麥芒如篲黍如粟。關中父老百領襦，", "殷勤為我下田租，百錢攜償絲桐客。遊春漫光塢花白，"]'),
('yuding-42','春歸昌谷','李賀','唐','御定全唐诗','yuding','','[]','束發方讀書，謀身苦不早。終軍未乘傳，顏子鬢先老。',312,'御定全唐詩/json/392.json','["束發方讀書，謀身苦不早。終軍未乘傳，顏子鬢先老。", "天網信崇大，矯士常慅慅。逸目駢甘華，羈心如荼蓼。", "旱雲二三月，岑岫相顛倒。誰揭赬玉盤，東方發紅照。", "春熱張鶴蓋，兔目官槐小。思焦面如病，嘗膽腸似絞。", "京國心爛漫，夜夢歸家少。發軔東門外，天地皆浩浩。", "青樹驪山頭，花風滿秦道。宮台光錯落，裝盡偏峰嶠。", "細綠及團紅，當路雜啼笑。香風下高廣，鞍馬正華耀。", "獨乘雞棲車，自覺少風調。心曲語形影，隻身焉足樂。", "豈能脫負簷，刻鶴曾無兆。幽幽太華側，老柏如建纛。", "龍皮相排戛，翠羽更蕩掉。驅趨委憔悴，眺覽強容貌。", "花蔓閡行輈，縠煙暝深徼。少健無所就，入門愧家老。", "聽講依大樹，觀書臨曲沼。知非出柙虎，甘作藏霧豹。", "韓鳥處矰繳，湘鯈在籠罩。狹行無廓落，壯士徒輕躁。"]'),
('yuding-43','昌穀詩','李賀','唐','御定全唐诗','yuding','','[]','昌穀五月稻，細青滿平水。遙巒相壓疊，頹綠愁墮地。',576,'御定全唐詩/json/392.json','["昌穀五月稻，細青滿平水。遙巒相壓疊，頹綠愁墮地。", "光潔無秋思，涼曠吹浮媚。竹香滿淒寂，粉節塗生翠。", "草發垂恨鬢，光露泣幽淚。層圍爛洞曲，芳徑老紅醉。", "攢蟲鎪古柳，蟬子鳴高邃。大帶委黃葛，紫蒲交狹涘。", "石錢差複藉，厚葉皆蟠膩。汰沙好平白，立馬印青字。", "晚鱗自遨遊，瘦鵠暝單跱。嘹嘹濕蛄聲，咽源驚濺起。", "紆緩玉真路，神娥蕙花裏。苔絮縈澗礫，山實垂赬紫。", "小柏儼重扇，肥松突丹髓。鳴流走響韻，壟秋拖光穟。", "鶯唱閔女歌，瀑懸楚練帔。風露滿笑眼，駢岩雜舒墜。", "亂條迸石嶺，細頸喧島毖。日腳掃昏翳，新雲啟華閟。", "謐謐厭夏光，商風道清氣。高眠服玉容，燒桂祀天幾。", "霧衣夜披拂，眠壇夢真粹。待駕棲鸞老，故宮椒壁圮。", "鴻瓏數鈴響，羈臣發涼思。陰藤束朱鍵，龍帳著魈魅。", "碧錦帖花檉，香衾事殘貴。歌塵蠹木在，舞彩長雲似。", "珍壤割繡段，裏俗祖風義。鄰凶不相杵，疫病無邪祀。", "鮐皮識仁惠，丱角知靦恥。縣省司刑官，戶乏詬租吏。", "竹藪添墮簡，石磯引鉤餌。溪灣轉水帶，芭蕉傾蜀紙。", "岑光晃縠襟，孤景拂繁事。泉尊陶宰酒，月眉謝郎妓。", "丁丁幽鐘遠，矯矯單飛至。霞巘殷嵯峨，危溜聽爭次。", "淡蛾流平碧，薄月眇陰悴。涼光入澗岸，廓盡山中意。", "漁童下宵網，霜禽竦煙翅。潭鏡滑蛟涎，浮珠噞魚戲。", "風桐瑤匣瑟，螢星錦城使。柳綴長縹帶，篁掉短笛吹。", "石根緣綠蘚，蘆筍抽丹漬。漂旋弄天影，古檜拏雲臂。", "愁月薇帳紅，罥雲香蔓刺。芒麥平百井，閑乘列千肆。"]'),
('yuding-44','銅駝悲','李賀','唐','御定全唐诗','yuding','','[]','落魄三月罷，尋花去東家。誰作送春曲，洛岸悲銅駝。',72,'御定全唐詩/json/392.json','["落魄三月罷，尋花去東家。誰作送春曲，洛岸悲銅駝。", "橋南多馬客，北山饒古人。客飲杯中酒，駝悲千萬春。", "生世莫徒勞，風吹盤上燭。厭見桃株笑，銅駝夜來哭。"]'),
('yuding-45','自昌穀到洛後門','李賀','唐','御定全唐诗','yuding','','[]','九月大野白，蒼岑竦秋門。寒涼十月末，露霰蒙曉昏。',156,'御定全唐詩/json/392.json','["九月大野白，蒼岑竦秋門。寒涼十月末，露霰蒙曉昏。", "澹色結晝天，心事填空雲。道上千里風，野竹蛇涎痕。", "石澗涷波聲，雞叫清寒晨。強行到東舍，解馬投舊鄰。", "東家名廖者，鄉曲傳姓辛。杖頭非飲酒，吾請造其人。", "始欲南去楚，又將西適秦。襄王與武帝，各自留青春。", "聞道蘭臺上，宋玉無歸魂。緗縹兩行字，蟄蟲蠹秋芸。", "為探秦台意，豈命餘負薪。"]'),
('yuding-46','七月一日曉入太行山','李賀','唐','御定全唐诗','yuding','','[]','一夕繞山秋，香露溘蒙菉。新橋倚雲阪，候蟲嘶露樸。',48,'御定全唐詩/json/392.json','["一夕繞山秋，香露溘蒙菉。新橋倚雲阪，候蟲嘶露樸。", "洛南今已遠，越衾誰為熟。石氣何淒淒，老莎如短鏃。"]'),
('yuding-47','秋涼詩，寄正字十二兄','李賀','唐','御定全唐诗','yuding','','[]','閉門感秋風，幽姿任契闊。大野生素空，天地曠肅殺。',120,'御定全唐詩/json/392.json','["閉門感秋風，幽姿任契闊。大野生素空，天地曠肅殺。", "露光泣殘蕙，蟲響連夜發。房寒寸輝薄，迎風絳紗折。", "披書古芸馥，恨唱華容歇。百日不相知，花光變涼節。", "弟兄誰念慮，箋翰既通達。青袍度白馬，草簡奏東闕。", "夢中相聚笑，覺見半床月。長思劇尋環，亂憂抵覃葛。"]'),
('yuding-0','艾如張','李賀','唐','御定全唐诗','yuding','','[]','錦襜褕，繡襠襦。強飲啄，哺爾雛。隴東臥穟滿風雨，',48,'御定全唐詩/json/393.json','["錦襜褕，繡襠襦。強飲啄，哺爾雛。隴東臥穟滿風雨，", "網絲漠漠無形影，誤爾觸之傷首紅。艾葉綠花誰剪刻，"]'),
('yuding-1','上雲樂','李賀','唐','御定全唐诗','yuding','','[]','飛香走紅滿天春，花龍盤盤上紫雲。三千宮女列金屋，',40,'御定全唐詩/json/393.json','["飛香走紅滿天春，花龍盤盤上紫雲。三千宮女列金屋，", "斷煙素，縫衣縷，八月一日君前舞。"]'),
('yuding-2','摩多樓子','李賀','唐','御定全唐诗','yuding','','[]','玉塞去金人，二萬四千里。風吹沙作雲，一時渡遼水。',72,'御定全唐詩/json/393.json','["玉塞去金人，二萬四千里。風吹沙作雲，一時渡遼水。", "天白水如練，甲絲雙串斷。行行莫苦辛，城月猶殘半。", "曉氣朔煙上，趢趗胡馬蹄。行人臨水別，隔隴長東西。"]'),
('yuding-3','猛虎行','李賀','唐','御定全唐诗','yuding','','[]','長戈莫舂，長弩莫抨。乳孫哺子，教得生獰。',80,'御定全唐詩/json/393.json','["長戈莫舂，長弩莫抨。乳孫哺子，教得生獰。", "舉頭為城，掉尾為旌。東海黃公，愁見夜行。", "道逢騶虞，牛哀不平。何用尺刀，壁上雷鳴。", "泰山之下，婦人哭聲。官家有程，吏不敢聽。"]'),
('yuding-4','日出行','李賀','唐','御定全唐诗','yuding','','[]','白日下昆侖，發光如舒絲。徒照葵藿心，不照遊子悲。',67,'御定全唐詩/json/393.json','["白日下昆侖，發光如舒絲。徒照葵藿心，不照遊子悲。", "折折黃河曲，日從中央轉。暘谷耳曾聞，若木眼不見。", "奈爾鑠石，胡為銷人。羿彎弓屬矢那不中，"]'),
('yuding-5','苦篁調嘯引','李賀','唐','御定全唐诗','yuding','','[]','請說軒轅在時事，伶倫采竹二十四。伶倫采之自昆丘，',64,'御定全唐詩/json/393.json','["請說軒轅在時事，伶倫采竹二十四。伶倫采之自昆丘，", "當時黃帝上天時，二十三管咸相隨，唯留一管人間吹。", "無德不能得此管，此管沉埋虞舜祠。"]'),
('yuding-6','拂舞歌辭','李賀','唐','御定全唐诗','yuding','','[]','吳娥聲絕天，空雲閑裴回。門外滿車馬，亦須生綠苔。',68,'御定全唐詩/json/393.json','["吳娥聲絕天，空雲閑裴回。門外滿車馬，亦須生綠苔。", "尊有烏程酒，勸君千萬壽。全勝漢武錦樓上，", "丹成作蛇乘白霧，千年重化玉井土。從蛇作土一千載，"]'),
('yuding-7','夜坐吟','李賀','唐','御定全唐诗','yuding','','[]','踏踏馬蹄誰見過，眼看北斗直天河。西風羅幕生翠波，',48,'御定全唐詩/json/393.json','["踏踏馬蹄誰見過，眼看北斗直天河。西風羅幕生翠波，", "明星爛爛東方陲，紅霞梢出東南涯，陸郎去矣乘班騅。"]'),
('yuding-8','箜篌引','李賀','唐','御定全唐诗','yuding','','[]','公乎公乎，提壺將焉如。屈平沉湘不足慕，',55,'御定全唐詩/json/393.json','["公乎公乎，提壺將焉如。屈平沉湘不足慕，", "北裏有賢兄，東鄰有小姑。隴畝油油黍與葫，", "被發奔流竟何如，賢兄小姑哭嗚嗚。"]'),
('yuding-9','巫山高','李賀','唐','御定全唐诗','yuding','','[]','碧叢叢，高插天，大江翻瀾神曳煙。楚魂尋夢風颸然，',40,'御定全唐詩/json/393.json','["碧叢叢，高插天，大江翻瀾神曳煙。楚魂尋夢風颸然，", "古祠近月蟾桂寒，椒花墜紅濕雲間。"]'),
('yuding-10','平城下','李賀','唐','御定全唐诗','yuding','','[]','饑寒平城下，夜夜守明月。別劍無玉花，海風斷鬢髮。',96,'御定全唐詩/json/393.json','["饑寒平城下，夜夜守明月。別劍無玉花，海風斷鬢髮。", "塞長連白空，遙見漢旗紅。青帳吹短笛，煙霧濕晝龍。", "日晚在城上，依稀望城下。風吹枯蓬起，城中嘶瘦馬。", "借問築城吏，去關幾千里。惟愁裹屍歸，不惜倒戈死。"]'),
('yuding-11','江南弄','李賀','唐','御定全唐诗','yuding','','[]','江中綠霧起涼波，天上疊巘紅嵯峨。水風浦雲生老竹，',40,'御定全唐詩/json/393.json','["江中綠霧起涼波，天上疊巘紅嵯峨。水風浦雲生老竹，", "吳歈越吟未終曲，江上團團帖寒玉。"]'),
('yuding-12','榮華樂','李賀','唐','御定全唐诗','yuding','','[]','鳶肩公子二十餘，齒編貝，唇激朱。氣如虹霓，飲如建瓴，',170,'御定全唐詩/json/393.json','["鳶肩公子二十餘，齒編貝，唇激朱。氣如虹霓，飲如建瓴，", "玉堂調笑金樓子，台下戲學邯鄲倡。口吟舌話稱女郎，", "將回日月先反掌，欲作江河唯畫地。峨峨虎冠上切雲，", "十二門前張大宅，晴春煙起連天碧。金鋪綴日雜紅光，", "丹穴取鳳充行庖，玃玃如拳那足食。金蟾呀呀蘭燭香，", "嘈嘈弦吹匝天開，洪崖簫聲繞天來。天長一矢貫雙虎，", "能教刻石平紫金，解送刻毛寄新兔。三皇皇后七貴人，"]'),
('yuding-13','相勸酒','李賀','唐','御定全唐诗','yuding','','[]','羲和騁六轡，晝夕不曾閑。彈烏崦嵫竹，抶馬蟠桃鞭。',128,'御定全唐詩/json/393.json','["羲和騁六轡，晝夕不曾閑。彈烏崦嵫竹，抶馬蟠桃鞭。", "蓐收既斷翠柳，青帝又造紅蘭。堯舜至今萬萬歲，", "臛蠵臑熊何足雲。會須鐘飲北海，箕踞南山。", "歌淫淫，管愔愔，橫波好送雕題金。人生得意且如此，", "伏願陛下鴻名終不歇，子孫綿如石上葛。", "來長安，車駢駢。中有梁冀舊宅，石崇故園。"]'),
('yuding-14','瑤華樂','李賀','唐','御定全唐诗','yuding','','[]','穆天子，走龍媒。八轡冬瓏逐天回，五精掃地凝雲開。',97,'御定全唐詩/json/393.json','["穆天子，走龍媒。八轡冬瓏逐天回，五精掃地凝雲開。", "高門左右日月環，四方錯鏤棱層殷。舞霞垂尾長盤珊，", "列旆如松，張蓋如輪。金風殿秋，清明發春。八鑾十乘，", "熏梅染柳將贈君。鉛華之水洗君骨，與君相對作真質。"]'),
('yuding-15','北中寒','李賀','唐','御定全唐诗','yuding','','[]','一方黑照三方紫，黃河冰合魚龍死。三尺木皮斷文理，',40,'御定全唐詩/json/393.json','["一方黑照三方紫，黃河冰合魚龍死。三尺木皮斷文理，", "爭瀯海水飛淩喧，山瀑無聲玉虹懸。"]'),
('yuding-16','梁台古愁','李賀','唐','御定全唐诗','yuding','','[]','梁王台沼空中立，天河之水夜飛入。台前鬥玉作蛟龍，',48,'御定全唐詩/json/393.json','["梁王台沼空中立，天河之水夜飛入。台前鬥玉作蛟龍，", "朝朝暮暮愁海翻，長繩系日樂當年。芙蓉凝紅得秋色，"]'),
('yuding-17','公無出門','李賀','唐','御定全唐诗','yuding','','[]','天迷迷，地密密。熊虺食人魂，雪霜斷人骨。',68,'御定全唐詩/json/393.json','["天迷迷，地密密。熊虺食人魂，雪霜斷人骨。", "嗾犬狺狺相索索，舐掌偏宜佩蘭客。帝遣乘軒災自息，", "毒虯相視振金環，狻猊猰貐吐饞涎。鮑焦一世披草眠，"]'),
('yuding-18','神弦別曲','李賀','唐','御定全唐诗','yuding','','[]','巫山小女隔雲別，春風松花山上發。綠蓋獨穿香徑歸，',40,'御定全唐詩/json/393.json','["巫山小女隔雲別，春風松花山上發。綠蓋獨穿香徑歸，", "南山桂樹為君死，雲衫淺汙紅脂花。"]'),
('yuding-19','綠水詞','李賀','唐','御定全唐诗','yuding','','[]','今宵好風月，阿侯在何處。為有傾人色，翻成足愁苦。',48,'御定全唐詩/json/393.json','["今宵好風月，阿侯在何處。為有傾人色，翻成足愁苦。", "東湖採蓮葉，南湖拔蒲根。未持寄小姑，且持感愁魂。"]'),
('yuding-20','沙路曲','李賀','唐','御定全唐诗','yuding','','[]','柳臉半眠丞相樹，佩馬釘鈴踏沙路。斷燼遺香嫋翠煙，',48,'御定全唐詩/json/393.json','["柳臉半眠丞相樹，佩馬釘鈴踏沙路。斷燼遺香嫋翠煙，", "獨垂重印押千官，金窠篆字紅屈盤。沙路歸來聞好語，"]'),
('yuding-21','上之回','李賀','唐','御定全唐诗','yuding','','[]','上之回，大旗喜。懸紅雲，撻鳳尾。劍匣破，舞蛟龍。',48,'御定全唐詩/json/393.json','["上之回，大旗喜。懸紅雲，撻鳳尾。劍匣破，舞蛟龍。", "蚩尤死，鼓逢逢。天高慶雷齊墜地，地無驚煙海千里。"]'),
('yuding-22','高軒過','李賀','唐','御定全唐诗','yuding','','[]','華裾織翠青如蔥，金環壓轡搖玲瓏。馬蹄隱耳聲隆隆，',64,'御定全唐詩/json/393.json','["華裾織翠青如蔥，金環壓轡搖玲瓏。馬蹄隱耳聲隆隆，", "二十八宿羅心胸，九精照耀貫當中。殿前作賦聲摩空，", "我今垂翅附冥鴻，他日不羞蛇作龍。"]'),
('yuding-23','貝宮夫人','李賀','唐','御定全唐诗','yuding','','[]','丁丁海女弄金環，雀釵翹揭雙翅關。六宮不語一生閑，',40,'御定全唐詩/json/393.json','["丁丁海女弄金環，雀釵翹揭雙翅關。六宮不語一生閑，", "秋肌稍覺玉衣寒，空光帖妥水如天。"]'),
('yuding-24','蘭香神女廟','李賀','唐','御定全唐诗','yuding','','[]','古春年年在，閑綠搖暖雲。松香飛晚華，柳渚含日昏。',180,'御定全唐詩/json/393.json','["古春年年在，閑綠搖暖雲。松香飛晚華，柳渚含日昏。", "沙砌落紅滿，石泉生水芹。幽篁畫新粉，蛾綠橫曉門。", "弱蕙不勝露，山秀愁空春。舞佩剪鸞翼，帳帶塗輕銀。", "蘭桂吹濃香，菱藕長莘莘。看雨逢瑤姬，乘船值江君。", "吹簫飲酒醉，結綬金絲裙。走天呵白鹿，游水鞭錦鱗。", "密發虛鬟飛，膩頰凝花勻。團鬢分蛛巢，穠眉籠小唇。", "弄蝶和輕妍，風光怯腰身。深幃金鴨冷，奩鏡幽鳳塵。", "踏霧乘同歸，撼玉山上聞。"]'),
('yuding-25','送韋仁實兄弟入關','李賀','唐','御定全唐诗','yuding','','[]','送客飲別酒，千觴無赭顏。何物最傷心，馬首鳴金鐶。',108,'御定全唐詩/json/393.json','["送客飲別酒，千觴無赭顏。何物最傷心，馬首鳴金鐶。", "野色浩無主，秋明空曠間。坐來壯膽破，斷目不能看。", "行槐引西道，青梢長攢攢。韋郎好兄弟，疊玉生文翰。", "我在山上舍，一畝蒿磽田。夜雨叫租吏，春聲暗交關。", "誰解念勞勞，蒼突唯南山。"]'),
('yuding-26','洛陽城外別皇甫湜','李賀','唐','御定全唐诗','yuding','','[]','洛陽吹別風，龍門起斷煙。冬樹束生澀，晚紫凝華天。',48,'御定全唐詩/json/393.json','["洛陽吹別風，龍門起斷煙。冬樹束生澀，晚紫凝華天。", "單身野霜上，疲馬飛蓬間。憑軒一雙淚，奉墜綠衣前。"]'),
('yuding-27','溪晚涼','李賀','唐','御定全唐诗','yuding','','[]','白狐向月號山風，秋寒掃雲留碧空。玉煙青濕白如幢，',40,'御定全唐詩/json/393.json','["白狐向月號山風，秋寒掃雲留碧空。玉煙青濕白如幢，", "層岫回岑複疊龍，苦篁對客吟歌筒。"]'),
('yuding-28','官不來，題皇甫湜先輩廳','李賀','唐','御定全唐诗','yuding','','[]','官不來，官庭秋，老桐錯幹青龍愁。書司曹佐走如牛，',24,'御定全唐詩/json/393.json','["官不來，官庭秋，老桐錯幹青龍愁。書司曹佐走如牛，"]'),
('yuding-29','長平箭頭歌','李賀','唐','御定全唐诗','yuding','','[]','漆灰骨末丹水沙，淒淒古血生銅花。白翎金簳雨中盡，',72,'御定全唐詩/json/393.json','["漆灰骨末丹水沙，淒淒古血生銅花。白翎金簳雨中盡，", "風長日短星蕭蕭，黑旗雲濕懸空夜。左魂右魄啼肌瘦，", "訪古汍瀾收斷鏃，折鋒赤璺曾刲肉。南陌東城馬上兒，"]'),
('yuding-30','江樓曲','李賀','唐','御定全唐诗','yuding','','[]','樓前流水江陵道，鯉魚風起芙蓉老。曉釵催鬢語南風，',48,'御定全唐詩/json/393.json','["樓前流水江陵道，鯉魚風起芙蓉老。曉釵催鬢語南風，", "蕭騷浪白雲差池，黃粉油衫寄郎主。新槽酒聲苦無力，"]'),
('yuding-31','塞下曲','李賀','唐','御定全唐诗','yuding','','[]','胡角引北風，薊門白于水。天含青海道，城頭月千里。',72,'御定全唐詩/json/393.json','["胡角引北風，薊門白于水。天含青海道，城頭月千里。", "露下旗濛濛，寒金鳴夜刻。蕃甲鎖蛇鱗，馬嘶青塚白。", "秋靜見旄頭，沙遠席羈愁。帳北天應盡，河聲出塞流。"]'),
('yuding-32','染絲上春機','李賀','唐','御定全唐诗','yuding','','[]','玉罌泣水桐花井，蒨絲沉水如雲影。美人懶態燕脂愁，',24,'御定全唐詩/json/393.json','["玉罌泣水桐花井，蒨絲沉水如雲影。美人懶態燕脂愁，"]'),
('yuding-33','五粒小松歌','李賀','唐','御定全唐诗','yuding','','[]','蛇子蛇孫鱗蜿蜿，新香幾粒洪崖飯。綠波浸葉滿濃光，',40,'御定全唐詩/json/393.json','["蛇子蛇孫鱗蜿蜿，新香幾粒洪崖飯。綠波浸葉滿濃光，", "月明白露秋淚滴，石筍溪雲肯寄書。"]'),
('yuding-34','塘上行','李賀','唐','御定全唐诗','yuding','','[]','藕花涼露濕，花缺藕根澀。飛下雌鴛鴦，塘水聲溘溘。',24,'御定全唐詩/json/393.json','["藕花涼露濕，花缺藕根澀。飛下雌鴛鴦，塘水聲溘溘。"]'),
('yuding-35','呂將軍歌','李賀','唐','御定全唐诗','yuding','','[]','呂將軍，騎赤兔。獨攜大膽出秦門，金粟堆邊哭陵樹。',96,'御定全唐詩/json/393.json','["呂將軍，騎赤兔。獨攜大膽出秦門，金粟堆邊哭陵樹。", "北方逆氣汙青天，劍龍夜叫將軍閑。將軍振袖揮劍鍔，", "恒山鐵騎請金槍，遙聞箙中花箭香。西郊寒蓬葉如刺，", "圓蒼低迷蓋張地，九州人事皆如此。赤山秀鋌禦時英，"]'),
('yuding-36','休洗紅','李賀','唐','御定全唐诗','yuding','','[]','休洗紅，洗多紅色淺。卿卿騁少年，昨日殷橋見。',34,'御定全唐詩/json/393.json','["休洗紅，洗多紅色淺。卿卿騁少年，昨日殷橋見。", "封侯早歸來，莫作弦上箭。"]'),
('yuding-37','神弦曲','李賀','唐','御定全唐诗','yuding','','[]','西山日沒東山昏，旋風吹馬馬踏雲。畫弦素管聲淺繁，',48,'御定全唐詩/json/393.json','["西山日沒東山昏，旋風吹馬馬踏雲。畫弦素管聲淺繁，", "古壁彩虯金帖尾，雨工騎入秋潭水。百年老鴞成木魅，"]'),
('yuding-38','野歌','李賀','唐','御定全唐诗','yuding','','[]','鴉翎羽箭山桑弓，仰天射落銜蘆鴻。麻衣黑肥沖北風，',40,'御定全唐詩/json/393.json','["鴉翎羽箭山桑弓，仰天射落銜蘆鴻。麻衣黑肥沖北風，", "寒風又變為春柳，條條看即煙濛濛。"]'),
('yuding-39','神弦','李賀','唐','御定全唐诗','yuding','','[]','女巫澆酒雲滿空，玉爐炭火香冬冬。海神山鬼來座中，',48,'御定全唐詩/json/393.json','["女巫澆酒雲滿空，玉爐炭火香冬冬。海神山鬼來座中，", "呼星召鬼歆杯盤，山魅食時人森寒。終南日色低平灣，"]'),
('yuding-40','將進酒','李賀','唐','御定全唐诗','yuding','','[]','琉璃鐘，琥珀濃，小槽酒滴真珠紅。烹龍炮鳳玉脂泣，',48,'御定全唐詩/json/393.json','["琉璃鐘，琥珀濃，小槽酒滴真珠紅。烹龍炮鳳玉脂泣，", "況是青春日將暮，桃花亂落如紅雨。勸君終日酩酊醉，"]'),
('yuding-41','美人梳頭歌','李賀','唐','御定全唐诗','yuding','','[]','西施曉夢綃帳寒，香鬟墮髻半沉檀。轆轤咿啞轉鳴玉，',73,'御定全唐詩/json/393.json','["西施曉夢綃帳寒，香鬟墮髻半沉檀。轆轤咿啞轉鳴玉，", "一編香絲雲撒地，玉釵落處無聲膩。纖手卻盤老鴉色，", "妝成pE鬌欹不斜，雲裾數步踏雁沙。背人不語向何處，"]'),
('yuding-42','月漉漉篇','李賀','唐','御定全唐诗','yuding','','[]','月漉漉，波煙玉。莎青桂花繁，芙蓉別江木。',68,'御定全唐詩/json/393.json','["月漉漉，波煙玉。莎青桂花繁，芙蓉別江木。", "粉態袷羅寒，雁羽鋪煙濕。誰能看石帆，乘船鏡中入。", "秋白鮮紅死，水香蓮子齊。挽菱隔歌袖，綠刺罥銀泥。"]'),
('yuding-43','京城','李賀','唐','御定全唐诗','yuding','','[]','驅馬出門意，牢落長安心。兩事誰向道，自作秋風吟。',24,'御定全唐詩/json/393.json','["驅馬出門意，牢落長安心。兩事誰向道，自作秋風吟。"]'),
('yuding-44','官街鼓','李賀','唐','御定全唐诗','yuding','','[]','曉聲隆隆催轉日，暮聲隆隆呼月出。漢城黃柳映新簾，',48,'御定全唐詩/json/393.json','["曉聲隆隆催轉日，暮聲隆隆呼月出。漢城黃柳映新簾，", "從君翠發蘆花色，獨共南山守中國。幾回天上葬神仙，"]'),
('yuding-45','許公子鄭姬歌','李賀','唐','御定全唐诗','yuding','','[]','許史世家外親貴，宮錦千端買沉醉。銅駝酒熟烘明膠，',96,'御定全唐詩/json/393.json','["許史世家外親貴，宮錦千端買沉醉。銅駝酒熟烘明膠，", "先將芍藥獻妝台，後解黃金大如鬥。莫愁簾中許合歡，", "兩馬八蹄踏蘭苑，情如合竹誰能見。夜光玉枕棲鳳凰，", "自從小靨來東道，曲裏長眉少見人。相如塚上生秋柏，"]'),
('yuding-46','新夏歌','李賀','唐','御定全唐诗','yuding','','[]','曉木千籠真蠟彩，落蕊枯香數分在。陰枝秀牙卷縹茸，',48,'御定全唐詩/json/393.json','["曉木千籠真蠟彩，落蕊枯香數分在。陰枝秀牙卷縹茸，", "刺香滿地菖蒲草，雨梁燕語悲身老。三月搖揚入河道，"]'),
('yuding-47','題歸夢','李賀','唐','御定全唐诗','yuding','','[]','長安風雨夜，書客夢昌穀。怡怡中堂笑，小弟栽澗菉。',48,'御定全唐詩/json/393.json','["長安風雨夜，書客夢昌穀。怡怡中堂笑，小弟栽澗菉。", "家門厚重意，望我飽饑腹。勞勞一寸心，燈花照魚目。"]'),
('yuding-48','經沙苑','李賀','唐','御定全唐诗','yuding','','[]','野水泛長瀾，宮牙開小蒨。無人柳自春，草渚鴛鴦暖。',48,'御定全唐詩/json/393.json','["野水泛長瀾，宮牙開小蒨。無人柳自春，草渚鴛鴦暖。", "晴嘶臥沙馬，老去悲啼展。今春還不歸，塞嚶折翅雁。"]'),
('yuding-49','出城別張又新酬李漢','李賀','唐','御定全唐诗','yuding','','[]','李子別上國，南山崆峒春。不聞今夕鼓，差慰煎情人。',301,'御定全唐詩/json/393.json','["李子別上國，南山崆峒春。不聞今夕鼓，差慰煎情人。", "趙壹賦命薄，馬卿家業貧。鄉書何所報，紫蕨生石雲。", "長安玉桂國，戟帶披侯門。慘陰地自光，寶馬踏曉昏。", "臘春戲草苑，玉挽鳴qX轔。綠網縋金鈴，霞卷清池漘。", "開貫瀉蚨母，買冰防夏蠅。時宜裂大袂，劍客車盤茵。", "小人如死灰，心切生秋榛。皇圖跨四海，百姓拖長紳。", "光明靄不發，腰龜徒甃銀。吾將噪禮樂，聲調摩清新。", "欲使十千歲，帝道如飛神。華實自蒼老，流采長傾湓。", "沒沒暗齰舌，涕血不敢論。今將下東道，祭酒而別秦。", "六郡無剿兒，長刀誰拭塵。地理陽無正，快馬逐服轅。", "二子美年少，調道講清渾。譏笑斷冬夜，家庭疏筱穿。", "曙風起四方，秋月當東懸。賦詩面投擲，悲哉不遇人。", "此別定沾臆，越布先裁巾。"]'),
('yuding-0','南園','李賀','唐','御定全唐诗','yuding','','[]','方領蕙帶折角巾，杜若已老蘭苕春。南山削秀藍玉合，',40,'御定全唐詩/json/394.json','["方領蕙帶折角巾，杜若已老蘭苕春。南山削秀藍玉合，", "鄭公鄉老開酒尊，坐泛楚奏吟招魂。"]'),
('yuding-1','假龍吟歌','李賀','唐','御定全唐诗','yuding','','[]','石軋銅杯，吟詠枯瘁。蒼鷹擺血，白鳳下肺。桂子自落，',49,'御定全唐詩/json/394.json','["石軋銅杯，吟詠枯瘁。蒼鷹擺血，白鳳下肺。桂子自落，", "窞中跳汰截清涎，隈壖臥水埋金爪。崖蹬蒼苔吊石發，"]'),
('yuding-2','感諷六首','李賀','唐','御定全唐诗','yuding','','[]','人間春蕩蕩，帳暖香揚揚。飛光染幽紅，誇嬌來洞房。',397,'御定全唐詩/json/394.json','["人間春蕩蕩，帳暖香揚揚。飛光染幽紅，誇嬌來洞房。", "舞席泥金蛇，桐竹羅花床。眼逐春瞑醉，粉隨淚色黃。", "王子下馬來，曲沼鳴鴛鴦。焉知腸車轉，一夕巡九方。", "苦風吹朔寒，沙驚秦木折。舞影逐空天，畫鼓餘清節。", "蜀書秋信斷，黑水朝波咽。嬌魂從回風，死處懸鄉月。", "雜雜胡馬塵，森森邊士戟。天教胡馬戰，曉雲皆血色。", "婦人攜漢卒，箭箙囊巾幗。不慚金印重，踉蹌腰鞬力。", "恂恂鄉門老，昨夜試鋒鏑。走馬遣書勳，誰能分粉墨。", "青門放彈去，馬色連空郊。何年帝家物，玉裝鞍上搖。", "去去走犬歸，來來坐烹羔。千金不了饌，狢肉稱盤臊。", "試問誰家子，乃老能佩刀。西山白蓋下，賢俊寒蕭蕭。", "曉菊泫寒露，似悲團扇風。秋涼經漢殿，班子泣衰紅。", "本無辭輦意，豈見入空宮。腰衱佩珠斷，灰蝶生陰松。", "蝶飛紅粉台，柳掃吹笙道。十日懸戶庭，九秋無衰草。", "調歌送風轉，杯池白魚小。水宴截香腴，菱科映青罩。", "zv蒙梨花滿，春昏弄長嘯。唯愁苦花落，不悟世衰到。", "撫舊唯銷魂，南山坐悲峭。"]'),
('yuding-3','莫愁曲','李賀','唐','御定全唐诗','yuding','','[]','草生龍坡下，鴉噪城堞頭。何人此城裏，城角栽石榴。',96,'御定全唐詩/json/394.json','["草生龍坡下，鴉噪城堞頭。何人此城裏，城角栽石榴。", "青絲系五馬，黃金絡雙牛。白魚駕蓮船，夜作十裏遊。", "歸來無人識，暗上沈香樓。羅床倚瑤瑟，殘月傾簾鉤。", "今日槿花落，明朝桐樹秋。莫負平生意，何名何莫愁。"]'),
('yuding-4','夜來樂','李賀','唐','御定全唐诗','yuding','','[]','紅羅複帳金流蘇，華燈九枝懸鯉魚。麗人映月開銅鋪，',70,'御定全唐詩/json/394.json','["紅羅複帳金流蘇，華燈九枝懸鯉魚。麗人映月開銅鋪，", "五絲封青鳧，阿侯此笑千萬餘。南軒漢轉簾影疏，", "漏長送佩承明廬，倡樓嵯峨明月孤。新客下馬故客去，"]'),
('yuding-5','嘲雪','李賀','唐','御定全唐诗','yuding','','[]','昨日發蔥嶺，今朝下蘭渚。喜從千里來，亂笑含春語。',48,'御定全唐詩/json/394.json','["昨日發蔥嶺，今朝下蘭渚。喜從千里來，亂笑含春語。", "龍沙濕漢旗，鳳扇迎秦素。久別遼城鶴，毛衣已應故。"]'),
('yuding-6','春懷引','李賀','唐','御定全唐诗','yuding','','[]','芳蹊密影成花洞，柳結濃煙花帶重。蟾蜍碾玉掛明弓，',40,'御定全唐詩/json/394.json','["芳蹊密影成花洞，柳結濃煙花帶重。蟾蜍碾玉掛明弓，", "阿侯系錦覓周郎，憑仗東風好相送。"]'),
('yuding-7','白虎行','李賀','唐','御定全唐诗','yuding','','[]','火烏日暗崩騰雲，秦皇虎視蒼生群。燒書滅國無暇日，',96,'御定全唐詩/json/394.json','["火烏日暗崩騰雲，秦皇虎視蒼生群。燒書滅國無暇日，", "燒丹未得不死藥，拏舟海上尋神仙。鯨魚張鬣海波沸，", "誰最苦兮誰最苦，報人義士深相許。漸離擊築荊卿歌，", "天授秦封祚未移，袞龍衣點荊卿血。朱旗卓地白虎死，"]'),
('yuding-8','有所思','李賀','唐','御定全唐诗','yuding','','[]','去年陌上歌離曲，今日君書遠遊蜀。簾外花開二月風，',96,'御定全唐詩/json/394.json','["去年陌上歌離曲，今日君書遠遊蜀。簾外花開二月風，", "想君白馬懸雕弓，世間何處無春風。君心未肯鎮如石，", "西風未起悲龍梭，年年織素攢雙蛾。江山迢遞無休絕，", "鴉鴉向曉鳴森木，風過池塘響叢玉。白日蕭條夢不成，"]'),
('yuding-9','啁少年','李賀','唐','御定全唐诗','yuding','','[]','青驄馬肥金鞍光，龍腦入縷羅衫香。美人狹坐飛瓊觴，',96,'御定全唐詩/json/394.json','["青驄馬肥金鞍光，龍腦入縷羅衫香。美人狹坐飛瓊觴，", "有時半醉百花前，背把金丸落飛鳥。自說生來未為客，", "長得積玉誇豪毅，每揖閒人多意氣。生來不讀半行書，", "榮枯遞傳急如箭，天公不肯於公偏。莫道韶華鎮長在，"]'),
('yuding-10','高平縣東私路','李賀','唐','御定全唐诗','yuding','','[]','侵侵槲葉香，木花滯寒雨。今夕山上秋，永謝無人處。',48,'御定全唐詩/json/394.json','["侵侵槲葉香，木花滯寒雨。今夕山上秋，永謝無人處。", "石溪遠荒澀，棠實懸辛苦。古者定幽尋，呼君作私路。"]'),
('yuding-11','神仙曲','李賀','唐','御定全唐诗','yuding','','[]','碧峰海面藏靈書，上帝揀作神仙居。清明笑語聞空虛，',48,'御定全唐詩/json/394.json','["碧峰海面藏靈書，上帝揀作神仙居。清明笑語聞空虛，", "鶴羽沖風過海遲，不如卻使青龍去。猶疑王母不相許，"]'),
('yuding-12','龍夜吟','李賀','唐','御定全唐诗','yuding','','[]','捲髮胡兒眼睛綠，高樓夜靜吹橫竹。一聲似向天上來，',64,'御定全唐詩/json/394.json','["捲髮胡兒眼睛綠，高樓夜靜吹橫竹。一聲似向天上來，", "蜀道秋深雲滿林，湘江半夜龍驚起。玉堂美人邊塞情，", "胡兒莫作隴頭吟，隔窗暗結愁人心。"]'),
('yuding-13','昆侖使者','李賀','唐','御定全唐诗','yuding','','[]','昆侖使者無消息，茂陵煙樹生愁色。金盤玉露自淋漓，',40,'御定全唐詩/json/394.json','["昆侖使者無消息，茂陵煙樹生愁色。金盤玉露自淋漓，", "何處偏傷萬國心，中天夜久高明月。"]'),
('yuding-14','漢唐姬飲酒歌','李賀','唐','御定全唐诗','yuding','','[]','禦服沾霜露，天衢長蓁棘。金隱秋塵姿，無人為帶飾。',168,'御定全唐詩/json/394.json','["禦服沾霜露，天衢長蓁棘。金隱秋塵姿，無人為帶飾。", "玉堂歌聲寢，芳林煙樹隔。雲陽臺上歌，鬼哭複何益。", "鐵劍常光光，至凶威屢逼。強梟噬母心，奔厲索人魄。", "相看兩相泣，淚下如波激。寧用清酒為，欲作黃泉客。", "不說玉山頹，且無飲中色。勉從天帝訴，天上寡沈厄。", "無處張繐帷，如何望松柏。妾身晝團團，君魂夜寂寂。", "蛾眉自覺長，頸粉誰憐白。矜持昭陽意，不肯看南陌。"]'),
('yuding-15','聽穎師琴歌','李賀','唐','御定全唐诗','yuding','','[]','別浦雲歸桂花渚，蜀國弦中雙鳳語。芙蓉葉落秋鸞離，',72,'御定全唐詩/json/394.json','["別浦雲歸桂花渚，蜀國弦中雙鳳語。芙蓉葉落秋鸞離，", "誰看挾劍赴長橋，誰看浸發題春竹。竺僧前立當吾門，", "涼館聞弦驚病客，藥囊暫別龍須席。請歌直請卿相歌，"]'),
('yuding-16','謠俗','李賀','唐','御定全唐诗','yuding','','[]','上林蝴蝶小，試伴漢家君。飛向南城去，誤落石榴裙。',48,'御定全唐詩/json/394.json','["上林蝴蝶小，試伴漢家君。飛向南城去，誤落石榴裙。", "脈脈花滿樹，翾翾燕繞雲。出門不識路，羞問陌頭人。"]'),
('yuding-17','靜女春曙曲','李賀','唐','御定全唐诗','yuding','','[]','嫩葉憐芳抱新蕊，泣露枝枝滴夭淚。粉窗香咽頹曉雲，',40,'御定全唐詩/json/394.json','["嫩葉憐芳抱新蕊，泣露枝枝滴夭淚。粉窗香咽頹曉雲，", "冰洞寒龍半匣水，一隻商鸞逐煙起。"]'),
('yuding-18','少年樂','李賀','唐','御定全唐诗','yuding','','[]','芳草落花如錦地，二十長遊醉鄉裏。紅纓不動白馬驕，',40,'御定全唐詩/json/394.json','["芳草落花如錦地，二十長遊醉鄉裏。紅纓不動白馬驕，", "陸郎倚醉牽羅袂，奪得寶釵金翡翠。"]'),
('yuding-19','句','李賀','唐','御定全唐诗','yuding','','[]','不見山巔樹，摧杌下為薪。日睹井中泥，上出作埃塵。',48,'御定全唐詩/json/394.json','["不見山巔樹，摧杌下為薪。日睹井中泥，上出作埃塵。", "情知一丘趣，不謝千里印。", "倚劍登高台，悠悠送春目。"]'),
('yuding-0','冰柱','劉叉','唐','御定全唐诗','yuding','','[]','師幹久不息，農為兵兮民重嗟。騷然縣宇，土崩水潰。',224,'御定全唐詩/json/395.json','["師幹久不息，農為兵兮民重嗟。騷然縣宇，土崩水潰。", "畹中無熟穀，壟上無桑麻。王春判序，百卉茁甲含葩。", "有客避兵奔遊僻，跋履險厄至三巴。貂裘蒙茸已敝縷，", "南畝未盈尺，纖片亂舞空紛拏。旋落旋逐朝暾化，", "始疑玉龍下界來人世，齊向茅簷布爪牙。又疑漢高帝，", "不為中山漿，清新馥鼻盈百車。不為池與沼，", "特稟朝澈氣，潔然自許靡間其邇遐。森然氣結一千里，", "勿被曲瓦，直下不能抑群邪。奈何時逼，不得時在我目中，", "反令井蛙壁蟲變容易，背人縮首競呀呀。", "我願天子回造化，藏之韞櫝玩之生光華。"]'),
('yuding-1','雪車','劉叉','唐','御定全唐诗','yuding','','[]','臘令凝綈三十日，繽紛密雪一複一。孰雲潤澤在枯荄，',185,'御定全唐詩/json/395.json','["臘令凝綈三十日，繽紛密雪一複一。孰雲潤澤在枯荄，", "人家千里無煙火，雞犬何太怨。天下恤吾氓，", "寒鎖侯門見客稀，色迷塞路行商斷。小小細細如塵間，", "載載欲何之，秘藏深宮以禦炎酷。徒能自衛九重間，", "戎夫尚逆命，扁箱鹿角誰為敵。士夫困征討，", "依違用事佞上方，猶驅餓民運造化防暑厄。", "吾聞躬耕南畝舜之聖，為民吞蝗唐之德。", "未聞eK孽苦蒼生，相群相黨上下為蝥賊。", "廟堂食祿不自慚，我為斯民歎息還歎息。"]'),
('yuding-2','修養','劉叉','唐','御定全唐诗','yuding','','[]','損神終日談虛空，不必歸命於胎中。我神不西亦不東，',64,'御定全唐詩/json/395.json','["損神終日談虛空，不必歸命於胎中。我神不西亦不東，", "世人逢一不逢一，一回存想一回出。只知一切望一切，", "惜哉自有不自親，明真汩沒隨埃塵。"]'),
('yuding-3','勿執古寄韓潮州','劉叉','唐','御定全唐诗','yuding','','[]','古人皆執古，不辭凍餓悲。今人亦執古，自取行坐危。',120,'御定全唐詩/json/395.json','["古人皆執古，不辭凍餓悲。今人亦執古，自取行坐危。", "老菊淩霜葩，獰松抱雪姿。武王亦至明，甯哀首陽饑。", "仲尼豈非聖，但為互鄉嗤。寸心生萬路，今古棼若絲。", "逐逐行不盡，茫茫休者誰。來恨不可遏，去悔何足追。", "玉石共笑唾，駑驥相賓士。請君勿執古，執古徒自隳。"]'),
('yuding-4','答孟東野','劉叉','唐','御定全唐诗','yuding','','[]','酸寒孟夫子，苦愛老叉詩。生澀有百篇，謂是瓊瑤辭。',96,'御定全唐詩/json/395.json','["酸寒孟夫子，苦愛老叉詩。生澀有百篇，謂是瓊瑤辭。", "百篇非所長，憂來豁窮悲。唯有剛腸鐵，百煉不柔虧。", "退之何可罵，東野何可欺。文王已雲沒，誰顧好爵縻。", "生死守一丘，甯計飽與饑。萬事付杯酒，從人笑狂癡。"]'),
('yuding-5','自古無長生勸姚合酒','劉叉','唐','御定全唐诗','yuding','','[]','奉子一杯酒，為子照顏色。但願腮上紅，莫管頦下白。',96,'御定全唐詩/json/395.json','["奉子一杯酒，為子照顏色。但願腮上紅，莫管頦下白。", "自古無長生，生者何戚戚。登山勿厭高，四望都無極。", "丘隴逐日多，天地為我窄。只見李耳書，對之空脈脈。", "何曾見天上，著得劉安宅。若問長生人，昭昭孔丘籍。"]'),
('yuding-6','獨飲','劉叉','唐','御定全唐诗','yuding','','[]','盡欲調太羹，自古無好手。所以山中人，兀兀但飲酒。',24,'御定全唐詩/json/395.json','["盡欲調太羹，自古無好手。所以山中人，兀兀但飲酒。"]'),
('yuding-7','作詩','劉叉','唐','御定全唐诗','yuding','','[]','作詩無知音，作不如不作。未逢賡載人，此道終寂寞。',48,'御定全唐詩/json/395.json','["作詩無知音，作不如不作。未逢賡載人，此道終寂寞。", "有虞今已歿，來者誰為托。朗詠豁心胸，筆與淚俱落。"]'),
('yuding-8','天津橋','劉叉','唐','御定全唐诗','yuding','','[]','洛陽宮闕照天地，四面山川無毒氣。',32,'御定全唐詩/json/395.json','["洛陽宮闕照天地，四面山川無毒氣。", "誰令漢祖都秦關，從此奸雄轉相熾。"]'),
('yuding-9','嘲荊卿','劉叉','唐','御定全唐诗','yuding','','[]','白虹千里氣，血頸一劍義。報恩不到頭，徒作輕生士。',24,'御定全唐詩/json/395.json','["白虹千里氣，血頸一劍義。報恩不到頭，徒作輕生士。"]'),
('yuding-10','代牛言','劉叉','唐','御定全唐诗','yuding','','[]','渴飲潁水流，餓喘吳門月。黃金如可種，我力終不竭。',24,'御定全唐詩/json/395.json','["渴飲潁水流，餓喘吳門月。黃金如可種，我力終不竭。"]'),
('yuding-11','莫問卜','劉叉','唐','御定全唐诗','yuding','','[]','莫問卜，人生吉凶皆自速。伏羲文王若無死，',20,'御定全唐詩/json/395.json','["莫問卜，人生吉凶皆自速。伏羲文王若無死，"]'),
('yuding-12','觀八駿圖','劉叉','唐','御定全唐诗','yuding','','[]','穆王八駿走不歇，海外去尋長日月。',32,'御定全唐詩/json/395.json','["穆王八駿走不歇，海外去尋長日月。", "五雲望斷阿母宮，歸來落得新白髮。"]'),
('yuding-13','經戰地','劉叉','唐','御定全唐诗','yuding','','[]','殺氣不上天，陰風吹雨血。冤魂不入地，髑髏哭沙月。',36,'御定全唐詩/json/395.json','["殺氣不上天，陰風吹雨血。冤魂不入地，髑髏哭沙月。", "人命固有常，此地何夭折。"]'),
('yuding-14','野哭','劉叉','唐','御定全唐诗','yuding','','[]','棘針生獰義路閑，野泉相吊聲潺潺。',32,'御定全唐詩/json/395.json','["棘針生獰義路閑，野泉相吊聲潺潺。", "哀哉異教溺頹俗，淳源一去何時還。"]'),
('yuding-15','古怨','劉叉','唐','御定全唐诗','yuding','','[]','君莫嫌醜婦，醜婦死守貞。山頭一怪石，長作望夫名。',48,'御定全唐詩/json/395.json','["君莫嫌醜婦，醜婦死守貞。山頭一怪石，長作望夫名。", "鳥有並翼飛，獸有比肩行。丈夫不立義，豈如鳥獸情。"]'),
('yuding-16','烈士詠','劉叉','唐','御定全唐诗','yuding','','[]','烈士或愛金，愛金不為貧。義死天亦許，利生鬼亦嗔。',36,'御定全唐詩/json/395.json','["烈士或愛金，愛金不為貧。義死天亦許，利生鬼亦嗔。", "胡為輕薄兒，使酒殺平人。"]'),
('yuding-17','狂夫','劉叉','唐','御定全唐诗','yuding','','[]','大妻唱舜歌，小妻鼓湘瑟。狂夫遊冶歸，端坐仍作色。',36,'御定全唐詩/json/395.json','["大妻唱舜歌，小妻鼓湘瑟。狂夫遊冶歸，端坐仍作色。", "不讀關雎篇，安知後妃德。"]'),
('yuding-18','餓詠','劉叉','唐','御定全唐诗','yuding','','[]','文王久不出，賢士如土賤。妻孥從餓死，敢愛黃金篆。',24,'御定全唐詩/json/395.json','["文王久不出，賢士如土賤。妻孥從餓死，敢愛黃金篆。"]'),
('yuding-19','自問','劉叉','唐','御定全唐诗','yuding','','[]','自問彭城子，何人授汝顛。酒腸寬似海，詩膽大於天。',48,'御定全唐詩/json/395.json','["自問彭城子，何人授汝顛。酒腸寬似海，詩膽大於天。", "斷劍徒勞匣，枯琴無複弦。相逢不多合，賴是向林泉。"]'),
('yuding-20','入蜀','劉叉','唐','御定全唐诗','yuding','','[]','望空問真宰，此路為誰開。峽色侵天去，江聲滾地來。',48,'御定全唐詩/json/395.json','["望空問真宰，此路為誰開。峽色侵天去，江聲滾地來。", "孔明深有意，鐘會亦何才。信此非人事，悲歌付一杯。"]'),
('yuding-21','塞上逢盧仝','劉叉','唐','御定全唐诗','yuding','','[]','直到桑幹北，逢君夜不眠。上樓腰腳健，懷土眼睛穿。',48,'御定全唐詩/json/395.json','["直到桑幹北，逢君夜不眠。上樓腰腳健，懷土眼睛穿。", "斗柄寒垂地，河流凍徹天。羈魂泣相向，何事有詩篇。"]'),
('yuding-22','偶書','劉叉','唐','御定全唐诗','yuding','','[]','日出扶桑一丈高，人間萬事細如毛。',32,'御定全唐詩/json/395.json','["日出扶桑一丈高，人間萬事細如毛。", "野夫怒見不平處，磨損胸中萬古刀。"]'),
('yuding-23','愛碣山石','劉叉','唐','御定全唐诗','yuding','','[]','碣石何青青，挽我雙眼睛。愛爾多古峭，不到人間行。',24,'御定全唐詩/json/395.json','["碣石何青青，挽我雙眼睛。愛爾多古峭，不到人間行。"]'),
('yuding-24','與孟東野','劉叉','唐','御定全唐诗','yuding','','[]','寒衣草木皮，饑飯葵藿根。不為孟夫子，豈識市井門。',24,'御定全唐詩/json/395.json','["寒衣草木皮，饑飯葵藿根。不為孟夫子，豈識市井門。"]'),
('yuding-25','姚秀才愛予小劍因贈','劉叉','唐','御定全唐诗','yuding','','[]','一條古時水，向我手心流。臨行瀉贈君，勿薄細碎仇。',24,'御定全唐詩/json/395.json','["一條古時水，向我手心流。臨行瀉贈君，勿薄細碎仇。"]'),
('yuding-26','老恨','劉叉','唐','御定全唐诗','yuding','','[]','雪打杉松殘，補書書不完。懶學渭上翁，辛苦把釣竿。',24,'御定全唐詩/json/395.json','["雪打杉松殘，補書書不完。懶學渭上翁，辛苦把釣竿。"]'),
('yuding-0','思歸樂','元稹','唐','御定全唐诗','yuding','','[]','山中思歸樂，盡作思歸鳴。爾是此山鳥，安得失鄉名。',432,'御定全唐詩/json/396.json','["山中思歸樂，盡作思歸鳴。爾是此山鳥，安得失鄉名。", "應緣此山路，自古離人征。陰愁感和氣，俾爾從此生。", "我雖失鄉去，我無失鄉情。慘舒在方寸，寵辱將何驚。", "浮生居大塊，尋丈可寄形。身安即形樂，豈獨樂咸京。", "命者道之本，死者天之平。安問遠與近，何言殤與彭。", "君看趙工部，八十支體輕。交州二十載，一到長安城。", "長安不須臾，複作交州行。交州又累歲，移鎮廣與荊。", "歸朝新天子，濟濟為上卿。肌膚無瘴色，飲食康且寧。", "長安一晝夜，死者如隕星。喪車四門出，何關炎瘴縈。", "況我三十二，百年未半程。江陵道塗近，楚俗雲水清。", "遐想玉泉寺，久聞峴山亭。此去盡綿曆，豈無心賞並。", "紅餐日充腹，碧澗朝析酲。開門待賓客，寄書安弟兄。", "閑窮四聲韻，悶閱九部經。身外皆委順，眼前隨所營。", "此意久已定，誰能求苟榮。所以官甚小，不畏權勢傾。", "傾心豈不易，巧詐神之刑。萬物有本性，況複人性靈。", "金埋無土色，玉墜無瓦聲。劍折有寸利，鏡破有片明。", "我可俘為囚，我可刃為兵。我心終不死，金石貫以誠。", "此誠患不至，誠至道亦亨。微哉滿山鳥，叫噪何足聽。"]'),
('yuding-1','春鳩','元稹','唐','御定全唐诗','yuding','','[]','春鳩與百舌，音響詎同年。如何一時語，俱得春風憐。',48,'御定全唐詩/json/396.json','["春鳩與百舌，音響詎同年。如何一時語，俱得春風憐。", "猶知化工意，當春不生蟬。免教爭叫噪，沸渭桃花前。"]'),
('yuding-2','春蟬','元稹','唐','御定全唐诗','yuding','','[]','我自東歸日，厭苦春鳩聲。作詩憐化工，不遣春蟬生。',96,'御定全唐詩/json/396.json','["我自東歸日，厭苦春鳩聲。作詩憐化工，不遣春蟬生。", "及來商山道，山深氣不平。春秋兩相似，蟲豸百種鳴。", "風松不成韻，蜩螗沸如羹。豈無朝陽鳳，羞與微物爭。", "安得天上雨，奔渾河海傾。蕩滌反時氣，然後好晴明。"]'),
('yuding-3','兔絲','元稹','唐','御定全唐诗','yuding','','[]','人生莫依倚，依倚事不成。君看兔絲蔓，依倚榛與荊。',120,'御定全唐詩/json/396.json','["人生莫依倚，依倚事不成。君看兔絲蔓，依倚榛與荊。", "荊榛易蒙密，百鳥撩亂鳴。下有狐兔穴，奔走亦縱橫。", "樵童斫將去，柔蔓與之並。翳薈生可恥，束縛死無名。", "桂樹月中出，珊瑚石上生。俊鶻度海食，應龍升天行。", "靈物本特達，不復相纏縈。纏縈竟何者，荊棘與飛莖。"]'),
('yuding-4','古社','元稹','唐','御定全唐诗','yuding','','[]','古社基址在，人散社不神。惟有空心樹，妖狐藏魅人。',156,'御定全唐詩/json/396.json','["古社基址在，人散社不神。惟有空心樹，妖狐藏魅人。", "狐惑意顛倒，臊腥不復聞。丘墳變城郭，花草仍荊榛。", "良田千萬頃，占作天荒田。主人議芟斫，怪見不敢前。", "那言空山燒，夜隨風馬奔。飛聲鼓鼙震，高焰旗幟翻。", "逡巡荊棘盡，狐兔無子孫。狐死魅人滅，煙消壇墠存。", "繞壇舊田地，給授有等倫。農收村落盛，社樹新團圓。", "社公千萬歲，永保村中民。"]'),
('yuding-5','松樹','元稹','唐','御定全唐诗','yuding','','[]','華山高幢幢，上有高高松。株株遙各各，葉葉相重重。',120,'御定全唐詩/json/396.json','["華山高幢幢，上有高高松。株株遙各各，葉葉相重重。", "槐樹夾道植，枝葉俱冥蒙。既無貞直幹，複有罥掛蟲。", "何不種松樹，使之搖清風。秦時已曾種，憔悴種不供。", "可憐孤松意，不與槐樹同。閑在高山頂，樛盤虯與龍。", "屈為大廈棟，庇蔭侯與公。不肯作行伍，俱在塵土中。"]'),
('yuding-6','芳樹','元稹','唐','御定全唐诗','yuding','','[]','芳樹已寥落，孤英尤可嘉。可憐團團葉，蓋覆深深花。',96,'御定全唐詩/json/396.json','["芳樹已寥落，孤英尤可嘉。可憐團團葉，蓋覆深深花。", "遊蜂競鑽刺，鬥雀亦紛拏。天生細碎物，不愛好光華。", "非無殲殄法，念爾有生涯。春雷一聲發，驚燕亦驚蛇。", "清池養神蔡，已複長蝦蟆。雨露貴平施，吾其春草芽。"]'),
('yuding-7','桐花','元稹','唐','御定全唐诗','yuding','','[]','朧月上山館，紫桐垂好陰。可惜暗澹色，無人知此心。',492,'御定全唐詩/json/396.json','["朧月上山館，紫桐垂好陰。可惜暗澹色，無人知此心。", "舜沒蒼梧野，鳳歸丹穴岑。遺落在人世，光華那複深。", "年年怨春意，不競桃杏林。唯占清明後，牡丹還複侵。", "況此空館閉，雲誰恣幽尋。徒煩鳥噪集，不語山嶔岑。", "滿院青苔地，一樹蓮花簪。自開還自落，暗芳終暗沈。", "爾生不得所，我願裁為琴。安置君王側，調和元首音。", "安問宮征角，先辨雅鄭淫。宮弦春以君，君若春日臨。", "商弦廉以臣，臣作旱天霖。人安角聲暢，人困鬥不任。", "羽以類萬物，祆物神不歆。征以節百事，奉事罔不欽。", "五者苟不亂，天命乃可忱。君若問孝理，彈作梁山吟。", "君若事宗廟，拊以和球琳。君若不好諫，願獻觸疏箴。", "君若不罷獵，請聽荒於禽。君若侈台殿，雍門可沾襟。", "君若傲賢雋，鹿鳴有食芩。君聞祈招什，車馬勿駸駸。", "君若欲敗度，中有式如金。君聞熏風操，志氣在愔愔。", "中有阜財語，勿受來獻賝。北裏當絕聽，禍莫大於淫。", "南風苟不競，無往遺之擒。奸聲不入耳，巧言甯孔壬。", "梟音亦雲革，安得沴與祲。天子既穆穆，群材亦森森。", "劍士還農野，絲人歸織紝。丹鳳巢阿閣，文魚遊碧潯。", "和氣浹寰海，易若溉蹄涔。改張乃可鼓，此語無古今。", "非琴獨能爾，事有諭因針。感爾桐花意，閑怨杳難禁。", "待我持斤斧，置君為大琛。"]'),
('yuding-8','雉媒','元稹','唐','御定全唐诗','yuding','','[]','雙雉在野時，可憐同嗜欲。毛衣前後成，一種文章足。',240,'御定全唐詩/json/396.json','["雙雉在野時，可憐同嗜欲。毛衣前後成，一種文章足。", "一雉獨先飛，衝開芳草綠。網羅幽草中，暗被潛羈束。", "剪刀摧六翮，絲線縫雙目。啖養能幾時，依然已馴熟。", "都無舊性靈，返與他心腹。置在芳草中，翻令誘同族。", "前時相失者，思君意彌篤。朝朝舊處飛，往往巢邊哭。", "今朝樹上啼，哀音斷還續。遠見爾文章，知君草中伏。", "和鳴忽相召，鼓翅遙相矚。畏我未肯來，又啄翳前粟。", "斂翮遠投君，飛馳勢奔蹙。罥掛在君前，向君聲促促。", "信君決無疑，不道君相覆。自恨飛太高，疏羅偶然觸。", "看看架上鷹，擬食無罪肉。君意定何如，依舊雕籠宿。"]'),
('yuding-9','箭鏃','元稹','唐','御定全唐诗','yuding','','[]','箭鏃本求利，淬礪良甚難。礪將何所用，礪以射兇殘。',168,'御定全唐詩/json/396.json','["箭鏃本求利，淬礪良甚難。礪將何所用，礪以射兇殘。", "不礪射不入，不射人不安。為盜即當射，寧問私與官。", "夜射官中盜，中之血闌幹。帶箭君前訴，君王悄不歡。", "頃曾為盜者，百箭中心攢。競將兒女淚，滴瀝助辛酸。", "君王責良帥，此禍誰為端。帥言發硎罪，不使刃稍刓。", "君王不忍殺，逐之如迸丸。仍令後來箭，盡可頭團團。", "發硎去雖遠，礪鏃心不闌。會射蛟螭盡，舟行無惡瀾。"]'),
('yuding-10','賽神','元稹','唐','御定全唐诗','yuding','','[]','村落事妖神，林木大如村。事來三十載，巫覡傳子孫。',456,'御定全唐詩/json/396.json','["村落事妖神，林木大如村。事來三十載，巫覡傳子孫。", "村中四時祭，殺盡雞與豚。主人不堪命，積燎曾欲燔。", "旋風天地轉，急雨江河翻。采薪持斧者，棄斧縱橫奔。", "山深多掩映，僅免鯨鯢吞。主人集鄰里，各各持酒樽。", "廟中再三拜，願得禾稼存。去年大巫死，小覡又妖言。", "邑中神明宰，有意效西門。焚除計未決，伺者迭乘軒。", "廟深荊棘厚，但見狐兔蹲。巫言小神變，可驗牛馬蕃。", "邑吏齊進說，幸勿禍鄉原。逾年計不定，縣聽良亦煩。", "涉夏祭時至，因令修四垣。憂虞神憤恨，玉帛意彌敦。", "我來神廟下，簫鼓正喧喧。因言遣妖術，滅絕由本根。", "主人中罷舞，許我重疊論。蜉蝣生濕處，鴟鴞集黃昏。", "主人邪心起，氣焰日夜繁。狐狸得蹊徑，潛穴主人園。", "腥臊襲左右，然後托丘樊。歲深樹成就，曲直可輪轅。", "幽妖盡依倚，萬怪之所屯。主人一心好，四面無籬藩。", "命樵執斤斧，怪木寧遽髡。主人且傾聽，再為諭清渾。", "阿膠在末派，罔象遊上源。靈藥逡巡盡，黑波朝夕噴。", "神龍厭流濁，先伐鼉與黿。黿鼉在龍穴，妖氣常郁溫。", "主人惡淫祀，先去邪與惛。惛邪中人意，蠱禍蝕精魂。", "德勝妖不作，勢強威亦尊。計窮然後賽，後賽複何恩。"]'),
('yuding-11','大觜烏','元稹','唐','御定全唐诗','yuding','','[]','陽烏有二類，嘴白者名慈。求食哺慈母，因以此名之。',529,'御定全唐詩/json/396.json','["陽烏有二類，嘴白者名慈。求食哺慈母，因以此名之。", "飲啄頗廉儉，音響亦柔雌。百巢同一樹，棲宿不復疑。", "得食先反哺，一身常苦羸。緣知五常性，翻被眾禽欺。", "其一觜大者，攫搏性貪癡。有力強如鶻，有爪利如錐。", "音聲甚eT嗗，潛通妖怪詞。受日餘光庇，終天無死期。", "翱翔富人屋，棲息屋前枝。巫言此烏至，財產日豐宜。", "主人一心惑，誘引不知疲。轉見烏來集，自言家轉孳。", "白鶴門外養，花鷹架上維。專聽烏喜怒，信受若神龜。", "舉家同此意，彈射不復施。往往清池側，卻令鵷鷺隨。", "群烏飽粱肉，毛羽色澤滋。遠近恣所往，貪殘無不為。", "巢禽攫雛卵，廄馬啄瘡痍。滲瀝脂膏盡，鳳凰那得知。", "主人一朝病，爭向屋簷窺。呦鷕呼群鵩，翩翻集怪鴟。", "主人偏養者，嘯聚最賓士。夜半仍驚噪，鵂鶹逐老狸。", "主人病心怯，燈火夜深移。左右雖無語，奄然皆淚垂。", "平明天出日，陰魅走參差。烏來屋簷上，又惑主人兒。", "兒即富家業，玩好方愛奇。占募能言鳥，置者許高貲。", "隴樹巢鸚鵡，言語好光儀。美人傾心獻，雕籠身自持。", "求者臨軒坐，置在白玉墀。先問鳥中苦，便言烏若斯。", "眾烏齊搏鑠，翠羽幾離披。遠擲千餘裏，美人情亦衰。", "舉家懲此患，事烏逾昔時。向言池上鷺，啄肉寢其皮。", "夜漏天終曉，陰雲風定吹。況爾烏何者，數極不知危。", "會結彌天網，盡取一無遺。常令阿閣上，宛宛宿長離。"]'),
('yuding-12','分水嶺','元稹','唐','御定全唐诗','yuding','','[]','崔嵬分水嶺，高下與雲平。上有分流水，東西隨勢傾。',216,'御定全唐詩/json/396.json','["崔嵬分水嶺，高下與雲平。上有分流水，東西隨勢傾。", "朝同一源出，暮隔千里情。風雨各自異，波瀾相背驚。", "勢高競奔注，勢曲已回縈。偶值當途石，蹙縮又縱橫。", "有時遭孔穴，變作嗚咽聲。褊淺無所用，奔波奚所營。", "團團井中水，不復東西征。上應美人意，中涵孤月明。", "旋風四面起，並深波不生。堅冰一時合，井深凍不成。", "終年汲引絕，不耗複不盈。五月金石鑠，既寒亦既清。", "易時不易性，改邑不改名。定如拱北極，瑩若燒玉英。", "君門客如水，日夜隨勢行。君看守心者，井水為君盟。"]'),
('yuding-13','四皓廟','元稹','唐','御定全唐诗','yuding','','[]','巢由昔避世，堯舜不得臣。伊呂雖急病，湯武乃可君。',288,'御定全唐詩/json/396.json','["巢由昔避世，堯舜不得臣。伊呂雖急病，湯武乃可君。", "四賢胡為者，千載名氛氳。顯晦有遺跡，前後疑不倫。", "秦政虐天下，黷武窮生民。諸侯戰必死，壯士眉亦顰。", "張良韓孺子，椎碎屬車輪。遂令英雄意，日夜思報秦。", "先生相將去，不復嬰世塵。雲卷在孤岫，龍潛為小鱗。", "秦王轉無道，諫者鼎鑊親。茅焦脫衣諫，先生無一言。", "趙高殺二世，先生如不聞。劉項取天下，先生游白雲。", "海內八年戰，先生全一身。漢業日已定，先生名亦振。", "不得為濟世，宜哉為隱淪。如何一朝起，屈作儲貳賓。", "安存孝惠帝，摧悴戚夫人。舍大以謀細，虯盤而蠖伸。", "惠帝竟不嗣，呂氏禍有因。雖懷安劉志，未若周與陳。", "皆落子房術，先生道何屯。出處貴明白，故吾今有雲。"]'),
('yuding-0','青雲驛','元稹','唐','御定全唐诗','yuding','','[]','岧嶢青雲嶺，下有千仞溪。裴回不可上，人倦馬亦嘶。',576,'御定全唐詩/json/397.json','["岧嶢青雲嶺，下有千仞溪。裴回不可上，人倦馬亦嘶。", "願登青雲路，若望丹霞梯。謂言青雲驛，繡戶芙蓉閨。", "謂言青雲騎，玉勒黃金蹄。謂言青雲具，瑚璉雜象犀。", "謂言青雲吏，的的顏如珪。懷此青雲望，安能複久稽。", "攀援信不易，風雨正淒淒。已怪杜鵑鳥，先來山下啼。", "才及青雲驛，忽遇蓬蒿妻。延我開蓽戶，鑿竇宛如圭。", "逡巡吏來謁，頭白顏色黧。饋食頻叫噪，假器仍乞醯。", "向時延我者，共舍藿與藜。乘我牂牁馬，蒙茸大如羝。", "悔為青雲意，此意良噬臍。昔游蜀門下，有驛名青泥。", "聞名意慘愴，若墜牢與狴。雲泥異所稱，人物一以齊。", "複聞閶闔上，下視日月低。銀城蕊珠殿，玉版金字題。", "大帝直南北，群仙侍東西。龍虎儼隊仗，雷霆轟鼓鼙。", "元君理庭內，左右桃花蹊。丹霞爛成綺，景雲輕若綈。", "天池光灩灩，瑤草綠萋萋。眾真千萬輩，柔顏盡如荑。", "手持鳳尾扇，頭戴翠羽笄。雲韶互鏗戛，霞服相提攜。", "雙雙發皓齒，各各揚輕袿。天祚樂未極，溟波浩無堤。", "穢賤靈所惡，安肯問黔黎。桑田變成海，宇縣烹為齏。", "虛皇不願見，雲霧重重翳。大帝安可夢，閶闔何由躋。", "靈物可見者，願以諭端倪。蟲蛇吐雲氣，妖氛變虹霓。", "獲麟書諸冊，豢龍醢為臡。鳳凰占梧桐，叢雜百鳥棲。", "野鶴啄腥蟲，貪饕不如雞。山鹿藏窟穴，虎豹吞其麛。", "靈物比靈境，冠履寧甚睽。道勝即為樂，何慚居稗稊。", "金張好車馬，於陵親灌畦。在梁或在火，不變玉與鵜。", "上天勿行行，潛穴勿淒淒。吟此青雲諭，達觀終不迷。"]'),
('yuding-1','陽城驛','元稹','唐','御定全唐诗','yuding','','[]','商有陽城驛，名同陽道州。陽公沒已久，感我淚交流。',576,'御定全唐詩/json/397.json','["商有陽城驛，名同陽道州。陽公沒已久，感我淚交流。", "昔公孝父母，行與曾閔儔。既孤善兄弟，兄弟和且柔。", "一夕不相見，若懷三歲憂。遂誓不婚娶，沒齒同衾裯。", "妹夫死他縣，遺骨無人收。公令季弟往，公與仲弟留。", "相別竟不得，三人同遠遊。共負他鄉骨，歸來藏故丘。", "棲遲居夏邑，邑人無苟偷。裏中競長短，來問劣與優。", "官刑一朝恥，公短終身羞。公亦不遺布，人自不盜牛。", "問公何能爾，忠信先自修。發言當道理，不顧黨與讎。", "聲香漸翕習，冠蓋若雲浮。少者從公學，老者從公游。", "往來相告報，縣尹與公侯。名落公卿口，湧如波薦舟。", "天子得聞之，書下再三求。書中願一見，不異旱地虯。", "何以持為聘，束帛藉琳球。何以持為禦，駟馬駕安輈。", "公方伯夷操，事殷不事周。我實唐士庶，食唐之田疇。", "我聞天子憶，安敢專自由。來為諫大夫，朝夕侍冕旒。", "希夷惇薄俗，密勿獻良籌。神醫不言術，人瘼曾暗瘳。", "月請諫官俸，諸弟相對謀。皆曰親戚外，酒散目前愁。", "公雲不有爾，安得此嘉猷。施餘盡酤酒，客來相獻酬。", "日旰不謀食，春深仍弊裘。人心良戚戚，我樂獨由由。", "貞元歲雲暮，朝有曲如鉤。風波勢奔蹙，日月光綢繆。", "齒牙屬為猾，禾黍暗生蟊。豈無司言者，肉食吞其喉。", "豈無司搏者，利柄扼其鞲。鼻複勢氣塞，不得辯熏蕕。", "公雖未顯諫，惴惴如患瘤。飛章八九上，皆若珠暗投。", "炎炎日將熾，積燎無人抽。公乃帥其屬，決諫同報仇。", "延英殿門外，叩閣仍叩頭。且曰事不止，臣諫誓不休。"]'),
('yuding-2','苦雨','元稹','唐','御定全唐诗','yuding','','[]','江瘴氣候惡，庭空田地蕪。煩昏一日內，陰暗三四殊。',312,'御定全唐詩/json/397.json','["江瘴氣候惡，庭空田地蕪。煩昏一日內，陰暗三四殊。", "巢燕汙床席，蒼蠅點肌膚。不足生詬怒，但若寡歡娛。", "夜來稍清晏，放體階前呼。未飽風月思，已為蚊蚋圖。", "我受簪組身，我生天地爐。炎蒸安敢倦，蟲豸何時無。", "淩晨坐堂廡，努力泥中趨。官家事不了，尤悔亦可虞。", "門外竹橋折，馬驚不敢逾。回頭命僮禦，向我色踟躕。", "自顧方濩落，安能相詰誅。隱忍心憤恨，翻為聲喣愉。", "逡巡崔嵬日，杲曜東南隅。已複雲蔽翳，不使及泥塗。", "良農盡蒲葦，厚地積潢汙。三光不得照，萬物何由蘇。", "安得飛廉車，磔裂雲將軀。又提精陽劍，蛟螭支節屠。", "陰沴皆電掃，幽妖亦雷驅。煌煌啟閶闔，軋軋掉幹樞。", "東西生日月，晝夜如轉珠。百川朝巨海，六龍蹋亨衢。", "此意倍寥廓，時來本須臾。今也泥鴻洞，黿鼉真得途。"]'),
('yuding-3','種竹','元稹','唐','御定全唐诗','yuding','','[]','昔公憐我直，比之秋竹竿。秋來苦相憶，種竹廳前看。',120,'御定全唐詩/json/397.json','["昔公憐我直，比之秋竹竿。秋來苦相憶，種竹廳前看。", "失地顏色改，傷根枝葉殘。清風猶淅淅，高節空團團。", "鳴蟬聒暮景，跳蛙集幽闌。塵土複晝夜，梢雲良獨難。", "丹丘信雲遠，安得臨仙壇。瘴江冬草綠，何人驚歲寒。", "可憐亭亭幹，一一青琅玕。孤鳳竟不至，坐傷時節闌。"]'),
('yuding-4','和樂天贈樊著作','元稹','唐','御定全唐诗','yuding','','[]','君為著作詩，志激詞且溫。璨然光揚者，皆以義烈聞。',396,'御定全唐詩/json/397.json','["君為著作詩，志激詞且溫。璨然光揚者，皆以義烈聞。", "千慮竟一失，冰玉不斷痕。謬予頑不肖，列在數子間。", "因君譏史氏，我亦能具陳。羲黃眇雲遠，載籍無遺文。", "煌煌二帝道，鋪設在典墳。堯心惟舜會，因著為話言。", "皋夔益稷禹，粗得無間然。緬然千載後，後聖曰孔宣。", "迥知皇王意，綴書為百篇。是時游夏輩，不敢措舌端。", "信哉作遺訓，職在聖與賢。如何至近古，史氏為閑官。", "但令識字者，竊弄刀筆權。由心書曲直，不使當世觀。", "貽之千萬代，疑言相並傳。人人異所見，各各私所遍。", "以是曰褒貶，不如都無焉。況乃丈夫志，用舍貴當年。", "顧予有微尚，願以出處論。出非利吾已，其出貴道全。", "全道豈虛設，道全當及人。全則富與壽，虧則饑與寒。", "遂我一身逸，不如萬物安。解懸不澤手，拯溺無折旋。", "神哉伊尹心，可以冠古先。其次有獨善，善己不善民。", "天地為一物，死生為一源。合雜分萬變，忽若風中塵。", "抗哉巢由志，堯舜不可遷。舍此二者外，安用名為賓。", "持謝著書郎，愚不願有雲。"]'),
('yuding-5','和樂天感鶴','元稹','唐','御定全唐诗','yuding','','[]','我有所愛鶴，毛羽霜雪妍。秋霄一滴露，聲聞林外天。',120,'御定全唐詩/json/397.json','["我有所愛鶴，毛羽霜雪妍。秋霄一滴露，聲聞林外天。", "自隨衛侯去，遂入大夫軒。雲貌久已隔，玉音無複傳。", "吟君感鶴操，不覺心惕然。無乃予所愛，誤為微物遷。", "因茲諭直質，未免柔細牽。君看孤松樹，左右蘿蔦纏。", "既可習為飽，亦可熏為荃。期君常善救，勿令終棄捐。"]'),
('yuding-6','諭寶二首','元稹','唐','御定全唐诗','yuding','','[]','沉玉在弱泥，泥弱玉易沉。扶桑寒日薄，不照萬丈心。',360,'御定全唐詩/json/397.json','["沉玉在弱泥，泥弱玉易沉。扶桑寒日薄，不照萬丈心。", "安得潛淵虯，拔壑超鄧林。泥封泰山址，水散旱天霖。", "洗此泥下玉，照耀台殿深。刻為傳國寶，神器人不侵。", "冰置白玉壺，始見清皎潔。珠穿殷紅縷，始見明洞徹。", "鏌鋣無人淬，兩刃幽壤鐵。秦鏡無人拭，一片埋霧月。", "驥局環堵中，骨附筋入節。虯蟠尺澤內，魚貫蛙同穴。", "艅艎無巨海，浮浮矜瀎潏。棟樑無廣廈，顛倒臥霜雪。", "大鵬無長空，舉翮受羈絏。豫樟無厚地，危柢真卼臲。", "圭璧無卞和，甘與頑石列。舜禹無陶堯，名隨腐草滅。", "神功伏神物，神物神乃別。神人不世出，所以神功絕。", "神物豈徒然，用之乃施設。禹功九州理，舜德天下悅。", "璧充傳國璽，圭用祈太折。千尋豫樟幹，九萬大鵬歇。", "棟樑庇生民，艅艎濟來哲。虯騰旱天雨，驥騁流電掣。", "鏡懸奸膽露，劍拂妖蛇裂。珠玉照乘光，冰瑩環坐熱。", "此物比在泥，斯言為誰發。於今盡凡耳，不為君不說。"]'),
('yuding-7','說劍','元稹','唐','御定全唐诗','yuding','','[]','吾友有寶劍，密之如密友。我實膠漆交，中堂共杯酒。',480,'御定全唐詩/json/397.json','["吾友有寶劍，密之如密友。我實膠漆交，中堂共杯酒。", "酒酣肝膽露，恨不眼前剖。高唱荊卿歌，亂擊相如缶。", "更擊複更唱，更酌亦更壽。白虹坐上飛，青蛇匣中吼。", "我聞音響異，疑是幹將偶。為君再拜言，神物可見不。", "君言我所重，我自為君取。迎篋已焚香，近鞘先澤手。", "徐抽寸寸刃，漸屈彎彎肘。殺殺霜在鋒，團團月臨紐。", "逡巡潛虯躍，鬱律驚左右。霆電滿室光，蛟龍繞身走。", "我為捧之泣，此劍別來久。鑄時近山破，藏在松桂朽。", "幽匣獄底埋，神人水心守。本是稽泥淬，果非雷煥有。", "我欲評劍功，願君良聽受。劍可剸犀兕，劍可切瓊玖。", "劍決天外雲，劍沖日中鬥。劍隳妖蛇腹，劍拂佞臣首。", "太古初斷鼇，武王親擊紂。燕丹卷地圖，陳平綰花綬。", "曾被桂樹枝，寒光射林藪。曾經鑄農器，利用翦稂莠。", "神物終變化，複為龍牝牡。晉末武庫燒，脫然排戶牖。", "為欲掃群胡，散作彌天帚。自茲失所往，豪英共為詬。", "今複誰人鑄，挺然千載後。既非古風胡，無乃近鴉九。", "自我與君游，平生益自負。況擎寶劍出，重以雄心扣。", "此劍何太奇，此心何太厚。勸君慎所用，所用無或苟。", "潛將辟魑魅，勿但防妾婦。留斬泓下蛟，莫試街中狗。", "君今困泥滓，我亦坌塵垢。俗耳驚大言，逢人少開口。"]'),
('yuding-8','書異','元稹','唐','御定全唐诗','yuding','','[]','孟冬初寒月，渚澤蒲尚青。飄蕭北風起，皓雪紛滿庭。',192,'御定全唐詩/json/397.json','["孟冬初寒月，渚澤蒲尚青。飄蕭北風起，皓雪紛滿庭。", "行過冬至後，凍閉萬物零。奔渾馳暴雨，驟鼓轟雷霆。", "傳雲不終日，通宵曾莫停。瘴雲愁拂地，急溜疑注瓶。", "洶湧潢潦濁，噴薄鯨鯢腥。跳趫井蛙喜，突兀水怪形。", "飛蚋奔不死，修蛇蟄再醒。應龍非時出，無乃歲不寧。", "吾聞陰陽戶，啟閉各有扃。後時無肅殺，廢職乃玄冥。", "座配五天帝，薦用百品珍。權為祝融奪，神其焉得靈。", "春秋雷電異，則必書諸經。仲冬雷雨苦，願省蒙蔽刑。"]'),
('yuding-9','和樂天折劍頭','元稹','唐','御定全唐诗','yuding','','[]','聞君得折劍，一片雄心起。詎意鐵蛟龍，潛在延津水。',60,'御定全唐詩/json/397.json','["聞君得折劍，一片雄心起。詎意鐵蛟龍，潛在延津水。", "風雲會一合，呼吸期萬里。雷震山嶽碎，電斬鯨鯢死。", "莫但寶劍頭，劍頭非此比。"]'),
('yuding-0','松鶴','元稹','唐','御定全唐诗','yuding','','[]','渚宮本坳下，佛廟有台閣。台下三四松，低昂勢前卻。',144,'御定全唐詩/json/398.json','["渚宮本坳下，佛廟有台閣。台下三四松，低昂勢前卻。", "是時晴景麗，松梢殘雪薄。日色相玲瓏，纖雲映羅幕。", "逡巡九霄外，似振風中鐸。漸見尺帛光，孤飛唳空鶴。", "裴回耀霜雪，顧慕下寥廓。蹋動樛盤枝，龍蛇互跳躍。", "俯瞰九江水，旁瞻萬里壑。無心眄烏鳶，有字悲城郭。", "清角已沉絕，虞韶亦冥寞。鶱翻勿重留，幸及鈞天作。"]'),
('yuding-1','競渡','元稹','唐','御定全唐诗','yuding','','[]','吾觀競舟子，因測大競源。天地昔將競，蓬勃晝夜昏。',360,'御定全唐詩/json/398.json','["吾觀競舟子，因測大競源。天地昔將競，蓬勃晝夜昏。", "龍蛇相嗔薄，海岱俱崩奔。群動皆攪撓，化作流渾渾。", "數極鬥心息，太和蒸混元。一氣忽為二，矗然畫乾坤。", "日月複照耀，春秋遞寒溫。八荒坦以曠，萬物羅以繁。", "聖人中間立，理世了不煩。延綿複幾歲，逮及羲與軒。", "炎皇熾如炭，蚩尤扇其燔。有熊競心起，驅獸出林樊。", "一戰波委焰，再戰火燎原。戰訖天下定，號之為軒轅。", "自是豈無競，瑣細不復言。其次有龍競，競渡龍之門。", "龍門浚如瀉，淙射不可援。赤鱗化時至，唐突鰭鬣掀。", "乘風瞥然去，萬里黃河翻。接瞬電烻出，微吟霹靂喧。", "傍瞻曠宇宙，俯瞰卑昆侖。庶類咸在下，九霄行易捫。", "倏辭蛙黽穴，遽排天帝閽。回悲曝鰓者，未免鯨鯢吞。", "帝命澤諸夏，不棄蟲與昆。隨時布膏露，稱物施厚恩。", "草木沾我潤，豚魚望我蕃。向來同競輩，豈料由我存。", "壯哉龍競渡，一競身獨尊。舍此皆蟻鬥，競舟何足論。"]'),
('yuding-2','寺院新竹','元稹','唐','御定全唐诗','yuding','','[]','寶地琉璃坼，紫苞琅玕踴。亭亭巧於削，一一大如拱。',168,'御定全唐詩/json/398.json','["寶地琉璃坼，紫苞琅玕踴。亭亭巧於削，一一大如拱。", "冰碧林外寒，峰巒眼前聳。槎枒矛戟合，屹仡龍蛇動。", "煙泛翠光流，歲餘霜彩重。風朝竽籟過，雨夜鬼神恐。", "佳色有鮮妍，修莖無擁腫。節高迷玉鏃，籜綴疑花捧。", "詎必太山根，本自仙壇種。誰令植幽壤，複此依閑冗。", "居然霄漢姿，坐受藩籬壅。噪集倦鴟烏，炎昏繁蠛蠓。", "未遭伶倫聽，非安子猶寵。威鳳來有時，虛心豈無奉。"]'),
('yuding-3','酬別致用','元稹','唐','御定全唐诗','yuding','','[]','風行自委順，雲合非有期。神哉心相見，無眹安得離。',216,'御定全唐詩/json/398.json','["風行自委順，雲合非有期。神哉心相見，無眹安得離。", "我有懇憤志，三十無人知。修身不言命，謀道不擇時。", "達則濟億兆，窮亦濟毫釐。濟人無大小，誓不空濟私。", "研幾未淳熟，與世忽參差。意氣一為累，猜仍良已隨。", "昨來竄荊蠻，分與平生隳。那言返為遇，獲見心所奇。", "一見肺肝盡，坦然無滯疑。感念交契定，淚流如斷縻。", "此交定生死，非為論盛衰。此契宗會極，非謂同路歧。", "君今虎在柙，我亦鷹就羈。馴養保性命，安能奮殊姿。", "玉色深不變，井水撓不移。相看各年少，未敢深自悲。"]'),
('yuding-4','竹部','元稹','唐','御定全唐诗','yuding','','[]','竹部竹山近，歲伐竹山竹。伐竹歲亦深，深林隔深谷。',144,'御定全唐詩/json/398.json','["竹部竹山近，歲伐竹山竹。伐竹歲亦深，深林隔深谷。", "朝朝冰雪行，夜夜豺狼宿。科首霜斷蓬，枯形燒餘木。", "一束十餘莖，千錢百餘束。得錢盈千百，得粟盈鬥斛。", "歸來不買食，父子分半菽。持此欲何為，官家歲輸促。", "我來荊門掾，寓食公堂肉。豈惟遍妻孥，亦以及僮僕。", "分爾有限資，飽我無端腹。愧爾不復言，爾生何太蹙。"]'),
('yuding-5','賽神','元稹','唐','御定全唐诗','yuding','','[]','楚俗不事事，巫風事妖神。事妖結妖社，不問疏與親。',216,'御定全唐詩/json/398.json','["楚俗不事事，巫風事妖神。事妖結妖社，不問疏與親。", "年年十月暮，珠稻欲垂新。家家不斂獲，賽妖無富貧。", "殺牛貰官酒，椎鼓集頑民。喧闐裏閭隘，凶酗日夜頻。", "歲暮雪霜至，稻珠隨隴湮。吏來官稅迫，求質倍稱緡。", "貧者日消鑠，富亦無倉囷。不謂事神苦，自言誠不真。", "岳陽賢刺史，念此為俗屯。未可一朝去，俾之為等倫。", "粗許存習俗，不得呼黨人。但許一日澤，不得月與旬。", "吾聞國僑理，三年名乃振。巫風燎原久，未必憐徙薪。", "我來歌此事，非獨歌政仁。此事四鄰有，亦欲聞四鄰。"]'),
('yuding-6','競舟','元稹','唐','御定全唐诗','yuding','','[]','楚俗不愛力，費力為競舟。買舟俟一競，競斂貧者賕。',240,'御定全唐詩/json/398.json','["楚俗不愛力，費力為競舟。買舟俟一競，競斂貧者賕。", "年年四五月，繭實麥小秋。積水堰堤壞，拔秧蒲稗稠。", "此時集丁壯，習競南畝頭。朝飲村社酒，暮椎鄰舍牛。", "祭船如祭祖，習競如習讎。連延數十日，作業不復憂。", "君侯饌良吉，會客陳膳羞。畫鷁四來合，大競長江流。", "建標明取捨，勝負死生求。一時歡呼罷，三月農事休。", "岳陽賢刺史，念此為俗疣。習俗難盡去，聊用去其尤。", "百船不留一，一競不滯留。自為裏中戲，我亦不寓遊。", "吾聞管仲教，沐樹懲墮遊。節此淫競俗，得為良政不。", "我來歌此事，非獨歌此州。此事數州有，亦欲聞數州。"]'),
('yuding-7','茅舍','元稹','唐','御定全唐诗','yuding','','[]','楚俗不理居，居人盡茅舍。茅苫竹梁棟，茅疏竹仍罅。',312,'御定全唐詩/json/398.json','["楚俗不理居，居人盡茅舍。茅苫竹梁棟，茅疏竹仍罅。", "邊緣堤岸斜，詰屈簷楹亞。籬落不蔽肩，街衢不容駕。", "南風五月盛，時雨不來下。竹蠹茅亦幹，迎風自焚灺。", "防虞集鄰里，巡警勞晝夜。遺燼一星然，連延禍相嫁。", "號呼憐穀帛，奔走伐桑柘。舊架已新焚，新茅又初架。", "前日洪州牧，念此常嗟訝。牧民未及久，郡邑紛如化。", "峻邸儼相望，飛甍遠相跨。旗亭紅粉泥，佛廟青鴛瓦。", "斯事才未終，斯人久雲謝。有客自洪來，洪民至今藉。", "惜其心太亟，作役無容暇。台觀亦已多，工徒稍冤吒。", "我欲他郡長，三時務耕稼。農收次邑居，先室後臺榭。", "啟閉既及期，公私亦相借。度材無強略，庀役有定價。", "不使及僭差，粗得禦寒夏。火至殊陳鄭，人安極嵩華。", "誰能繼此名，名流襲蘭麝。五袴有前聞，斯言我非詐。"]'),
('yuding-8','後湖','元稹','唐','御定全唐诗','yuding','','[]','荊有泥濘水，在荊之邑郛。郛前水在後，謂之為後湖。',288,'御定全唐詩/json/398.json','["荊有泥濘水，在荊之邑郛。郛前水在後，謂之為後湖。", "環湖十餘裏，歲積潢與汙。臭腐魚鱉死，不植菰與蒲。", "鄭公理三載，其理用喣愉。歲稔民四至，隘廛亦隘衢。", "公乃署其地，為民先矢謨。人人儻自為，我亦不庀徒。", "下裏得聞之，各各相俞俞。提攜翁及孫，捧戴婦與姑。", "壯者負礫石，老亦捽茅芻。斤磨片片雪，椎隱連連珠。", "朝餐布庭落，夜宿完戶樞。鄰里近相告，新戚遠相呼。", "鬻者自為鬻，酤者自為酤。雞犬豐中市，人民岐下都。", "百年廢滯所，一旦奧浩區。我實司水土，得為官事無。", "人言賤事貴，貴直不貴諛。此實公所小，安用歌袴襦。", "答雲潭及廣，以至鄂與吳。萬里盡澤國，居人皆墊濡。", "富者不容蓋，貧者不庇軀。得不歌此事，以我為楷模。"]'),
('yuding-9','八駿圖詩','元稹','唐','御定全唐诗','yuding','','[]','穆滿志空闊，將行九州野。神馭四來歸，天與八駿馬。',120,'御定全唐詩/json/398.json','["穆滿志空闊，將行九州野。神馭四來歸，天與八駿馬。", "龍種無凡性，龍行無暫舍。朝辭扶桑底，暮宿昆侖下。", "鼻息吼春雷，蹄聲裂寒瓦。尾掉滄波黑，汗染白雲赭。", "華輈本修密，翠蓋尚妍冶。禦者腕不移，乘者寐不假。", "車無輪扁斫，轡無王良把。雖有萬駿來，誰是敢騎者。"]'),
('yuding-10','畫松','元稹','唐','御定全唐诗','yuding','','[]','張璪畫古松，往往得神骨。翠帚掃春風，枯龍戛寒月。',72,'御定全唐詩/json/398.json','["張璪畫古松，往往得神骨。翠帚掃春風，枯龍戛寒月。", "流傳畫師輩，奇態盡埋沒。纖枝無蕭灑，頑幹空突兀。", "乃悟埃塵心，難狀煙霄質。我去淅陽山，深山看真物。"]'),
('yuding-11','遣興十首','元稹','唐','御定全唐诗','yuding','','[]','始見梨花房，坐對梨花白。行看梨葉青，已複梨葉赤。',481,'御定全唐詩/json/398.json','["始見梨花房，坐對梨花白。行看梨葉青，已複梨葉赤。", "嚴霜九月半，危蒂幾時客。況有高高原，秋風四來迫。", "莫厭夏日長，莫愁冬日短。欲識短複長，君看寒又暖。", "城中百萬家，冤哀雜絲管。草沒奉誠園，軒車昔曾滿。", "孤竹迸荒園，誤與蓬麻列。久擁蕭蕭風，空長高高節。", "嚴霜蕩群穢，蓬斷麻亦折。獨立轉亭亭，心期鳳凰別。", "豔豔翦紅英，團團削翠莖。托根在褊淺，因依泥滓生。", "中有合歡蕊，池枯難遽呈。涼宵露華重，低徊當月明。", "晚荷猶展卷，早蟬遽蕭嘹。露葉行已重，況乃江風搖。", "炎夏火再伏，清商暗回飆。寄言抱志士，日月東西跳。", "買馬買鋸牙，買犢買破車。養禽當養鶻，種樹先種花。", "人生負俊健，天意與光華。莫學蚯蚓輩，食泥近土涯。", "愛直莫愛誇，愛疾莫愛斜。愛謨莫愛詐，愛施莫愛奢。", "擇才不求備，任物不過涯。用人如用己，理國如理家。", "z8々刀刃光，彎彎弓面張。入水斬犀兕，上山椎虎狼。", "裏中無老少，喚作癲兒郎。一日風雲會，橫行歸故鄉。", "團團規內星，未必明如月。托跡近北辰，周天無淪沒。", "老人在南極，地遠光不發。見則壽聖明，願照高高闕。", "河清諒嘉瑞，吾帝真聖人。時哉不我夢，此時為廢民。", "光陰本跳躑，功業勞苦辛。一到江陵郡，三年成去塵。"]'),
('yuding-12','野節鞭','元稹','唐','御定全唐诗','yuding','','[]','神鞭鞭宇宙，玉鞭鞭騏驥。緊綛野節鞭，本用鞭贔屭。',288,'御定全唐詩/json/398.json','["神鞭鞭宇宙，玉鞭鞭騏驥。緊綛野節鞭，本用鞭贔屭。", "使君鞭甚長，使君馬亦利。司馬並馬行，司馬馬憔悴。", "短鞭不可施，疾步無由致。使君駐馬言，願以長鞭遺。", "此遺不尋常，此鞭不容易。金堅無繳繞，玉滑無塵膩。", "青蛇坼生石，不刺山阿地。烏龜旋眼斑，不染江頭淚。", "長看雷雨痕，未忍駑駘試。持用換所持，無令等閒棄。", "答雲君何奇，贈我君所貴。我用亦不凡，終身保明義。", "誓以鞭奸頑，不以鞭蹇躓。指撝狡兔蹤，決撻怪龍睡。", "惜令寸寸折，節節不虛墜。因作換鞭詩，詩成謂同志。", "而我得聞之，笑君年少意。安用換長鞭，鞭長亦奚為。", "我有鞭尺餘，泥拋風雨漬。不擬閑贈行，唯將爛誇醉。", "春來信馬頭，款緩花前轡。願我遲似攣，饒君疾如翅。"]'),
('yuding-0','旱災自咎，貽七縣宰同州時','元稹','唐','御定全唐诗','yuding','','[]','吾聞上帝心，降命明且仁。臣稹苟有罪，胡不災我身。',456,'御定全唐詩/json/399.json','["吾聞上帝心，降命明且仁。臣稹苟有罪，胡不災我身。", "胡為旱一州，禍此千萬人。一旱猶可忍，其旱亦已頻。", "臘雪不滿地，膏雨不降春。惻惻詔書下，半減麥與緡。", "半租豈不薄，尚竭力與筋。竭力不敢憚，慚戴天子恩。", "累累婦拜姑，呐呐翁語孫。禾黍日夜長，足得盈我囷。", "還填折粟稅，酬償貰麥鄰。苟無公私責，飲水不為貧。", "歡言未盈口，旱氣已再振。六月天不雨，秋孟亦既旬。", "區區昧陋積，禱祝非不勤。日馳衰白顏，再拜泥甲鱗。", "歸來重思忖，願告諸邑君。以彼天道遠，豈如人事親。", "團團囹圄中，無乃冤不申。擾擾食廩內，無乃奸有因。", "軋軋輸送車，無乃使不倫。遙遙負擔卒，無乃役不均。", "今年無大麥，計與珠玉濱。村胥與裏吏，無乃求取繁。", "符下斂錢急，值官因酒嗔。誅求與撻罰，無乃不逡巡。", "生小下裏住，不曾州縣門。訴詞千萬恨，無乃不得聞。", "強豪富酒肉，窮獨無芻薪。俱由案牘吏，無乃移禍屯。", "官分市井戶，迭配水陸珍。未蒙所償直，無乃不敢言。", "有一於此事，安可尤蒼旻。借使漏刑憲，得不虞鬼神。", "自顧頑滯牧，坐貽災沴臻。上羞朝廷寄，下愧閭裏民。", "豈無神明宰，為我同苦辛。共布慈惠語，慰此衢客塵。"]'),
('yuding-1','蟲豸詩：巴蛇','元稹','唐','御定全唐诗','yuding','','[]','巴蛇千種毒，其最鼻褰蛇。掉舌翻紅焰，盤身蹙白花。',144,'御定全唐詩/json/399.json','["巴蛇千種毒，其最鼻褰蛇。掉舌翻紅焰，盤身蹙白花。", "噴人豎毛髮，飲浪沸泥沙。欲學叔敖瘞，其如多似麻。", "越嶺南濱海，武都西隱戎。雄黃假名石，鷣鳥遠難籠。", "詎有隳腸計，應無破腦功。巴山晝昏黑，妖霧毒濛濛。", "漢帝斬蛇劍，晉時燒上天。自茲繁巨蟒，往往壽千年。", "白晝遮長道，青溪蒸毒煙。戰龍蒼海外，平地血浮船。"]'),
('yuding-2','蟲豸詩：蛒蜂','元稹','唐','御定全唐诗','yuding','','[]','巴蛇蟠窟穴，穴下有巢蜂。近樹禽垂翅，依原獸絕蹤。',144,'御定全唐詩/json/399.json','["巴蛇蟠窟穴，穴下有巢蜂。近樹禽垂翅，依原獸絕蹤。", "微遭斷手足，厚毒破心胸。昔甚招魂句，那知眼自逢。", "梨笑清都月，蜂遊紫殿春。構脾分部伍，嚼蕊奉君親。", "翅羽頗同類，心神固異倫。安知人世裏，不有噬人人。", "蘭蕙本同畹，蜂蛇亦雜居。害心俱毒螫，妖焰兩吹噓。", "雷蟄吞噬止，枯焚巢穴除。可憐相濟惡，勿謂禍無餘。"]'),
('yuding-3','蟲豸詩：蜘蛛','元稹','唐','御定全唐诗','yuding','','[]','蜘蛛天下足，巴蜀就中多。縫隙容長踦，虛空織橫羅。',144,'御定全唐詩/json/399.json','["蜘蛛天下足，巴蜀就中多。縫隙容長踦，虛空織橫羅。", "縈纏傷竹柏，吞噬及蟲蛾。為送佳人喜，珠櫳無奈何。", "網密將求食，絲斜誤著人。因依方紀緒，掛罥遂容身。", "截道蟬冠礙，漫天玉露頻。兒童憐小巧，漸欲及車輪。", "稚子憐圓網，佳人祝喜絲。那知緣暗隙，忽被齧柔肌。", "毒腠攻猶易，焚心療恐遲。看看長祆緒，和扁欲漣洏。"]'),
('yuding-4','蟲豸詩：蟻子','元稹','唐','御定全唐诗','yuding','','[]','蟻子生無處，偏因濕處生。陰霪煩擾攘，拾粒苦嚶嚀。',145,'御定全唐詩/json/399.json','["蟻子生無處，偏因濕處生。陰霪煩擾攘，拾粒苦嚶嚀。", "床上主人病，耳中虛藏鳴。雷霆翻不省，聞汝作牛聲。", "時術功雖細，年深禍亦成。攻穿漏江海，噆食困蛟鯨。", "敢憚榱dw蠹，深藏柱石傾。寄言持重者，微物莫全輕。", "攘攘終朝見，悠悠卒歲疑。詎能分牝牡，焉得有蝝蚳。", "徙市竟何意，生涯都幾時。巢由或逢我，應似我相期。"]'),
('yuding-5','蟲豸詩：蟆子','元稹','唐','御定全唐诗','yuding','','[]','蟆子微於蚋，朝繁夜則無。毫端生羽翼，針喙噆肌膚。',144,'御定全唐詩/json/399.json','["蟆子微於蚋，朝繁夜則無。毫端生羽翼，針喙噆肌膚。", "暗毒應難免，羸形日漸枯。將身遠相就，不敢恨非辜。", "晦景權藏毒，明時敢噬人。不勞生詬怒，只足助酸辛。", "隼眥看無物，蛇軀庇有鱗。天方芻狗我，甘與爾相親。", "有口深堪異，趨時詎可量。誰令通鼻息，何故辨馨香。", "沉水來滄海，崇蘭泛露光。那能枉焚爇，爾眾我微茫。"]'),
('yuding-6','蟲豸詩：浮塵子','元稹','唐','御定全唐诗','yuding','','[]','可歎浮塵子，纖埃喻此微。寧論隔紗幌，並解透綿衣。',144,'御定全唐詩/json/399.json','["可歎浮塵子，纖埃喻此微。寧論隔紗幌，並解透綿衣。", "有毒能成痏，無聲不見飛。病來雙眼暗，何計辨雰霏。", "乍可巢蚊睫，胡為附蟒鱗。已微於蠢蠢，仍害及仁人。", "動植皆分命，毫芒亦是身。哀哉此幽物，生死敵浮塵。", "但覺皮膚憯，安知瑣細來。因風吹薄霧，向日誤輕埃。", "暗齧堪銷骨，潛飛有禍胎。然無防備處，留待雪霜摧。"]'),
('yuding-7','蟲豸詩：虻','元稹','唐','御定全唐诗','yuding','','[]','陰深山有瘴，濕墊草多虻。眾噬錐刀毒，群飛風雨聲。',144,'御定全唐詩/json/399.json','["陰深山有瘴，濕墊草多虻。眾噬錐刀毒，群飛風雨聲。", "汗粘瘡痏痛，日曝苦辛行。飽爾蛆殘腹，安知天地情。", "千山溪沸石，六月火燒雲。自顧生無類，那堪毒有群。", "搏牛皮若截，噬馬血成文。蹄角尚如此，肌膚安可雲。", "辛螫終非久，炎涼本遞興。秋風自天落，夏蘖與霜澄。", "一鏡開潭面，千鋒露石棱。氣平蟲豸死，雲路好攀登。"]'),
('yuding-8','楚歌十首','元稹','唐','御定全唐诗','yuding','','[]','楚人千萬戶，生死系時君。當璧便為嗣，賢愚安可分。',480,'御定全唐詩/json/399.json','["楚人千萬戶，生死系時君。當璧便為嗣，賢愚安可分。", "干戈長浩浩，篡亂亦紛紛。縱有明在下，區區何足雲。", "陶虞事已遠，尼父獨將明。潛穴龍無位，幽林蘭自生。", "楚王謀授邑，此意複中傾。未別子西語，縱來何所成。", "平王漸昏惑，無極轉承恩。子建猶相貳，伍奢安得存。", "生居宮雉閟，死葬寢園尊。豈料奔吳士，鞭屍郢市門。", "懼盈因鄧曼，罷獵為樊姬。盛德留金石，清風鑒薄帷。", "襄王忽妖夢，宋玉複淫辭。萬事捐宮館，空山雲雨期。", "宜僚南市住，未省食人恩。臨難忽相感，解紛寧用言。", "何如晉夷甫，坐占紫微垣。看著五胡亂，清談空自尊。", "誰恃王深寵，誰為楚上卿。包胥心獨許，連夜哭秦兵。", "千乘徒虛爾，一夫安可輕。殷勤聘名士，莫但倚方城。", "梁業雄圖盡，遺孫世運消。宣明徒有號，江漢不相朝。", "碑碣高臨路，松枝半作樵。唯餘開聖寺，猶學武皇妖。", "江陵南北道，長有遠人來。死別登舟去，生心上馬回。", "榮枯誠異日，今古盡同灰。巫峽朝雲起，荊王安在哉。", "三峽連天水，奔波萬里來。風濤各自急，前後苦相推。", "倒入黃牛漩，驚沖灩澦堆。古今流不盡，流去不曾回。", "八荒同日月，萬古共山川。生死既由命，興衰還付天。", "棲棲王粲賦，憤憤屈平篇。各自埋幽恨，江流終宛然。"]'),
('yuding-9','襄陽道','元稹','唐','御定全唐诗','yuding','','[]','羊公名漸遠，唯有峴山碑。近日稱難繼，曹王任馬彝。',48,'御定全唐詩/json/399.json','["羊公名漸遠，唯有峴山碑。近日稱難繼，曹王任馬彝。", "椒蘭俱下世，城郭到今時。漢水清如玉，流來本為誰。"]'),
('yuding-10','賦得魚登龍門','元稹','唐','御定全唐诗','yuding','','[]','魚貫終何益，龍門在苦登。有成當作雨，無用恥為鵬。',72,'御定全唐詩/json/399.json','["魚貫終何益，龍門在苦登。有成當作雨，無用恥為鵬。", "激浪誠難溯，雄心亦自憑。風雲潛會合，鬐鬣忽騰淩。", "泥滓辭河濁，煙霄見海澄。回瞻順流輩，誰敢望同升。"]'),
('yuding-11','貞元曆','元稹','唐','御定全唐诗','yuding','','[]','象魏才頒曆，龍鑣已禦天。猶看後元曆，新署永貞年。',48,'御定全唐詩/json/399.json','["象魏才頒曆，龍鑣已禦天。猶看後元曆，新署永貞年。", "半歲光陰在，三朝禮數遷。無因書簡冊，空得詠詩篇。"]'),
('yuding-12','塞馬','元稹','唐','御定全唐诗','yuding','','[]','塞馬倦江渚，今朝神彩生。曉風寒獵獵，乍得草頭行。',48,'御定全唐詩/json/399.json','["塞馬倦江渚，今朝神彩生。曉風寒獵獵，乍得草頭行。", "夷狄寢烽候，關河無戰聲。何由當陣面，從爾四蹄輕。"]'),
('yuding-13','鹿角鎮','元稹','唐','御定全唐诗','yuding','','[]','去年湖水滿，此地覆行舟。萬怪吹高浪，千人死亂流。',48,'御定全唐詩/json/399.json','["去年湖水滿，此地覆行舟。萬怪吹高浪，千人死亂流。", "誰能問帝子，何事寵陽侯。漸恐鯨鯢大，波濤及九州。"]'),
('yuding-14','感事三首','元稹','唐','御定全唐诗','yuding','','[]','為國謀羊舌，從來不為身。此心長自保，終不學張陳。',72,'御定全唐詩/json/399.json','["為國謀羊舌，從來不為身。此心長自保，終不學張陳。", "自笑心何劣，區區辨所冤。伯仁雖到死，終不向人言。", "富貴年皆長，風塵舊轉稀。白頭方見絕，遙為一沾衣。"]'),
('yuding-15','題翰林東閣前小松','元稹','唐','御定全唐诗','yuding','','[]','簷礙修鱗亞，霜侵簇翠黃。唯餘入琴韻，終待舜弦張。',24,'御定全唐詩/json/399.json','["簷礙修鱗亞，霜侵簇翠黃。唯餘入琴韻，終待舜弦張。"]'),
('yuding-0','《清都夜境','元稹','唐','御定全唐诗','yuding','','[]','夜久連觀靜，斜月何晶熒。寥天如碧玉，歷歷綴華星。',120,'御定全唐詩/json/400.json','["夜久連觀靜，斜月何晶熒。寥天如碧玉，歷歷綴華星。", "樓榭自陰映，雲牖深冥冥。纖埃悄不起，玉砌寒光清。", "棲鶴露微影，枯松多怪形。南廂儼容衛，音響如可聆。", "啟聖發空洞，朝真趨廣庭。閑開蕊珠殿，暗閱金字經。", "屏氣動方息，凝神心自靈。悠悠車馬上，浩思安得寧。"]'),
('yuding-1','春晚寄楊十二，兼呈趙八','元稹','唐','御定全唐诗','yuding','','[]','濛濛竹樹深，簾牖多清陰。避日坐林影，餘花委芳襟。',108,'御定全唐詩/json/400.json','["濛濛竹樹深，簾牖多清陰。避日坐林影，餘花委芳襟。", "傾尊就殘酌，舒卷續微吟。空際颺高蝶，風中聆素琴。", "廣庭備幽趣，複對商山岑。獨此愛時景，曠懷雲外心。", "遷鶯戀嘉木，求友多好音。自無琅玕實，安得蓮花簪。", "寄之二君子，希見雙南金。"]'),
('yuding-2','與楊十二、李三早入永壽寺看牡丹','元稹','唐','御定全唐诗','yuding','','[]','曉入白蓮宮，琉璃花界淨。開敷多喻草，淩亂被幽徑。',96,'御定全唐詩/json/400.json','["曉入白蓮宮，琉璃花界淨。開敷多喻草，淩亂被幽徑。", "壓砌錦地鋪，當霞日輪映。蝶舞香暫飄，蜂牽蕊難正。", "籠處彩雲合，露湛紅珠瑩。結葉影自交，搖風光不定。", "繁華有時節，安得保全盛。色見盡浮榮，希君了真性。"]'),
('yuding-3','春餘遣興','元稹','唐','御定全唐诗','yuding','','[]','春去日漸遲，庭空草偏長。餘英間初實，雪絮縈蛛網。',144,'御定全唐詩/json/400.json','["春去日漸遲，庭空草偏長。餘英間初實，雪絮縈蛛網。", "好鳥多息陰，新篁已成響。簾開斜照入，樹褭遊絲上。", "絕跡念物閑，良時契心賞。單衣頗新綽，虛室複清敞。", "置酒奉親賓，樹萱自怡養。笑倚連枝花，恭扶瑞藤杖。", "步屟恣優遊，望山多氣象。雲葉遙卷舒，風裾動蕭爽。", "簪纓固煩雜，江海徒浩蕩。野馬籠赤霄，無由負羈鞅。"]'),
('yuding-4','憶雲之','元稹','唐','御定全唐诗','yuding','','[]','為魚實愛泉，食辛寧避蓼。人生既相合，不復論窕窕。',168,'御定全唐詩/json/400.json','["為魚實愛泉，食辛寧避蓼。人生既相合，不復論窕窕。", "滄海良有窮，白日非長皎。何事一人心，各在四方表。", "泛若逐水萍，居為附松蔦。流浪隨所之，縈紆牽所繞。", "百齡頗局促，況複迷壽夭。芟發君已衰，冠歲予非小。", "娛樂不及時，暮年壯心少。感此幽念綿，遂為長悄悄。", "中庭草木春，曆亂遞相擾。奇樹花冥冥，竹竿鳳褭褭。", "幽芳被蘭徑，安得寄天杪。萬里瀟湘魂，夜夜南枝鳥。"]'),
('yuding-5','別李三','元稹','唐','御定全唐诗','yuding','','[]','階蓂附瑤砌，叢蘭偶芳藿。高位良有依，幽姿亦相托。',96,'御定全唐詩/json/400.json','["階蓂附瑤砌，叢蘭偶芳藿。高位良有依，幽姿亦相托。", "鮑叔知我貧，烹葵不為薄。半面契始終，千金比然諾。", "人生系時命，安得無苦樂。但感遊子顏，又值餘英落。", "蒼蒼秦樹雲，去去緱山鶴。日暮分手歸，楊花滿城郭。"]'),
('yuding-6','秋夕遠懷','元稹','唐','御定全唐诗','yuding','','[]','旦夕天氣爽，風飄葉漸輕。星繁河漢白，露逼衾枕清。',48,'御定全唐詩/json/400.json','["旦夕天氣爽，風飄葉漸輕。星繁河漢白，露逼衾枕清。", "丹鳥月中滅，莎雞床下鳴。悠悠此懷抱，況複多遠情。"]'),
('yuding-7','東西道','元稹','唐','御定全唐诗','yuding','','[]','天皇開四極，便有東西道。萬古閱行人，行人幾人老。',48,'御定全唐詩/json/400.json','["天皇開四極，便有東西道。萬古閱行人，行人幾人老。", "顧我倦行者，息陰何不早。少壯塵事多，那言壯年好。"]'),
('yuding-8','分流水','元稹','唐','御定全唐诗','yuding','','[]','古時愁別淚，滴作分流水。日夜東西流，分流幾千里。',48,'御定全唐詩/json/400.json','["古時愁別淚，滴作分流水。日夜東西流，分流幾千里。", "通塞兩不見，波瀾各自起。與君相背飛，去去心如此。"]'),
('yuding-9','西還','元稹','唐','御定全唐诗','yuding','','[]','悠悠洛陽夢，鬱鬱灞陵樹。落日正西歸，逢君又東去。',24,'御定全唐詩/json/400.json','["悠悠洛陽夢，鬱鬱灞陵樹。落日正西歸，逢君又東去。"]'),
('yuding-10','含風夕','元稹','唐','御定全唐诗','yuding','','[]','炎昏倦煩久，逮此含風夕。夏服稍輕清，秋堂已岑寂。',240,'御定全唐詩/json/400.json','["炎昏倦煩久，逮此含風夕。夏服稍輕清，秋堂已岑寂。", "載欣涼宇曠，複念佳辰擲。絡緯驚歲功，顧我何成績。", "青熒微月鉤，幽暉洞陰魄。水鏡涵玉輪，若見淵泉璧。", "參差簾牖重，次第籠虛白。樹影滿空床，螢光綴深壁。", "悵望牽牛星，複為經年隔。露網褭風珠，輕河泛遙碧。", "詎無深秋夜，感此乍流易。亦有遲暮年，壯年良自惜。", "迴圈切中腸，感念追往昔。接瞬無停陰，何言問陳積。", "馨香推蕙蘭，堅貞諭松柏。生物固有涯，安能比金石。", "況茲百齡內，擾擾紛眾役。日月東西馳，飛車無留跡。", "來者良未窮，去矣定奚適。委順在物為，營營複何益。"]'),
('yuding-11','秋堂夕','元稹','唐','御定全唐诗','yuding','','[]','炎涼正回互，金火鬱相乘。雲雷時交構，川澤方蒸騰。',216,'御定全唐詩/json/400.json','["炎涼正回互，金火鬱相乘。雲雷時交構，川澤方蒸騰。", "清風一朝勝，白露忽已凝。草木凡氣盡，始見天地澄。", "況此秋堂夕，幽懷曠無朋。蕭條簾外雨，倏閃案前燈。", "書卷滿床席，蠨蛸懸複升。啼兒屢啞咽，倦僮時寢興。", "泛覽昏夜目，詠謠暢煩膺。況吟獲麟章，欲罷久不能。", "堯舜事已遠，丘道安可勝。蜉蝣不信鶴，蜩鷃肯窺鵬。", "當年且不偶，沒世何必稱。胡為揭聞見，褒貶貽愛憎。", "焉用汩其泥，豈在清如冰。非白又非黑，誰能點青蠅。", "處世苟無悶，佯狂道非弘。無言被人覺，予亦笑孫登。"]'),
('yuding-12','酬樂天','元稹','唐','御定全唐诗','yuding','','[]','放鶴在深水，置魚在高枝。升沉或異勢，同謂非所宜。',144,'御定全唐詩/json/400.json','["放鶴在深水，置魚在高枝。升沉或異勢，同謂非所宜。", "君為邑中吏，皎皎鸞鳳姿。顧我何為者，翻侍白玉墀。", "昔作芸香侶，三載不暫離。逮茲忽相失，旦夕夢魂思。", "崔嵬驪山頂，宮樹遙參差。只得兩相望，不得長相隨。", "多君歲寒意，裁作秋興詩。上言風塵苦，下言時節移。", "官家事拘束，安得攜手期。願為雲與雨，會合天之垂。"]'),
('yuding-13','楊子華畫三首','元稹','唐','御定全唐诗','yuding','','[]','楊畫遠于展，何言今在茲。依然古妝服，但感時節移。',168,'御定全唐詩/json/400.json','["楊畫遠于展，何言今在茲。依然古妝服，但感時節移。", "念君一朝意，遺我千載思。子亦幾時客，安能長苦悲。", "皓腕卷紅袖，錦鞲臂蒼鶚。故人斷弦心，稚齒從禽樂。", "當年惜貴遊，遺形寄丹雘。骨象或依稀，鉛華已寥落。", "似對古人民，無複昔城郭。子亦觀病身，色空俱寂寞。", "顛倒世人心，紛紛乏公是。真賞畫不成，畫賞真相似。", "丹青各所尚，工拙何足恃。求此妄中精，嗟哉子華子。"]'),
('yuding-14','西州院','元稹','唐','御定全唐诗','yuding','','[]','自入西州院，唯見東川城。今夜城頭月，非暗又非明。',144,'御定全唐詩/json/400.json','["自入西州院，唯見東川城。今夜城頭月，非暗又非明。", "文案床席滿，卷舒贓罪名。慘淒且煩倦，棄之階下行。", "悵望天回轉，動搖萬里情。參辰次第出，牛女顛倒傾。", "況此風中柳，枝條千萬莖。到來籬下筍，亦已長短生。", "感愴正多緒，鴉鴉相喚驚。牆上杜鵑鳥，又作思歸鳴。", "以彼撩亂思，吟為幽怨聲。吟罷終不寢，冬冬複鐺鐺。"]'),
('yuding-15','台中鞫獄憶開元觀舊事呈損之兼贈周兄四十韻','元稹','唐','御定全唐诗','yuding','','[]','憶在開元館，食柏練玉顏。疏慵日高臥，自謂輕人寰。',482,'御定全唐詩/json/400.json','["憶在開元館，食柏練玉顏。疏慵日高臥，自謂輕人寰。", "李生隔牆住，隔牆如隔山。怪我久不識，先來問驕頑。", "十過乃一往，遂成相往還。以我文章卷，文章甚斒斕。", "因言辛庾輩，亦願放羸孱。既回數子顧，輾轉相連攀。", "驅令選科目，若在闠與闤。學隨塵土墜，漫數公卿關。", "唯恐壞情性，安能懼謗訕。還招辛庾李，靜處杯巡環。", "進取果由命，不由趨險艱。穿楊二三子，弓矢次第彎。", "推我亦上道，再聯朝士班。二月除禦史，三月使巴蠻。", "蠻民詀諵訴，齧指明痛癏。憐蠻不解語，為發昏帥奸。", "歸來五六月，旱色天地殷。分司別兄弟，各各淚潸潸。", "哀哉劇部職，唯數贓罪鍰。死款依稀取，鬥辭方便刪。", "道心常自愧，柔發難久黫。折支望車乘，支痛誰置患。", "奇哉乳臭兒，緋紫繃被間。漸大官漸貴，漸富心漸慳。", "鬧裝轡頭觼，靜拭腰帶斑。鷂子繡線oT，狗兒金油環。", "香湯洗驄馬，翠篾籠白鷳。月請公王封，冰受天子頒。", "開筵試歌舞，別宅寵妖嫻。坐臥摩綿褥，捧擁綟絲鬟。", "旦夕不相離，比翼若飛鸞。而我亦何苦，三十身已鰥。", "愁吟心骨顫，寒臥支體m5。居處雖幽靜，尤悔少愉懶。", "不如周道士，鶴嶺臨鐘灣。繞院松瑟瑟，通畦水潺潺。", "陽坡自尋蕨，村沼看漚菅。窮通兩未遂，營營真老閑。"]'),
('yuding-16','韋氏館與周隱客、杜歸和泛舟','元稹','唐','御定全唐诗','yuding','','[]','天色低澹澹，池光漫油油。輕舟閑繳繞，不遠池上樓。',96,'御定全唐詩/json/400.json','["天色低澹澹，池光漫油油。輕舟閑繳繞，不遠池上樓。", "時物欣外獎，真元隨內修。神恬津藏滿，氣委支節柔。", "眾處豈自異，曠懷誰我儔。風車籠野馬，八荒安足遊。", "開顏陸渾杜，握手靈都周。持君寶珠贈，頂戴頭上頭。"]'),
('yuding-17','劉氏館集隱客、歸和、子元、及之、子蒙、晦之','元稹','唐','御定全唐诗','yuding','','[]','濕墊緣竹徑，寥落護岸冰。偶然沽市酒，不越四五升。',48,'御定全唐詩/json/400.json','["濕墊緣竹徑，寥落護岸冰。偶然沽市酒，不越四五升。", "詩客愛時景，道人話升騰。笑言各有趣，悠哉古孫登。"]'),
('yuding-18','寄隱客','元稹','唐','御定全唐诗','yuding','','[]','我年三十二，鬢有八九絲。非無官次第，其如身早衰。',144,'御定全唐詩/json/400.json','["我年三十二，鬢有八九絲。非無官次第，其如身早衰。", "今人誇貴富，肉食與妖姬。而我俱不樂，貴富亦何為。", "況逢多士朝，賢俊若布棋。班行次第立，朱紫相參差。", "謨猷密勿進，羽檄縱橫馳。監察官甚小，發言無所裨。", "小官仍不了，譴奪亦已隨。時或不之棄，得不自棄之。", "陶君喜不遇，顧我複何疑。潛書周隱士，白雲今有期。"]'),
('yuding-19','元和五年予官不了罰俸西歸三月六日至陝府與吳十一兄端公崔二十二院長思愴曩游因投五十韻','元稹','唐','御定全唐诗','yuding','','[]','小年閑愛春，認得春風意。未有花草時，先醲曉窗睡。',576,'御定全唐詩/json/400.json','["小年閑愛春，認得春風意。未有花草時，先醲曉窗睡。", "霞朝澹雲色，霽景牽詩思。漸到柳枝頭，川光始明媚。", "長安車馬客，傾心奉權貴。晝夜塵土中，那言早春至。", "此時我獨游，我遊有倫次。閑行曲江岸，便宿慈恩寺。", "扣林引寒龜，疏叢出幽翠。淩晨過杏園，曉露凝芳氣。", "初陽好明淨，嫩樹憐低庳。排房似綴珠，欲啼紅臉淚。", "新鶯語嬌小，淺水光流利。冷飲空腹杯，因成日高醉。", "酒醒聞飯鐘，隨僧受遺施。餐罷還複游，過從上文記。", "行逢二月半，始足遊春騎。是時春已老，我遊亦雲既。", "藤開九華觀，草結三條隧。新筍踴犀株，落梅翻蝶翅。", "名倡繡轂車，公子青絲轡。朝士還旬休，豪家得春賜。", "提攜好音樂，翦鏟空田地。同占杏花園，喧闐各叢萃。", "顧予煩寢興，複往散憔悴。倦僕色肌羸，蹇驢行跛痹。", "春衫未成就，冬服漸塵膩。傾蓋吟短章，書空憶難字。", "遙聞公主笑，近被王孫戲。邀我上華筵，橫頭坐賓位。", "那知我年少，深解酒中事。能唱犯聲歌，偏精變籌義。", "含詞待殘拍，促舞遞繁吹。叫噪擲投盤，生獰攝觥使。", "逡巡光景晏，散亂東西異。古觀閉閑門，依然複幽閟。", "無端矯情性，漫學求科試。薄藝何足雲，虛名偶頻遂。", "拾遺天子前，密奏升平議。召見不須臾，憸庸已猜忌。", "朝陪香案班，暮作風塵尉。去歲又登朝，登為柏台吏。", "台官相束縛，不許放情志。寓直勞送迎，上堂煩避諱。", "分司在東洛，所職尤不易。罰俸得西歸，心知受朝庇。", "常山攻小寇，淮右擇良帥。國難身不行，勞生欲何為。"]'),
('yuding-0','寄吳士矩端公五十韻','元稹','唐','御定全唐诗','yuding','','[]','昔在鳳翔日，十歲即相識。未有好文章，逢人賞顏色。',577,'御定全唐詩/json/401.json','["昔在鳳翔日，十歲即相識。未有好文章，逢人賞顏色。", "可憐何郎面，二十才冠飾。短髮予近梳，羅衫紫蟬翼。", "伯舅各驕縱，仁兄未摧抑。事業若杯盤，詩書甚徽纆。", "西州戎馬地，賢豪事雄特。百萬時可贏，十千良易借。", "寒食桐陰下，春風柳林側。藉草送遠遊，列筵酬博塞。", "萎蕤雲幕翠，燦爛紅茵赩。膾縷輕似絲，香醅膩如職。", "將軍頻下城，佳人盡傾國。媚語嬌不聞，纖腰軟無力。", "歌辭妙宛轉，舞態能剜刻。箏弦玉指調，粉汗紅綃拭。", "予時最年少，專務酒中職。未能解生獰，偏矜任狂直。", "曲庇桃根盞，橫講捎雲式。亂布鬥分朋，惟新間讒慝。", "恥作最先吐，羞言未朝食。醉眼漸紛紛，酒聲頻cH々。", "扣節參差亂，飛觥往來織。強起相維持，翻成兩匍匐。", "邊霜颯然降，戰馬鳴不息。但喜秋光麗，誰憂塞雲黑。", "常隨獵騎走，多在豪家匿。夜飲天既明，朝歌日還昃。", "荒狂歲雲久，名利心潛逼。時輩多得途，親朋屢相敕。", "閑因適農野，忽複愛稼穡。平生中聖人，翻然腐腸賊。", "亦從酒仙去，便被書魔惑。脫跡壯士場，甘心豎儒域。", "矜持翠筠管，敲斷黃金勒。屢益蘭膏燈，猶研兔枝墨。", "崎嶇來掉蕩，矯枉事沉默。隱笑甚艱難，斂容還屴崱。", "與君始分散，勉我勞修飾。岐路各營營，別離長惻惻。", "行看二十載，萬事紛何極。相值或須臾，安能洞胸臆。", "昨來陝郊會，悲歡兩難克。問我新相知，但報長相憶。", "豈無新知者，不及小相得。亦有生歲游，同年不同德。", "為別詎幾時，伊予墜溝洫。大江鼓風浪，遠道參荊棘。"]'),
('yuding-1','三月二十四日宿曾峰館，夜對桐花，寄樂天','元稹','唐','御定全唐诗','yuding','','[]','微月照桐花，月微花漠漠。怨澹不勝情，低回拂簾幕。',96,'御定全唐詩/json/401.json','["微月照桐花，月微花漠漠。怨澹不勝情，低回拂簾幕。", "葉新陰影細，露重枝條弱。夜久春恨多，風清暗香薄。", "是夕遠思君，思君瘦如削。但感事暌違，非言官好惡。", "奏書金鑾殿，步屣青龍閣。我在山館中，滿地桐花落。"]'),
('yuding-2','酬樂天書懷見寄','元稹','唐','御定全唐诗','yuding','','[]','新昌北門外，與君從此分。街衢走車馬，塵土不見君。',288,'御定全唐詩/json/401.json','["新昌北門外，與君從此分。街衢走車馬，塵土不見君。", "君為分手歸，我行行不息。我上秦嶺南，君直樞星北。", "秦嶺高崔嵬，商山好顏色。月照山館花，裁詩寄相憶。", "天明作詩罷，草草隨所如。憑人寄將去，三月無報書。", "荊州白日晚，城上鼓冬冬。行逢賀州牧，致書三四封。", "封題樂天字，未坼已沾裳。坼書八九讀，淚落千萬行。", "中有酬我詩，句句截我腸。仍雲得詩夜，夢我魂淒涼。", "終言作書處，上直金鑾東。詩書費一夕，萬恨緘其中。", "中宵宮中出，複見宮月斜。書罷月亦落，曉燈隨暗花。", "想君書罷時，南望勞所思。況我江上立，吟君懷我詩。", "懷我浩無極，江水秋正深。清見萬丈底，照我平生心。", "感君求友什，因報壯士吟。持謝眾人口，銷盡猶是金。"]'),
('yuding-3','酬樂天登樂遊園見憶','元稹','唐','御定全唐诗','yuding','','[]','昔君樂遊園，悵望天欲曛。今我大江上，快意波翻雲。',96,'御定全唐詩/json/401.json','["昔君樂遊園，悵望天欲曛。今我大江上，快意波翻雲。", "秋空壓澶漫，澒洞無垢氛。四顧皆豁達，我眉今日伸。", "長安隘朝市，百道走埃塵。軒車隨對列，骨肉非本親。", "誇游丞相第，偷入常侍門。愛君直如發，勿念江湖人。"]'),
('yuding-4','酬樂天早夏見懷','元稹','唐','御定全唐诗','yuding','','[]','庭柚有垂實，燕巢無宿雛。我亦辭社燕，茫茫焉所如。',72,'御定全唐詩/json/401.json','["庭柚有垂實，燕巢無宿雛。我亦辭社燕，茫茫焉所如。", "君詩夏方早，我歎秋已徂。食物風土異，衾裯時節殊。", "荒草滿田地，近移江上居。八日複切九，月明侵半除。"]'),
('yuding-5','酬樂天勸醉','元稹','唐','御定全唐诗','yuding','','[]','神曲清濁酒，牡丹深淺花。少年欲相飲，此樂何可涯。',156,'御定全唐詩/json/401.json','["神曲清濁酒，牡丹深淺花。少年欲相飲，此樂何可涯。", "沉機造神境，不必悟楞伽。酡顏返童貌，安用成丹砂。", "劉伶稱酒德，所稱良未多。願君聽此曲，我為盡稱嗟。", "一杯顏色好，十盞膽氣加。半酣得自恣，酩酊歸太和。", "共醉真可樂，飛觥撩亂歌。獨醉亦有趣，兀然無與他。", "美人醉燈下，左右流橫波。王孫醉床上，顛倒眠綺羅。", "君今勸我醉，勸醉意如何。"]'),
('yuding-6','和樂天初授戶曹喜而言志','元稹','唐','御定全唐诗','yuding','','[]','王爵無細大，得請即為恩。君求戶曹掾，貴以祿奉親。',192,'御定全唐詩/json/401.json','["王爵無細大，得請即為恩。君求戶曹掾，貴以祿奉親。", "聞君得所請，感我欲沾巾。今人重軒冕，所重華與紛。", "矜誇仕台閣，奔走無朝昏。君衣不盈篋，君食不滿囷。", "君言養既薄，何以榮我門。披誠再三請，天子憐儉貧。", "詞曹直文苑，捧詔榮且忻。歸來高堂上，兄弟羅酒尊。", "各稱千萬壽，共飲三四巡。我實知君者，千里能具陳。", "感君求祿意，求祿殊眾人。上以奉顏色，餘以及親賓。", "棄名不棄實，謀養不謀身。可憐白華士，永願淩青雲。"]'),
('yuding-7','和樂天贈吳丹','元稹','唐','御定全唐诗','yuding','','[]','不識吳生面，久知吳生道。跡雖染世名，心本奉天老。',192,'御定全唐詩/json/401.json','["不識吳生面，久知吳生道。跡雖染世名，心本奉天老。", "雌一守命門，回九填血腦。委氣榮衛和，咽津顏色好。", "傳聞共甲子，衰隤盡枯槁。獨有冰雪容，纖華奪鮮縞。", "問人何能爾，吳實曠懷抱。弁冕徒掛身，身外非所寶。", "伊予固童昧，希真亦雲早。石壇玉晨尊，晝夜長自掃。", "密印視丹田，遊神夢三島。萬過黃庭經，一食青精稻。", "冥搜方朔桃，結念安期棗。綠發幸未改，丹誠自能保。", "行當擺塵纓，吳門事探討。君為先此詞，終期搴瑤草。"]'),
('yuding-8','和樂天秋題曲江','元稹','唐','御定全唐诗','yuding','','[]','十載定交契，七年鎮相隨。長安最多處，多是曲江池。',96,'御定全唐詩/json/401.json','["十載定交契，七年鎮相隨。長安最多處，多是曲江池。", "梅杏春尚小，芰荷秋已衰。共愛寥落境，相將偏此時。", "綿綿紅蓼水，颺颺白鷺鶿。詩句偶未得，酒杯聊久持。", "今來雲雨曠，舊賞魂夢知。況乃江楓夕，和君秋興詩。"]'),
('yuding-9','和樂天別弟後月夜作','元稹','唐','御定全唐诗','yuding','','[]','聞君別愛弟，明天照夜寒。秋雁拂簷影，曉琴當砌彈。',72,'御定全唐詩/json/401.json','["聞君別愛弟，明天照夜寒。秋雁拂簷影，曉琴當砌彈。", "悵望天澹澹，因思路漫漫。吟為別弟操，聞者為辛酸。", "況我兄弟遠，一身形影單。江波浩無極，但見時歲闌。"]'),
('yuding-10','和樂天秋題牡丹叢','元稹','唐','御定全唐诗','yuding','','[]','敝宅豔山卉，別來長歎息。吟君晚叢詠，似見摧頹色。',36,'御定全唐詩/json/401.json','["敝宅豔山卉，別來長歎息。吟君晚叢詠，似見摧頹色。", "欲識別後容，勤過晚叢側。"]'),
('yuding-11','春月','元稹','唐','御定全唐诗','yuding','','[]','春月雖至明，終有靄靄光。不似秋冬色，逼人寒帶霜。',240,'御定全唐詩/json/401.json','["春月雖至明，終有靄靄光。不似秋冬色，逼人寒帶霜。", "纖粉澹虛壁，輕煙籠半床。分暉間林影，餘照上虹梁。", "病久塵事隔，夜閑清興長。擁抱顛倒領，步屣東西廂。", "風柳結柔援，露梅飄暗香。雪含櫻綻蕊，珠蹙桃綴房。", "杳杳有餘思，行行安可忘。四鄰非舊識，無以話中腸。", "南有居士儼，默坐調心王。款關一問訊，為我披衣裳。", "延我入深竹，暖我於小堂。視身琉璃瑩，諭指芭蕉黃。", "複有比丘溢，早傳龍樹方。口中秘丹訣，肘後懸青囊。", "錫杖雖獨振，刀圭期共嘗。未知仙近遠，已覺神輕翔。", "夜久魂耿耿，月明露蒼蒼。悲哉沉眠士，寧見茲夕良。"]'),
('yuding-12','月臨花','元稹','唐','御定全唐诗','yuding','','[]','臨風颺颺花，透影朧朧月。巫峽隔波雲，姑峰漏霞雪。',48,'御定全唐詩/json/401.json','["臨風颺颺花，透影朧朧月。巫峽隔波雲，姑峰漏霞雪。", "鏡勻嬌麵粉，燈泛高籠纈。夜久清露多，啼珠墜還結。"]'),
('yuding-13','紅芍藥','元稹','唐','御定全唐诗','yuding','','[]','芍藥綻紅綃，巴籬織青瑣。繁絲蹙金蕊，高焰當爐火。',120,'御定全唐詩/json/401.json','["芍藥綻紅綃，巴籬織青瑣。繁絲蹙金蕊，高焰當爐火。", "翦刻彤雲片，開張赤霞裹。煙輕琉璃葉，風亞珊瑚朵。", "受露色低迷，向人嬌婀娜。酡顏醉後泣，小女妝成坐。", "豔豔錦不如，夭夭桃未可。晴霞畏欲散，晚日愁將墮。", "結植本為誰，賞心期在我。采之諒多思，幽贈何由果。"]'),
('yuding-14','送王十一南行','元稹','唐','御定全唐诗','yuding','','[]','夏水漾天末，晚暘依岸村。風調烏尾勁，眷戀餘芳尊。',120,'御定全唐詩/json/401.json','["夏水漾天末，晚暘依岸村。風調烏尾勁，眷戀餘芳尊。", "解袂方瞬息，征帆已翩翻。江豚湧高浪，楓樹搖去魂。", "遠戍宗侶泊，暮煙洲渚昏。離心詎幾許，驟若移寒溫。", "此別信非久，胡為坐憂煩。我留石難轉，君泛雲無根。", "萬里湖南月，三聲山上猿。從茲耿幽夢，夜夜湘與沅。"]'),
('yuding-15','三歎','元稹','唐','御定全唐诗','yuding','','[]','孤劍鋒刃澀，猶能神彩生。有時雷雨過，暗吼闐闐聲。',240,'御定全唐詩/json/401.json','["孤劍鋒刃澀，猶能神彩生。有時雷雨過，暗吼闐闐聲。", "主人閟靈寶，畏作升天行。淬礪當陽鐵，刻為幹鏌名。", "遠求鸊鵜瑩，同用玉匣盛。顏色縱相類，利鈍頗相傾。", "雄為光電烻，雌但深泓澄。龍怒有奇變，青蛇終不驚。", "仙鳳翠皇死，葳蕤光彩低。非無鴛鸞侶，誓不同樹棲。", "飛馳歲雲暮，感念雛在泥。顧影不自暖，寄爾蟠桃雞。", "馴養豈無愧，類族安得齊。願言成羽翼，奮翅淩丹梯。", "天驥失龍偶，三年常夜嘶。哀緣噴風斷，渴且含霜啼。", "長恐絕遺類，不復躡雲霓。非無駉駉者，鶴意不在雞。", "春來筋骨瘦，吊影心亦迷。自此渥窪種，應生濁水泥。"]'),
('yuding-16','遣晝','元稹','唐','御定全唐诗','yuding','','[]','密竹有清陰，曠懷無塵滓。況乃秋日光，玲瓏曉窗裏。',120,'御定全唐詩/json/401.json','["密竹有清陰，曠懷無塵滓。況乃秋日光，玲瓏曉窗裏。", "旬休聊自適，今辰日高起。櫛沐坐前軒，風輕鏡如水。", "開卷恣詠謠，望雲閑徙倚。新菊媚鮮妍，短萍憐靃靡。", "掃除田地靜，摘掇園蔬美。幽玩愜詩流，空堂稱居士。", "客來傷寂寞，我念遺煩鄙。心跡兩相忘，誰能驗行止。"]'),
('yuding-17','冬夜懷李侍禦、王太祝、段丞','元稹','唐','御定全唐诗','yuding','','[]','浩露煙壒盡，月光閑有餘。松篁細陰影，重以簾牖疏。',144,'御定全唐詩/json/401.json','["浩露煙壒盡，月光閑有餘。松篁細陰影，重以簾牖疏。", "泛覽星粲粲，輕河悠碧虛。纖雲不成葉，脈脈風絲舒。", "丹灶熾東序，燒香羅玉書。飄飄魂神舉，若驂鸞鶴輿。", "感念夙昔意，華尚簪與裾。簪裾詎幾許，累創吞鉤魚。", "今聞馨香道，一以悟臭帑。悟覺誓不惑，永抱胎仙居。", "晝夜欣所適，安知歲雲除。行行二三友，君懷複何如。"]'),
('yuding-18','西齋小松二首','元稹','唐','御定全唐诗','yuding','','[]','松樹短于我，清風亦已多。況乃枝上雪，動搖微月波。',96,'御定全唐詩/json/401.json','["松樹短于我，清風亦已多。況乃枝上雪，動搖微月波。", "幽姿得閒地，詎感歲蹉跎。但恐廈終構，藉君當奈何。", "簇簇枝新黃，纖纖攢素指。柔苙漸依條，短莎還半委。", "清風日夜高，淩雲意何已。千歲盤老龍，修鱗自茲始。"]'),
('yuding-19','周先生','元稹','唐','御定全唐诗','yuding','','[]','寥寥空山岑，冷冷風松林。流月垂鱗光，懸泉揚高音。',48,'御定全唐詩/json/401.json','["寥寥空山岑，冷冷風松林。流月垂鱗光，懸泉揚高音。", "希夷周先生，燒香調琴心。神力盈三千，誰能還黃金。"]'),
('yuding-0','遣春十首','元稹','唐','御定全唐诗','yuding','','[]','曉月籠雲影，鶯聲餘霧中。暗芳飄露氣，輕寒生柳風。',480,'御定全唐詩/json/402.json','["曉月籠雲影，鶯聲餘霧中。暗芳飄露氣，輕寒生柳風。", "冉冉一趨府，未為勞我躬。因茲得晨起，但覺情興隆。", "久雨憐霽景，偶來堤上行。空蒙天色嫩，杳淼江面平。", "百草短長出，眾禽高下鳴。春陽各有分，予亦澹無情。", "鏡皎碧潭水，微波粗成文。煙光垂碧草，瓊脈散纖雲。", "岸柳好陰影，風裾遺垢氛。悠然送春目，八荒誰與群。", "低迷籠樹煙，明淨當霞日。陽焰波春空，平湖漫凝溢。", "雪鷺遠近飛，渚牙淺深出。江流複浩蕩，相為坐紆鬱。", "暄寒深淺春，紅白前後花。顏色詎相讓，生成良有涯。", "梅芳勿自早，菊秀勿自賒。各將一時意，終年無再華。", "高屋童稚少，春來歸燕多。葺舊良易就，新院亦已羅。", "俯憐雛化卵，仰愧鵬無窠。巢棟與巢幕，秋風俱奈何。", "撩亂撲樹蜂，摧殘戀房蕊。風吹雨又頻，安得繁於綺。", "酒杯沉易過，世事紛何已。莫倚顏似花，君看歲如水。", "繞郭高高塚，半是荊王墓。後嗣熾陽臺，前賢甘蓽路。", "善惡徒自分，波流盡東注。胡然不飲酒，坐落桐花樹。", "花陰莎草長，藉莎閑自酌。坐看鶯鬥枝，輕花滿尊杓。", "葛巾竹稍掛，書卷琴上閣。沽酒過此生，狂歌眼前樂。", "梨葉已成陰，柳條紛起絮。波綠紫屏風，螺紅碧籌箸。", "三杯面上熱，萬事心中去。我意風散雲，何勞問行處。"]'),
('yuding-1','表夏十首','元稹','唐','御定全唐诗','yuding','','[]','夏風多暖暖，樹木有繁陰。新筍紫長短，早櫻紅淺深。',480,'御定全唐詩/json/402.json','["夏風多暖暖，樹木有繁陰。新筍紫長短，早櫻紅淺深。", "煙花雲幕重，榴豔朝景侵。華實各自好，詎雲芳意沉。", "初日滿階前，輕風動簾影。旬時得休浣，高臥閱清景。", "僮兒拂巾箱，鴉軋深林井。心到物自閑，何勞遠箕潁。", "江瘴炎夏早，蒸騰信難度。今宵好風月，獨此荒庭趣。", "露葉傾暗光，流星委餘素。但恐清夜徂，詎悲朝景暮。", "孟月夏猶淺，奇雲未成峰。度霞紅漠漠，壓浪白溶溶。", "玉委有餘潤，飆馳無去蹤。何如捧雲雨，噴毒隨蛟龍。", "流芳遞炎景，繁英盡寥落。公署香滿庭，晴霞覆闌藥。", "裁紅起高焰，綴綠排新萼。憑此遣幽懷，非言念將謔。", "紅絲散芳樹，旋轉光風急。煙泛被籠香，露濃妝面濕。", "佳人不在此，恨望階前立。忽厭夏景長，今春行已及。", "百舌漸吞聲，黃鶯正嬌小。雲鴻方警夜，籠雞已鳴曉。", "當時客自適，運去誰能矯。莫厭夏蟲多，蜩螗定相擾。", "翩翩簾外燕，戢戢巢內雛。啖食筋力盡，毛衣成紫襦。", "朝來各飛去，雄雌梁上呼。養子將備老，惡兒那勝無。", "西山夏雪消，江勢東南瀉。風波高若天，灩澦低於馬。", "正被黃牛旋，難期白帝下。我在平地行，翻憂濟川者。", "靈均死波後，是節常浴蘭。彩縷碧筠粽，香粳白玉團。", "逝者良自苦，今人反為歡。哀哉徇名士，沒命求所難。"]'),
('yuding-2','解秋十首','元稹','唐','御定全唐诗','yuding','','[]','清晨頮寒水，動搖襟袖輕。翳翳林上葉，不知秋暗生。',480,'御定全唐詩/json/402.json','["清晨頮寒水，動搖襟袖輕。翳翳林上葉，不知秋暗生。", "回悲鏡中發，華白三四莖。豈無滿頭黑，念此衰已萌。", "微霜才結露，翔鳩初變鷹。無乃天地意，使之行小懲。", "鴟鴞誠可惡，蔽日有高鵬。舍大以擒細，我心終不能。", "往歲學仙侶，各在無何鄉。同時騖名者，次第鵷鷺行。", "而我兩不遂，三十鬢添霜。日暮江上立，蟬鳴楓樹黃。", "後伏火猶在，先秋蟬已多。雲色日夜白，驕陽能幾何。", "壤隙漏江海，忽微成網羅。勿言時不至，但恐歲蹉跎。", "新月才到地，輕河如泛雲。螢飛高下火，樹影參差文。", "露簟有微潤，清香時暗焚。夜閒心寂默，洞庭無垢氛。", "霽麗床前影，飄蕭簾外竹。簟涼朝睡重，夢覺茶香熟。", "親烹園內葵，憑買家家曲。釀酒並毓蔬，人來有棋局。", "寒竹秋雨重，淩霄晚花落。低回翠玉梢，散亂梔黃萼。", "顏色有殊異，風霜無好惡。年年百草芳，畢意同蕭索。", "春非我獨春，秋非我獨秋。豈念百草死，但念霜滿頭。", "頭白古所同，胡為坐煩憂。茫茫百年內，處身良未休。", "西風冷衾簟，輾轉布華茵。來者承玉體，去者流芳塵。", "適意醜為好，及時疏亦親。衰周仲尼出，無乃為妖人。", "漠漠江面燒，微微楓樹煙。今日複今夕，秋懷方浩然。", "況我頭上發，衰白不待年。我懷有時極，此意何由詮。"]'),
('yuding-3','遣病十首','元稹','唐','御定全唐诗','yuding','','[]','服藥備江瘴，四年方一癘。豈是藥無功，伊予久留滯。',480,'御定全唐詩/json/402.json','["服藥備江瘴，四年方一癘。豈是藥無功，伊予久留滯。", "滯留人固薄，瘴久藥難制。去日良已甘，歸途奈無際。", "棄置何所任，鄭公憐我病。三十九萬錢，資予養頑暝。", "身賤殺何益，恩深報難罄。公其萬千年，世有天之鄭。", "憶作孩稚初，健羨成人列。倦學厭日長，嬉遊念佳節。", "今來漸諱年，頓與前心別。白日速如飛，佳晨亦騷屑。", "昔在痛飲場，憎人病辭醉。病來身怕酒，始悟他人意。", "怕酒豈不閑，悲無少年氣。傳語少年兒，杯盤莫回避。", "憶初頭始白，晝夜驚一縷。漸及鬢與須，多來不能數。", "壯年等閒過，過壯年已五。華髮不再青，勞生竟何補。", "在家非不病，有病心亦安。起居甥侄扶，藥餌兄嫂看。", "今病兄遠路，道遙書信難。寄言嬌小弟，莫作官家官。", "燕巢官舍內，我爾俱為客。歲晚我獨留，秋深爾安適。", "風高翅羽垂，路遠煙波隔。去去玉山岑，人間網羅窄。", "簷宇夜來曠，暗知秋已生。臥悲衾簟冷，病覺支體輕。", "炎昏豈不倦，時去聊自驚。浩歎終一夕，空堂天欲明。", "秋依靜處多，況乃淩晨趣。深竹蟬晝風，翠茸衫曉露。", "庭莎病看長，林果閑知數。何以強健時，公門日勞騖。", "朝結故鄉念，暮作空堂寢。夢別淚亦流，啼痕暗橫枕。", "昔愁憑酒遣，今病安能飲。落盡秋槿花，離人病猶甚。"]'),
('yuding-4','寒','元稹','唐','御定全唐诗','yuding','','[]','江瘴節候暖，臘初梅已殘。夜來北風至，喜見今日寒。',48,'御定全唐詩/json/402.json','["江瘴節候暖，臘初梅已殘。夜來北風至，喜見今日寒。", "扣冰淺塘水，擁雪深竹闌。複此滿尊醁，但嗟誰與歡。"]'),
('yuding-5','玉泉道中作','元稹','唐','御定全唐诗','yuding','','[]','楚俗物候晚，孟冬才有霜。早農半華實，夕水含風涼。',96,'御定全唐詩/json/402.json','["楚俗物候晚，孟冬才有霜。早農半華實，夕水含風涼。", "遐想雲外寺，峰巒渺相望。松門接官路，泉脈連僧房。", "微露上弦月，暗焚初夜香。穀深煙壒淨，山虛鐘磬長。", "念此清境遠，複憂塵事妨。行行即前路，勿滯分寸光。"]'),
('yuding-6','遣病','元稹','唐','御定全唐诗','yuding','','[]','自古誰不死，不復記其名。今年京城內，死者老少並。',240,'御定全唐詩/json/402.json','["自古誰不死，不復記其名。今年京城內，死者老少並。", "獨孤才四十，仕宦方榮榮。李三三十九，登朝有清聲。", "趙昌八十餘，三擁大將旌。為生信異異，之死同冥冥。", "其家哭泣愛，一一無異情。其類嗟歎惜，各各無重輕。", "萬齡龜菌等，一死天地平。以此方我病，我病何足驚。", "借如今日死，亦足了一生。借使到百年，不知何所成。", "況我早師佛，屋宅此身形。舍彼複就此，去留何所縈。", "前身為過跡，來世即前程。但念行不息，豈憂無路行。", "蛻骨龍不死，蛻皮蟬自鳴。胡為神蛻體，此道人不明。", "持謝愛朋友，寄之仁弟兄。吟此可達觀，世言何足聽。"]'),
('yuding-7','感夢','元稹','唐','御定全唐诗','yuding','','[]','十月初二日，我行蓬州西。三十裏有館，有館名芳溪。',576,'御定全唐詩/json/402.json','["十月初二日，我行蓬州西。三十裏有館，有館名芳溪。", "荒郵屋舍壞，新雨田地泥。我病百日餘，肌體顧若刲。", "氣填暮不食，早早掩竇圭。陰寒筋骨病，夜久燈火低。", "忽然寢成夢，宛見顏如珪。似歎久離別，嗟嗟複淒淒。", "問我何病痛，又歎何棲棲。答雲痰滯久，與世複相暌。", "重雲痰小疾，良藥固易擠。前時奉橘丸，攻疾有神功。", "何不善和療，豈獨頭有風。殷勤平生事，款曲無不終。", "悲歡兩相極，以是半日中。言罷相與行，行行古城裏。", "同行複一人，不識誰氏子。逡巡急吏來，呼喚願且止。", "馳至相君前，再拜複再起。啟雲吏有奉，奉命傳所旨。", "事有大驚忙，非君不能理。答雲久就閑，不願見勞使。", "多謝致勤勤，未敢相唯唯。我因前獻言，此事愚可料。", "亂熱由靜消，理繁在知要。君如冬月陽，奔走不必召。", "君如銅鏡明，萬物自可照。願君許蒼生，勿複高體調。", "相君不我言，顧我再三笑。行行及城戶，黯黯餘日暉。", "相君不我言，命我從此歸。不省別時語，但省涕淋漓。", "覺來身體汗，坐臥心骨悲。閃閃燈背壁，膠膠雞去塒。", "倦童顛倒寢，我淚縱橫垂。淚垂啼不止，不止啼且聲。", "啼聲覺僮僕，僮僕撩亂驚。問我何所苦，問我何所思。", "我亦不能語，慘慘即路岐。前經新政縣，今夕複明辰。", "置置滿心氣，不得說向人。奇哉趙明府，怪我眉不伸。", "雲有北來僧，住此月與旬。自言辨貴骨，謂若識天真。", "談游費閟景，何不與逡巡。僧來為予語，語及昔所知。", "自言有奇中，裴相未相時。讀書靈山寺，住處接園籬。"]'),
('yuding-8','和東川李相公慈竹十二韻','元稹','唐','御定全唐诗','yuding','','[]','慈竹不外長，密比青瑤華。矛攢有森束，玉粒無蹉跎。',144,'御定全唐詩/json/402.json','["慈竹不外長，密比青瑤華。矛攢有森束，玉粒無蹉跎。", "纖粉妍膩質，細瓊交翠柯。亭亭霄漢近，靄靄雨露多。", "冰碧寒夜聳，簫韶風晝羅。煙含朧朧影，月泛鱗鱗波。", "鸞鳳一已顧，燕雀永不過。幽姿媚庭實，顥氣爽天涯。", "峻節高轉露，貞筠寒更佳。托身仙壇上，靈物神所呵。", "時與天籟合，日聞陽春歌。應憐孤生者，摧折成病痾。"]'),
('yuding-0','酬東川李相公十六韻','元稹','唐','御定全唐诗','yuding','','[]','昔附赤霄羽，葳蕤遊紫垣。鬥班香案上，奏語玉晨尊。',192,'御定全唐詩/json/403.json','["昔附赤霄羽，葳蕤遊紫垣。鬥班香案上，奏語玉晨尊。", "戇直撩忌諱，科儀懲傲頑。自從真籍除，棄置勿複論。", "前時共遊者，日夕黃金軒。請帝下巫覡，八荒求我魂。", "鸞鳳屢鳴顧，燕雀尚籬藩。徒令霄漢外，往往塵念存。", "存念豈虛設，並投瓊與璠。彈珠古所訝，此用何太敦。", "鄒律寒氣變，鄭琴祥景奔。靈芝繞身出，左右光彩繁。", "碾玉無俗色，蕊珠非世言。重慚前日句，陋若蕕並蓀。", "臘月巴地雨，瘴江愁浪翻。因持駭雞寶，一照濁水昏。"]'),
('yuding-1','酬獨孤二十六送歸通州','元稹','唐','御定全唐诗','yuding','','[]','再拜捧兄贈，拜兄珍重言。我有平生志，臨別將具論。',192,'御定全唐詩/json/403.json','["再拜捧兄贈，拜兄珍重言。我有平生志，臨別將具論。", "十歲慕倜儻，愛白不愛昏。寧愛寒切烈，不愛暘溫暾。", "二十走獵騎，三十遊海門。憎兔跳躍躍，惡鵬黑翻翻。", "鼇釣氣方壯，鶻拳心頗尊。下觀猙獰輩，一掃冀不存。", "名冠壯士籍，功酬明主恩。不然合身棄，何況身上痕。", "金石有銷爍，肺腑無寒溫。分畫久已定，波濤何足煩。", "嘗希蘇門嘯，詎厭巴樹猿。瘴水徒浩浩，浮雲亦軒軒。", "長歌莫長歎，飲斛莫飲樽。生為醉鄉客，死作達士魂。"]'),
('yuding-2','酬劉猛見送','元稹','唐','御定全唐诗','yuding','','[]','種花有顏色，異色即為妖。養鳥惡羽翮，剪翮不待高。',204,'御定全唐詩/json/403.json','["種花有顏色，異色即為妖。養鳥惡羽翮，剪翮不待高。", "非無剪傷者，物性難自逃。百足雖捷捷，商羊亦翹翹。", "伊餘狷然質，謬入多士朝。任氣有愎戇，容身寡朋曹。", "愚狂偶似直，靜僻非敢驕。一為毫髮忤，十載山川遙。", "爍鐵不在火，割肌不在刀。險心露山嶽，流語翻波濤。", "六尺安敢主，方寸由自調。神劍土不蝕，異布火不燋。", "雖無二物姿，庶欲效一毫。未能深蹙蹙，多謝相勞勞。", "去去我移馬，遲遲君過橋。雲勢正橫壑，江流初滿槽。", "持此慰遠道，此之為舊交。"]'),
('yuding-3','酬樂天赴江州路上見寄三首','元稹','唐','御定全唐诗','yuding','','[]','昔在京城心，今在吳楚末。千山道路險，萬里音塵闊。',252,'御定全唐詩/json/403.json','["昔在京城心，今在吳楚末。千山道路險，萬里音塵闊。", "天上參與商，地上胡與越。終天升沉異，滿地網羅設。", "心有無眹環，腸有無繩結。有結解不開，有環尋不歇。", "山嶽移可盡，江海塞可絕。離恨若空虛，窮年思不徹。", "生莫強相同，相同會相別。", "襄陽大堤繞，我向堤前住。燭隨花豔來，騎送朝雲去。", "萬竿高廟竹，三月徐亭樹。我昔憶君時，君今懷我處。", "有身有離別，無地無岐路。風塵同古今，人世勞新故。", "人亦有相愛，我爾殊眾人。朝朝寧不食，日日願見君。", "一日不得見，愁腸坐氛氳。如何遠相失，各作萬里雲。", "雲高風苦多，會合難遽因。天上猶有礙，何況地上身。"]'),
('yuding-4','郵竹','元稹','唐','御定全唐诗','yuding','','[]','庭有蕭蕭竹，門有闐闐騎。囂靜本殊途，因依偶同寄。',48,'御定全唐詩/json/403.json','["庭有蕭蕭竹，門有闐闐騎。囂靜本殊途，因依偶同寄。", "亭亭乍幹雲，嫋嫋亦垂地。人有異我心，我無異人意。"]'),
('yuding-5','落月','元稹','唐','御定全唐诗','yuding','','[]','落月沉餘影，陰渠流暗光。蚊聲靄窗戶，螢火繞屋樑。',48,'御定全唐詩/json/403.json','["落月沉餘影，陰渠流暗光。蚊聲靄窗戶，螢火繞屋樑。", "飛幌翠雲薄，新荷清露香。不吟複不寐，竟夕池水傍。"]'),
('yuding-6','高荷','元稹','唐','御定全唐诗','yuding','','[]','種藕百餘根，高荷才四葉。颭閃碧雲扇，團圓青玉疊。',48,'御定全唐詩/json/403.json','["種藕百餘根，高荷才四葉。颭閃碧雲扇，團圓青玉疊。", "亭亭自抬舉，鼎鼎難藏擫。不學著水荃，一生長怗怗。"]'),
('yuding-7','和裴校書鷺鷥飛','元稹','唐','御定全唐诗','yuding','','[]','鷺鷥鷺鷥何遽飛，鴉驚雀噪難久依。',32,'御定全唐詩/json/403.json','["鷺鷥鷺鷥何遽飛，鴉驚雀噪難久依。", "清江見底草堂在，一點白光終不歸。"]'),
('yuding-8','夜池','元稹','唐','御定全唐诗','yuding','','[]','荷葉團圓莖削削，綠萍面上紅衣落。',32,'御定全唐詩/json/403.json','["荷葉團圓莖削削，綠萍面上紅衣落。", "滿池明月思啼螿，高屋無人風張幕。"]'),
('yuding-9','酬楊司業十二兄早秋述情見寄','元稹','唐','御定全唐诗','yuding','','[]','白髮故人少，相逢意彌遠。往事共銷沉，前期各衰晚。',72,'御定全唐詩/json/403.json','["白髮故人少，相逢意彌遠。往事共銷沉，前期各衰晚。", "昨來遇彌苦，已複雲離巘。秋草古膠庠，寒沙廢宮苑。", "知心豈忘鮑，詠懷難和阮。壯志日蕭條，那能競朝幰。"]'),
('yuding-10','代杭人作使君一朝去二首','元稹','唐','御定全唐诗','yuding','','[]','使君一朝去，遺愛在人口。惠化境內春，才名天下首。',72,'御定全唐詩/json/403.json','["使君一朝去，遺愛在人口。惠化境內春，才名天下首。", "為問龔黃輩，兼能作詩否。", "使君一朝去，斷腸如剉檗。無複見冰壺，唯應鏤金石。", "自此一州人，生男盡名白。"]'),
('yuding-11','長慶曆','元稹','唐','御定全唐诗','yuding','','[]','年曆複年曆，卷盡悲且惜。曆日何足悲，但悲年運易。',48,'御定全唐詩/json/403.json','["年曆複年曆，卷盡悲且惜。曆日何足悲，但悲年運易。", "年年豈無歎，此歎何唧唧。所歎別此年，永無長慶曆。"]'),
('yuding-12','順宗至德大聖大安孝皇帝挽歌詞三首','元稹','唐','御定全唐诗','yuding','','[]','不改延洪祚，因成揖讓朝。謳歌同戴啟，遏密共思堯。',145,'御定全唐詩/json/403.json','["不改延洪祚，因成揖讓朝。謳歌同戴啟，遏密共思堯。", "雨露施恩廣，梯航會葬遙。號弓那獨切，曾感昔年招。", "前春文祖廟，大舜嗣堯登。及此逾年感，還因是月崩。", "壽緣追孝促，業在繼明興。儉詔同今古，山川繞灞陵。", "七月悲風起，淒涼萬國人。羽儀經巷內，轀fm轉城闉。", "暝色依陵早，秋聲入輅新。自嗟同草木，不識永貞春。"]'),
('yuding-13','憲宗章武孝皇帝挽歌詞三首','元稹','唐','御定全唐诗','yuding','','[]','國付重離後，身隨十聖仙。北辰移帝座，西日到虞泉。',144,'御定全唐詩/json/403.json','["國付重離後，身隨十聖仙。北辰移帝座，西日到虞泉。", "方丈言虛設，華胥事眇然。觸鱗曾在宥，偏哭墮髯前。", "天寶遺餘事，元和盛聖功。二凶梟帳下，三叛斬都中。", "始服沙陀虜，方吞邏逤戎。狼星如要射，猶有鼎湖弓。", "月落禁垣西，星攢曉仗齊。風傳宮漏苦，雲拂羽儀低。", "路隘車千兩，橋危馬萬蹄。共蹉封石檢，不為報功泥。"]'),
('yuding-14','恭王故太妃挽歌詞二首','元稹','唐','御定全唐诗','yuding','','[]','燕姞貽天夢，梁王盡孝思。雖從魏詔葬，得用漢藩儀。',96,'御定全唐詩/json/403.json','["燕姞貽天夢，梁王盡孝思。雖從魏詔葬，得用漢藩儀。", "曙月殘光斂，寒簫度曲遲。平生奉恩地，哀挽欲何之。", "文衛羅新壙，仙娥掩暝山。雪雲埋隴合，簫鼓望城還。", "寒樹風難靜，霜郊夜更閑。哀榮深孝嗣，儀錶在河間。"]'),
('yuding-15','哭呂衡州六首','元稹','唐','御定全唐诗','yuding','','[]','氣敵三人傑，交深一紙書。我投冰瑩眼，君報水憐魚。',288,'御定全唐詩/json/403.json','["氣敵三人傑，交深一紙書。我投冰瑩眼，君報水憐魚。", "髀股惟誇瘦，膏肓豈暇除。傷心死諸葛，憂道不憂餘。", "望有經綸釣，虔收宰相刀。江文駕風遠，雲貌接天高。", "國待球琳器，家藏虎豹韜。盡將千載寶，埋入五原蒿。", "白馬雙旌隊，青山八陣圖。請纓期系虜，枕草誓捐軀。", "勢激三千壯，年應四十無。遙聞不瞑目，非是不憐吳。", "雕鶚生難敵，沉檀死更香。兒童喧巷市，羸老哭碑堂。", "雁起沙汀暗，雲連海氣黃。祝融峰上月，幾照北人喪。", "回雁峰前雁，春回盡卻回。聯行四人去，同葬一人來。", "鐃吹臨江返，城池隔霧開。滿船深夜哭，風棹楚猿哀。", "杜預春秋癖，揚雄著述精。在時兼不語，終古定歸名。", "耒水波文細，湘江竹葉輕。平生思風月，潛寐若為情。"]'),
('yuding-16','僧如展及韋載同遊碧澗寺，各賦詩，予落句云，他生莫忘靈山座，滿壁人名後會稀，展共吟他生之句，因話釋氏緣會，所以莫不悽然，久之不十日而展公長逝，驚悼返覆，則他生豈有兆耶？其間展公仍賦黃字五十韻，飛札相示，予方屬和未畢，自此不復撰成，徒以四韻為識','元稹','唐','御定全唐诗','yuding','','[]','重吟前日他生句，豈料逾旬便隔生。會擬一來身塔下，',40,'御定全唐詩/json/403.json','["重吟前日他生句，豈料逾旬便隔生。會擬一來身塔下，", "縱使得如羊叔子，不聞兼記舊交情。"]'),
('yuding-17','公安縣遠安寺水亭見展公題壁漂然淚流因書四韻','元稹','唐','御定全唐诗','yuding','','[]','碧澗去年會，與師三兩人。今來見題壁，師已是前身。',48,'御定全唐詩/json/403.json','["碧澗去年會，與師三兩人。今來見題壁，師已是前身。", "芰葉迎僧夏，楊花度俗春。空將數行淚，灑遍塔中塵。"]'),
('yuding-18','寒食日毛空路示侄晦及從簡','元稹','唐','御定全唐诗','yuding','','[]','我昔孩提從我兄，我今衰白爾初成。',32,'御定全唐詩/json/403.json','["我昔孩提從我兄，我今衰白爾初成。", "分明寄取原頭路，百世長須此路行。"]'),
('yuding-19','別孫村老人','元稹','唐','御定全唐诗','yuding','','[]','年年漸覺老人稀，欲別孫翁淚滿衣。',32,'御定全唐詩/json/403.json','["年年漸覺老人稀，欲別孫翁淚滿衣。", "未死不知何處去，此身終向此原歸。"]'),
('yuding-20','和樂天劉家花','元稹','唐','御定全唐诗','yuding','','[]','閑坊靜曲同消日，淚草傷花不為春。',32,'御定全唐詩/json/403.json','["閑坊靜曲同消日，淚草傷花不為春。", "遍問舊交零落盡，十人才有兩三人。"]'),
('yuding-21','褒城驛二首','元稹','唐','御定全唐诗','yuding','','[]','容州詩句在褒城，幾度經過眼暫明。',64,'御定全唐詩/json/403.json','["容州詩句在褒城，幾度經過眼暫明。", "今日重看滿衫淚，可憐名字已前生。", "憶昔萬株梨映竹，遇逢黃令醉殘春。", "梨枯竹盡黃令死，今日再來衰病身。"]'),
('yuding-22','和樂天夢亡友劉太白同遊二首','元稹','唐','御定全唐诗','yuding','','[]','君詩昨日到通州，萬里知君一夢劉。',64,'御定全唐詩/json/403.json','["君詩昨日到通州，萬里知君一夢劉。", "閑坐思量小來事，只應元是夢中游。", "老來東郡複西州，行處生塵為喪劉。", "縱使劉君魂魄在，也應至死不同遊。"]'),
('yuding-23','酬樂天見憶，兼傷仲遠','元稹','唐','御定全唐诗','yuding','','[]','死別重泉閟，生離萬里賒。瘴侵新病骨，夢到故人家。',72,'御定全唐詩/json/403.json','["死別重泉閟，生離萬里賒。瘴侵新病骨，夢到故人家。", "遙淚陳根草，閑收落地花。庾公樓悵望，巴子國生涯。", "河任天然曲，江隨峽勢斜。與君皆直戇，須分老泥沙。"]'),
('yuding-24','與樂天同葬杓直','元稹','唐','御定全唐诗','yuding','','[]','元伯來相葬，山濤誓撫孤。不知他日事，兼得似君無。',24,'御定全唐詩/json/403.json','["元伯來相葬，山濤誓撫孤。不知他日事，兼得似君無。"]'),
('yuding-0','夜閑','元稹','唐','御定全唐诗','yuding','','[]','感極都無夢，魂銷轉易驚。風簾半鉤落，秋月滿床明。',48,'御定全唐詩/json/404.json','["感極都無夢，魂銷轉易驚。風簾半鉤落，秋月滿床明。", "悵望臨階坐，沉吟繞樹行。孤琴在幽匣，時迸斷弦聲。"]'),
('yuding-1','感小株夜合','元稹','唐','御定全唐诗','yuding','','[]','纖幹未盈把，高條才過眉。不禁風苦動，偏受露先萎。',48,'御定全唐詩/json/404.json','["纖幹未盈把，高條才過眉。不禁風苦動，偏受露先萎。", "不分秋同盡，深嗟小便衰。傷心落殘葉，猶識合昏期。"]'),
('yuding-2','醉醒','元稹','唐','御定全唐诗','yuding','','[]','積善坊中前度飲，謝家諸婢笑扶行。',32,'御定全唐詩/json/404.json','["積善坊中前度飲，謝家諸婢笑扶行。", "今宵還似當時醉，半夜覺來聞哭聲。"]'),
('yuding-3','追昔遊','元稹','唐','御定全唐诗','yuding','','[]','謝傅堂前音樂和，狗兒吹笛膽娘歌。花園欲盛千場飲，',40,'御定全唐詩/json/404.json','["謝傅堂前音樂和，狗兒吹笛膽娘歌。花園欲盛千場飲，", "再來門館唯相吊，風落秋池紅葉多。"]'),
('yuding-4','空屋題','元稹','唐','御定全唐诗','yuding','','[]','朝從空屋裏，騎馬入空台。盡日推閒事，還歸空屋來。',48,'御定全唐詩/json/404.json','["朝從空屋裏，騎馬入空台。盡日推閒事，還歸空屋來。", "月明穿暗隙，燈燼落殘灰。更想咸陽道，魂車昨夜回。"]'),
('yuding-5','初寒夜寄盧子蒙','元稹','唐','御定全唐诗','yuding','','[]','月是陰秋鏡，寒為寂寞資。輕寒酒醒後，斜月枕前時。',48,'御定全唐詩/json/404.json','["月是陰秋鏡，寒為寂寞資。輕寒酒醒後，斜月枕前時。", "倚壁思閒事，回燈檢舊詩。聞君亦同病，終夜遠相悲。"]'),
('yuding-6','城外回，謝子蒙見諭','元稹','唐','御定全唐诗','yuding','','[]','十裏撫柩別，一身騎馬回。寒煙半堂影，燼火滿庭灰。',48,'御定全唐詩/json/404.json','["十裏撫柩別，一身騎馬回。寒煙半堂影，燼火滿庭灰。", "稚女憑人問，病夫空自哀。潘安寄新詠，仍是夜深來。"]'),
('yuding-7','諭子蒙','元稹','唐','御定全唐诗','yuding','','[]','撫稚君休感，無兒我不傷。片雲離岫遠，雙燕念巢忙。',48,'御定全唐詩/json/404.json','["撫稚君休感，無兒我不傷。片雲離岫遠，雙燕念巢忙。", "大壑誰非水，華星各自光。但令長有酒，何必謝家莊。"]'),
('yuding-8','遣悲懷三首','元稹','唐','御定全唐诗','yuding','','[]','謝公最小偏憐女，嫁與黔婁百事乖。顧我無衣搜畫篋，',120,'御定全唐詩/json/404.json','["謝公最小偏憐女，嫁與黔婁百事乖。顧我無衣搜畫篋，", "今日俸錢過十萬，與君營奠複營齋。", "昔日戲言身後意，今朝皆到眼前來。衣裳已施行看盡，", "誠知此恨人人有，貧賤夫妻百事哀。", "閑坐悲君亦自悲，百年都是幾多時。鄧攸無子尋知命，", "唯將終夜長開眼，報答平生未展眉。"]'),
('yuding-9','旅眠','元稹','唐','御定全唐诗','yuding','','[]','內外都無隔，帷屏不復張。夜眠兼客坐，同在火爐床。',24,'御定全唐詩/json/404.json','["內外都無隔，帷屏不復張。夜眠兼客坐，同在火爐床。"]'),
('yuding-10','除夜','元稹','唐','御定全唐诗','yuding','','[]','憶昔歲除夜，見君花燭前。今宵祝文上，重疊敘新年。',48,'御定全唐詩/json/404.json','["憶昔歲除夜，見君花燭前。今宵祝文上，重疊敘新年。", "閑處低聲哭，空堂背月眠。傷心小兒女，撩亂火堆邊。"]'),
('yuding-11','感夢','元稹','唐','御定全唐诗','yuding','','[]','行吟坐歎知何極，影絕魂銷動來年。',32,'御定全唐詩/json/404.json','["行吟坐歎知何極，影絕魂銷動來年。", "今夜商山館中夢，分明同在後堂前。"]'),
('yuding-12','合衣寢','元稹','唐','御定全唐诗','yuding','','[]','良夕背燈坐，方成合衣寢。酒醉夜未闌，幾回顛倒枕。',24,'御定全唐詩/json/404.json','["良夕背燈坐，方成合衣寢。酒醉夜未闌，幾回顛倒枕。"]'),
('yuding-13','竹簟','元稹','唐','御定全唐诗','yuding','','[]','竹簟襯重茵，未忍都令卷。憶昨初來日，看君自施展。',24,'御定全唐詩/json/404.json','["竹簟襯重茵，未忍都令卷。憶昨初來日，看君自施展。"]'),
('yuding-14','聽庾及之彈烏夜啼引','元稹','唐','御定全唐诗','yuding','','[]','君彈烏夜啼，我傳樂府解古題。良人在獄妻在閨，',94,'御定全唐詩/json/404.json','["君彈烏夜啼，我傳樂府解古題。良人在獄妻在閨，", "後人寫出烏啼引，吳調哀弦聲楚楚。四五年前作拾遺，", "歸來相見淚如珠，唯說閑宵長拜烏。君來到舍是烏力，", "感君此曲有深意，昨日烏啼桐葉墜。當時為我賽烏人，"]'),
('yuding-15','夢井','元稹','唐','御定全唐诗','yuding','','[]','夢上高高原，原上有深井。登高意枯渴，願見深泉冷。',240,'御定全唐詩/json/404.json','["夢上高高原，原上有深井。登高意枯渴，願見深泉冷。", "裴回繞井顧，自照泉中影。沉浮落井瓶，井上無懸綆。", "念此瓶欲沉，荒忙為求請。遍入原上村，村空犬仍猛。", "還來繞井哭，哭聲通複哽。哽噎夢忽驚，覺來房舍靜。", "燈焰碧朧朧，淚光疑冏冏。鐘聲夜方半，坐臥心難整。", "忽憶咸陽原，荒田萬餘頃。土厚壙亦深，埋魂在深埂。", "埂深安可越，魂通有時逞。今宵泉下人，化作瓶相憬。", "感此涕汍瀾，汍瀾涕沾領。所傷覺夢間，便覺死生境。", "豈無同穴期，生期諒綿永。又恐前後魂，安能兩知省。", "尋環意無極，坐見天將昞。吟此夢井詩，春朝好光景。"]'),
('yuding-16','江陵三夢','元稹','唐','御定全唐诗','yuding','','[]','平生每相夢，不省兩相知。況乃幽明隔，夢魂徒爾為。',432,'御定全唐詩/json/404.json','["平生每相夢，不省兩相知。況乃幽明隔，夢魂徒爾為。", "情知夢無益，非夢見何期。今夕亦何夕，夢君相見時。", "依稀舊妝服，晻淡昔容儀。不道間生死，但言將別離。", "分張碎針線，襵疊故屏幃。撫稚再三囑，淚珠千萬垂。", "囑雲唯此女，自歎總無兒。尚念嬌且騃，未禁寒與饑。", "君複不憘事，奉身猶脫遺。況有官縛束，安能長顧私。", "他人生間別，婢僕多謾欺。君在或有托，出門當付誰。", "言罷泣幽噎，我亦涕淋漓。驚悲忽然寤，坐臥若狂癡。", "月影半床黑，蟲聲幽草移。心魂生次第，覺夢久自疑。", "寂默深想像，淚下如流澌。百年永已訣，一夢何太悲。", "悲君所嬌女，棄置不我隨。長安遠於日，山川雲間之。", "縱我生羽翼，網羅生縶維。今宵淚零落，半為生別滋。", "感君下泉魄，動我臨川思。一水不可越，黃泉況無涯。", "此懷何由極，此夢何由追。坐見天欲曙，江風吟樹枝。", "古原三丈穴，深葬一枝瓊。崩剝山門壞，煙綿墳草生。", "久依荒隴坐，卻望遠村行。驚覺滿床月，風波江上聲。", "君骨久為土，我心長似灰。百年何處盡，三夜夢中來。", "逝水良已矣，行雲安在哉。坐看朝日出，眾鳥雙裴回。"]'),
('yuding-17','張舊蚊幬','元稹','唐','御定全唐诗','yuding','','[]','逾年間生死，千里曠南北。家居無見期，況乃異鄉國。',192,'御定全唐詩/json/404.json','["逾年間生死，千里曠南北。家居無見期，況乃異鄉國。", "破盡裁縫衣，忘收遺翰墨。獨有纈紗幬，憑人遠攜得。", "施張合歡榻，展卷雙鴛翼。已矣長空虛，依然舊顏色。", "裴回將就寢，徙倚情何極。昔透香田田，今無魂惻惻。", "隙穿斜月照，燈背空床黑。達理強開懷，夢啼還過臆。", "平生貧寡歡，夭枉勞苦憶。我亦距幾時，胡為自摧逼。", "燭蛾焰中舞，繭蠶叢上織。燋爛各自求，他人顧何力。", "多離因苟合，惡影當務息。往事勿複言，將來幸前識。"]'),
('yuding-18','獨夜傷懷贈呈張侍禦','元稹','唐','御定全唐诗','yuding','','[]','燼火孤星滅，殘燈寸焰明。竹風吹面冷，簷雪墜階聲。',48,'御定全唐詩/json/404.json','["燼火孤星滅，殘燈寸焰明。竹風吹面冷，簷雪墜階聲。", "寡鶴連天叫，寒雛徹夜驚。只應張侍禦，潛會我心情。"]'),
('yuding-19','六年春遣懷八首','元稹','唐','御定全唐诗','yuding','','[]','傷禽我是籠中鶴，沉劍君為泉下龍。',256,'御定全唐詩/json/404.json','["傷禽我是籠中鶴，沉劍君為泉下龍。", "重纊猶存孤枕在，春衫無復舊裁縫。", "檢得舊書三四紙，高低闊狹粗成行。", "自言並食尋高事，唯念山深驛路長。", "公無渡河音響絕，已隔前春複去秋。", "今日閑窗拂塵土，殘弦猶迸鈿箜篌。", "婢僕曬君餘服用，嬌癡稚女繞床行。", "玉梳鈿朵香膠解，盡日風吹玳瑁箏。", "伴客銷愁長日飲，偶然乘興便醺醺。", "怪來醒後傍人泣，醉裏時時錯問君。", "我隨楚澤波中梗，君作咸陽泉下泥。", "百事無心值寒食，身將稚女帳前啼。", "童稚癡狂撩亂走，繡球花仗滿堂前。", "病身一到繐帷下，還向臨階背日眠。", "小於潘岳頭先白，學取莊周淚莫多。", "止竟悲君須自省，川流前後各風波。"]'),
('yuding-20','答友封見贈','元稹','唐','御定全唐诗','yuding','','[]','荀令香銷潘簟空，悼亡詩滿舊屏風。',32,'御定全唐詩/json/404.json','["荀令香銷潘簟空，悼亡詩滿舊屏風。", "扶床小女君先識，應為些些似外翁。"]'),
('yuding-21','夢成之','元稹','唐','御定全唐诗','yuding','','[]','燭暗船風獨夢驚，夢君頻問向南行。',32,'御定全唐詩/json/404.json','["燭暗船風獨夢驚，夢君頻問向南行。", "覺來不語到明坐，一夜洞庭湖水聲。"]'),
('yuding-22','哭小女降真','元稹','唐','御定全唐诗','yuding','','[]','雨點輕漚風複驚，偶來何事去何情。',32,'御定全唐詩/json/404.json','["雨點輕漚風複驚，偶來何事去何情。", "浮生未到無生地，暫到人間又一生。"]'),
('yuding-23','哭女樊','元稹','唐','御定全唐诗','yuding','','[]','秋天淨綠月分明，何事巴猿不剩鳴。',32,'御定全唐詩/json/404.json','["秋天淨綠月分明，何事巴猿不剩鳴。", "應是一聲腸斷去，不容啼到第三聲。"]'),
('yuding-24','哭女樊四十韻','元稹','唐','御定全唐诗','yuding','','[]','逝者何由見，中人未達情。馬無生角望，猿有斷腸鳴。',480,'御定全唐詩/json/404.json','["逝者何由見，中人未達情。馬無生角望，猿有斷腸鳴。", "去伴投遐徼，來隨夢險程。四年巴養育，萬里硤回縈。", "病是他鄉染，魂應遠處驚。山魈邪亂逼，沙虱毒潛嬰。", "母約看甯辨，餘慵療不精。欲尋方次第，俄值疾充盈。", "燈火徒相守，香花只浪擎。蓮初開月梵，蕣已落朝榮。", "魄散雲將盡，形全玉尚瑩。空垂兩行血，深送一枝瓊。", "秘祝休巫覡，安眠放使令。舊衣和篋施，殘藥滿甌傾。", "乳媼閑於社，醫僧婗似酲。憫渠身覺剩，訝佛力難爭。", "騎竹癡猶子，牽車小外甥。等長迷過影，遙戲誤啼聲。", "涴紙傷餘畫，扶床念試行。獨留呵面鏡，誰弄倚牆箏。", "憶昨工言語，憐初妙長成。撩風妒鸚舌，淩露觸蘭英。", "翠鳳輿真女，紅蕖捧化生。只憂嫌五濁，終恐向三清。", "宿惡諸葷味，懸知眾物名。環從枯樹得，經認寶函盛。", "慍怒偏憎數，分張雅愛平。最憐貪栗妹，頻救懶書兄。", "為占嬌饒分，良多眷戀誠。別常回面泣，歸定出門迎。", "解怪還家晚，長將遠信呈。說人偷罪過，要我抱縱橫。", "騰蹋游江舫，攀緣看樂棚。和蠻歌字拗，學妓舞腰輕。", "迢遞離荒服，提攜到近京。未容誇伎倆，唯恨枉聰明。", "往緒心千結，新絲鬢百莖。暗窗風報曉，秋幌雨聞更。", "敗槿蕭疏館，衰楊破壞城。此中臨老淚，仍自哭孩嬰。"]'),
('yuding-25','哭子十首','元稹','唐','御定全唐诗','yuding','','[]','維鵜受刺因吾過，得馬生災念爾冤。',320,'御定全唐詩/json/404.json','["維鵜受刺因吾過，得馬生災念爾冤。", "獨在中庭倚閑樹，亂蟬嘶噪欲黃昏。", "才能辨別東西位，未解分明管帶身。", "自食自眠猶未得，九重泉路托何人。", "爾母溺情連夜哭，我身因事有時悲。", "鐘聲欲絕東方動，便是尋常上學時。", "蓮花上品生真界，兜率天中離世途。", "彼此業緣多障礙，不知還得見兒無。", "節量梨栗愁生疾，教示詩書望早成。", "鞭撲校多憐校少，又緣遺恨哭三聲。", "深嗟爾更無兄弟，自歎予應絕子孫。", "寂寞講堂基址在，何人車馬入高門。", "往年鬢已同潘嶽，垂老年教作鄧攸。", "煩惱數中除一事，自茲無複子孫憂。", "長年苦境知何限，豈得因兒獨喪明。", "消遣又來緣爾母，夜深和淚有經聲。", "烏生八子今無七，猿叫三聲月正孤。", "寂寞空堂天欲曙，拂簾雙燕引新雛。", "頻頻子落長江水，夜夜巢邊舊處棲。", "若是愁腸終不斷，一年添得一聲啼。"]'),
('yuding-26','感逝','元稹','唐','御定全唐诗','yuding','','[]','頭白夫妻分無子，誰令蘭夢感衰翁。三聲啼婦臥床上，',40,'御定全唐詩/json/404.json','["頭白夫妻分無子，誰令蘭夢感衰翁。三聲啼婦臥床上，", "情知此恨人皆有，應與暮年心不同。"]'),
('yuding-27','妻滿月日相唁','元稹','唐','御定全唐诗','yuding','','[]','十月辛勤一月悲，今朝相見淚淋漓。',32,'御定全唐詩/json/404.json','["十月辛勤一月悲，今朝相見淚淋漓。", "狂風落盡莫惆悵，猶勝因花壓折枝。"]'),
('yuding-0','代曲江老人百韻','元稹','唐','御定全唐诗','yuding','','[]','何事花前泣，曾逢舊日春。先皇初在鎬，賤子正游秦。',577,'御定全唐詩/json/405.json','["何事花前泣，曾逢舊日春。先皇初在鎬，賤子正游秦。", "撥亂干戈後，經文禮樂辰。徽章懸象魏，貔虎畫騏驎。", "光武休言戰，唐堯念睦姻。琳琅鋪柱礎，葛藟茂河漘。", "尚齒惇耆艾，搜材拔積薪。裴王持藻鏡，姚宋斡陶鈞。", "內史稱張敞，蒼生借寇恂。名卿唯講德，命士恥憂貧。", "杞梓無遺用，芻蕘不忘詢。懸金收逸驥，鼓瑟薦嘉賓。", "羽翼皆隨鳳，圭璋肯雜瑉。班行容濟濟，文質道彬彬。", "百度依皇極，千門辟紫宸。措刑非苟簡，稽古蹈因循。", "書謬偏求伏，詩亡遠聽申。雄推三虎賈，群擢八龍荀。", "海外恩方洽，寰中教不泯。儒林精閫奧，流品重清淳。", "天淨三光麗，時和四序均。卑官休力役，蠲賦免艱辛。", "蠻貊同車軌，鄉原盡裏仁。帝途高蕩蕩，風俗厚誾誾。", "暇日耕耘足，豐年雨露頻。戍煙生不見，村豎老猶純。", "耒耜勤千畝，牲牢奉六禋。南郊禮天地，東野辟原勻。", "校獵求初吉，先農蔔上寅。萬方來合雜，五色瑞輪囷。", "池籞呈朱雁，壇場得白麟。酹金光照耀，奠璧彩璘玢。", "掉蕩雲門發，蹁躚鷺羽振。集靈撞玉磬，和鼓奏金錞。", "建簴崇牙盛，銜鐘獸目嗔。總幹形屹崒，戛敔背嶙峋。", "文物千官會，夷音九部陳。魚龍華外戲，歌舞洛中嬪。", "佳節修酺禮，非時宴侍臣。梨園明月夜，花萼豔陽晨。", "李杜詩篇敵，蘇張筆力勻。樂章輕鮑照，碑板笑顏竣。", "泰獄陪封禪，汾陰頌鬼神。星移逐西顧，風暖助東巡。", "浴德留湯穀，搜畋過渭濱。沸天雷殷殷，匝地轂轔轔。", "沃土心逾熾，豪家禮漸湮。老農羞荷鍤，貪賈學垂紳。"]'),
('yuding-1','開元觀閒居，酬吳士矩侍禦三十韻','元稹','唐','御定全唐诗','yuding','','[]','靜習狂心盡，幽居道氣添。神編啟黃簡，秘籙捧朱簽。',360,'御定全唐詩/json/405.json','["靜習狂心盡，幽居道氣添。神編啟黃簡，秘籙捧朱簽。", "爛熳煙霞駐，優遊歲序淹。登壇擁旄節，趨殿禮胡髯。", "醮起彤庭燭，香開白玉奩。結盟金劍重，斬魅寶刀銛。", "禹步星綱動，焚符灶鬼詹。冥搜呼直使，章奏役飛廉。", "仙籍聊憑檢，浮名複為占。赤誠祈皓鶴，綠發代青縑。", "虛室常懷素，玄關屢引枮。貂蟬徒自寵，鷗鷺不相嫌。", "始悟身為患，唯欣祿未恬。龜龍戀淮海，雞犬傍閭閻。", "松笠新偏翠，山峰遠更尖。簫聲吟茂竹，虹影逗虛簷。", "初日先通牖，輕颸每透簾。露盤朝滴滴，鉤月夜纖纖。", "已得餐霞味，應嗤食蓼甜。工琴閑度晝，耽酒醉銷炎。", "幾案隨宜設，詩書逐便拈。灌園多抱甕，刈藿乍腰鐮。", "野鳥終難縶，鷦鷯本易厭。風高雲遠逝，波駭鯉深潛。", "邸第過從隔，蓬壺夢寐瞻。所希顏頗練，誰恨突無黔。", "思拙慚圭璧，詞煩雜米鹽。諭錐言太小，求藥意何謙。", "語默君休問，行藏我詎兼。狂歌終此曲，情盡口長箝。"]'),
('yuding-2','病減逢春，期白二十二、辛大不至十韻','元稹','唐','御定全唐诗','yuding','','[]','病與窮陰退，春從血氣生。寒膚漸舒展，陽脈乍虛盈。',120,'御定全唐詩/json/405.json','["病與窮陰退，春從血氣生。寒膚漸舒展，陽脈乍虛盈。", "就日臨階坐，扶床履地行。問人知面瘦，祝鳥願身輕。", "風暖牽詩興，時新變賣聲。饑饞看藥忌，閑悶點書名。", "舊雪依深竹，微和動早萌。推遷悲往事，疏數辨交情。", "琴待嵇中散，杯思阮步兵。世間除卻病，何者不營營。"]'),
('yuding-3','黃明府詩','元稹','唐','御定全唐诗','yuding','','[]','少年曾痛飲，黃令苦飛觥。席上當時走，馬前今日迎。',120,'御定全唐詩/json/405.json','["少年曾痛飲，黃令苦飛觥。席上當時走，馬前今日迎。", "依稀迷姓氏，積漸識平生。故友身皆遠，他鄉眼暫明。", "便邀連榻坐，兼共榜船行。酒思臨風亂，霜棱掃地平。", "不堪深淺酌，貪愴古今情。邐迤七盤路，坡陀數丈城。", "花疑褒女笑，棧想武侯征。一種埋幽石，老閑千載名。"]'),
('yuding-4','酬翰林白學士代書一百韻','元稹','唐','御定全唐诗','yuding','','[]','昔歲俱充賦，同年遇有司。八人稱迥拔，兩郡濫相知。',576,'御定全唐詩/json/405.json','["昔歲俱充賦，同年遇有司。八人稱迥拔，兩郡濫相知。", "逸驥初翻步，鞲鷹暫脫羈。遠途憂地窄，高視覺天卑。", "併入紅蘭署，偏親白玉規。近朱憐冉冉，伐木願偲偲。", "魚魯非難識，鉛黃自懶持。心輕馬融帳，謀奪子房帷。", "秀髮幽岩電，清澄隘岸陂。九霄排直上，萬里整前期。", "勇贈棲鸞句，慚當古井詩。多聞全受益，擇善頗相師。", "脫俗殊常調，潛工大有為。還醇憑酎酒，運智托圍棋。", "情會招車胤，閑行覓戴逵。僧餐月燈閣，醵宴劫灰池。", "勝概爭先到，篇章競出奇。輸贏論破的，點竄肯容絲。", "山岫當街翠，牆花拂面枝。鶯聲愛嬌小，燕翼玩逶迤。", "轡為逢車緩，鞭緣趁伴施。密攜長上樂，偷宿靜坊姬。", "僻性慵朝起，新晴助晚嬉。相歡常滿目，別處鮮開眉。", "翰墨題名盡，光陰聽話移。綠袍因醉典，烏帽逆風遺。", "暗插輕籌箸，仍提小屈卮。本弦才一舉，下口已三遲。", "逃席沖門出，歸倡借馬騎。狂歌繁節亂，醉舞半衫垂。", "散漫紛長薄，邀遮守隘岐。幾遭朝士笑，兼任巷童隨。", "苟務形骸達，渾將性命推。何曾愛官序，不省計家資。", "忽悟成虛擲，翻然歎未宜。使回耽樂事，堅赴策賢時。", "寢食都忘倦，園廬遂絕窺。勞神甘戚戚，攻短過孜孜。", "葉怯穿楊箭，囊藏透穎錐。超遙望雲雨，擺落占泉坻。", "略削荒涼苑，搜求激直詞。那能作牛後，更擬助洪基。", "唱第聽雞集，趨朝忘馬疲。內人輿禦案，朝景麗神旗。", "首被呼名姓，多慚冠等衰。千官容眷盼，五色照離披。", "鵷侶從茲洽，鷗情轉自縻。分張殊品命，中外卻驅馳。"]'),
('yuding-0','紀懷，贈李六戶曹、崔二十功曹五十韻','元稹','唐','御定全唐诗','yuding','','[]','昔冠諸生首，初因三道征。公卿碧墀會，名姓白麻稱。',577,'御定全唐詩/json/406.json','["昔冠諸生首，初因三道征。公卿碧墀會，名姓白麻稱。", "日月光遙射，煙霄志漸弘。榮班聯錦繡，諫紙賜箋藤。", "便欲呈肝膽，何言犯股肱。椎埋沖鬥劍，消碎瑩壺冰。", "赤縣才分務，青驄已迥乘。因騎度海鶻，擬殺蔽天鵬。", "縛虎聲空壯，連鼇力未勝。風翻波竟蹙，山壓勢逾崩。", "僇辱徒相困，蒼黃性不能。酣歌離峴頂，負氣入江陵。", "華表當蟾魄，高樓掛玉繩。角聲悲掉蕩，城影暗棱層。", "軍幕威容盛，官曹禮數兢。心雖出雲鶴，身尚觸籠鷹。", "竦足良甘分，排衙苦未曾。通名參將校，抵掌見親朋。", "喣沫求涓滴，滄波怯鬥升。荒居鄰鬼魅，羸馬步殑fF。", "白草堂簷短，黃梅雨氣蒸。沾黏經汗席，颭閃盡油燈。", "夜怯餐膚蚋，朝煩拂面蠅。過從愁厭賤，專靜畏猜仍。", "旅寓誰堪托，官聯自可憑。甲科崔並騖，柱史李齊升。", "共展排空翼，俱遭激遠矰。他鄉元易感，同病轉相矜。", "投分多然諾，忘言少愛憎。誓將探肺腑，恥更辨淄澠。", "會宿形骸遠，論交意氣增。一心吞渤澥，戮力拔嵩恒。", "語到磨圭角，疑消破弩症。吹噓期指掌，患難許簷簦。", "鎩翮鸞棲棘，藏鋒箭在弸。雪中方睹桂，木上莫施罾。", "且泛夤沿水，兼過被病僧。有時鞭款段，盡日醉懵僜。", "躡屐看秧稻，敲船和采菱。叉魚江火合，喚客谷神應。", "嘯傲雖開口，幽憂複滿膺。望雲鰭撥剌，透匣色騰淩。", "每想潢池寇，猶稽赤族懲。夔龍勞算畫，貔虎帶威棱。", "逐鳥忠潛奮，懸旌意遠凝。弢弓思徹劄，絆驥悶牽縆。", "運甓調辛苦，聞雞屢寢興。閑隨人兀兀，夢聽鼓冬冬。"]'),
('yuding-1','答姨兄胡靈之見寄五十韻','元稹','唐','御定全唐诗','yuding','','[]','憶昔鳳翔城，齠年是事榮。理家煩伯舅，相宅盡吾兄。',577,'御定全唐詩/json/406.json','["憶昔鳳翔城，齠年是事榮。理家煩伯舅，相宅盡吾兄。", "詩律蒙親授，朋遊忝自迎。題頭筠管縵，教射角弓騂。", "矮馬駝鬃bi，犛牛獸面纓。對談依赳赳，送客步盈盈。", "米碗諸賢讓，蠡杯大戶傾。一船席外語，三榼拍心精。", "傳盞加分數，橫波擲目成。華奴歌淅淅，媚子舞卿卿。", "鬥設狂為好，誰憂飲敗名。屠過隱朱亥，樓夢古秦嬴。", "環坐唯便草，投盤暫廢觥。春郊才爛熳，夕鼓已砰轟。", "荏苒移灰管，喧闐倦塞兵。糟漿聞漸足，書劍訝無成。", "抵璧慚虛棄，彈珠覺用輕。遂籠雲際鶴，來狎穀中鶯。", "學問攻方苦，篇章興太清。囊疏螢易透，錐鈍股多坑。", "筆陣戈矛合，文房棟桷撐。豆萁才敏俊，羽獵正崢嶸。", "岐下尋時別，京師觸處行。醉眠街北廟，閑繞宅南營。", "柳愛淩寒軟，梅憐上番驚。觀松青黛笠，欄藥紫霞英。", "盡日聽僧講，通宵詠月明。正耽幽趣樂，旋被宦途縈。", "吏晉資材枉，留秦歲序更。我髯黳數寸，君發白千莖。", "芸閣懷鉛暇，姑峰帶雪晴。何由身倚玉，空睹翰飛瓊。", "世道難於劍，讒言巧似笙。但憎心可轉，不解跽如擎。", "始效神羊觸，俄隨旅雁征。孤芳安可駐，五鼎幾時烹。", "潦倒沉泥滓，欹危踐矯衡。登樓王粲望，落帽孟嘉情。", "巫峽連天水，章台塞路荊。雨摧漁火焰，風引竹枝聲。", "分作屯之蹇，那知困亦亨。官曹三語掾，國器萬尋楨。", "逸傑雄姿迥，皇王雅論評。蕙依潛可習，雲合定誰令。", "原燎逢冰井，鴻流值木罌。智囊推有在，勇爵敢徒爭。", "迅拔看鵬舉，高音侍鶴鳴。所期人拭目，焉肯自佯盲。"]'),
('yuding-2','酬許五康佐','元稹','唐','御定全唐诗','yuding','','[]','奮迅君何晚，羈離我詎儔。鶴籠閑警露，鷹縛悶牽鞲。',120,'御定全唐詩/json/406.json','["奮迅君何晚，羈離我詎儔。鶴籠閑警露，鷹縛悶牽鞲。", "蓬閣深沉省，荊門遠慢州。課書同吏職，旅宦各鄉愁。", "白日傷心過，滄江滿眼流。嘶風悲代馬，喘月伴吳牛。", "枯涸方窮轍，生涯不系舟。猿啼三峽雨，蟬報兩京秋。", "珠玉慚新贈，芝蘭忝舊遊。他年問狂客，須向老農求。"]'),
('yuding-3','送崔侍禦之嶺南二十韻','元稹','唐','御定全唐诗','yuding','','[]','漢法戎施幕，秦官郡置監。蕭何歸舊印，鮑永授新銜。',240,'御定全唐詩/json/406.json','["漢法戎施幕，秦官郡置監。蕭何歸舊印，鮑永授新銜。", "幣聘雖盈篋，泥章未破緘。蛛懸絲繚繞，鵲報語詀諵。", "再礪神羊角，重開憲簡函。鞶纓驄赳赳，緌佩繡縿縿。", "逸翮憐鴻翥，離心覺刃劖。聯遊虧片玉，洞照失明鑒。", "遙想車登嶺，那無淚滿衫。茅蒸連蟒氣，衣漬度梅黬。", "象鬥緣溪竹，猿鳴帶雨杉。颶風狂浩浩，韶石峻嶄嶄。", "宿浦宜深泊，祈瀧在至諴。瘴江乘早度，毒草莫親芟。", "試蠱看銀黑，排腥貴食鹹。菌須蟲已蠹，果重鳥先鵮。", "冰瑩懷貪水，霜清顧痛岩。珠璣當盡擲，薏苡詎能讒。", "荊俗欺王粲，吾生問季咸。遠書多不達，勤為枉攕攕。"]'),
('yuding-4','酬段丞與諸棋流會宿弊居見贈二十四韻','元稹','唐','御定全唐诗','yuding','','[]','鳴局寧虛日，閑窗任廢時。琴書甘盡棄，園井詎能窺。',288,'御定全唐詩/json/406.json','["鳴局寧虛日，閑窗任廢時。琴書甘盡棄，園井詎能窺。", "運石疑填海，爭籌憶坐帷。赤心方苦鬥，紅燭已先施。", "蛇勢縈山合，鴻聯度嶺遲。堂堂排直陣，袞袞逼羸師。", "懸劫偏深猛，回征特險巇。旁攻百道進，死戰萬般為。", "異日玄黃隊，今宵黑白棋。斫營看迥點，對壘重相持。", "善敗雖稱怯，驕盈最易欺。狼牙當必碎，虎口禍難移。", "乘勝同三捷，扶顛望一詞。希因送目便，敢恃指縱奇。", "退引防邊策，雄吟斬將詩。眠床都浪置，通夕共忘疲。", "曉雉風傳角，寒叢雪壓枝。繁星收玉版，殘月耀冰池。", "僧請聞鐘粥，賓催下藥卮。獸炎餘炭在，蠟淚短光衰。", "俯仰嗟陳跡，殷勤蔔後期。公私牽去住，車馬各支離。", "分作終身癖，兼從是事隳。此中無限興，唯怕俗人知。"]'),
('yuding-5','酬竇校書二十韻','元稹','唐','御定全唐诗','yuding','','[]','鷗鷺元相得，杯觴每共傳。芳遊春爛熳，晴望月團圓。',240,'御定全唐詩/json/406.json','["鷗鷺元相得，杯觴每共傳。芳遊春爛熳，晴望月團圓。", "調笑風流劇，論文屬對全。賞花珠並綴，看雪璧常連。", "竹寺荒唯好，松齋小更憐。潛投孟公轄，狂乞莫愁錢。", "塵土拋書卷，槍籌弄酒權。令誇齊箭道，力鬥抹弓弦。", "但喜添樽滿，誰憂乏桂然。漸輕身外役，渾證飲中禪。", "及我辭雲陛，逢君仕圃田。音徽千里斷，魂夢兩情偏。", "足聽猿啼雨，深藏馬腹鞭。官醪半清濁，夷饌雜腥膻。", "顧影無依倚，甘心守靜專。那知暮江上，俱會落英前。", "款曲生平在，悲涼歲序遷。鶴方同北渚，鴻又過南天。", "麗句慚虛擲，沉機懶強牽。粗酬珍重意，工拙定相懸。"]'),
('yuding-6','泛江玩月十二韻','元稹','唐','御定全唐诗','yuding','','[]','楚塞分形勢，羊公壓大邦。因依多士子，參畫盡敦厖。',144,'御定全唐詩/json/406.json','["楚塞分形勢，羊公壓大邦。因依多士子，參畫盡敦厖。", "岳璧閑相對，荀龍自有雙。共將船載酒，同泛月臨江。", "遠樹懸金鏡，深潭倒玉幢。委波添淨練，洞照滅凝釭。", "闐咽沙頭市，玲瓏竹岸窗。巴童唱巫峽，海客話神瀧。", "已困連飛盞，猶催未倒缸。飲荒情爛熳，風棹樂崢摐。", "勝事他年憶，愁心此夜降。知君皆逸韻，須為應莛撞。"]'),
('yuding-7','痁臥聞幕中諸公征樂會飲，因有戲呈三十韻','元稹','唐','御定全唐诗','yuding','','[]','濩落因寒甚，沉陰與病偕。藥囊堆小案，書卷塞空齋。',362,'御定全唐詩/json/406.json','["濩落因寒甚，沉陰與病偕。藥囊堆小案，書卷塞空齋。", "脹腹看成鼓，羸形漸比柴。道情憂易適，溫瘴氣難排。", "治t3扶輕仗，開門立靜街。耳鳴疑暮角，眼暗助昏霾。", "野竹連荒草，平陂接斷崖。坐隅甘對鵩，當路恐遭豺。", "蛇蠱迷弓影，雕翎落箭靫。晚籬喧鬥雀，殘菊半枯荄。", "悵望悲回雁，依遲傍古槐。一生長苦節，三省詎行怪。", "奔北翻成勇，司南卻是咼。穹蒼真漠漠，風雨漫喈喈。", "彼美猶溪女，其誰占館娃。誠知通有日，太極浩無涯。", "布卦求無妄，祈天願孔皆。藏衰謀計拙，地僻往還乖。", "況羨蓮花侶，方欣綺席諧。鈿車迎妓樂，銀翰屈朋儕。", "白紵顰歌黛，同蹄墜舞釵。纖身霞出海，豔臉月臨淮。", "籌箸隨宜放，投盤止罰啀。紅娘留醉打，觥使及醒差。", "顧我潛孤憤，何人想獨懷。夜燈然檞葉，凍雪墮磚階。", "壞壁虛缸倚，深爐小火埋。鼠驕銜筆硯，被冷束筋骸。", "畢竟圖斟酌，先須遣癘痎。槍旗如在手，那複敢崴pN。"]'),
('yuding-8','酬友封話舊敘懷十二韻','元稹','唐','御定全唐诗','yuding','','[]','風波千里別，書信二年稀。乍見悲兼喜，猶驚是與非。',144,'御定全唐詩/json/406.json','["風波千里別，書信二年稀。乍見悲兼喜，猶驚是與非。", "身名判作夢，杯盞莫相違。草館同床宿，沙頭待月歸。", "春深鄉路遠，老去宦情微。魏闕何由到，荊州且共依。", "人欺翻省事，官冷易藏威。但擬馴鷗鳥，無因用弩機。", "開張圖卷軸，顛倒醉衫衣。蓴菜銀絲嫩，鱸魚雪片肥。", "憐君詩似湧，贈我筆如飛。會遣諸伶唱，篇篇入禁闈。"]'),
('yuding-9','送王協律游杭越十韻','元稹','唐','御定全唐诗','yuding','','[]','去去莫淒淒，餘杭接會稽。松門天竺寺，花洞若耶溪。',120,'御定全唐詩/json/406.json','["去去莫淒淒，餘杭接會稽。松門天竺寺，花洞若耶溪。", "浣渚逢新豔，蘭亭識舊題。山經秦帝望，壘辨越王棲。", "江樹春常早，城樓月易低。鏡呈湖面出，雲疊海潮齊。", "章甫官人戴，蓴絲姹女提。長幹迎客鬧，小市隔煙迷。", "紙亂紅藍壓，甌凝碧玉泥。荊南無抵物，來日為儂攜。"]'),
('yuding-10','送東川馬逢侍禦使回十韻','元稹','唐','御定全唐诗','yuding','','[]','風水荊門闊，文章蜀地豪。眼青賓禮重，眉白眾情高。',120,'御定全唐詩/json/406.json','["風水荊門闊，文章蜀地豪。眼青賓禮重，眉白眾情高。", "思勇曾吞筆，投虛慣用刀。詞鋒倚天劍，學海駕雲濤。", "南郡傳紗帳，東方讓錦袍。旋吟新樂府，便續古離騷。", "雪岸猶封草，春江欲滿槽。餞筵君置醴，隨俗我餔糟。", "莫歎巴三峽，休驚鬢二毛。流年等頭過，人世各勞勞。"]'),
('yuding-0','酬盧秘書','元稹','唐','御定全唐诗','yuding','','[]','偶有沖天氣，都無處世才。未容榮路穩，先踏禍機開。',240,'御定全唐詩/json/407.json','["偶有沖天氣，都無處世才。未容榮路穩，先踏禍機開。", "分久沉荊掾，慚經廁柏台。理推愁易惑，鄉思病難裁。", "夜伴吳牛喘，春驚朔雁回。北人腸斷送，西日眼穿頹。", "唯望魂歸去，那知詔下來。涸魚千丈水，僵燕一聲雷。", "幽匣提清鏡，衰顏拂故埃。夢雲期紫閣，厭雨別黃梅。", "親戚迎時到，班行見處陪。文工猶畏忌，朝士絕嫌猜。", "新識蓬山傑，深交翰苑材。連投珠作貫，獨和玉成堆。", "劇敵徒相軋，羸師亦自媒。磨礱刮骨刃，翻擲委心灰。", "恐被神明哭，憂為造化災。私調破葉箭，定飲搴旗杯。", "金寶潛砂礫，芝蘭似草萊。憑君毫髮鑒，莫遣翳莓苔。"]'),
('yuding-1','見人詠韓舍人新律詩，因有戲贈','元稹','唐','御定全唐诗','yuding','','[]','喜聞韓古調，兼愛近詩篇。玉磬聲聲徹，金鈴個個圓。',120,'御定全唐詩/json/407.json','["喜聞韓古調，兼愛近詩篇。玉磬聲聲徹，金鈴個個圓。", "高疏明月下，細膩早春前。花態繁於綺，閨情軟似綿。", "輕新便妓唱，凝妙入僧禪。欲得人人伏，能教面面全。", "延之苦拘檢，摩詰好因緣。七字排居敬，千詞敵樂天。", "殷勤閑太祝，好去老通川。莫漫裁章句，須饒紫禁仙。"]'),
('yuding-2','奉和權相公行次臨闕驛逢鄭僕射相公歸朝俄頃分途因以奉贈詩十四韻','元稹','唐','御定全唐诗','yuding','','[]','帝下赤霄符，搜求造化爐。中台歸內座，太一直南都。',168,'御定全唐詩/json/407.json','["帝下赤霄符，搜求造化爐。中台歸內座，太一直南都。", "黃霸乘軺入，王尊叱馭趨。萬人東道送，六纛北風驅。", "棧閣才傾蓋，關門已合繻。貫魚行邐迤，交馬語踟躕。", "去速熊羆兆，來馳虎豹夫。昔憐三易地，今訝兩分途。", "別路環山雪，離章運寸珠。鋒鋩斷犀兕，波浪沒蓬壺。", "區宇聲雖動，淮河孽未誅。將軍遙策畫，師氏密籲謨。", "漢上壇仍築，褒西陣再圖。公方先二虜，何暇進愚儒。"]'),
('yuding-3','酬樂天東南行詩一百韻','元稹','唐','御定全唐诗','yuding','','[]','我病方吟越，君行已過湖。去應緣直道，哭不為窮途。',577,'御定全唐詩/json/407.json','["我病方吟越，君行已過湖。去應緣直道，哭不為窮途。", "亞竹寒驚牖，空堂夜向隅。暗魂思背燭，危夢怯乘桴。", "坐痛筋骸憯，旁嗟物候殊。雨蒸蟲沸渭，浪湧怪睢盱。", "索綆飄蚊蚋，蓬麻甃舳艫。短簷苫稻草，微俸封漁租。", "泥浦喧撈蛤，荒郊險鬥貙。鯨吞近溟漲，猿鬧接黔巫。", "芒屩泅牛婦，丫頭蕩槳夫。酢醅荷裹賣，醨酒水淋沽。", "舞態翻鴝鵒，歌詞咽鷓鴣。夷音啼似笑，蠻語謎相呼。", "江郭船添店，山城木豎郛。吠聲沙市犬，爭食墓林烏。", "獷俗誠堪憚，妖神甚可虞。欲令仁漸及，已被瘧潛圖。", "膳減思調鼎，行稀恐蠹樞。雜蓴多剖鱔，和黍半蒸菰。", "綠粽新菱實，金丸小木奴。芋羹真暫淡，bJ炙漫塗蘇。", "炰鱉那勝羜，烹鯄只似鱸。楚風輕似蜀，巴地濕如吳。", "氣濁星難見，州斜日易晡。通宵但雲霧，未酉即桑榆。", "瘴窟蛇休蟄，炎溪暑不徂。倀魂陰叫嘯，鵩貌晝踟躕。", "鄉里家藏蠱，官曹世乏儒。斂緡偷印信，傳箭作符繻。", "椎髻拋巾幗，鑹刀代轆轤。當心鞙銅鼓，背弝射桑弧。", "豈複民氓料，須將鳥獸驅。是非渾並漆，詞訟敢研朱。", "陋室鴞窺伺，衰形蟒覬覦。鬢毛霜點合，襟淚血痕濡。", "倍憶京華伴，偏忘我爾軀。謫居今共遠，榮路昔同趨。", "科試銓衡局，衙參典校廚。月中分桂樹，天上識昌蒲。", "應召逢鴻澤，陪遊值賜酺。心唯撞衛磬，耳不亂齊竽。", "海岱詞鋒截，皇王筆陣驅。疾奔淩騕褭，高唱軋吳歈。", "點檢張儀舌，提攜傅說圖。擺囊看利穎，開頷出明珠。", "並取千人特，皆非十上徒。白麻雲色膩，墨詔電光粗。"]'),
('yuding-4','和樂天送客遊嶺南二十韻','元稹','唐','御定全唐诗','yuding','','[]','我自離鄉久，君那度嶺頻。一杯魂慘澹，萬里路艱辛。',240,'御定全唐詩/json/407.json','["我自離鄉久，君那度嶺頻。一杯魂慘澹，萬里路艱辛。", "江館連沙市，瀧船泊水濱。騎田回北顧，銅柱指南鄰。", "大壑浮三島，周天過五均。波心湧樓閣，規外布星辰。", "狒狒穿筒格，猩猩置屐馴。貢兼蛟女絹，俗重語兒巾。", "舶主腰藏寶，黃家砦起塵。歌鐘排象背，炊爨上魚身。", "電白雷山接，旗紅賊艦新。島夷徐市種，廟覡趙佗神。", "鳶跕方知瘴，蛇蘇不待春。曙潮雲斬斬，夜海火磷磷。", "冠冕中華客，梯航異域臣。果然皮勝錦，吉了舌如人。", "風黖秋茅葉，煙埋曉月輪。定應玄發變，焉用翠毛珍。", "句漏沙須買，貪泉貨莫親。能傳稚川術，何患隱之貧。"]'),
('yuding-5','獻滎陽公詩五十韻','元稹','唐','御定全唐诗','yuding','','[]','鄭驛騎翩翩，丘門子弟賢。文翁開學日，正禮騁途年。',576,'御定全唐詩/json/407.json','["鄭驛騎翩翩，丘門子弟賢。文翁開學日，正禮騁途年。", "駿骨黃金買，英髦絳帳延。趨風皆蹀足，侍坐各差肩。", "解榻招徐稚，登樓引仲宣。鳳攢題字扇，魚落講經筵。", "盛氣河包濟，貞姿嶽柱天。皋夔當五百，鄒魯重三千。", "科鬥翻騰取，關雎教授先。篆垂朝露滴，詩綴夜珠聯。", "逸禮多心匠，焚書舊口傳。陳遵修尺牘，阮瑀讓飛箋。", "中的顏初啟，抽毫踵未旋。森羅萬木合，屬對百花全。", "詞海跳波湧，文星拂坐懸。戴馮遙避席，祖逖後施鞭。", "西蜀淩雲賦，東陽詠月篇。勁芟鼇足斷，精貫虱心穿。", "浩汗神彌王，鷂颺興欲仙。冰壺通皓雪，綺樹眇晴煙。", "驅駕雷霆走，鋪陳錦繡鮮。清機登穾奧，流韻溢山川。", "墨客膺潛服，談賓膝誤前。張鱗定摧敗，折角反矜憐。", "句句推瓊玉，聲聲播管弦。纖新撩造化，澒洞斡陶甄。", "衛磬琤鍧極，齊竽僭濫偏。空虛慚炙輠，點竄許懷鉛。", "憊色秋來草，哀吟雨後蟬。自傷魂慘沮，何暇思幽玄。", "喜到樽罍側，愁親幾案邊。菁華知竭矣，肺腑尚求旃。", "抵滯渾成醉，徘徊轉慕膻。老歎才漸少，閑苦病相煎。", "瓦礫難追琢，芻蕘分棄捐。漫勞成懇懇，那得美娟娟。", "拙劣仍非速，迂愚且異專。移時停筆硯，揮景乏戈鋋。", "儀舌忻猶在，舒帷誓不褰。會將連獻楚，深恥謬游燕。", "蒲有臨書葉，韋充讀易編。沙須披見寶，經擬帶耕田。", "入霧長期閏，持朱本望研。輪轅呈曲直，鑿枘取方圓。", "呼吸寧徒爾，沾濡豈浪然。過簫資響亮，隨水漲淪漣。", "惜日看圭短，偷光恨壁堅。勤勤雕朽木，細細導蒙泉。"]'),
('yuding-0','酬樂天江樓夜吟稹詩，因成三十韻','元稹','唐','御定全唐诗','yuding','','[]','忽見君新句，君吟我舊篇。見當巴徼外，吟在楚江前。',360,'御定全唐詩/json/408.json','["忽見君新句，君吟我舊篇。見當巴徼外，吟在楚江前。", "思鄙寧通律，聲清遂扣玄。三都時覺重，一顧世稱妍。", "排韻曾遙答，分題幾共聯。昔憑銀翰寫，今賴玉音宣。", "布鼓隨椎響，坯泥仰匠圓。鈴因風斷續，珠與調牽綿。", "阮籍驚長嘯，商陵怨別弦。猿羞啼月峽，鶴讓警秋天。", "志士潛興感，高僧暫廢禪。興飄滄海動，氣合碧雲連。", "點綴工微者，吹噓勢特然。休文徒倚檻，彥伯浪回船。", "伎樂當筵唱，兒童滿巷傳。改張思婦錦，騰躍賈人箋。", "魏拙虛教出，曹風敢望痊。定遭才子笑，恐賺學生癲。", "裁什情何厚，飛書信不專。隼猜鴻蓄縮，虎橫犬迍邅。", "水墨看雖久，瓊瑤喜尚全。才從魚裏得，便向市頭懸。", "夜置堂東序，朝鋪座右邊。手尋韋欲絕，淚滴紙渾穿。", "甘蔗銷殘醉，醍醐醒早眠。深藏那遽滅，同詠苦無緣。", "雅羨詩能聖，終嗟藥未仙。五千誠遠道，四十已中年。", "暗魄多相夢，衰容每自憐。卒章還慟哭，蚊蚋溢山川。"]'),
('yuding-1','酬樂天待漏入閣見贈','元稹','唐','御定全唐诗','yuding','','[]','未勘銀台契，先排浴殿關。沃心因特召，承旨絕常班。',120,'御定全唐詩/json/408.json','["未勘銀台契，先排浴殿關。沃心因特召，承旨絕常班。", "颭閃才人袖，嘔鴉軟舉鐶。宮花低作帳，雲從積成山。", "密視樞機草，偷瞻咫尺顏。恩垂天語近，對久漏聲閑。", "丹陛曾同立，金鑾恨獨攀。筆無鴻業潤，袍愧紫文殷。", "河水通天上，瀛州接世間。謫仙名籍在，何不重來還。"]'),
('yuding-2','酬樂天早春閒遊西湖頗多野趣恨不得與微之同賞因思在越官重事殷鏡湖之遊或恐未暇因成十八韻見寄樂天前篇到時適會予亦宴鏡湖南亭因述目前所睹以成酬答末章亦示暇誠則勢使之然亦欲粗為恬養之贈耳','元稹','唐','御定全唐诗','yuding','','[]','雁思欲回賓，風聲乍變新。各攜紅粉伎，俱伴紫垣人。',216,'御定全唐詩/json/408.json','["雁思欲回賓，風聲乍變新。各攜紅粉伎，俱伴紫垣人。", "水面波疑縠，山腰虹似巾。柳條黃大帶，茭葑綠文茵。", "雪盡才通屐，汀寒未有蘋。向陽偏曬羽，依岸小遊鱗。", "浦嶼崎嶇到，林園次第巡。墨池憐嗜學，丹井羨登真。", "雅歎游方盛，聊非意所親。白頭辭北闕，滄海是東鄰。", "問俗煩江界，搜畋想渭津。故交音訊少，歸夢往來頻。", "獨喜同門舊，皆為列郡臣。三刀連地軸，一葦礙車輪。", "尚阻青天霧，空瞻白玉塵。龍因雕字識，犬為送書馴。", "勝事無窮境，流年有限身。懶將閒氣力，爭鬥野塘春。"]'),
('yuding-3','江邊四十韻','元稹','唐','御定全唐诗','yuding','','[]','官借江邊宅，天生地勢坳。欹危饒壞構，迢遞接長郊。',480,'御定全唐詩/json/408.json','["官借江邊宅，天生地勢坳。欹危饒壞構，迢遞接長郊。", "怪鵩頻棲息，跳蛙頗混淆。總無籬繳繞，尤怕虎咆哮。", "停潦魚招獺，空倉鼠敵貓。土虛煩穴蟻，柱朽畏藏蛟。", "蛇虺吞簷雀，豺狼逐野麃。犬驚狂浩浩，雞亂響嘐嘐。", "濩落貧甘守，荒涼穢盡包。斷簾飛熠耀，當戶網蠨蛸。", "曲突翻成沼，行廊卻代庖。橋橫老顛枿，馬病裛芻茭。", "一一床頭點，連連砌下泡。辱泥疑在絳，避雨想經崤。", "相顧憂為鱉，誰能複系匏。誓心來利往，卜食過安爻。", "何計逃昏墊，移文報舊交。棟樑存伐木，苫蓋愧分茅。", "金管排黃荻，琅玕嫋翠梢。花磚水面鬥，鴛瓦玉聲敲。", "方礎荊山采，修掾郢匠鉋。隱錐雷震蟄，破竹箭鳴骹。", "正寢初停午，頻眠欲轉胞。囷圓收薄祿，廚敝備嘉肴。", "各各人寧宇，雙雙燕賀巢。高門受車轍，華廄稱蒲捎。", "尺寸皆隨用，毫釐敢浪拋。篾餘籠白鶴，枝剩架青鵁。", "制榻容筐篚，施關拒鬥筲。欄幹防汲井，密室待持膠。", "庭草傭工薙，園蔬稚子掊。本圖閑種植，那要擇肥磽。", "綠柚勤勤數，紅榴個個抄。池清漉螃蟹，瓜蠹拾螌蟊。", "曬篆看沙鳥，磨刀綻海鮫。羅灰修藥灶，築垛閱弓弰。", "散誕都由習，童蒙剩懶教。最便陶靜飲，還作解愁嘲。", "近浦聞歸楫，遙城罷曉鐃。王孫如有問，須為並揮鞘。"]'),
('yuding-4','春六十韻','元稹','唐','御定全唐诗','yuding','','[]','節應寒灰下，春生返照中。未能消積雪，已漸少回風。',577,'御定全唐詩/json/408.json','["節應寒灰下，春生返照中。未能消積雪，已漸少回風。", "迎氣邦經重，齋誠帝念隆。龍驤紫宸北，天壓翠壇東。", "仙仗搖佳彩，榮光答聖衷。便從威仰座，隨入大羅宮。", "先到璿淵底，偷穿玳瑁櫳。館娃朝鏡晚，太液曉冰融。", "撩摘芳情遍，搜求好處終。九霄渾可哥，萬姓尚忡忡。", "晝漏頻加箭，宵暉欲半弓。驅令三殿出，乞與百蠻同。", "直自方壺島，斜臨絕漠戎。南巡曖珠樹，西轉麗崆峒。", "度嶺梅甘坼，潛泉脈暗洪。悠悠鋪塞草，冉冉著江楓。", "蠶役投筐妾，耘催荷蓧翁。既蒸難發地，仍送懶歸鴻。", "約略環區宇，殷勤綺鎬灃。華山青黛撲，渭水碧沙蒙。", "宿露清餘靄，晴煙塞迥空。燕巢才點綴，鶯舌最惺憁。", "膩粉梨園白，胭脂桃徑紅。郁金垂嫩柳，罯畫委高籠。", "地甲門闌大，天開禁掖崇。層台張舞鳳，閣道架飛虹。", "麹糵調神化，鵷鸞竭至忠。歌鐘齊錫宴，車服獎庸功。", "俊造欣時用，閭閻賀歲豐。倡樓妝z8々，農野綠芃芃。", "貴主驕矜盛，豪家恃賴雄。偏沾打球彩，頻得鑄錢銅。", "專殺擒楊若，殊恩赦鄧通。女孫新在內，嬰稚近封公。", "游衍關心樂，詩書對面聾。盤筵饒異味，音樂斥庸工。", "酒愛油衣淺，杯誇瑪瑙烘。挑鬟玉釵髻，刺繡寶裝攏。", "啟齒呈編貝，彈絲動削蔥。醉圓雙媚靨，波溢兩明瞳。", "但賞歡無極，那知恨亦充。洞房閑窈窕，庭院獨蔥蘢。", "謝砌縈殘絮，班窗網曙蟲。望夫身化石，為伯首如蓬。", "顧我沉憂士，騎他老病驄。靜街乘曠蕩，初日接曈曨。", "飲敗肺常渴，魂驚耳更聰。虛逢好陽豔，其那苦昏懵。"]'),
('yuding-5','月三十韻','元稹','唐','御定全唐诗','yuding','','[]','蓂葉標新朔，霜豪引細輝。白眉驚半隱，虹勢訝全微。',360,'御定全唐詩/json/408.json','["蓂葉標新朔，霜豪引細輝。白眉驚半隱，虹勢訝全微。", "涼魄潭空洞，虛弓雁畏威。上弦何汲汲，佳色轉依依。", "綺幕殘燈斂，妝樓破鏡飛。玲瓏穿竹樹，岑寂思屏幃。", "坐愛規將合，行看望已幾。絳河冰鑒朗，黃道玉輪巍。", "迥照偏瓊砌，餘光借粉闈。泛池相皎潔，壓桂共芳菲。", "的的當歌扇，娟娟透舞衣。殷勤入懷什，懇款墮雲圻。", "素液傳烘盞，鳴琴薦碧徽。椒房深肅肅，蘭路靄霏霏。", "翡翠通簾影，琉璃瑩殿扉。西園筵玳瑁，東壁射蛜蝛。", "老將占天陣，幽人釣石磯。荷鋤元亮息，回棹子猷歸。", "迢遞同千里，孤高淨九圍。從星作風雨，配日麗旌旗。", "麟鬥寧徒設，蠅聲豈浪譏。司存委卿士，新拜出郊畿。", "今古雖雲極，虧盈不易違。珠胎方夜滿，清露忍朝晞。", "漸減姮娥面，徐收楚練機。卞疑雕璧碎，潘感竟床稀。", "捐篋辭班女，潛波蔽虙妃。氛埃誰定滅，蟾兔杳難希。", "須遣圓明盡，良嗟造化非。如能付刀尺，別為創璿璣。"]'),
('yuding-6','飲致用神麹酒三十韻','元稹','唐','御定全唐诗','yuding','','[]','七月調神麹，三春釀綠醽。雕鐫荊玉盞，烘透內丘瓶。',360,'御定全唐詩/json/408.json','["七月調神麹，三春釀綠醽。雕鐫荊玉盞，烘透內丘瓶。", "試滴盤心露，疑添案上螢。滿尊凝止水，祝地落繁星。", "翻陋瓊漿濁，唯聞石髓馨。冰壺通角簟，金鏡徹雲屏。", "雪映煙光薄，霜涵霽色泠。蚌珠懸皎皛，桂魄倒瀴溟。", "晝灑蟬將飲，宵揮鶴誤聆。琉璃驚太白，鐘乳訝微青。", "詎敢辭濡首，並憐可鑒形。行當遣俗累，便得造禪扃。", "何憚說千日，甘從過百齡。但令長泛蟻，無複恨漂萍。", "膽壯還增氣，機忘反自冥。甕眠思畢卓，糟籍憶劉伶。", "仿佛中聖日，希夷夾大庭。眼前須底物，座右任他銘。", "刮骨都無痛，如泥未擬停。殘觴猶漠漠，華燭已熒熒。", "真性臨時見，狂歌半睡聽。喧闐爭意氣，調笑學娉婷。", "酩酊焉知極，羈離忽暫寧。雞聲催欲曙，蟾影照初醒。", "咽絕鵑啼竹，蕭撩雁去汀。遙城傳漏箭，鄉寺響風鈴。", "楚澤一為梗，堯階屢變蓂。醉荒非獨此，愁夢幾曾經。", "每恥窮途哭，今那客淚零。感君澄醴酒，不遣渭和涇。"]'),
('yuding-7','感石榴二十韻','元稹','唐','御定全唐诗','yuding','','[]','何年安石國，萬里貢榴花。迢遞河源道，因依漢使槎。',240,'御定全唐詩/json/408.json','["何年安石國，萬里貢榴花。迢遞河源道，因依漢使槎。", "酸辛犯蔥嶺，憔悴涉龍沙。初到摽珍木，多來比亂麻。", "深拋故園裏，少種貴人家。唯我荊州見，憐君胡地賒。", "從教當路長，兼恣入簷斜。綠葉裁煙翠，紅英動日華。", "新簾裙透影，疏牖燭籠紗。委作金爐焰，飄成玉砌瑕。", "乍驚珠綴密，終誤繡幃奢。琥珀烘梳碎，燕支懶頰塗。", "風翻一樹火，電轉五雲車。絳帳迎宵日，芙蕖綻早牙。", "淺深俱隱映，前後各分葩。宿露低蓮臉，朝光借綺霞。", "暗虹徒繳繞，濯錦莫周遮。俗態能嫌舊，芳姿尚可嘉。", "非專愛顏色，同恨阻幽遐。滿眼思鄉淚，相嗟亦自嗟。"]'),
('yuding-8','度門寺','元稹','唐','御定全唐诗','yuding','','[]','北祖三禪地，西山萬樹松。門臨溪一帶，橋映竹千重。',240,'御定全唐詩/json/408.json','["北祖三禪地，西山萬樹松。門臨溪一帶，橋映竹千重。", "翦鑿基階正，包藏景氣濃。諸岩分院宇，雙嶺抱垣墉。", "舍利開層塔，香爐占小峰。道場居士置，經藏大師封。", "太子知栽植，神王守要衝。由旬排講座，丈六寫真容。", "佛語迦陵說，僧行猛虎從。修羅抬日拒，樓至拔霜鋒。", "畫井垂枯朽，穿池救噞喁。蕉非難敗壞，槿喻暫豐茸。", "寶界留遺事，金棺滅去蹤。缽傳烘瑪瑙，石長翠芙蓉。", "影帳紗全落，繩床土半壅。荒林迷醉象，危壁亞盤龍。", "行色憐初月，歸程待曉鐘。心源雖了了，塵世苦憧憧。", "宿蔭高聲懺，齋糧並力舂。他生再來此，還願總相逢。"]'),
('yuding-9','大雲寺二十韻','元稹','唐','御定全唐诗','yuding','','[]','地勝宜台殿，山晴離垢氛。現身千佛國，護世四王軍。',240,'御定全唐詩/json/408.json','["地勝宜台殿，山晴離垢氛。現身千佛國，護世四王軍。", "碧耀高樓瓦，赬飛半壁文。鶴林縈古道，雁塔沒歸雲。", "幡影中天颺，鐘聲下界聞。攀蘿極峰頂，游目到江濆。", "馴鴿閑依綴，調猿靜守群。虎行風捷獵，龍睡氣氛氳。", "獲稻禪衣卷，燒畬劫火焚。新英蜂采掇，荒草象耕耘。", "缽付靈童洗，香教善女熏。果枝低罯罯，花雨澤雰雰。", "示化維摩疾，降魔力士勳。聽經神變見，說偈鳥紛紜。", "上境光猶在，深溪暗不分。竹籠煙欲暝，松帶日餘曛。", "真諦成知別，迷心尚有雲。多生沉五蘊，宿習樂三墳。", "諭鹿車雖設，如蠶緒正棼。且將平等義，還奉聖明君。"]'),
('yuding-10','和友封題開善寺十韻','元稹','唐','御定全唐诗','yuding','','[]','梁王開佛廟，雲構歲時遙。珠綴飛閑鴿，紅泥落碎椒。',120,'御定全唐詩/json/408.json','["梁王開佛廟，雲構歲時遙。珠綴飛閑鴿，紅泥落碎椒。", "燈籠青焰短，香印白灰銷。古匣收遺施，行廊畫本朝。", "藏經沾雨爛，魔女捧花嬌。亞樹牽藤閣，橫查壓石橋。", "竹荒新筍細，池淺小魚跳。匠正琉璃瓦，僧鋤芍藥苗。", "旋蒸茶嫩葉，偏把柳長條。便欲忘歸路，方知隱易招。"]'),
('yuding-0','牡丹二首','元稹','唐','御定全唐诗','yuding','','[]','簇蕊風頻壞，裁紅雨更新。眼看吹落地，便別一年春。',48,'御定全唐詩/json/409.json','["簇蕊風頻壞，裁紅雨更新。眼看吹落地，便別一年春。", "繁綠陰全合，衰紅展漸難。風光一抬舉，猶得暫時看。"]'),
('yuding-1','象人','元稹','唐','御定全唐诗','yuding','','[]','被色空成象，觀空色異真。自悲人是假，那複假為人。',24,'御定全唐詩/json/409.json','["被色空成象，觀空色異真。自悲人是假，那複假為人。"]'),
('yuding-2','與楊十二巨源盧十九經濟同遊大安亭各賦二物各為五韻探得松石','元稹','唐','御定全唐诗','yuding','','[]','片石與孤松，曾經物外逢。月臨棲鶴影，雲抱老人峰。',60,'御定全唐詩/json/409.json','["片石與孤松，曾經物外逢。月臨棲鶴影，雲抱老人峰。", "蜀客君當問，秦官我舊封。積膏當琥珀，新劫長芙蓉。", "待補蒼蒼去，樛柯早變龍。"]'),
('yuding-3','賦得春雪映早梅','元稹','唐','御定全唐诗','yuding','','[]','飛舞先春雪，因依上番梅。一枝方漸秀，六出已同開。',72,'御定全唐詩/json/409.json','["飛舞先春雪，因依上番梅。一枝方漸秀，六出已同開。", "積素光逾密，真花節暗催。摶風飄不散，見晛忽偏摧。", "郢曲琴空奏，羌音笛自哀。今朝兩成詠，翻挾昔人才。"]'),
('yuding-4','賦得玉卮無當','元稹','唐','御定全唐诗','yuding','','[]','共惜連城寶，翻成無當卮。詎慚君子貴，深訝巧工隳。',72,'御定全唐詩/json/409.json','["共惜連城寶，翻成無當卮。詎慚君子貴，深訝巧工隳。", "泛蟻功全小，如虹色不移。可憐殊礫石，何計辨糟醨。", "江海誠難滿，盤筵莫忘施。縱乖斟酌意，猶得對光儀。"]'),
('yuding-5','賦得數蓂','元稹','唐','御定全唐诗','yuding','','[]','將課司天曆，先觀近砌蓂。一旬開應月，五日數從星。',72,'御定全唐詩/json/409.json','["將課司天曆，先觀近砌蓂。一旬開應月，五日數從星。", "桂滿叢初合，蟾虧影漸零。辨時長有素，數閏或餘青。", "墜葉推前事，新芽察未形。堯年始今歲，方欲瑞千齡。"]'),
('yuding-6','賦得九月盡','元稹','唐','御定全唐诗','yuding','','[]','霜降三旬後，蓂餘一葉秋。玄陰迎落日，涼魄盡殘鉤。',48,'御定全唐詩/json/409.json','["霜降三旬後，蓂餘一葉秋。玄陰迎落日，涼魄盡殘鉤。", "半夜灰移管，明朝帝禦裘。潘安過今夕，休詠賦中愁。"]'),
('yuding-7','賦得雨後花','元稹','唐','御定全唐诗','yuding','','[]','紅芳憐靜色，深與雨相宜。餘滴下纖蕊，殘珠墮細枝。',48,'御定全唐詩/json/409.json','["紅芳憐靜色，深與雨相宜。餘滴下纖蕊，殘珠墮細枝。", "浣花江上思，啼粉鏡中窺。念此低回久，風光幸一吹。"]'),
('yuding-8','早歸','元稹','唐','御定全唐诗','yuding','','[]','春靜曉風微，淩晨帶酒歸。遠山籠宿霧，高樹影朝暉。',48,'御定全唐詩/json/409.json','["春靜曉風微，淩晨帶酒歸。遠山籠宿霧，高樹影朝暉。", "飲馬魚驚水，穿花露滴衣。嬌鶯似相惱，含囀傍人飛。"]'),
('yuding-9','晚秋','元稹','唐','御定全唐诗','yuding','','[]','竹露滴寒聲，離人曉思驚。酒醒秋簟冷，風急夏衣輕。',48,'御定全唐詩/json/409.json','["竹露滴寒聲，離人曉思驚。酒醒秋簟冷，風急夏衣輕。", "寢倦解幽夢，慮閑添遠情。誰憐獨欹枕，斜月透窗明。"]'),
('yuding-10','送林複夢赴韋令辟','元稹','唐','御定全唐诗','yuding','','[]','蜀路危於劍，憐君自坦途。幾回曾啖炙，千里遠銜珠。',48,'御定全唐詩/json/409.json','["蜀路危於劍，憐君自坦途。幾回曾啖炙，千里遠銜珠。", "野性便荒飲，時風忌酒徒。相門多禮讓，前後莫相逾。"]'),
('yuding-11','憶楊十二','元稹','唐','御定全唐诗','yuding','','[]','楊子愛言詩，春天好詠時。戀花從馬滯，聯句放杯遲。',48,'御定全唐詩/json/409.json','["楊子愛言詩，春天好詠時。戀花從馬滯，聯句放杯遲。", "日映含煙竹，風牽臥柳絲。南山更多興，須作白雲期。"]'),
('yuding-12','夜合','元稹','唐','御定全唐诗','yuding','','[]','綺樹滿朝陽，融融有露光。雨多疑濯錦，風散似分妝。',48,'御定全唐詩/json/409.json','["綺樹滿朝陽，融融有露光。雨多疑濯錦，風散似分妝。", "葉密煙蒙火，枝低繡拂牆。更憐當暑見，留詠日偏長。"]'),
('yuding-13','新竹','元稹','唐','御定全唐诗','yuding','','[]','新篁才解籜，寒色已青蔥。冉冉偏凝粉，蕭蕭漸引風。',48,'御定全唐詩/json/409.json','["新篁才解籜，寒色已青蔥。冉冉偏凝粉，蕭蕭漸引風。", "扶疏多透日，寥落未成叢。惟有團團節，堅貞大小同。"]'),
('yuding-14','秋相望','元稹','唐','御定全唐诗','yuding','','[]','簷月驚殘夢，浮涼滿夏衾。蠨蛸低戶網，螢火度牆陰。',48,'御定全唐詩/json/409.json','["簷月驚殘夢，浮涼滿夏衾。蠨蛸低戶網，螢火度牆陰。", "爐暗燈光短，床空帳影深。此時相望久，高樹憶橫岑。"]'),
('yuding-15','春病','元稹','唐','御定全唐诗','yuding','','[]','病來閑臥久，因見靜時心。殘月曉窗迥，落花幽院深。',48,'御定全唐詩/json/409.json','["病來閑臥久，因見靜時心。殘月曉窗迥，落花幽院深。", "望山移坐榻，行藥步牆陰。車馬門前度，遙聞哀苦吟。"]'),
('yuding-16','山竹枝','元稹','唐','御定全唐诗','yuding','','[]','深院虎溪竹，遠公身自栽。多慚折君節，扶我出山來。',48,'御定全唐詩/json/409.json','["深院虎溪竹，遠公身自栽。多慚折君節，扶我出山來。", "貴宅安危步，難將混俗材。還投輞川水，從作老龍回。"]'),
('yuding-17','悟禪三首寄胡果','元稹','唐','御定全唐诗','yuding','','[]','近聞胡隱士，潛認得心王。不恨百年促，翻悲萬劫長。',144,'御定全唐詩/json/409.json','["近聞胡隱士，潛認得心王。不恨百年促，翻悲萬劫長。", "有修終有限，無事亦無殃。慎莫通方便，應機不頓忘。", "百年都幾日，何事苦囂然。晚歲倦為學，閒心易到禪。", "病宜多宴坐，貧似少攀緣。自笑無名字，因名自在天。", "近見新章句，因知見在心。春遊晉祠水，晴上霍山岑。", "問法僧當偈，還丹客贈金。莫驚頭欲白，禪觀老彌深。"]'),
('yuding-18','東台去','元稹','唐','御定全唐诗','yuding','','[]','陶君喜不遇，予每為君言。今日東台去，澄心在陸渾。',48,'御定全唐詩/json/409.json','["陶君喜不遇，予每為君言。今日東台去，澄心在陸渾。", "旋抽隨日俸，並買近山園。千萬崔兼白，殷勤承主恩。"]'),
('yuding-19','戴光弓','元稹','唐','御定全唐诗','yuding','','[]','潞府筋角勁，戴光因合成。因君懷膽氣，贈我定交情。',48,'御定全唐詩/json/409.json','["潞府筋角勁，戴光因合成。因君懷膽氣，贈我定交情。", "不擬閑穿葉，那能枉始生。唯調一隻箭，飛入破聊城。"]'),
('yuding-20','劉頗詩','元稹','唐','御定全唐诗','yuding','','[]','一言感激士，三世義忠臣。破甕嫌妨路，燒莊恥屬人。',48,'御定全唐詩/json/409.json','["一言感激士，三世義忠臣。破甕嫌妨路，燒莊恥屬人。", "迥分遼海氣，閑踏洛陽塵。儻使權由我，還君白馬津。"]'),
('yuding-21','夜飲','元稹','唐','御定全唐诗','yuding','','[]','燈火隔簾明，竹梢風雨聲。詩篇隨意贈，杯酒越巡行。',48,'御定全唐詩/json/409.json','["燈火隔簾明，竹梢風雨聲。詩篇隨意贈，杯酒越巡行。", "漫唱江朝曲，閑征藥草名。莫辭終夜飲，朝起又營營。"]'),
('yuding-22','褒城驛','元稹','唐','御定全唐诗','yuding','','[]','嚴秦修此驛，兼漲驛前池。已種千竿竹，又栽千樹梨。',48,'御定全唐詩/json/409.json','["嚴秦修此驛，兼漲驛前池。已種千竿竹，又栽千樹梨。", "四年三月半，新筍晚花時。悵望東川去，等閒題作詩。"]'),
('yuding-23','閑二首','元稹','唐','御定全唐诗','yuding','','[]','晻澹洲煙白，籬篩日腳紅。江喧過雲雨，船泊打頭風。',96,'御定全唐詩/json/409.json','["晻澹洲煙白，籬篩日腳紅。江喧過雲雨，船泊打頭風。", "艇子收魚市，鴉兒噪荻叢。不堪堤上立，滿眼是蚊蟲。", "青衫經夏黕，白髮望鄉稠。雨冷新秋簟，星稀欲曙樓。", "連鴻盡南去，雙鯉本東流。北信無人寄，蟬聲滿樹頭。"]'),
('yuding-24','欲曙','元稹','唐','御定全唐诗','yuding','','[]','江堤閱暗流，漏鼓急殘籌。片月低城堞，稀星轉角樓。',49,'御定全唐詩/json/409.json','["江堤閱暗流，漏鼓急殘籌。片月低城堞，稀星轉角樓。", "鶴媒華表上，sV鵊柳枝頭。不為來趨府，何因欲曙遊。"]'),
('yuding-25','寄胡靈之','元稹','唐','御定全唐诗','yuding','','[]','早歲顛狂伴，城中共幾年。有時潛步出，連夜小亭眠。',48,'御定全唐詩/json/409.json','["早歲顛狂伴，城中共幾年。有時潛步出，連夜小亭眠。", "月影侵床上，花叢在眼前。今宵正風雨，空宅楚江邊。"]'),
('yuding-26','夜雨','元稹','唐','御定全唐诗','yuding','','[]','水怪潛幽草，江雲擁廢居。雷驚空屋柱，電照滿床書。',48,'御定全唐詩/json/409.json','["水怪潛幽草，江雲擁廢居。雷驚空屋柱，電照滿床書。", "竹瓦風頻裂，茅簷雨漸疏。平生滄海意，此去怯為魚。"]'),
('yuding-27','酬李六醉後見寄口號','元稹','唐','御定全唐诗','yuding','','[]','頓愈關風疾，因吟口號詩。文章紛似繡，珠玉布如棋。',72,'御定全唐詩/json/409.json','["頓愈關風疾，因吟口號詩。文章紛似繡，珠玉布如棋。", "健羨觥飛酒，蒼黃日映籬。命童寒色倦，撫稚晚啼饑。", "潦倒慚相識，平生頗自奇。明公將有問，林下是靈龜。"]'),
('yuding-28','歸田','元稹','唐','御定全唐诗','yuding','','[]','陶君三十七，掛綬出都門。我亦今年去，商山淅岸村。',48,'御定全唐詩/json/409.json','["陶君三十七，掛綬出都門。我亦今年去，商山淅岸村。", "冬修方丈室，春種桔槔園。千萬人間事，從茲不復言。"]'),
('yuding-29','緣路','元稹','唐','御定全唐诗','yuding','','[]','總是玲瓏竹，兼藏淺漫溪。沙平深見底，石亂不成泥。',48,'御定全唐詩/json/409.json','["總是玲瓏竹，兼藏淺漫溪。沙平深見底，石亂不成泥。", "煙火遙村落，桑麻隔稻畦。此中如有問，甘被到頭迷。"]'),
('yuding-30','誚盧戡與予數約遊三寺，戡獨沉醉而不行','元稹','唐','御定全唐诗','yuding','','[]','乘興無羈束，閑行信馬蹄。路幽穿竹遠，野迥望雲低。',48,'御定全唐詩/json/409.json','["乘興無羈束，閑行信馬蹄。路幽穿竹遠，野迥望雲低。", "素帚茅花亂，圓珠稻實齊。如何盧進士，空戀醉如泥。"]'),
('yuding-31','遣春三首','元稹','唐','御定全唐诗','yuding','','[]','楊公三不惑，我惑兩般全。逢酒判身病，拈花盡意憐。',144,'御定全唐詩/json/409.json','["楊公三不惑，我惑兩般全。逢酒判身病，拈花盡意憐。", "水生低岸沒，梅蹙小珠連。千萬紅顏輩，須驚又一年。", "柳眼開渾盡，梅心動已闌。風光好時少，杯酒病中難。", "學問慵都廢，聲名老更判。唯餘看花伴，未免憶長安。", "失卻遊花伴，因風浪引將。柳堤遙認馬，梅徑誤尋香。", "晚景行看謝，春心漸欲狂。園林都不到，何處枉風光。"]'),
('yuding-32','歲日','元稹','唐','御定全唐诗','yuding','','[]','一日今年始，一年前事空。淒涼百年事，應與一年同。',24,'御定全唐詩/json/409.json','["一日今年始，一年前事空。淒涼百年事，應與一年同。"]'),
('yuding-33','湘南登臨湘樓','元稹','唐','御定全唐诗','yuding','','[]','高處望瀟湘，花時萬井香。雨餘憐日嫩，歲閨覺春長。',48,'御定全唐詩/json/409.json','["高處望瀟湘，花時萬井香。雨餘憐日嫩，歲閨覺春長。", "霞刹分危榜，煙波透遠光。情知樓上好，不是仲宣鄉。"]'),
('yuding-34','晚宴湘亭','元稹','唐','御定全唐诗','yuding','','[]','晚日宴清湘，晴空走豔陽。花低愁露醉，絮起覺春狂。',48,'御定全唐詩/json/409.json','["晚日宴清湘，晴空走豔陽。花低愁露醉，絮起覺春狂。", "舞旋紅裙急，歌垂碧袖長。甘心出童羖，須一盡時荒。"]'),
('yuding-35','酒醒','元稹','唐','御定全唐诗','yuding','','[]','飲醉日將盡，醒時夜已闌。暗燈風焰曉，春席水窗寒。',48,'御定全唐詩/json/409.json','["飲醉日將盡，醒時夜已闌。暗燈風焰曉，春席水窗寒。", "未解縈身帶，猶傾墜枕冠。呼兒問狼藉，疑是夢中歡。"]'),
('yuding-0','獨遊','元稹','唐','御定全唐诗','yuding','','[]','遠地難逢侶，閒人且獨行。上山隨老鶴，接酒待殘鶯。',48,'御定全唐詩/json/410.json','["遠地難逢侶，閒人且獨行。上山隨老鶴，接酒待殘鶯。", "花當西施面，泉勝衛玠清。鵜鶘滿春野，無限好同聲。"]'),
('yuding-1','洞庭湖','元稹','唐','御定全唐诗','yuding','','[]','人生除泛海，便到洞庭波。駕浪沉西日，吞空接曙河。',48,'御定全唐詩/json/410.json','["人生除泛海，便到洞庭波。駕浪沉西日，吞空接曙河。", "虞巡竟安在，軒樂詎曾過。唯有君山下，狂風萬古多。"]'),
('yuding-2','雪天','元稹','唐','御定全唐诗','yuding','','[]','故鄉千里夢，往事萬重悲。小雪沉陰夜，閑窗老病時。',48,'御定全唐詩/json/410.json','["故鄉千里夢，往事萬重悲。小雪沉陰夜，閑窗老病時。", "獨聞歸去雁，偏詠別來詩。慚愧紅妝女，頻驚兩鬢絲。"]'),
('yuding-3','贈熊士登','元稹','唐','御定全唐诗','yuding','','[]','平生本多思，況複老逢春。今日梅花下，他鄉值故人。',24,'御定全唐詩/json/410.json','["平生本多思，況複老逢春。今日梅花下，他鄉值故人。"]'),
('yuding-4','別嶺南熊判官','元稹','唐','御定全唐诗','yuding','','[]','十年常遠道，不忍別離聲。況複三巴外，仍逢萬里行。',48,'御定全唐詩/json/410.json','["十年常遠道，不忍別離聲。況複三巴外，仍逢萬里行。", "桐花新雨氣，梨葉晚春晴。到海知何日，風波從此生。"]'),
('yuding-5','水上寄樂天','元稹','唐','御定全唐诗','yuding','','[]','眼前明月水，先入漢江流。漢水流江海，西江過庾樓。',48,'御定全唐詩/json/410.json','["眼前明月水，先入漢江流。漢水流江海，西江過庾樓。", "庾樓今夜月，君豈在樓頭。萬一樓頭望，還應望我愁。"]'),
('yuding-6','夏陽亭臨望，寄河陽侍禦堯','元稹','唐','御定全唐诗','yuding','','[]','望遠音書絕，臨川意緒長。殷勤眼前水，千里到河陽。',24,'御定全唐詩/json/410.json','["望遠音書絕，臨川意緒長。殷勤眼前水，千里到河陽。"]'),
('yuding-7','日高睡','元稹','唐','御定全唐诗','yuding','','[]','隔是身如夢，頻來不為名。憐君近南住，時得到山行。',24,'御定全唐詩/json/410.json','["隔是身如夢，頻來不為名。憐君近南住，時得到山行。"]'),
('yuding-8','輞川','元稹','唐','御定全唐诗','yuding','','[]','世累為身累，閑忙不自由。殷勤輞川水，何事出山流。',24,'御定全唐詩/json/410.json','["世累為身累，閑忙不自由。殷勤輞川水，何事出山流。"]'),
('yuding-9','天壇歸','元稹','唐','御定全唐诗','yuding','','[]','為結區中累，因辭洞裏花。還來舊城郭，煙火萬人家。',24,'御定全唐詩/json/410.json','["為結區中累，因辭洞裏花。還來舊城郭，煙火萬人家。"]'),
('yuding-10','雨後','元稹','唐','御定全唐诗','yuding','','[]','倦寢數殘更，孤燈暗又明。竹梢餘雨重，時複拂簾驚。',24,'御定全唐詩/json/410.json','["倦寢數殘更，孤燈暗又明。竹梢餘雨重，時複拂簾驚。"]'),
('yuding-11','晴日','元稹','唐','御定全唐诗','yuding','','[]','多病苦虛羸，晴明強展眉。讀書心緒少，閑臥日長時。',24,'御定全唐詩/json/410.json','["多病苦虛羸，晴明強展眉。讀書心緒少，閑臥日長時。"]'),
('yuding-12','直台','元稹','唐','御定全唐诗','yuding','','[]','麋入神羊隊，鳥驚海鷺眠。仍教百餘日，迎送直廳前。',24,'御定全唐詩/json/410.json','["麋入神羊隊，鳥驚海鷺眠。仍教百餘日，迎送直廳前。"]'),
('yuding-13','行宮','元稹','唐','御定全唐诗','yuding','','[]','寥落古行宮，宮花寂寞紅。白頭宮女在，閑坐說玄宗。',24,'御定全唐詩/json/410.json','["寥落古行宮，宮花寂寞紅。白頭宮女在，閑坐說玄宗。"]'),
('yuding-14','醉行','元稹','唐','御定全唐诗','yuding','','[]','秋風方索漠，霜貌足暌攜。今日騎驄馬，街中醉蹋泥。',24,'御定全唐詩/json/410.json','["秋風方索漠，霜貌足暌攜。今日騎驄馬，街中醉蹋泥。"]'),
('yuding-15','指巡胡','元稹','唐','御定全唐诗','yuding','','[]','遣悶多憑酒，公心只仰胡。挺身唯直指，無意獨欺愚。',24,'御定全唐詩/json/410.json','["遣悶多憑酒，公心只仰胡。挺身唯直指，無意獨欺愚。"]'),
('yuding-16','飲新酒','元稹','唐','御定全唐诗','yuding','','[]','聞君新酒熟，況值菊花秋。莫怪平生志，圖銷盡日愁。',24,'御定全唐詩/json/410.json','["聞君新酒熟，況值菊花秋。莫怪平生志，圖銷盡日愁。"]'),
('yuding-17','香球','元稹','唐','御定全唐诗','yuding','','[]','順俗唯團轉，居中莫動搖。愛君心不惻，猶訝火長燒。',24,'御定全唐詩/json/410.json','["順俗唯團轉，居中莫動搖。愛君心不惻，猶訝火長燒。"]'),
('yuding-18','景申秋八首','元稹','唐','御定全唐诗','yuding','','[]','年年秋意緒，多向雨中生。漸欲煙火近，稍憐衣服輕。',384,'御定全唐詩/json/410.json','["年年秋意緒，多向雨中生。漸欲煙火近，稍憐衣服輕。", "詠詩閑處立，憶事夜深行。濩落尋常慣，淒涼別為情。", "蚊幌雨來卷，燭蛾燈上稀。啼兒冷秋簟，思婦問寒衣。", "簾斷螢火入，窗明蝙蝠飛。良辰日夜去，漸與壯心違。", "嗢嗢簷溜凝，丁丁窗雨繁。枕傾筒簟滑，幔颭案燈翻。", "喚魘兒難覺，吟詩婢苦煩。強眠終不著，閑臥暗消魂。", "瓶瀉高簷雨，窗來激箭風。病憎燈火暗，寒覺薄幃空。", "婢報樵蘇竭，妻愁院落通。老夫慵計數，教想蔡城東。", "風頭難著枕，病眼厭看書。無酒銷長夜，回燈照小餘。", "三元推廢王，九曜入乘除。廊廟應多算，參差斡太虛。", "經雨籬落壞，入秋田地荒。竹垂哀折節，蓮敗惜空房。", "小片慈菇白，低叢柚子黃。眼前撩亂輩，無不是同鄉。", "雨柳枝枝弱，風光片片斜。蜻蜓憐曉露，蛺蝶戀秋花。", "饑啅空籬雀，寒棲滿樹鴉。荒涼池館內，不似有人家。", "病苦十年後，連陰十日餘。人方教作鼠，天豈遣為魚。", "鮫綻酆城劍，蟲凋鬼火書。出聞泥濘盡，何地不摧車。"]'),
('yuding-19','遣行十首','元稹','唐','御定全唐诗','yuding','','[]','慘切風雨夕，沉吟離別情。燕辭前日社，蟬是每年聲。',480,'御定全唐詩/json/410.json','["慘切風雨夕，沉吟離別情。燕辭前日社，蟬是每年聲。", "暗淚深相感，危心亦自驚。不如元不識，俱作路人行。", "十五年前事，恓惶無限情。病僮更借出，羸馬共馳聲。", "射葉楊才破，聞弓雁已驚。小年辛苦學，求得苦辛行。", "徙倚簷宇下，思量去住情。暗螢穿竹見，斜雨隔窗聲。", "就枕回轉數，聞雞撩亂驚。一家同草草，排比送君行。", "已愴朋交別，複懷兒女情。相兄亦相舊，同病又同聲。", "白髮年年剩，秋蓬處處驚。不堪身漸老，頻送異鄉行。", "塞上風雨思，城中兄弟情。北隨鵷立位，南送雁來聲。", "遇適尤兼恨，聞書喜複驚。唯應遙料得，知我伴君行。", "暮欲歌吹樂，暗沖泥水情。稻花秋雨氣，江石夜灘聲。", "犬吠穿籬出，鷗眠起水驚。愁君明月夜，獨自入山行。", "七過褒城驛，回回各為情。八年身世夢，一種水風聲。", "尋覓詩章在，思量歲月驚。更悲西塞別，終夜繞池行。", "褒縣驛前境，曲江池上情。南堤衰柳意，西寺晚鐘聲。", "雲水興方遠，風波心已驚。可憐皆老大，不得自由行。", "見說巴風俗，都無漢性情。猿聲蘆管調，羌笛竹雞聲。", "迎候人應少，平安火莫驚。每逢危棧處，須作貫魚行。", "聞道陰平郡，翛然古戍情。橋兼麋鹿蹋，山應鼓鼙聲。", "羌婦梳頭緊，蕃牛護尾驚。憐君閑悶極，只傍白江行。"]'),
('yuding-20','生春二十首','元稹','唐','御定全唐诗','yuding','','[]','何處生春早，春生雲色中。籠蔥閑著水，晻淡欲隨風。',576,'御定全唐詩/json/410.json','["何處生春早，春生雲色中。籠蔥閑著水，晻淡欲隨風。", "度曉分霞態，餘光庇雪融。晚來低漠漠，渾欲泥幽叢。", "何處生春早，春生漫雪中。渾無到地片，唯逐入樓風。", "屋上些些薄，池心旋旋融。自悲銷散盡，誰假入蘭叢。", "何處生春早，春生霽色中。遠林橫返照，高樹亞東風。", "水凍霜威庇，泥新地氣融。漸知殘雪薄，杪近最憐叢。", "何處生春早，春生曙火中。星圍分暗陌，煙氣滿晴風。", "宮樹棲鴉亂，城樓帶雪融。競排閶闔側，珂傘自相叢。", "何處生春早，春生曉禁中。殿階龍旆日，漏閣寶箏風。", "藥樹香煙重，天顏瑞氣融。柳梅渾未覺，青紫已叢叢。", "何處生春早，春生江路中。雨移臨浦市，晴候過湖風。", "蘆筍錐猶短，淩澌玉漸融。數宗船載足，商婦兩眉叢。", "何處生春早，春生野墅中。病翁閑向日，征婦懶成風。", "斫筤天雖暖，穿區凍未融。鞭牛縣門外，爭土蓋蠶叢。", "何處生春早，春生冰岸中。尚憐扶臘雪，漸覺受東風。", "織女雲橋斷，波神玉貌融。便成嗚咽去，流恨與蓮叢。", "何處生春早，春生柳眼中。芽新才綻日，茸短未含風。", "綠誤眉心重，黃驚蠟淚融。碧條殊未合，愁緒已先叢。", "何處生春早，春生梅援中。蕊排難犯雪，香乞擬來風。", "隴迥羌聲怨，江遙客思融。年年最相惱，緣未有諸叢。", "何處生春早，春生鳥思中。鵲巢移舊歲，鳶羽旋高風。", "鴻雁驚沙暖，鴛鴦愛水融。最憐雙翡翠，飛入小梅叢。", "何處生春早，春生池榭中。鏤瓊冰陷日，文縠水回風。", "柳愛和身動，梅愁合樹融。草芽猶未出，挑得小萱叢。"]');
